var surah002 = {
  number: 2,
  nameArabic: "al-Baqarah",
  nameEnglish: "Al-Baqarah",
  meaning: "The Cow",
  totalAyahs: 286,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laaam-Meeem", english: "L. M", romanUrdu: "Alif Laam Meem" },
    { number: 2, arabic: "ذَٰلِكَ ٱلْكِتَٰبُ لَا رَيْبَ ۛ فِيهِ ۛ هُدًۭى لِّلْمُتَّقِينَ", transliteration: "Thalika alkitabu la rayba feehi hudan lilmuttaqeena", transliterationB: "Zaalikal Kitaabu laa raiba feeh; udal lilmuttaqeen", english: "This is the Book; in it is guidance sure, without doubt, to those who fear Allah", romanUrdu: "Yeh Allah ki kitab hai, is mein koi shakk nahin, hidayat hai un parheizgaar logon ke liye" },
    { number: 3, arabic: "ٱلَّذِينَ يُؤْمِنُونَ بِٱلْغَيْبِ وَيُقِيمُونَ ٱلصَّلَوٰةَ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ", transliteration: "Allatheena yuminoona bialghaybi wayuqeemoona alssalata wamimma razaqnahum yunfiqoona", transliterationB: "Allazeena yu'minoona bilghaibi wa yuqeemoonas salaata wa mimmaa razaqnaahum yunfiqoon", english: "Who believe in the Unseen, are steadfast in prayer, and spend out of what We have provided for them", romanUrdu: "Jo gaib par iman latey hain, namaz qayam karte hain , jo rizq humne unko diya hai usmein se kharch karte hain" },
    { number: 4, arabic: "وَٱلَّذِينَ يُؤْمِنُونَ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ وَبِٱلْءَاخِرَةِ هُمْ يُوقِنُونَ", transliteration: "Waallatheena yuminoona bima onzila ilayka wama onzila min qablika wabialakhirati hum yooqinoona", transliterationB: "Wallazeena yu'minoona bimaa unzila ilaika wa maaa unzila min qablika wa bil Aakhirati hum yooqinoon", english: "And who believe in the Revelation sent to thee, and sent before thy time, and (in their hearts) have the assurance of the Hereafter", romanUrdu: "Jo kitab tumpar nazil ki gayi hai (yani Quran) aur jo kitabein tumse pehle nazil ki gayi thi un sab par iman latey hain aur aakhirat par yaqeen rakhte hain" },
    { number: 5, arabic: "أُو۟لَٰٓئِكَ عَلَىٰ هُدًۭى مِّن رَّبِّهِمْ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Olaika AAala hudan min rabbihim waolaika humu almuflihoona", transliterationB: "Ulaaa'ika 'alaa hudam mir rabbihim wa ulaaa'ika humul muflihoon", english: "They are on (true) guidance, from their Lord, and it is these who will prosper", romanUrdu: "Aisey log apne Rubb ki taraf se raah e raast par hain aur wahi falaah paney waley hain" },
    { number: 6, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ سَوَآءٌ عَلَيْهِمْ ءَأَنذَرْتَهُمْ أَمْ لَمْ تُنذِرْهُمْ لَا يُؤْمِنُونَ", transliteration: "Inna allatheena kafaroo sawaon AAalayhim aanthartahum am lam tunthirhum la yuminoona", transliterationB: "Innal lazeena kafaroo sawaaa'un 'alaihim 'a-anzar tahum am lam tunzirhum laa yu'minoon", english: "As to those who reject Faith, it is the same to them whether thou warn them or do not warn them; they will not believe", romanUrdu: "Jin logon ne (in baaton ko tasleem karne se) inkar kardiya, unke liye yaksan hai, khwa tum unhein khabardaar karo ya na karo, bahar haal woh maanne waley nahin hai" },
    { number: 7, arabic: "خَتَمَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَعَلَىٰ سَمْعِهِمْ ۖ وَعَلَىٰٓ أَبْصَٰرِهِمْ غِشَٰوَةٌۭ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌۭ", transliteration: "Khatama Allahu AAala quloobihim waAAala samAAihim waAAala absarihim ghishawatun walahum AAathabun AAatheemun", transliterationB: "Khatamal laahu 'alaa quloobihim wa 'alaa sam'i-him wa 'alaaa absaarihim ghishaa watunw wa lahum 'azaabun 'azeem", english: "Allah hath set a seal on their hearts and on their hearing, and on their eyes is a veil; great is the penalty they (incur)", romanUrdu: "Allah ne unke dilon aur unke kaano par mohar laga di hai aur unki aankhon par purda padh gaya hai, woh sakht saza ke mustahiq hain" },
    { number: 8, arabic: "وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ وَبِٱلْيَوْمِ ٱلْءَاخِرِ وَمَا هُم بِمُؤْمِنِينَ", transliteration: "Wamina alnnasi man yaqoolu amanna biAllahi wabialyawmi alakhiri wama hum bimumineena", transliterationB: "Wa minan naasi mai yaqoolu aamannaa billaahi wa bil yawmil aakhiri wa maa hum bimu'mineen", english: "Of the people there are some who say: \"We believe in Allah and the Last Day;\" but they do not (really) believe", romanUrdu: "Baaz log aisey bhi hain jo kehte hain ke hum Allah par aur aakhirat ke din par iman laye hain, halaanke dar-haqeeqat woh momin nahin hain" },
    { number: 9, arabic: "يُخَٰدِعُونَ ٱللَّهَ وَٱلَّذِينَ ءَامَنُوا۟ وَمَا يَخْدَعُونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ", transliteration: "YukhadiAAoona Allaha waallatheena amanoo wama yakhdaAAoona illa anfusahum wama yashAAuroona", transliterationB: "Yukhaadi'oonal laaha wallazeena aamanoo wa maa yakhda'oona illaaa anfusahum wa maa yash'uroon", english: "Fain would they deceive Allah and those who believe, but they only deceive themselves, and realise (it) not", romanUrdu: "Woh Allah aur iman laney walon ke saath dhoke-baazi kar rahey hain, magar darasal woh khud apne aap hi ko dhoke mein daal rahey hain aur unhein iska shaoor nahin hai" },
    { number: 10, arabic: "فِى قُلُوبِهِم مَّرَضٌۭ فَزَادَهُمُ ٱللَّهُ مَرَضًۭا ۖ وَلَهُمْ عَذَابٌ أَلِيمٌۢ بِمَا كَانُوا۟ يَكْذِبُونَ", transliteration: "Fee quloobihim maradun fazadahumu Allahu maradan walahum AAathabun aleemun bima kanoo yakthiboona", transliterationB: "Fee quloobihim mara dun fazzdahumul laahu maradan wa lahum 'azaabun aleemum bimaa kaanoo yakziboon", english: "In their hearts is a disease; and Allah has increased their disease: And grievous is the penalty they (incur), because they are false (to themselves)", romanUrdu: "Unke dilon mein ek bimari hai jisey Allah ne aur zyada bada diya, aur jo jhoot woh bolte hain, uski padash mein unke liye dardnaak saza hai" },
    { number: 11, arabic: "وَإِذَا قِيلَ لَهُمْ لَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ قَالُوٓا۟ إِنَّمَا نَحْنُ مُصْلِحُونَ", transliteration: "Waitha qeela lahum la tufsidoo fee alardi qaloo innama nahnu muslihoona", transliterationB: "Wa izaa qeela lahum laa tufsidoo fil ardi qaalo innamaa nahnu muslihoon", english: "When it is said to them: \"Make not mischief on the earth,\" they say: \"Why, we only Want to make peace", romanUrdu: "Jab kabhi unse kaha gaya ke zameen mein fasaad barpa na karo to unhon ne yahi kaha ke hum to islaah karne waley hain" },
    { number: 12, arabic: "أَلَآ إِنَّهُمْ هُمُ ٱلْمُفْسِدُونَ وَلَٰكِن لَّا يَشْعُرُونَ", transliteration: "Ala innahum humu almufsidoona walakin la yashAAuroona", transliterationB: "Alaaa innahum humul mufsidoona wa laakil laa yash'uroon", english: "Of a surety, they are the ones who make mischief, but they realise (it) not", romanUrdu: "Khabardaar! Haqeeqat mein yahi log mufsid (fasaad karne waley) hain magar unhein shaoor nahin hai" },
    { number: 13, arabic: "وَإِذَا قِيلَ لَهُمْ ءَامِنُوا۟ كَمَآ ءَامَنَ ٱلنَّاسُ قَالُوٓا۟ أَنُؤْمِنُ كَمَآ ءَامَنَ ٱلسُّفَهَآءُ ۗ أَلَآ إِنَّهُمْ هُمُ ٱلسُّفَهَآءُ وَلَٰكِن لَّا يَعْلَمُونَ", transliteration: "Waitha qeela lahum aminoo kama amana alnnasu qaloo anuminu kama amana alssufahao ala innahum humu alssufahao walakin la yaAAlamoona", transliterationB: "Wa izaa qeela lahum aaminoo kamaaa aamanan naasu qaalooo anu'minu kamaaa aamanas sufahaaa'; alaaa innahum humus sufahaaa'u wa laakil laa ya'lamoon", english: "When it is said to them: \"Believe as the others believe:\" They say: \"Shall we believe as the fools believe?\" Nay, of a surety they are the fools, but they do not know", romanUrdu: "Aur jab unse kaha gaya jis tarah dusre log iman laye hain usi tarah tum bhi iman lao to unhon ne yahi jawab diya “kya hum bewaqoofon ki tarah iman layein?” khabardaar! Haqeeqat mein to yeh khud bewaqoof hain, magar yeh jantey nahin hain" },
    { number: 14, arabic: "وَإِذَا لَقُوا۟ ٱلَّذِينَ ءَامَنُوا۟ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَوْا۟ إِلَىٰ شَيَٰطِينِهِمْ قَالُوٓا۟ إِنَّا مَعَكُمْ إِنَّمَا نَحْنُ مُسْتَهْزِءُونَ", transliteration: "Waitha laqoo allatheena amanoo qaloo amanna waitha khalaw ila shayateenihim qaloo inna maAAakum innama nahnu mustahzioona", transliterationB: "Wa izaa laqul lazeena aamanoo qaalooo aamannaa wa izaa khalw ilaa shayaateenihim qaalooo innaa ma'akum innamaa nahnu mustahzi'oon", english: "When they meet those who believe, they say: \"We believe;\" but when they are alone with their evil ones, they say: \"We are really with you: We (were) only jesting", romanUrdu: "Jab yeh ehle iman se milte hain, to kehte hain ke hum iman laye hain aur jab alaidagi (alone/privy) mein apne shaytano se milte hain, to kehte hain ke asal mein to hum tumhare saath hain aur in logon se mehaz mazaaq kar rahey hain" },
    { number: 15, arabic: "ٱللَّهُ يَسْتَهْزِئُ بِهِمْ وَيَمُدُّهُمْ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ", transliteration: "Allahu yastahzio bihim wayamudduhum fee tughyanihim yaAAmahoona", transliterationB: "Allahu yastahzi'u bihim wa yamudduhum fee tughyaanihim ya'mahoon", english: "Allah will throw back their mockery on them, and give them rope in their trespasses; so they will wander like blind ones (To and fro)", romanUrdu: "Allah unse mazaq kar raha hai, woh inki rassi daraaz kiye jata hai, aur yeh apni sarkashi mein andhon (blind) ki tarah bhatakte chale jatay hain" },
    { number: 16, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلضَّلَٰلَةَ بِٱلْهُدَىٰ فَمَا رَبِحَت تِّجَٰرَتُهُمْ وَمَا كَانُوا۟ مُهْتَدِينَ", transliteration: "Olaika allatheena ishtarawoo alddalalata bialhuda fama rabihat tijaratuhum wama kanoo muhtadeena", transliterationB: "Ulaaa'ikal lazeenash tara wud dalaalata bilhudaa famaa rabihat tijaaratuhum wa maa kaanoo muhtadeen", english: "These are they who have bartered Guidance for error: But their traffic is profitless, and they have lost true direction", romanUrdu: "Yeh woh log hain jinhon ne hidayat ke badle gumaraahi khareed li hai, magar yeh sauda inke liye nafa-baksh nahin hai aur yeh hargiz saheeh raaste par nahin hain" },
    { number: 17, arabic: "مَثَلُهُمْ كَمَثَلِ ٱلَّذِى ٱسْتَوْقَدَ نَارًۭا فَلَمَّآ أَضَآءَتْ مَا حَوْلَهُۥ ذَهَبَ ٱللَّهُ بِنُورِهِمْ وَتَرَكَهُمْ فِى ظُلُمَٰتٍۢ لَّا يُبْصِرُونَ", transliteration: "Mathaluhum kamathali allathee istawqada naran falamma adaat ma hawlahu thahaba Allahu binoorihim watarakahum fee thulumatin la yubsiroona", transliterationB: "Masaluhum kamasalillazis tawqada naaran falammaaa adaaa'at maa hawlahoo zahabal laahu binoorihim wa tarakahum fee zulumaatil laa yubsiroon", english: "Their similitude is that of a man who kindled a fire; when it lighted all around him, Allah took away their light and left them in utter darkness. So they could not see", romanUrdu: "Inki misaal aisey hai jaise ek shaks ne aag roshan ki aur jab usne sarey maahol ko roshan kardiya to Allah ne inka noor e basarat (vision) salb karliya aur inhein is haal mein chodh diya ke taareekiyon (andheron) mein inhein kuch nazar nahin aata" },
    { number: 18, arabic: "صُمٌّۢ بُكْمٌ عُمْىٌۭ فَهُمْ لَا يَرْجِعُونَ", transliteration: "Summun bukmun AAumyun fahum la yarjiAAoona", transliterationB: "Summum bukmun 'umyun fahum laa yarji'oon", english: "Deaf, dumb, and blind, they will not return (to the path)", romanUrdu: "Yeh behre hain, gungay hain, andhey hain, yeh ab na paltenge" },
    { number: 19, arabic: "أَوْ كَصَيِّبٍۢ مِّنَ ٱلسَّمَآءِ فِيهِ ظُلُمَٰتٌۭ وَرَعْدٌۭ وَبَرْقٌۭ يَجْعَلُونَ أَصَٰبِعَهُمْ فِىٓ ءَاذَانِهِم مِّنَ ٱلصَّوَٰعِقِ حَذَرَ ٱلْمَوْتِ ۚ وَٱللَّهُ مُحِيطٌۢ بِٱلْكَٰفِرِينَ", transliteration: "Aw kasayyibin mina alssamai feehi thulumatun waraAAdun wabarqun yajAAaloona asabiAAahum fee athanihim mina alssawaAAiqi hathara almawti waAllahu muheetun bialkafireena", transliterationB: "Aw kasaiyibim minas samaaa'i feehi zulumaatunw wa ra'dunw wa barq, yaj'aloona asaabi'ahum feee aazaanihim minas sawaa'iqi hazaral mawt' wallaahu muheetum bilkaafireen", english: "Or (another similitude) is that of a rain-laden cloud from the sky: In it are zones of darkness, and thunder and lightning: They press their fingers in their ears to keep out the stunning thunder-clap, the while they are in terror of death. But Allah is ever round the rejecters of Faith", romanUrdu: "Ya phir inki misaal yun samajho ke aasman se zoar ki baarish ho rahi hai aur iske saath andheri ghata aur kadak chamak bhi hai, yeh bijli ki kadake sunkar apni jaano ke khauf se kaano mein ungliyan thunse lete hain aur Allah in munkireen e haqq ko har taraf se gherey mein liye huey hai" },
    { number: 20, arabic: "يَكَادُ ٱلْبَرْقُ يَخْطَفُ أَبْصَٰرَهُمْ ۖ كُلَّمَآ أَضَآءَ لَهُم مَّشَوْا۟ فِيهِ وَإِذَآ أَظْلَمَ عَلَيْهِمْ قَامُوا۟ ۚ وَلَوْ شَآءَ ٱللَّهُ لَذَهَبَ بِسَمْعِهِمْ وَأَبْصَٰرِهِمْ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Yakadu albarqu yakhtafu absarahum kullama adaa lahum mashaw feehi waitha athlama AAalayhim qamoo walaw shaa Allahu lathahaba bisamAAihim waabsarihim inna Allaha AAala kulli shayin qadeerun", transliterationB: "Yakaadul barqu yakhtafu absaarahum kullamaaa adaaa'a lahum mashaw feehi wa izaaa azlama 'alaihim qaamoo; wa law shaaa'al laahu lazahaba bisam'ihim wa absaarihim; innal laaha 'alaa kulli shai'in Qadeer", english: "The lightning all but snatches away their sight; every time the light (Helps) them, they walk therein, and when the darkness grows on them, they stand still. And if Allah willed, He could take away their faculty of hearing and seeing; for Allah hath power over all things", romanUrdu: "Chamak se inki haalat yeh ho rahi hai ke goya anqareeb bijli inki basarat (vision) uchak le jayegi, jab zara kuch roshni inhein mehsoos hoti hai to ismein kuch door chal lete hain aur jab inpar andhera cha jata hai to khade ho jatay hain. Allah chahta to inki samaat (hearing) aur basarat bilkul hi salb karleta, yaqeenan woh har cheez par qadir hai" },
    { number: 21, arabic: "يَٰٓأَيُّهَا ٱلنَّاسُ ٱعْبُدُوا۟ رَبَّكُمُ ٱلَّذِى خَلَقَكُمْ وَٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ", transliteration: "Ya ayyuha alnnasu oAAbudoo rabbakumu allathee khalaqakum waallatheena min qablikum laAAallakum tattaqoona", transliterationB: "Yaaa aiyuhan naasu'budoo Rabbakumul lazee khalaqakum wallazeena min qablikum la'allakum tattaqoon", english: "O ye people! Adore your Guardian-Lord, who created you and those who came before you, that ye may have the chance to learn righteousness", romanUrdu: "Logon! Bandagi ikhtiyar karo apne us Rubb ki jo tumhara aur tumse pehle jo log ho guzre hain un sabka khaliq hai, tumhare bachne ki tawaqqu isi surat se ho sakti hai" },
    { number: 22, arabic: "ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ فِرَٰشًۭا وَٱلسَّمَآءَ بِنَآءًۭ وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزْقًۭا لَّكُمْ ۖ فَلَا تَجْعَلُوا۟ لِلَّهِ أَندَادًۭا وَأَنتُمْ تَعْلَمُونَ", transliteration: "Allathee jaAAala lakumu alarda firashan waalssamaa binaan waanzala mina alssamai maan faakhraja bihi mina alththamarati rizqan lakum fala tajAAaloo lillahi andadan waantum taAAlamoona", transliterationB: "Allazee ja'ala lakumul arda firaashanw wassamaaa'a binaaa 'anw wa anzala minassamaaa'i maaa'an fa akhraja bihee minas samaraati rizqal lakum falaa taj'aloo lillaahi andaadanw wa antum ta'lamoon", english: "Who has made the earth your couch, and the heavens your canopy; and sent down rain from the heavens; and brought forth therewith Fruits for your sustenance; then set not up rivals unto Allah when ye know (the truth)", romanUrdu: "Wahi to hai jisne tumhare liye zameen ka farsh bichaya, aasman ki chath banayi, upar se pani barsaya aur uske zariye se har tarah ki paidwaar nikal kar tumhare liye rizq baham pahunchaya, pas jab tum yeh jaante ho to dusron ko Allah ka madd e muqabil na thehrao" },
    { number: 23, arabic: "وَإِن كُنتُمْ فِى رَيْبٍۢ مِّمَّا نَزَّلْنَا عَلَىٰ عَبْدِنَا فَأْتُوا۟ بِسُورَةٍۢ مِّن مِّثْلِهِۦ وَٱدْعُوا۟ شُهَدَآءَكُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wain kuntum fee raybin mimma nazzalna AAala AAabdina fatoo bisooratin min mithlihi waodAAoo shuhadaakum min dooni Allahi in kuntum sadiqeena", transliterationB: "Wa in kuntum fee raibim mimmaa nazzalnaa 'alaa 'abdinaa fatoo bi Sooratim mim mislihee wad'oo shuhadaaa'akum min doonil laahi in kuntum saadiqeen", english: "And if ye are in doubt as to what We have revealed from time to time to Our servant, then produce a Sura like thereunto; and call your witnesses or helpers (If there are any) besides Allah, if your (doubts) are true", romanUrdu: "Aur agar tumhein is amr mein shakk hai ke yeh kitab jo humne apne bandey par utari hai, yeh hamari hai ya nahin, to iske manind (similar) ek hi surat bana lao, apne saarey humnawa ko bula lo (associates to assist you), ek Allah ko chodh kar baki jis jis ki chaho madad lelo agar tum sacchey ho to yeh kaam karke dikhao" },
    { number: 24, arabic: "فَإِن لَّمْ تَفْعَلُوا۟ وَلَن تَفْعَلُوا۟ فَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِى وَقُودُهَا ٱلنَّاسُ وَٱلْحِجَارَةُ ۖ أُعِدَّتْ لِلْكَٰفِرِينَ", transliteration: "Fain lam tafAAaloo walan tafAAaloo faittaqoo alnnara allatee waqooduha alnnasu waalhijaratu oAAiddat lilkafireena", transliterationB: "Fail lam taf'aloo wa lan taf'aloo fattaqun Naaral latee waqooduhan naasu walhijaaratu u'iddat lilkaafireen", english: "But if ye cannot- and of a surety ye cannot- then fear the Fire whose fuel is men and stones,- which is prepared for those who reject Faith", romanUrdu: "Lekin agar tumne aisa na kiya aur yaqeenan kabhi nahin kar sakte, to daro us aag se jiska indhan (fuel) banengey Insan aur patthar, jo muhaiyya ki gayi hai munkireen e haqq ke liye" },
    { number: 25, arabic: "وَبَشِّرِ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ أَنَّ لَهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ كُلَّمَا رُزِقُوا۟ مِنْهَا مِن ثَمَرَةٍۢ رِّزْقًۭا ۙ قَالُوا۟ هَٰذَا ٱلَّذِى رُزِقْنَا مِن قَبْلُ ۖ وَأُتُوا۟ بِهِۦ مُتَشَٰبِهًۭا ۖ وَلَهُمْ فِيهَآ أَزْوَٰجٌۭ مُّطَهَّرَةٌۭ ۖ وَهُمْ فِيهَا خَٰلِدُونَ", transliteration: "Wabashshiri allatheena amanoo waAAamiloo alssalihati anna lahum jannatin tajree min tahtiha alanharu kullama ruziqoo minha min thamaratin rizqan qaloo hatha allathee ruziqna min qablu waotoo bihi mutashabihan walahum feeha azwajun mutahharatun wahum feeha khalidoona", transliterationB: "Wa bashshiril lazeena aamanoo wa 'amilus saalihaati anna lahum jannaatin tajree min tahtihal anhaaru kullamaa riziqoo minhaa min samaratir rizqan qaaloo haazal lazee ruziqnaa min qablu wa utoo bihee mutashaabihaa, wa lahum feehaaa azwaajum mutahhara tunw wa hum feehaa khaalidoon", english: "But give glad tidings to those who believe and work righteousness, that their portion is Gardens, beneath which rivers flow. Every time they are fed with fruits therefrom, they say: \"Why, this is what we were fed with before,\" for they are given things in similitude; and they have therein companions pure (and holy); and they abide therein (for ever)", romanUrdu: "Aur (aey paighambar), jo log is kitab par iman le aaye aur (iske mutabiq) apne aamaal durust karlein, unhein khushkhabri dedo ke unke liye aisey baagh hain, jinke nichey nehrein behti hongi. Un baaghon ke phal surat mein duniya ke phalon se miltey jhulte honge, jab koi phal unhein khane ko diya jayega, to woh kahenge ke aisey hi phal issey pehle duniya mein humko diye jatay thay. Unke liye wahan pakeeza biwiyan hongi, aur woh wahan hamesha rahenge" },
    { number: 26, arabic: "۞ إِنَّ ٱللَّهَ لَا يَسْتَحْىِۦٓ أَن يَضْرِبَ مَثَلًۭا مَّا بَعُوضَةًۭ فَمَا فَوْقَهَا ۚ فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ فَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۖ وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَيَقُولُونَ مَاذَآ أَرَادَ ٱللَّهُ بِهَٰذَا مَثَلًۭا ۘ يُضِلُّ بِهِۦ كَثِيرًۭا وَيَهْدِى بِهِۦ كَثِيرًۭا ۚ وَمَا يُضِلُّ بِهِۦٓ إِلَّا ٱلْفَٰسِقِينَ", transliteration: "Inna Allaha la yastahyee an yadriba mathalan ma baAAoodatan fama fawqaha faamma allatheena amanoo fayaAAlamoona annahu alhaqqu min rabbihim waamma allatheena kafaroo fayaqooloona matha arada Allahu bihatha mathalan yudillu bihi katheeran wayahdee bihi katheeran wama yudillu bihi illa alfasiqeena", transliterationB: "Innal laaha laa yastahyeee ai yadriba masalam maa ba'oodatan famaa fawqahaa; faammal lazeena aamanoo faya'lamoona annahul haqqu mir rabbihim wa ammal lazeena kafaroo fayaqooloona maazaaa araadal laahu bihaazaa masalaa; yudillu bihee kaseeranw wa yahdee bihee kaseeraa; wa maa yudillu biheee illal faasiqeen", english: "Allah disdains not to use the similitude of things, lowest as well as highest. Those who believe know that it is truth from their Lord; but those who reject Faith say: \"What means Allah by this similitude?\" By it He causes many to stray, and many He leads into the right path; but He causes not to stray, except those who forsake (the path)", romanUrdu: "Haan, Allah issey hargiz nahin sharmata ke machhar ya issey bhi haqeer-tar (insignificant) kisi cheez ki tamseelein (examples) de. Jo log haqq baat ko qabool karne waley hain , woh inhi tamseelon ko dekh kar jaan lete hain ke yeh haqq hai jo unke Rubb hi ki taraf se aaya hai, aur jo maanne waley nahin hain, woh inhein sunkar kehne lagte hain ke aisi tamseelon se Allah ko kya sarokar? Is tarah Allah ek hi baat se bahuton ko gumraahi mein mubtila kardeta hai aur bahuton ko raah e raast dikha deta hai. Aur gumraahi mein woh unhi ko mubtila karta hai jo faasiq hain" },
    { number: 27, arabic: "ٱلَّذِينَ يَنقُضُونَ عَهْدَ ٱللَّهِ مِنۢ بَعْدِ مِيثَٰقِهِۦ وَيَقْطَعُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيُفْسِدُونَ فِى ٱلْأَرْضِ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", transliteration: "Allatheena yanqudoona AAahda Allahi min baAAdi meethaqihi wayaqtaAAoona ma amara Allahu bihi an yoosala wayufsidoona fee alardi olaika humu alkhasiroona", transliterationB: "Allazeena yanqudoona 'ahdal laahi mim ba'di meesaaqihee wa yaqt'oona maaa amaral laahu biheee ai yoosala wa yufsidoona fil ard; ulaaa'ika hum khaasirron", english: "Those who break Allah's Covenant after it is ratified, and who sunder what Allah Has ordered to be joined, and do mischief on earth: These cause loss (only) to themselves", romanUrdu: "Allah ke ahad ko mazboot baandh lene ke baad todh dete hain, Allah ne jisey jodhne ka hukum diya hai usey kaat-te hain, aur zameen mein fasaad barpa karte hain. Haqeeqat mein yahi log nuqsan uthane waley hain" },
    { number: 28, arabic: "كَيْفَ تَكْفُرُونَ بِٱللَّهِ وَكُنتُمْ أَمْوَٰتًۭا فَأَحْيَٰكُمْ ۖ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ثُمَّ إِلَيْهِ تُرْجَعُونَ", transliteration: "Kayfa takfuroona biAllahi wakuntum amwatan faahyakum thumma yumeetukum thumma yuhyeekum thumma ilayhi turjaAAoona", transliterationB: "Kaifa takfuroona billaahi wa kuntum amwaatan fa ahyaakum summa yumeetukum summa yuhyeekum summaa ilaihi turja'oon", english: "How can ye reject the faith in Allah?- seeing that ye were without life, and He gave you life; then will He cause you to die, and will again bring you to life; and again to Him will ye return", romanUrdu: "Tum Allah ke saath kufr ka rawayya kaise ikhtiyar karte ho halaanke tum bay-jaan thay , usne tumko zindagi ata ki, phir wahi tumhari jaan salb karega, phir wahi tumhein dobara zindagi ata karega, phir usi ki taraf tumhein palat kar jana hai" },
    { number: 29, arabic: "هُوَ ٱلَّذِى خَلَقَ لَكُم مَّا فِى ٱلْأَرْضِ جَمِيعًۭا ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ فَسَوَّىٰهُنَّ سَبْعَ سَمَٰوَٰتٍۢ ۚ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Huwa allathee khalaqa lakum ma fee alardi jameeAAan thumma istawa ila alssamai fasawwahunna sabAAa samawatin wahuwa bikulli shayin AAaleemun", transliterationB: "Huwal lazee khalaqa lakum maa fil ardi jamee'an summas tawaaa ilas samaaa'i fasaw waahunna sab'a samaa waat; wa Huwa bikulli shai'in Aleem", english: "It is He Who hath created for you all things that are on earth; Moreover His design comprehended the heavens, for He gave order and perfection to the seven firmaments; and of all things He hath perfect knowledge", romanUrdu: "Wahi to hai, jisne tumhare liye zameen ki saari cheezein paida ki, phir upar ki taraf tawajju farmayi aur saat aasman ustwaar kiye aur woh har cheez ka ilm rakhne wala hai" },
    { number: 30, arabic: "وَإِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى جَاعِلٌۭ فِى ٱلْأَرْضِ خَلِيفَةًۭ ۖ قَالُوٓا۟ أَتَجْعَلُ فِيهَا مَن يُفْسِدُ فِيهَا وَيَسْفِكُ ٱلدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَ ۖ قَالَ إِنِّىٓ أَعْلَمُ مَا لَا تَعْلَمُونَ", transliteration: "Waith qala rabbuka lilmalaikati innee jaAAilun fee alardi khaleefatan qaloo atajAAalu feeha man yufsidu feeha wayasfiku alddimaa wanahnu nusabbihu bihamdika wanuqaddisu laka qala innee aAAlamu ma la taAAlamoona", transliterationB: "Wa iz qaala rabbuka lil malaaa'ikati innee jaa'ilun fil ardi khaleefatan qaalooo ataj'alu feehaa mai yufsidu feehaa wa yasfikud dimaaa'a wa nahnu nusabbihu bihamdika wa nuqaddisu laka qaala inneee a'lamu maa laa ta'lamoon", english: "Behold, thy Lord said to the angels: \"I will create a vicegerent on earth.\" They said: \"Wilt Thou place therein one who will make mischief therein and shed blood?- whilst we do celebrate Thy praises and glorify Thy holy (name)?\" He said: \"I know what ye know not", romanUrdu: "Phir zara us waqt ka tasavvur karo jab tumhare Rubb ne Farishton se kaha tha ke “ main zameen mein ek khalifa banane wala hoon” unhon ne arz kiya : “kya aap zameen mein kisi aisey ko muqarrar karne waley hain, jo iske intezaam ko bigadh dega aur khoon-reziyan karega? Aap ki hamd o sana ke saath tasbeeh aur aap ke liye taqdees to hum kar hi rahey hain.” Farmaya: “ main jaanta hoon jo kuch tum nahin jaante.”" },
    { number: 31, arabic: "وَعَلَّمَ ءَادَمَ ٱلْأَسْمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَى ٱلْمَلَٰٓئِكَةِ فَقَالَ أَنۢبِـُٔونِى بِأَسْمَآءِ هَٰٓؤُلَآءِ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "WaAAallama adama alasmaa kullaha thumma AAaradahum AAala almalaikati faqala anbioonee biasmai haolai in kuntum sadiqeena", transliterationB: "Wa 'allama Aadamal asmaaa'a kullahaa summa 'aradahum 'alal malaaa'ikati faqaala ambi'oonee bias maaa'i haaa'ulaaa'i in kuntum saadiqeen", english: "And He taught Adam the names of all things; then He placed them before the angels, and said: \"Tell me the names of these if ye are right", romanUrdu: "Iske baad Allah ne Adam ko saari cheezon ke naam sikhaye, phir unhein Farishton ke samne pesh kiya aur farmaya “agar tumhara khayal saheeh hai (ke kisi khalifa ke taqarrur se intezam bigad jayega) to zara in cheezon ke naam batao.”" },
    { number: 32, arabic: "قَالُوا۟ سُبْحَٰنَكَ لَا عِلْمَ لَنَآ إِلَّا مَا عَلَّمْتَنَآ ۖ إِنَّكَ أَنتَ ٱلْعَلِيمُ ٱلْحَكِيمُ", transliteration: "Qaloo subhanaka la AAilma lana illa ma AAallamtana innaka anta alAAaleemu alhakeemu", transliterationB: "Qaaloo subhaanaka laa 'ilma lanaaa illaa maa 'allamtanaaa innaka antal'aleemul hakeem", english: "They said: \"Glory to Thee, of knowledge We have none, save what Thou Hast taught us: In truth it is Thou Who art perfect in knowledge and wisdom", romanUrdu: "Unhon ne arz kiya: “nuqs (defect) se paak to aap hi ki zaat hai, hum to bas itna hi ilm rakhte hain, jitna aapne humko de diya hai, haqeeqat mein sab kuch jaanne aur samajhne wala aap ke siwa koi nahin”" },
    { number: 33, arabic: "قَالَ يَٰٓـَٔادَمُ أَنۢبِئْهُم بِأَسْمَآئِهِمْ ۖ فَلَمَّآ أَنۢبَأَهُم بِأَسْمَآئِهِمْ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ غَيْبَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَأَعْلَمُ مَا تُبْدُونَ وَمَا كُنتُمْ تَكْتُمُونَ", transliteration: "Qala ya adamu anbihum biasmaihim falamma anbaahum biasmaihim qala alam aqul lakum innee aAAlamu ghayba alssamawati waalardi waaAAlamu ma tubdoona wama kuntum taktumoona", transliterationB: "Qaala yaaa Aadamu ambi' hum biasmaaa'ihimfalammaaa amba ahum bi asmaaa'ihim qaala alam aqul lakum inneee a'lamu ghaibas samaawaati wal ardi wa a'lamu maa tubdoona wa maa kuntum taktumoon", english: "He said: \"O Adam! Tell them their names.\" When he had told them, Allah said: \"Did I not tell you that I know the secrets of heaven and earth, and I know what ye reveal and what ye conceal", romanUrdu: "Phir Allah ne Adam se kaha: “ tum inhein in cheezon ke naam batao” jab usne unko un sabke naam bata diye, to Allah ne farmaya : “ maine tum se kaha na tha ke main aasmano aur zameen ki woh saari haqeeqatein jaanta hoon jo tumse makhfi (chupi) hain, jo kuch tum zaahir karte ho, woh bhi mujhey maloom hai aur jo kuch tum chupate ho, usey bhi main jaanta hoon.”" },
    { number: 34, arabic: "وَإِذْ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ وَٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَٰفِرِينَ", transliteration: "Waith qulna lilmalaikati osjudoo liadama fasajadoo illa ibleesa aba waistakbara wakana mina alkafireena", transliterationB: "Wa iz qulnaa lilmalaaa'i katis judoo liAadama fasajadooo illaaa Ibleesa abaa wastakbara wa kaana minal kaafireen", english: "And behold, We said to the angels: \"Bow down to Adam\" and they bowed down. Not so Iblis: he refused and was haughty: He was of those who reject Faith", romanUrdu: "Phir jab humne Farishton ko hukum diya ke Adam ke aagey jhuk jao, to sab jhuk gaye, magar Iblis ne inkar kiya, woh apni badayi ke ghamand mein padh gaya aur nafarmaano mein shamil ho gaya" },
    { number: 35, arabic: "وَقُلْنَا يَٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ وَكُلَا مِنْهَا رَغَدًا حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّٰلِمِينَ", transliteration: "Waqulna ya adamu oskun anta wazawjuka aljannata wakula minha raghadan haythu shituma wala taqraba hathihi alshshajarata fatakoona mina alththalimeena", transliterationB: "Wa qulnaa yaaa Aadamus kun anta wa zawjukal jannata wa kulaa minhaa raghadan haisu shi'tumaa wa laa taqabaa haazihish shajarata fatakoonaa minaz zaalimeen", english: "We said: \"O Adam! dwell thou and thy wife in the Garden; and eat of the bountiful things therein as (where and when) ye will; but approach not this tree, or ye run into harm and transgression", romanUrdu: "Phir humne Adam se kaha ke “Tum aur tumhari biwi, dono jannat mein raho aur yahan ba-faraagat jo chaho khao, magar is darakht ka rukh na karna, warna zaalimon mein shumaar honge”" },
    { number: 36, arabic: "فَأَزَلَّهُمَا ٱلشَّيْطَٰنُ عَنْهَا فَأَخْرَجَهُمَا مِمَّا كَانَا فِيهِ ۖ وَقُلْنَا ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّۭ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّۭ وَمَتَٰعٌ إِلَىٰ حِينٍۢ", transliteration: "Faazallahuma alshshaytanu AAanha faakhrajahuma mimma kana feehi waqulna ihbitoo baAAdukum libaAAdin AAaduwwun walakum fee alardi mustaqarrun wamataAAun ila heenin", transliterationB: "Fa azallahumash Shaitaanu 'anhaa fa akhrajahumaa mimmaa kaanaa fee wa qulnah bitoo ba'dukum liba'din 'aduwwunw wa lakum fil ardi mustaqarrunw wa mataa'un ilaa heen", english: "Then did Satan make them slip from the (garden), and get them out of the state (of felicity) in which they had been. We said: \"Get ye down, all (ye people), with enmity between yourselves. On earth will be your dwelling-place and your means of livelihood - for a time", romanUrdu: "Aakhir e kaar shaytan ne in dono ko is darakht ki targeeb dekar hamare hukum ki pairwi se hata diya aur inhein us haalat se nikalwa kar chodha jismein woh thay. Humne hukum diya ke, ab tum sab yahan se utar jao, tum ek dusre ke dushman ho aur tumhein ek khaas waqt tak zameen (mein) theharna aur wahin guzar basar karna hai”" },
    { number: 37, arabic: "فَتَلَقَّىٰٓ ءَادَمُ مِن رَّبِّهِۦ كَلِمَٰتٍۢ فَتَابَ عَلَيْهِ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ", transliteration: "Fatalaqqa adamu min rabbihi kalimatin fataba AAalayhi innahu huwa alttawwabu alrraheemu", transliterationB: "Fatalaqqaaa Aadamu mir Rabbihee Kalimaatin fataaba 'alayh; innahoo Huwat Tawwaabur Raheem", english: "Then learnt Adam from his Lord words of inspiration, and his Lord Turned towards him; for He is Oft-Returning, Most Merciful", romanUrdu: "Us waqt Adam ne apne Rubb se chandh kaleemat seekh kar tauba ki, jisko uske Rubb ne qabool karliya, kyunke woh bada maaf karne wala aur reham farmane wala hai" },
    { number: 38, arabic: "قُلْنَا ٱهْبِطُوا۟ مِنْهَا جَمِيعًۭا ۖ فَإِمَّا يَأْتِيَنَّكُم مِّنِّى هُدًۭى فَمَن تَبِعَ هُدَاىَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Qulna ihbitoo minha jameeAAan faimma yatiyannakum minnee hudan faman tabiAAa hudaya fala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Qulnah bitoo minhaa jamee 'an fa immaa yaatiyannakum minnee hudan faman tabi'a hudaaya falaa khawfun 'alaihim wa laa hum yahza noon", english: "We said: \"Get ye down all from here; and if, as is sure, there comes to you Guidance from me, whosoever follows My guidance, on them shall be no fear, nor shall they grieve", romanUrdu: "Humne kaha ke, “tum sab yahan se utar jao phir jo meri taraf se koi hidayat tumhare paas pahunche, to jo log meri hidayat ki pairwi karenge, unke liye kisi khauf aur ranjh ka mauqa na hoga" },
    { number: 39, arabic: "وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Waallatheena kafaroo wakaththaboo biayatina olaika ashabu alnnari hum feeha khalidoona", transliterationB: "Wallazeena kafaroo wa kaz zabooo bi aayaatinaa ulaaa'ika Ashaabun Naari hum feehaa khaalidoon", english: "But those who reject Faith and belie Our Signs, they shall be companions of the Fire; they shall abide therein", romanUrdu: "Aur jo isko qabool karne se inkar karenge aur hamari aayat ko jhutlayenge, woh aag mein janey waley log hain, jahan woh hamesha rahenge.”" },
    { number: 40, arabic: "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَوْفُوا۟ بِعَهْدِىٓ أُوفِ بِعَهْدِكُمْ وَإِيَّٰىَ فَٱرْهَبُونِ", transliteration: "Ya banee israeela othkuroo niAAmatiya allatee anAAamtu AAalaykum waawfoo biAAahdee oofi biAAahdikum waiyyaya fairhabooni", transliterationB: "Yaa Baneee Israaa'eelaz kuroo ni'matiyal lateee an'amtu 'alaikum wa awfoo bi'Ahdeee oofi bi ahdikum wa iyyaaya farhaboon", english: "O Children of Israel! call to mind the (special) favour which I bestowed upon you, and fulfil your covenant with Me as I fulfil My Covenant with you, and fear none but Me", romanUrdu: "Aey bani-Israel ! zara khayal karo meri us niyamat ka jo maine tumko ata ki thi, mere saath tumhara jo ahad (covenant) tha usey tum poora karo, to mera jo ahad tumhare saath tha usey main poora karunga aur mujh hi se tum daro" },
    { number: 41, arabic: "وَءَامِنُوا۟ بِمَآ أَنزَلْتُ مُصَدِّقًۭا لِّمَا مَعَكُمْ وَلَا تَكُونُوٓا۟ أَوَّلَ كَافِرٍۭ بِهِۦ ۖ وَلَا تَشْتَرُوا۟ بِـَٔايَٰتِى ثَمَنًۭا قَلِيلًۭا وَإِيَّٰىَ فَٱتَّقُونِ", transliteration: "Waaminoo bima anzaltu musaddiqan lima maAAakum wala takoonoo awwala kafirin bihi wala tashtaroo biayatee thamanan qaleelan waiyyaya faittaqooni", transliterationB: "Wa aaminoo bimaaa anzaltu musaddiqal limaa ma'akum wa laa takoonooo awwala kaafirim bihee wa laa tashtaroo bi Aayaatee samanan qaleelanw wa iyyaaya fattaqoon", english: "And believe in what I reveal, confirming the revelation which is with you, and be not the first to reject Faith therein, nor sell My Signs for a small price; and fear Me, and Me alone", romanUrdu: "Aur maine jo kitab bheji hai uspar iman lao, yeh us kitab ki taeed (confirm) mein hai jo tumhare paas pehle se maujood thi, lihaza sabse pehle tum hi iske munkir na ban jao thodi keemat par meri aayat ko na bech daalo aur mere gazab se bacho" },
    { number: 42, arabic: "وَلَا تَلْبِسُوا۟ ٱلْحَقَّ بِٱلْبَٰطِلِ وَتَكْتُمُوا۟ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ", transliteration: "Wala talbisoo alhaqqa bialbatili wataktumoo alhaqqa waantum taAAlamoona", transliterationB: "Wa laa talbisul haqqa bilbaatili wa taktumul haqqa wa antum ta'lamoon", english: "And cover not Truth with falsehood, nor conceal the Truth when ye know (what it is)", romanUrdu: "Baatil ka rang chadha kar haqq ko mushtaba (confusing) na banao aur na jaante boojhte haqq ko chupane ki koshish karo" },
    { number: 43, arabic: "وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱرْكَعُوا۟ مَعَ ٱلرَّٰكِعِينَ", transliteration: "Waaqeemoo alssalata waatoo alzzakata wairkaAAoo maAAa alrrakiAAeena", transliterationB: "Wa aqeemus salaata wa aatuz zakaata warka'oo ma'ar raaki'een", english: "And be steadfast in prayer; practise regular charity; and bow down your heads with those who bow down (in worship)", romanUrdu: "Namaz qayam karo, zakaat do aur jo log mere aagey jhuk rahey hain unke saath tum bhi jhuk jao" },
    { number: 44, arabic: "۞ أَتَأْمُرُونَ ٱلنَّاسَ بِٱلْبِرِّ وَتَنسَوْنَ أَنفُسَكُمْ وَأَنتُمْ تَتْلُونَ ٱلْكِتَٰبَ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Atamuroona alnnasa bialbirri watansawna anfusakum waantum tatloona alkitaba afala taAAqiloona", transliterationB: "Ataamuroonan naasa bilbirri wa tansawna anfusakum wa antum tatloonal Kitaab; afalaa ta'qiloon", english: "Do ye enjoin right conduct on the people, and forget (To practise it) yourselves, and yet ye study the Scripture? Will ye not understand", romanUrdu: "Tum dusron ko to neki ka raasta ikhtiyar karne ke liye kehte ho, magar apne aap ko bhool jatay ho? Halaanke tum kitab ki tilawat karte ho, kya tum aqal se bilkul hi kaam nahin letay" },
    { number: 45, arabic: "وَٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ وَإِنَّهَا لَكَبِيرَةٌ إِلَّا عَلَى ٱلْخَٰشِعِينَ", transliteration: "WaistaAAeenoo bialssabri waalssalati wainnaha lakabeeratun illa AAala alkhashiAAeena", transliterationB: "Wasta'eenoo bissabri was Salaah; wa innahaa lakabee ratun illaa alal khaashi'een", english: "Nay, seek (Allah's) help with patient perseverance and prayer: It is indeed hard, except to those who bring a lowly spirit", romanUrdu: "Sabar aur namaz se madad lo, beshak namaz ek sakht mushkil kaam hai" },
    { number: 46, arabic: "ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُوا۟ رَبِّهِمْ وَأَنَّهُمْ إِلَيْهِ رَٰجِعُونَ", transliteration: "Allatheena yathunnoona annahum mulaqoo rabbihim waannahum ilayhi rajiAAoona", transliterationB: "Allazeena yazunnoona annahum mulaaqoo Rabbihim wa annahum ilaihi raaji'oon", english: "Who bear in mind the certainty that they are to meet their Lord, and that they are to return to Him", romanUrdu: "Magar un farma-bardaar bandon ke liye mushkil nahin hai jo samajhte hain ke aakhir e kaar unhein apne Rubb se milna aur usi ki taraf palat kar jana hai" },
    { number: 47, arabic: "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Ya banee israeela othkuroo niAAmatiya allatee anAAamtu AAalaykum waannee faddaltukum AAala alAAalameena", transliterationB: "Yaa Baneee Israaa'eelaz kuroo ni'matiyal lateee an'amtu 'alaikum wa annee faddaltukum 'alal 'aalameen", english: "Children of Israel! call to mind the (special) favour which I bestowed upon you, and that I preferred you to all other (for My Message)", romanUrdu: "Aey bani Israel! Yaad karo meri us niyamat ko , jissey maine tumhein nawaza tha aur is baat ko ke maine tumhein duniya ki saari qaumon par fazilat ata ki thi" },
    { number: 48, arabic: "وَٱتَّقُوا۟ يَوْمًۭا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍۢ شَيْـًۭٔا وَلَا يُقْبَلُ مِنْهَا شَفَٰعَةٌۭ وَلَا يُؤْخَذُ مِنْهَا عَدْلٌۭ وَلَا هُمْ يُنصَرُونَ", transliteration: "Waittaqoo yawman la tajzee nafsun AAan nafsin shayan wala yuqbalu minha shafaAAatun wala yukhathu minha AAadlun wala hum yunsaroona", transliterationB: "Wattaqoo Yawmal laa tajzee nafsun 'an nafsin shai'anw wa laa yuqbalu minhaa shafaa'atunw wa laa yu'khazu minhaa 'adlunw wa laa hum yunsaroon", english: "Then guard yourselves against a day when one soul shall not avail another nor shall intercession be accepted for her, nor shall compensation be taken from her, nor shall anyone be helped (from outside)", romanUrdu: "Aur daro us din se jab koi kisi ke zara kaam na aayega, na kisi ki taraf se sifarish qabool hogi, na kisi ko fidiya lekar choda jayega, aur na mujreemon ko kahin se madad mil sakegi" },
    { number: 49, arabic: "وَإِذْ نَجَّيْنَٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ يُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌۭ مِّن رَّبِّكُمْ عَظِيمٌۭ", transliteration: "Waith najjaynakum min ali firAAawna yasoomoonakum sooa alAAathabi yuthabbihoona abnaakum wayastahyoona nisaakum wafee thalikum balaon min rabbikum AAatheemun", transliterationB: "Wa iz najjainaakum min Aali Fir'awna yasoomoonakum sooo'al azaabi yuzabbihoona abuaaa'akum wa yastahyoona nisaaa'akum; wa fee zaalikum balaaa'um mir Rabbikum 'azeem", english: "And remember, We delivered you from the people of Pharaoh: They set you hard tasks and punishments, slaughtered your sons and let your women-folk live; therein was a tremendous trial from your Lord", romanUrdu: "Yaad karo woh waqt, jab humne tumko Firouniyon ki ghulami se nijaat bakshi, unhon ne tumhein sakht azaab mein mubtila kar rakkha tha, tumhare ladkon ko zibah karte thay aur tumhari ladkiyon ko zinda rehne dete thay aur is haalat mein tumhare Rubb ki taraf se tumhari badi aazmaish thi" },
    { number: 50, arabic: "وَإِذْ فَرَقْنَا بِكُمُ ٱلْبَحْرَ فَأَنجَيْنَٰكُمْ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَ وَأَنتُمْ تَنظُرُونَ", transliteration: "Waith faraqna bikumu albahra faanjaynakum waaghraqna ala firAAawna waantum tanthuroona", transliterationB: "Wa iz faraqnaa bikumul bahra fa anjainaakum wa agh-raqnaaa Aala Fir'awna wa antum tanzuroon", english: "And remember We divided the sea for you and saved you and drowned Pharaoh's people within your very sight", romanUrdu: "Yaad karo woh waqt, jab humne samandar phadh kar tumhare liye raasta banaya, phir ismein se tumhein ba-khairiyat guzarwa diya, phir wahin tumhari aankhon ke saamne Firouniyon ko garqaab (drown) kiya" },
    { number: 51, arabic: "وَإِذْ وَٰعَدْنَا مُوسَىٰٓ أَرْبَعِينَ لَيْلَةًۭ ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَٰلِمُونَ", transliteration: "Waith waAAadna moosa arbaAAeena laylatan thumma ittakhathtumu alAAijla min baAAdihi waantum thalimoona", transliterationB: "Wa iz waa'adnaa Moosaaa arba'eena lailatan summattakhaztumul 'ijla mim ba'dihee wa antum zaalimoon", english: "And remember We appointed forty nights for Moses, and in his absence ye took the calf (for worship), and ye did grievous wrong", romanUrdu: "Yaad karo, jab humne Moosa ko chalis shabana roz ki qarardaad par bulaya, to uske peechey tum bachdey (calf) ko apna mabood bana baithey us waqt tumne badi zyadati ki thi" },
    { number: 52, arabic: "ثُمَّ عَفَوْنَا عَنكُم مِّنۢ بَعْدِ ذَٰلِكَ لَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Thumma AAafawna AAankum min baAAdi thalika laAAallakum tashkuroona", transliterationB: "Summa 'afawnaa 'ankum mim ba'di zaalika la'allakum tashkuroon", english: "Even then We did forgive you; there was a chance for you to be grateful", romanUrdu: "Magar ispar bhi humne tumhein maaf kardiya ke shayad ab tum shukar-guzar bano" },
    { number: 53, arabic: "وَإِذْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَٱلْفُرْقَانَ لَعَلَّكُمْ تَهْتَدُونَ", transliteration: "Waith atayna moosa alkitaba waalfurqana laAAallakum tahtadoona", transliterationB: "Wa iz aatainaa Moosal kitaaba wal Furqaana la'allakum tahtadoon", english: "And remember We gave Moses the Scripture and the Criterion (Between right and wrong): There was a chance for you to be guided aright", romanUrdu: "Yaad karo ke (theek us waqt jab tum yeh zulm kar rahey thay) humne Moosa ko kitab aur furqan ata ki taa-ke tum uske zariye se seedha raasta paa sako" },
    { number: 54, arabic: "وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَٰقَوْمِ إِنَّكُمْ ظَلَمْتُمْ أَنفُسَكُم بِٱتِّخَاذِكُمُ ٱلْعِجْلَ فَتُوبُوٓا۟ إِلَىٰ بَارِئِكُمْ فَٱقْتُلُوٓا۟ أَنفُسَكُمْ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ عِندَ بَارِئِكُمْ فَتَابَ عَلَيْكُمْ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ", transliteration: "Waith qala moosa liqawmihi ya qawmi innakum thalamtum anfusakum biittikhathikumu alAAijla fatooboo ila bariikum faoqtuloo anfusakum thalikum khayrun lakum AAinda bariikum fataba AAalaykum innahu huwa alttawwabu alrraheemu", transliterationB: "Wa iz qaala Moosaa liqawmihee yaa qawmi innakum zalamtum anfusakum bittikhaa zikumul 'ijla fatoobooo ilaa Baari'ikum faqtulooo anfusakum zaalikum khairul lakum 'inda Baari'ikum fataaba 'alaikum; innahoo Huwat Tawwaabur Raheem", english: "And remember Moses said to his people: \"O my people! Ye have indeed wronged yourselves by your worship of the calf: So turn (in repentance) to your Maker, and slay yourselves (the wrong-doers); that will be better for you in the sight of your Maker.\" Then He turned towards you (in forgiveness): For He is Oft-Returning, Most Merciful", romanUrdu: "Yaad karo jab Moosa ( yeh niyamat lete huey palta, to us) ne apni qaum se kaha ke “logon, tumne bachde ko mabood bana kar apne upar sakht zulm kiya hai, lihaza tum log apne khaliq ke huzoor tauba karo aur apni jaano ko halaak karo, isi mein tumhare khaliq ke nazdeek tumhari behtari hai” us waqt tumhare khaliq ne tumhari tauba qabool karli ke woh bada maaf karne wala aur reham farmane wala hai" },
    { number: 55, arabic: "وَإِذْ قُلْتُمْ يَٰمُوسَىٰ لَن نُّؤْمِنَ لَكَ حَتَّىٰ نَرَى ٱللَّهَ جَهْرَةًۭ فَأَخَذَتْكُمُ ٱلصَّٰعِقَةُ وَأَنتُمْ تَنظُرُونَ", transliteration: "Waith qultum ya moosa lan numina laka hatta nara Allaha jahratan faakhathatkumu alssaAAiqatu waantum tanthuroona", transliterationB: "Wa iz qultum yaa Moosaa lan nu'mina laka hattaa naral laaha jahratan fa akhazat kumus saa'iqatu wa antum tanzuroon", english: "And remember ye said: \"O Moses! We shall never believe in thee until we see Allah manifestly,\" but ye were dazed with thunder and lighting even as ye looked on", romanUrdu: "Yaad karo jab tumne Moosa se kaha tha ke hum tumhare kehne ka hargiz yaqeen na karenge, jab tak ke apni aankhon se alaniya khuda ko ( tumse kalaam karte) na dekhlein, us waqt tumhare dekhte dekhte ek zabardast saayqe ne(thunderbolt struck) tumko aa liya" },
    { number: 56, arabic: "ثُمَّ بَعَثْنَٰكُم مِّنۢ بَعْدِ مَوْتِكُمْ لَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Thumma baAAathnakum min baAAdi mawtikum laAAallakum tashkuroona", transliterationB: "Summa ba'asnaakum mim ba'di mawtikum la'allakum tashkuroon", english: "Then We raised you up after your death: Ye had the chance to be grateful", romanUrdu: "Tum be-jaan hokar gir chuke thay, magar phir humne tumko jila uthaya, shayad ke is ehsan ke baad tum shukar-guzar ban jao" },
    { number: 57, arabic: "وَظَلَّلْنَا عَلَيْكُمُ ٱلْغَمَامَ وَأَنزَلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ ۖ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "Wathallalna AAalaykumu alghamama waanzalna AAalaykumu almanna waalssalwa kuloo min tayyibati ma razaqnakum wama thalamoona walakin kanoo anfusahum yathlimoona", transliterationB: "Wa zallalnaa 'alaikumul ghamaama wa anzalnaa 'alaikumul Manna was Salwaa kuloo min taiyibaati maa razaqnaakum wa maa zalamoonaa wa laakin kaanooo anfusahum yazlimoon", english: "And We gave you the shade of clouds and sent down to you Manna and quails, saying: \"Eat of the good things We have provided for you:\" (But they rebelled); to us they did no harm, but they harmed their own souls", romanUrdu: "Humne tumpar abar ka saya (cloud to overshadow) kiya, mann o salwa ki giza tumhare liye faraham ki aur tumse kaha ke jo paak cheezein humne tumhein bakshi hain, unhein khao, magar tumhare aslaaf (forefathers) ne jo kuch kiya, woh humpar zulm na tha, balke unhon ne aap apne hi upar zulm kiya" },
    { number: 58, arabic: "وَإِذْ قُلْنَا ٱدْخُلُوا۟ هَٰذِهِ ٱلْقَرْيَةَ فَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ رَغَدًۭا وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًۭا وَقُولُوا۟ حِطَّةٌۭ نَّغْفِرْ لَكُمْ خَطَٰيَٰكُمْ ۚ وَسَنَزِيدُ ٱلْمُحْسِنِينَ", transliteration: "Waith qulna odkhuloo hathihi alqaryata fakuloo minha haythu shitum raghadan waodkhuloo albaba sujjadan waqooloo hittatun naghfir lakum khatayakum wasanazeedu almuhsineena", transliterationB: "Wa iz qulnad khuloo haazihil qaryata fakuloo minhaa haisu shi'tum raghadanw wadkhulul baaba sujjadanw wa qooloo hittatun naghfir lakum khataayaakum; wa sanazeedul muhsineen", english: "And remember We said: \"Enter this town, and eat of the plenty therein as ye wish; but enter the gate with humility, in posture and in words, and We shall forgive you your faults and increase (the portion of) those who do good", romanUrdu: "Phir yaad karo jab humne kaha tha ke, “yeh basti jo tumhare saamne hai, ismein dakhil ho jao, iski paidawaar jis tarah chaho mazey se khao, magar basti ke darwaze mein sajda-reiz hotey huey daakhil hona aur kehte jana hitta-tun hitta-tun (Relieve us of our burdens/magfirat), hum tumhari khataon se darguzar karenge aur neikukaron ko mazeed fazal o karam se nawazenge”" },
    { number: 59, arabic: "فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَنزَلْنَا عَلَى ٱلَّذِينَ ظَلَمُوا۟ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ", transliteration: "Fabaddala allatheena thalamoo qawlan ghayra allathee qeela lahum faanzalna AAala allatheena thalamoo rijzan mina alssamai bima kanoo yafsuqoona", transliterationB: "Fabaddalal lazeena zalamoo qawlan ghairal lazee qeela lahum fa anzalnaa 'alal lazeena zalamoo rijzam minas samaaa'i bimaa kaanoo yafsuqoon", english: "But the transgressors changed the word from that which had been given them; so We sent on the transgressors a plague from heaven, for that they infringed (Our command) repeatedly", romanUrdu: "Magar jo baat kahi gayi thi, zalimon ne usey badal kar kuch aur kardiya, aakhir e kaar humne zulm karne walon par aasman se azaab nazil kiya, yeh saza thi un na-farmaniyon ki jo woh kar rahey thay" },
    { number: 60, arabic: "۞ وَإِذِ ٱسْتَسْقَىٰ مُوسَىٰ لِقَوْمِهِۦ فَقُلْنَا ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنفَجَرَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًۭا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍۢ مَّشْرَبَهُمْ ۖ كُلُوا۟ وَٱشْرَبُوا۟ مِن رِّزْقِ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", transliteration: "Waithi istasqa moosa liqawmihi faqulna idrib biAAasaka alhajara fainfajarat minhu ithnata AAashrata AAaynan qad AAalima kullu onasin mashrabahum kuloo waishraboo min rizqi Allahi wala taAAthaw fee alardi mufsideena", transliterationB: "Wa izis tasqaa Moosaa liqawmihee faqulnad rib bi'asaakal hajara fanfajarat minhusnataaa 'ashrata 'aynan qad 'alima kullu unaasim mash rabahum kuloo washraboo mir rizqil laahi wa laa ta'saw fil ardi mufsideen", english: "And remember Moses prayed for water for his people; We said: \"Strike the rock with thy staff.\" Then gushed forth therefrom twelve springs. Each group knew its own place for water. So eat and drink of the sustenance provided by Allah, and do no evil nor mischief on the (face of the) earth", romanUrdu: "Yaad karo, jab Moosa ne apni qaum ke liye pani ki dua ki to humne kaha ke falaan chattan par apna asa maaro chunanchey ussey barah (twelve) chashmey (springs) phoot nikle aur har qabiley ne jaan liya ke kaunsi jagah uske pani lene ki hai. Us waqt yeh hidayat kardi gayi thi ke Allah ka diya hua rizq khao, pio aur zameen mein fasaad na phaylate phiro" },
    { number: 61, arabic: "وَإِذْ قُلْتُمْ يَٰمُوسَىٰ لَن نَّصْبِرَ عَلَىٰ طَعَامٍۢ وَٰحِدٍۢ فَٱدْعُ لَنَا رَبَّكَ يُخْرِجْ لَنَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ مِنۢ بَقْلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَا ۖ قَالَ أَتَسْتَبْدِلُونَ ٱلَّذِى هُوَ أَدْنَىٰ بِٱلَّذِى هُوَ خَيْرٌ ۚ ٱهْبِطُوا۟ مِصْرًۭا فَإِنَّ لَكُم مَّا سَأَلْتُمْ ۗ وَضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ وَٱلْمَسْكَنَةُ وَبَآءُو بِغَضَبٍۢ مِّنَ ٱللَّهِ ۗ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّۦنَ بِغَيْرِ ٱلْحَقِّ ۗ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ", transliteration: "Waith qultum ya moosa lan nasbira AAala taAAamin wahidin faodAAu lana rabbaka yukhrij lana mimma tunbitu alardu min baqliha waqiththaiha wafoomiha waAAadasiha wabasaliha qala atastabdiloona allathee huwa adna biallathee huwa khayrun ihbitoo misran fainna lakum ma saaltum waduribat AAalayhimu alththillatu waalmaskanatu wabaoo bighadabin mina Allahi thalika biannahum kanoo yakfuroona biayati Allahi wayaqtuloona alnnabiyyeena bighayri alhaqqi thalika bima AAasaw wakanoo yaAAtadoona", transliterationB: "Wa iz qultum yaa Moosaa lan nasbira 'alaa ta'aaminw waahidin fad'u lanaa rabbaka yukhrij lanaa mimmaa tumbitul ardu mimbaqlihaa wa qis saaa'ihaa wa foomihaa wa 'adasihaa wa basalihaa qaala atastabdiloonal lazee huwa adnaa billazee huwa khayr; ihbitoo misran fa inna lakum maa sa altum; wa duribat 'alaihimuz zillatu walmaskanatu wa baaa'oo bighadabim minal laah; zaalika bi annahum kaano yakfuroona bi aayaatil laahi wa yaqtuloonan Nabiyyeena bighairil haqq; zaalika bimaa 'asaw wa kaanoo ya'tadoon", english: "And remember ye said: \"O Moses! we cannot endure one kind of food (always); so beseech thy Lord for us to produce for us of what the earth groweth, -its pot-herbs, and cucumbers, Its garlic, lentils, and onions.\" He said: \"Will ye exchange the better for the worse? Go ye down to any town, and ye shall find what ye want!\" They were covered with humiliation and misery; they drew on themselves the wrath of Allah. This because they went on rejecting the Signs of Allah and slaying His Messengers without just cause. This because they rebelled and went on transgressing", romanUrdu: "Yaad karo, jab tumne kaha tha ke, “Aey Moosa, hum ek hi tarah ke khane par sabr nahin kar saktey, apne Rubb se dua karo ke hamare liye zameen ki paidawaar saag, tarkari, kheera, kakdi, gehoon, lasan, pyaz, daal wagaira paida karey” to Moosa ne kaha “ “kya ek behtar cheez ke bajaye tum adna darje ki cheezein lena chahte ho? Accha, kisi shehri aabaadi mein jaa raho, jo kuch tum maangte ho wahan mil jayega”. Aakhir e kaar naubat yahan tak pahunchi ke zillat o khwari aur pasti o badhaali unpar musallat ho gayi aur woh Allah ke gazab mein ghir gaye, yeh nateeja tha iska jo woh Allah ki aayat se kufr karne lagey aur paighambaron ko na-haqq qatal karne lagey, yeh nateeja tha unki nafarmaaniyon ka aur is baat ka ke woh hudood e sharaa se nikal nikal jatay thay" },
    { number: 62, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلنَّصَٰرَىٰ وَٱلصَّٰبِـِٔينَ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَعَمِلَ صَٰلِحًۭا فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Inna allatheena amanoo waallatheena hadoo waalnnasara waalssabieena man amana biAllahi waalyawmi alakhiri waAAamila salihan falahum ajruhum AAinda rabbihim wala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Innal lazeena aamanoo wallazeena haadoo wan nasaaraa was Saabi'eena man aamana billaahi wal yawmil aakhiri wa 'amila saalihan falahum ajruhum 'inda Rabbihim wa laa khawfun 'alaihim wa laa hum yahzanoon", english: "Those who believe (in the Qur'an), and those who follow the Jewish (scriptures), and the Christians and the Sabians,- any who believe in Allah and the Last Day, and work righteousness, shall have their reward with their Lord; on them shall be no fear, nor shall they grieve", romanUrdu: "Yaqeen jaano ke Nabi e arabi ko maanne waley hon ya yahudi, Isayi hon ya Sabyi, jo bhi Allah aur roz e aakhir par iman layega aur neik amal karega, uska ajar uske Rubb ke paas hai aur uske liye kisi khauf aur ranjh ka mauqa nahin hai" },
    { number: 63, arabic: "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ", transliteration: "Waith akhathna meethaqakum warafaAAna fawqakumu alttoora khuthoo ma ataynakum biquwwatin waothkuroo ma feehi laAAallakum tattaqoona", transliterationB: "Wa iz akhaznaa meesaaqakum wa rafa'naa fawqakumut Toora khuzoo maaa aatainaakum biquwwatinw wazkuroo maa feehi la'allakum tattaqoon", english: "And remember We took your covenant and We raised above you (The towering height) of Mount (Sinai): (Saying): \"Hold firmly to what We have given you and bring (ever) to remembrance what is therein: Perchance ye may fear Allah", romanUrdu: "Yaad karo woh waqt, jab humne Tur (tur pahad) ko tumpar utha kar tumse pukhta ahad liya tha aur kaha tha ke “jo kitab hum tumhein de rahey hain usey mazbooti ke saath thamna aur jo ehkaam o hidayaat ismein darj hain unhein yaad rakhna, isi zariye se tawaqqu ki ja sakti hai ke tum taqwa ki rawish par chal sakogey”" },
    { number: 64, arabic: "ثُمَّ تَوَلَّيْتُم مِّنۢ بَعْدِ ذَٰلِكَ ۖ فَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ لَكُنتُم مِّنَ ٱلْخَٰسِرِينَ", transliteration: "Thumma tawallaytum min baAAdi thalika falawla fadlu Allahi AAalaykum warahmatuhu lakuntum mina alkhasireena", transliterationB: "Summa tawallaitum mim ba'di zaalika falawlaa fadlul laahi 'alaikum wa rahmatuhoo lakuntum minal khaasireen", english: "But ye turned back thereafter: Had it not been for the Grace and Mercy of Allah to you, ye had surely been among the lost", romanUrdu: "Magar iske baad tum apne ahad se phir gaye ispar bhi Allah ke fazal aur uski rehmat ne tumhara saath na choda, warna tum kabhi ke tabaah ho chuke hotay" },
    { number: 65, arabic: "وَلَقَدْ عَلِمْتُمُ ٱلَّذِينَ ٱعْتَدَوْا۟ مِنكُمْ فِى ٱلسَّبْتِ فَقُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَٰسِـِٔينَ", transliteration: "Walaqad AAalimtumu allatheena iAAtadaw minkum fee alssabti faqulna lahum koonoo qiradatan khasieena", transliterationB: "Wa laqad 'alimtumul lazeena'-tadaw minkum fis Sabti faqulnaa lahum koonoo qiradatan khaasi'een", english: "And well ye knew those amongst you who transgressed in the matter of the Sabbath: We said to them: \"Be ye apes, despised and rejected", romanUrdu: "Phir tumhein apni qaum ke un logon ka qissa to maloom hi hai jinhon ne Sabt (sabbath) ka kanoon toda tha, humne unhein kehdiya ke bandar ban jao aur is haal mein raho ke har taraf se tumpar dhutkaar phitkaar padey" },
    { number: 66, arabic: "فَجَعَلْنَٰهَا نَكَٰلًۭا لِّمَا بَيْنَ يَدَيْهَا وَمَا خَلْفَهَا وَمَوْعِظَةًۭ لِّلْمُتَّقِينَ", transliteration: "FajaAAalnaha nakalan lima bayna yadayha wama khalfaha wamawAAithatan lilmuttaqeena", transliterationB: "Faja'alnaahaa nakaalal limaa baina yadihaa wa maa khalfahaa wa maw'izatal lilmuttaqeen", english: "So We made it an example to their own time and to their posterity, and a lesson to those who fear Allah", romanUrdu: "Is tarah humne unke anjaam ko us zamane ke logon aur baad ki aane wali nasalon ke liye ibrat aur darne walon ke liye naseehat bana kar choda" },
    { number: 67, arabic: "وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦٓ إِنَّ ٱللَّهَ يَأْمُرُكُمْ أَن تَذْبَحُوا۟ بَقَرَةًۭ ۖ قَالُوٓا۟ أَتَتَّخِذُنَا هُزُوًۭا ۖ قَالَ أَعُوذُ بِٱللَّهِ أَنْ أَكُونَ مِنَ ٱلْجَٰهِلِينَ", transliteration: "Waith qala moosa liqawmihi inna Allaha yamurukum an tathbahoo baqaratan qaloo atattakhithuna huzuwan qala aAAoothu biAllahi an akoona mina aljahileena", transliterationB: "Wa iz qaala Moosaa liqawmiheee innal laaha yaamurukum an tazbahoo baqaratan qaalooo atattakhizunna huzuwan qaala a'oozu billaahi an akoona minal jaahileen", english: "And remember Moses said to his people: \"Allah commands that ye sacrifice a heifer.\" They said: \"Makest thou a laughing-stock of us?\" He said: \"Allah save me from being an ignorant (fool)", romanUrdu: "Phir woh waqiya yaad karo, jab Moosa ne apne qaum se kaha ke, Allah tumhein ek gai (cow) zibaah karne ka hukm deta hai. Kehne lagey kya tum humse mazaaq karte ho? Moosa ne kaha, main issey khuda ki panaah maangta hoon ke jaahilon ki si baatein karoon" },
    { number: 68, arabic: "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ لَّا فَارِضٌۭ وَلَا بِكْرٌ عَوَانٌۢ بَيْنَ ذَٰلِكَ ۖ فَٱفْعَلُوا۟ مَا تُؤْمَرُونَ", transliteration: "Qaloo odAAu lana rabbaka yubayyin lana ma hiya qala innahu yaqoolu innaha baqaratun la faridun wala bikrun AAawanun bayna thalika faifAAaloo ma tumaroona", transliterationB: "Qaalud-'u lanaa rabbaka yubaiyil lanaa maa hee; qaala innahoo yaqoolu innahaa baqaratul laa faaridunw wa laa bikrun 'awaanum baina zaalika faf'aloo maa tu'maroon", english: "They said: \"Beseech on our behalf Thy Lord to make plain to us what (heifer) it is!\" He said; \"He says: The heifer should be neither too old nor too young, but of middling age. Now do what ye are commanded", romanUrdu: "Bole, accha apne Rubb se darkhwast karo ke woh humein is gai ki kuch tafseel bataye, Moosa ne kaha, Allah ka irshad hai ke woh aisi gai honi chahiye jo na boodhi ho na bachhiya, balke ausat umar ki ho, lihaza jo hukm diya jata hai uski tameel karo" },
    { number: 69, arabic: "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا لَوْنُهَا ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ صَفْرَآءُ فَاقِعٌۭ لَّوْنُهَا تَسُرُّ ٱلنَّٰظِرِينَ", transliteration: "Qaloo odAAu lana rabbaka yubayyin lana ma lawnuha qala innahu yaqoolu innaha baqaratun safrao faqiAAun lawnuha tasurru alnnathireena", transliterationB: "Qaalud-'u lanaa rabaaka yubaiyil lanaa maa lawnuhaa; qaala innahoo yaqoolu innahaa baqaratun safraaa'u faqi'ul lawnuhaa tasurrunnaazireen", english: "They said: \"Beseech on our behalf Thy Lord to make plain to us Her colour.\" He said: \"He says: A fawn-coloured heifer, pure and rich in tone, the admiration of beholders", romanUrdu: "Phir kehne lagey apne Rubb se yeh aur puch do ke uska rang kaisa ho, Moosa ne kaha woh farmata hai zard (yellow) rang ki gai honi chahiye, jiska rang aisa shukh (bright) ho ke dekhne walon ka jee khush ho jaye" },
    { number: 70, arabic: "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ إِنَّ ٱلْبَقَرَ تَشَٰبَهَ عَلَيْنَا وَإِنَّآ إِن شَآءَ ٱللَّهُ لَمُهْتَدُونَ", transliteration: "Qaloo odAAu lana rabbaka yubayyin lana ma hiya inna albaqara tashabaha AAalayna wainna in shaa Allahu lamuhtadoona", transliterationB: "Qaalud-'u lanaa rabbaka yubaiyil lanaa maa hiya innal baqara tashaabaha 'alainaa wa innaaa in shaaa'al laahu lamuhtadoon", english: "They said: \"Beseech on our behalf Thy Lord to make plain to us what she is: To us are all heifers alike: We wish indeed for guidance, if Allah wills", romanUrdu: "Phir boley apne Rubb se saaf saaf puch kar batao kaisi gai matloob hai, humein iski taayun mein ishtabah (confusion) ho gaya hai, Allah ne chaha to hum iska pata paa lenge" },
    { number: 71, arabic: "قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ لَّا ذَلُولٌۭ تُثِيرُ ٱلْأَرْضَ وَلَا تَسْقِى ٱلْحَرْثَ مُسَلَّمَةٌۭ لَّا شِيَةَ فِيهَا ۚ قَالُوا۟ ٱلْـَٰٔنَ جِئْتَ بِٱلْحَقِّ ۚ فَذَبَحُوهَا وَمَا كَادُوا۟ يَفْعَلُونَ", transliteration: "Qala innahu yaqoolu innaha baqaratun la thaloolun tutheeru alarda wala tasqee alhartha musallamatun la shiyata feeha qaloo alana jita bialhaqqi fathabahooha wama kadoo yafAAaloona", transliterationB: "Qaala innahoo yaqoolu innahaa baqaratul laa zaloolun tuseerul arda wa laa tasqil harsa musallamatullaa shiyata feehaa; qaalul 'aana jita bilhaqq; fazabahoohaa wa maa kaado yaf'aloon", english: "He said: \"He says: A heifer not trained to till the soil or water the fields; sound and without blemish.\" They said: \"Now hast thou brought the truth.\" Then they offered her in sacrifice, but not with good-will", romanUrdu: "Moosa ne jawab diya: Allah kehta hai ke woh aisi gai hai jissey khidmat nahin li jati, na zameen joth-ti hai na pani kheenchti hai, saheeh saalim aur be-daag hai, ispar woh pukaar utthey ke haan, ab tumne theek pata bataya hai,phir unhone usey zibaah kiya, warna woh aisa karte maloom na hotay thay" },
    { number: 72, arabic: "وَإِذْ قَتَلْتُمْ نَفْسًۭا فَٱدَّٰرَْٰٔتُمْ فِيهَا ۖ وَٱللَّهُ مُخْرِجٌۭ مَّا كُنتُمْ تَكْتُمُونَ", transliteration: "Waith qataltum nafsan faiddaratum feeha waAllahu mukhrijun ma kuntum taktumoona", transliterationB: "Wa iz qataltum nafsan faddaara'tum feehaa wallaahu mukrijum maa kuntum taktumoon", english: "Remember ye slew a man and fell into a dispute among yourselves as to the crime: But Allah was to bring forth what ye did hide", romanUrdu: "Aur tumhein yaad hai woh waqia jab tumne ek shaks ki jaan li thi, phir uske barey mein jhagadne aur ek dusre par qatal ka ilzam thopne lagey thay aur Allah ne faisla karliya tha ke jo kuch tum chupate ho usey khol kar rakh dega" },
    { number: 73, arabic: "فَقُلْنَا ٱضْرِبُوهُ بِبَعْضِهَا ۚ كَذَٰلِكَ يُحْىِ ٱللَّهُ ٱلْمَوْتَىٰ وَيُرِيكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ", transliteration: "Faqulna idriboohu bibaAAdiha kathalika yuhyee Allahu almawta wayureekum ayatihi laAAallakum taAAqiloona", transliterationB: "Faqulnad riboohu biba'dihaa; kazaalika yuhyil laa hul mawtaa wa yureekum aayaatihee la'allakum ta'qiloon", english: "So We said: \"Strike the (body) with a piece of the (heifer).\" Thus Allah bringeth the dead to life and showeth you His Signs: Perchance ye may understand", romanUrdu: "Us waqt humne hukm diya ke maqtool ki laash ko uske ek hissey se zarb lagaoo, dekho is tarah Allah murdon ko zindagi bakshta hai aur tumhein apni nishaniyan dikhata hai taa-ke tum samjho" },
    { number: 74, arabic: "ثُمَّ قَسَتْ قُلُوبُكُم مِّنۢ بَعْدِ ذَٰلِكَ فَهِىَ كَٱلْحِجَارَةِ أَوْ أَشَدُّ قَسْوَةًۭ ۚ وَإِنَّ مِنَ ٱلْحِجَارَةِ لَمَا يَتَفَجَّرُ مِنْهُ ٱلْأَنْهَٰرُ ۚ وَإِنَّ مِنْهَا لَمَا يَشَّقَّقُ فَيَخْرُجُ مِنْهُ ٱلْمَآءُ ۚ وَإِنَّ مِنْهَا لَمَا يَهْبِطُ مِنْ خَشْيَةِ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Thumma qasat quloobukum min baAAdi thalika fahiya kaalhijarati aw ashaddu qaswatan wainna mina alhijarati lama yatafajjaru minhu alanharu wainna minha lama yashshaqqaqu fayakhruju minhu almao wainna minha lama yahbitu min khashyati Allahi wama Allahu bighafilin AAamma taAAmaloona", transliterationB: "Summa qasat quloobukum mim ba'di zaalika fahiya kalhijaarati aw-ashaadu qaswah; wa inna minal hijaarati lamaa yatafajjaru minhul anhaar; wa inna minhaa lamaa yash shaqqaqu fayakhruju minhul maaa'; wa inna minhaa lamaa yahbitu min khashyatil laa; wa mal laahu bighaafilin 'ammaa ta'maloon", english: "Thenceforth were your hearts hardened: They became like a rock and even worse in hardness. For among rocks there are some from which rivers gush forth; others there are which when split asunder send forth water; and others which sink for fear of Allah. And Allah is not unmindful of what ye do", romanUrdu: "Magar aisi nishaniyan dekhne ke baad bhi aakhir e kaar tumhare dil sakht hogaye, pattharon ki tarah sakht, balke sakhti mein kuch inse bhi badey huey, kyunke pattharon mein se to koi aisa bhi hota hai jismein se chashme phoot behte hain, koi phathta hai aur ismein se pani nikal aata hai aur koi khuda ke khauf se laraz kar girr bhi padhta hai. Allah tumhare kartooton se bekhabar nahin hai" },
    { number: 75, arabic: "۞ أَفَتَطْمَعُونَ أَن يُؤْمِنُوا۟ لَكُمْ وَقَدْ كَانَ فَرِيقٌۭ مِّنْهُمْ يَسْمَعُونَ كَلَٰمَ ٱللَّهِ ثُمَّ يُحَرِّفُونَهُۥ مِنۢ بَعْدِ مَا عَقَلُوهُ وَهُمْ يَعْلَمُونَ", transliteration: "AfatatmaAAoona an yuminoo lakum waqad kana fareequn minhum yasmaAAoona kalama Allahi thumma yuharrifoonahu min baAAdi ma AAaqaloohu wahum yaAAlamoona", transliterationB: "Afatatma'oona ai yu'minoo lakum wa qad kaana fareequm minhum yasma'oona Kalaamal laahi summa yuharri foonahoo mim ba'di maa'aqaloohu wa hum ya'lamoon", english: "Can ye (o ye men of Faith) entertain the hope that they will believe in you?- Seeing that a party of them heard the Word of Allah, and perverted it knowingly after they understood it", romanUrdu: "Aey Musalmano! Ab kya in logon se tum yeh tawaqqu rakhte ho ke yeh tumhari dawat par iman le ayenge? Halaanke inmein se ek giroh ka shewa yeh raha hai ke Allah ka kalaam suna aur phir khoob samajh boojh kar danista ismein tehreef (changes) ki" },
    { number: 76, arabic: "وَإِذَا لَقُوا۟ ٱلَّذِينَ ءَامَنُوا۟ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَا بَعْضُهُمْ إِلَىٰ بَعْضٍۢ قَالُوٓا۟ أَتُحَدِّثُونَهُم بِمَا فَتَحَ ٱللَّهُ عَلَيْكُمْ لِيُحَآجُّوكُم بِهِۦ عِندَ رَبِّكُمْ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Waitha laqoo allatheena amanoo qaloo amanna waitha khala baAAduhum ila baAAdin qaloo atuhaddithoonahum bima fataha Allahu AAalaykum liyuhajjookum bihi AAinda rabbikum afala taAAqiloona", transliterationB: "Wa izaa laqul lazeena aamanoo qaalooo aamannaa wa izaakhalaa ba'duhum ilaa ba'din qaalooo atuhaddisoonahum bimaa fatahal laahu 'alaikum liyuhaajjookum bihee 'inda rabbikum; afalaa ta'qiloon", english: "Behold! when they meet the men of Faith, they say: \"We believe\": But when they meet each other in private, they say: \"Shall you tell them what Allah hath revealed to you, that they may engage you in argument about it before your Lord?\"- Do ye not understand (their aim)", romanUrdu: "(Muhammad Rasool Allah par) iman laney walon se milte hain to kehte hain ke hum bhi unhein maante hain, aur jab aapas mein ek dusre se takhliye (private) ki baat chit hoti hai to kehte hain ke bewaqoof ho gaye ho? In logon ko woh baatein batate ho jo Allah ne tumpar kholi hain taa-ke tumhare Rubb ke paas tumhare muqable mein unhein hujjat mein pesh karein" },
    { number: 77, arabic: "أَوَلَا يَعْلَمُونَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ", transliteration: "Awala yaAAlamoona anna Allaha yaAAlamu ma yusirroona wama yuAAlinoona", transliterationB: "Awalaa ya'lamoona annal laaha ya'lamu maa yusirroona wa maa yu'linoon", english: "Know they not that Allah knoweth what they conceal and what they reveal", romanUrdu: "Aur kya yeh jaante nahin hain ke jo kuch yeh chupate hain aur jo kuch zaahir karte hain, Allah ko sab baaton ki khabar hai" },
    { number: 78, arabic: "وَمِنْهُمْ أُمِّيُّونَ لَا يَعْلَمُونَ ٱلْكِتَٰبَ إِلَّآ أَمَانِىَّ وَإِنْ هُمْ إِلَّا يَظُنُّونَ", transliteration: "Waminhum ommiyyoona la yaAAlamoona alkitaba illa amaniyya wain hum illa yathunnoona", transliterationB: "Wa minhum ummiyyoona laa ya'lamoonal kitaaba illaaa amaaniyya wa in hum illaa yazunnoon", english: "And there are among them illiterates, who know not the Book, but (see therein their own) desires, and they do nothing but conjecture", romanUrdu: "Inmein ek dusra giroh ummiyon ka hai, jo kitab ka to ilm rakhte nahin, bas apni bay-buniyad ummedon aur aarzuon ko liye baithey hain aur mehaz weham o gumaan par chale jaa rahey hain" },
    { number: 79, arabic: "فَوَيْلٌۭ لِّلَّذِينَ يَكْتُبُونَ ٱلْكِتَٰبَ بِأَيْدِيهِمْ ثُمَّ يَقُولُونَ هَٰذَا مِنْ عِندِ ٱللَّهِ لِيَشْتَرُوا۟ بِهِۦ ثَمَنًۭا قَلِيلًۭا ۖ فَوَيْلٌۭ لَّهُم مِّمَّا كَتَبَتْ أَيْدِيهِمْ وَوَيْلٌۭ لَّهُم مِّمَّا يَكْسِبُونَ", transliteration: "Fawaylun lillatheena yaktuboona alkitaba biaydeehim thumma yaqooloona hatha min AAindi Allahi liyashtaroo bihi thamanan qaleelan fawaylun lahum mimma katabat aydeehim wawaylun lahum mimma yaksiboona", transliterationB: "Fawailul lillazeena yaktuboonal kitaaba bi aydddhim summa yaqooloona haazaa min 'indil laahi liyashtaroo bihee samanan qaleelan fawilul lahum mimaa katabat aydeehim wa wailul lahum mimmaa yaksiboon", english: "Then woe to those who write the Book with their own hands, and then say:\"This is from Allah,\" to traffic with it for miserable price!- Woe to them for what their hands do write, and for the gain they make thereby", romanUrdu: "Pas halakat aur tabahi hai un logon ke liye jo apne haathon se sharaa ka nawishta likhte hain (who write books with their own hands), phir logon se kehte hain ke yeh Allah ke paas se aaya hua hai taa-ke iske muawze mein thoda sa faiyda hasil karlein. Unke haathon ka likha bhi unke liye tabahi ka samaan hai aur unki yeh kamayi bhi unke liye mujeeb e halakat" },
    { number: 80, arabic: "وَقَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًۭا مَّعْدُودَةًۭ ۚ قُلْ أَتَّخَذْتُمْ عِندَ ٱللَّهِ عَهْدًۭا فَلَن يُخْلِفَ ٱللَّهُ عَهْدَهُۥٓ ۖ أَمْ تَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Waqaloo lan tamassana alnnaru illa ayyaman maAAdoodatan qul attakhathtum AAinda Allahi AAahdan falan yukhlifa Allahu AAahdahu am taqooloona AAala Allahi ma la taAAlamoona", transliterationB: "Wa qaaloo lan tamassanan Naaru illaaa ayyaamam ma'doo dah; qul attakhaztum 'indal laahi 'ahdan falai yukhlifal laahu 'ahdahooo am taqooloona 'alal laahi maa laa ta'lamoon", english: "And they say: \"The Fire shall not touch us but for a few numbered days:\" Say: \"Have ye taken a promise from Allah, for He never breaks His promise? or is it that ye say of Allah what ye do not know", romanUrdu: "Woh kehte hain ke dozakh ki aag humein hargiz choone wali nahin illa yeh ke chandh roz ki saza mil jaye to mil jaye. Inse pucho , kya tumne Allah se koi ahad le liya hai, jiski khilaf-warzi woh nahin kar sakta? Ya baat yeh hai ke tum Allah ke zimme daal kar aisi baatein kehdete ho jinke mutaaliq tumhein ilm nahin hai ke usne inka zimma liya hai? Aakhir tumhein dozakh ki aag kyun na chooeygi" },
    { number: 81, arabic: "بَلَىٰ مَن كَسَبَ سَيِّئَةًۭ وَأَحَٰطَتْ بِهِۦ خَطِيٓـَٔتُهُۥ فَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Bala man kasaba sayyiatan waahatat bihi khateeatuhu faolaika ashabu alnnari hum feeha khalidoona", transliterationB: "Balaa man kasaba sayyi'atanw wa ahaatat bihee khateee'atuhoo fa-ulaaa'ika Ashaabun Naari hum feehaa khaalidoon", english: "Nay, those who seek gain in evil, and are girt round by their sins,- they are companions of the Fire: Therein shall they abide (For ever)", romanUrdu: "Jo bhi badhi kamayega aur apni khata-kaari ke chakkar mein pada rahega, woh dozakhi hai aur dozakh hi mein woh hamesha rahega" },
    { number: 82, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Waallatheena amanoo waAAamiloo alssalihati olaika ashabu aljannati hum feeha khalidoona", transliterationB: "Wallazeena aamanoo wa 'amilus saalihaati ulaaa'ika Ashaabul Jannati hum feeha khaalidoon", english: "But those who have faith and work righteousness, they are companions of the Garden: Therein shall they abide (For ever)", romanUrdu: "Aur jo log imam layenge aur neik amal karnege wahi jannati hain aur jannat mein woh hamesha rahenge" },
    { number: 83, arabic: "وَإِذْ أَخَذْنَا مِيثَٰقَ بَنِىٓ إِسْرَٰٓءِيلَ لَا تَعْبُدُونَ إِلَّا ٱللَّهَ وَبِٱلْوَٰلِدَيْنِ إِحْسَانًۭا وَذِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَقُولُوا۟ لِلنَّاسِ حُسْنًۭا وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ثُمَّ تَوَلَّيْتُمْ إِلَّا قَلِيلًۭا مِّنكُمْ وَأَنتُم مُّعْرِضُونَ", transliteration: "Waith akhathna meethaqa banee israeela la taAAbudoona illa Allaha wabialwalidayni ihsanan wathee alqurba waalyatama waalmasakeeni waqooloo lilnnasi husnan waaqeemoo alssalata waatoo alzzakata thumma tawallaytum illa qaleelan minkum waantum muAAridoona", transliterationB: "Wa iz akhaznaa meesaaqa Baneee Israaa'eela laa ta'budoona illal laaha wa bil waalidaini ihsaananw wa zil qurbaa walyataamaa walmasaakeeni wa qooloo linnaasi husnanw wa aqeemus salaata wa aatuzZakaata summa tawallitum illaa qaleelam minkum wa antum mu'ridoon", english: "And remember We took a covenant from the Children of Israel (to this effect): Worship none but Allah; treat with kindness your parents and kindred, and orphans and those in need; speak fair to the people; be steadfast in prayer; and practise regular charity. Then did ye turn back, except a few among you, and ye backslide (even now)", romanUrdu: "Yaad karo, Israel ki aulad se humne pukhta ahad liya tha ke Allah ke siwa kisi ki ibadat na karna, Maa Baap ke saath, rishtedaaron ke saath, yateemon aur miskeeno ke saath neik sulook karna, logon se bhali baat kehna , Namaz qayam karna aur zakaat dena, magar thode aadmiyon ke siwa tum sab us ahad se phir gaye aur ab tak phirey huey ho" },
    { number: 84, arabic: "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ لَا تَسْفِكُونَ دِمَآءَكُمْ وَلَا تُخْرِجُونَ أَنفُسَكُم مِّن دِيَٰرِكُمْ ثُمَّ أَقْرَرْتُمْ وَأَنتُمْ تَشْهَدُونَ", transliteration: "Waith akhathna meethaqakum la tasfikoona dimaakum wala tukhrijoona anfusakum min diyarikum thumma aqrartum waantum tashhadoona", transliterationB: "Wa iz akhaznaa meesaa qakum laa tasfikoona dimaaa'akum wa laa tukrijoona anfusakum min diyaarikum summa aqrartum wa antum tashhadoon", english: "And remember We took your covenant (to this effect): Shed no blood amongst you, nor turn out your own people from your homes: and this ye solemnly ratified, and to this ye can bear witness", romanUrdu: "Phir zara yaad karo, humne tumse mazboot ahad liya tha ke aapas mein ek dusre ka khoon na bahana aur na ek dusre ko ghar se be-ghar karna, tumne iska iqrar kiya tha, tum khud ispar gawah ho" },
    { number: 85, arabic: "ثُمَّ أَنتُمْ هَٰٓؤُلَآءِ تَقْتُلُونَ أَنفُسَكُمْ وَتُخْرِجُونَ فَرِيقًۭا مِّنكُم مِّن دِيَٰرِهِمْ تَظَٰهَرُونَ عَلَيْهِم بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَإِن يَأْتُوكُمْ أُسَٰرَىٰ تُفَٰدُوهُمْ وَهُوَ مُحَرَّمٌ عَلَيْكُمْ إِخْرَاجُهُمْ ۚ أَفَتُؤْمِنُونَ بِبَعْضِ ٱلْكِتَٰبِ وَتَكْفُرُونَ بِبَعْضٍۢ ۚ فَمَا جَزَآءُ مَن يَفْعَلُ ذَٰلِكَ مِنكُمْ إِلَّا خِزْىٌۭ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَيَوْمَ ٱلْقِيَٰمَةِ يُرَدُّونَ إِلَىٰٓ أَشَدِّ ٱلْعَذَابِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Thumma antum haolai taqtuloona anfusakum watukhrijoona fareeqan minkum min diyarihim tathaharoona AAalayhim bialithmi waalAAudwani wain yatookum osara tufadoohum wahuwa muharramun AAalaykum ikhrajuhum afatuminoona bibaAAdi alkitabi watakfuroona bibaAAdin fama jazao man yafAAalu thalika minkum illa khizyun fee alhayati alddunya wayawma alqiyamati yuraddoona ila ashaddi alAAathabi wama Allahu bighafilin AAamma taAAmaloona", transliterationB: "Summa antum haaa'ulaaa'i taqtuloona anfusakum wa tukhrijoona fareeqam minkum min diyaarihim tazaaharoona 'alaihim bil ismi wal'udwaani wa iny yaatookum usaaraa tufaadoohum wahuwa muharramun 'alaikum ikhraajuhum; afatu' mi-noona biba'dil Kitaabi wa takfuroona biba'd; famaa jazaaa'u mai yaf'alu zaalika minkum illaa khizyun fil hayaatid-dunyaa wa yawmal qiyaamati yuraddoona ilaaa ashaddil 'azaab; wa mal laahu bighaafilin 'ammaa ta'maloon", english: "After this it is ye, the same people, who slay among yourselves, and banish a party of you from their homes; assist (Their enemies) against them, in guilt and rancour; and if they come to you as captives, ye ransom them, though it was not lawful for you to banish them. Then is it only a part of the Book that ye believe in, and do ye reject the rest? but what is the reward for those among you who behave like this but disgrace in this life?- and on the Day of Judgment they shall be consigned to the most grievous penalty. For Allah is not unmindful of what ye do", romanUrdu: "Magar aaj wahi tum ho ke apne bhai bandhon ko qatal karte ho, apni biradri ke kuch logon ko be-khanuma (be-ghar) kardete ho, zulm o zyadati ke saath unke khilaf jatthey bandiyan (grouping / cooperating) karte ho , aur jab woh ladayi mein pakde huey tumhare paas aate hain to unki rihayi ke liye fidiye ka lein dain karte ho, halaanke unhein unke gharon se nikalna hi seray se tumpar haraam tha. To kya tum kitab ke ek hissey par iman latey ho aur dusre hissey ke saath kufr karte ho? Phir tum mein se jo log aisa karein unki saza iske siwa aur kya hai ke duniya ki zindagi mein zaleel o khwar hokar rahein aur aakhirat mein shadeed-tareen azaab ki taraf pher diye jayein? Allah un harkaat se be-khabar nahin hai jo tum kar rahey ho" },
    { number: 86, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا بِٱلْءَاخِرَةِ ۖ فَلَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنصَرُونَ", transliteration: "Olaika allatheena ishtarawoo alhayata alddunya bialakhirati fala yukhaffafu AAanhumu alAAathabu wala hum yunsaroona", transliterationB: "Ulaaa'ikal lazeenash tarawul hayaatad dunyaa bil aakhirati falaa yukhaffafu 'anhumul 'azaabu wa laa hum yunsaroon", english: "These are the people who buy the life of this world at the price of the Hereafter: their penalty shall not be lightened nor shall they be helped", romanUrdu: "Yeh woh log hain jinhon ne aakhirat bech kar duniya ki zindagi khareed li hai, lihaza na inki saza mein ko takhfeef (kami) hogi aur na unhein koi madad pahunch sakegi" },
    { number: 87, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَقَفَّيْنَا مِنۢ بَعْدِهِۦ بِٱلرُّسُلِ ۖ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَٰتِ وَأَيَّدْنَٰهُ بِرُوحِ ٱلْقُدُسِ ۗ أَفَكُلَّمَا جَآءَكُمْ رَسُولٌۢ بِمَا لَا تَهْوَىٰٓ أَنفُسُكُمُ ٱسْتَكْبَرْتُمْ فَفَرِيقًۭا كَذَّبْتُمْ وَفَرِيقًۭا تَقْتُلُونَ", transliteration: "Walaqad atayna moosa alkitaba waqaffayna min baAAdihi bialrrusuli waatayna AAeesa ibna maryama albayyinati waayyadnahu biroohi alqudusi afakullama jaakum rasoolun bima la tahwa anfusukumu istakbartum fafareeqan kaththabtum wafareeqan taqtuloona", transliterationB: "Wa laqad aatainaa Moosal Kitaaba wa qaffainaa mim ba'dihee bir Rusuli wa aatainaa 'Eesab-na-Maryamal baiyinaati wa ayyadnaahu bi Roohil Qudus; afakullamaa jaaa'akum Rasoolum bimaa laa tahwaaa anfusukumus takbartum fafareeqan kazzabtum wa fareeqan taqtuloon", english: "We gave Moses the Book and followed him up with a succession of messengers; We gave Jesus the son of Mary Clear (Signs) and strengthened him with the holy spirit. Is it that whenever there comes to you a messenger with what ye yourselves desire not, ye are puffed up with pride?- Some ye called impostors, and others ye slay", romanUrdu: "Humne Moosa ko kitab di, iske baad pai dar pai Rasool bheje, aakhir e kaar Isa Ibn Maryam ko roshan nishaniyan dekar bheja aur rooh e paak se uski madad ki, phir yeh tumhara kya dhang hai ke jab bhi koi Rasool tumhari khwahishaat e nafs ke khilaf koi cheez lekar tumhare paas aaya, to tumne uske muqable mein sarkashi hi ki, kisi ko jhutlaya aur kisi ko qatal kar daala" },
    { number: 88, arabic: "وَقَالُوا۟ قُلُوبُنَا غُلْفٌۢ ۚ بَل لَّعَنَهُمُ ٱللَّهُ بِكُفْرِهِمْ فَقَلِيلًۭا مَّا يُؤْمِنُونَ", transliteration: "Waqaloo quloobuna ghulfun bal laAAanahumu Allahu bikufrihim faqaleelan ma yuminoona", transliterationB: "Wa qaaloo quloobunaa ghulf; bal la'anahumul laahu bikufrihim faqaleelam maa yu'minoon", english: "They say, \"Our hearts are the wrappings (which preserve Allah's Word: we need no more).\" Nay, Allah's curse is on them for their blasphemy: Little is it they believe", romanUrdu: "Woh kehte hain, hamare dil mehfooz hain, nahin asal baat yeh hai ke unke kufr ki wajah se unpar Allah ki phitkar padi hai, isliye woh kam hi iman latey hain" },
    { number: 89, arabic: "وَلَمَّا جَآءَهُمْ كِتَٰبٌۭ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌۭ لِّمَا مَعَهُمْ وَكَانُوا۟ مِن قَبْلُ يَسْتَفْتِحُونَ عَلَى ٱلَّذِينَ كَفَرُوا۟ فَلَمَّا جَآءَهُم مَّا عَرَفُوا۟ كَفَرُوا۟ بِهِۦ ۚ فَلَعْنَةُ ٱللَّهِ عَلَى ٱلْكَٰفِرِينَ", transliteration: "Walamma jaahum kitabun min AAindi Allahi musaddiqun lima maAAahum wakanoo min qablu yastaftihoona AAala allatheena kafaroo falamma jaahum ma AAarafoo kafaroo bihi falaAAnatu Allahi AAala alkafireena", transliterationB: "Wa lammaa jaaa'ahum Kitaabum min 'indil laahi musaddiqul limaa ma'ahum wa kaanoo min qablu yastaftihoona 'alal lazeena kafaroo falammaa jaaa'ahum maa 'arafoo kafaroo bih; fala 'natul laahi 'alal kaafireen", english: "And when there comes to them a Book from Allah, confirming what is with them,- although from of old they had prayed for victory against those without Faith,- when there comes to them that which they (should) have recognised, they refuse to believe in it but the curse of Allah is on those without Faith", romanUrdu: "Aur ab jo ek kitab Allah ki taraf se unke paas aayi hai, uske saath unka kya bartaao hai? Bawajood yeh ke woh us kitab ki tasdeeq karti hai jo unke paas pehle se maujood thi, bawajood yeh ke iski aamad se pehle woh khud kuffar ke muqable mein fatah o nusrat ki duaein maanga karte thay, magar jab woh cheez aa gayi jisey woh pehchan bhi gaye to unhon ne usey maanne se inkar kardiya, khuda ki laanat in munkireen par" },
    { number: 90, arabic: "بِئْسَمَا ٱشْتَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ أَن يَكْفُرُوا۟ بِمَآ أَنزَلَ ٱللَّهُ بَغْيًا أَن يُنَزِّلَ ٱللَّهُ مِن فَضْلِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ فَبَآءُو بِغَضَبٍ عَلَىٰ غَضَبٍۢ ۚ وَلِلْكَٰفِرِينَ عَذَابٌۭ مُّهِينٌۭ", transliteration: "Bisama ishtaraw bihi anfusahum an yakfuroo bima anzala Allahu baghyan an yunazzila Allahu min fadlihi AAala man yashao min AAibadihi fabaoo bighadabin AAala ghadabin walilkafireena AAathabun muheenun", transliterationB: "Bi'samash taraw biheee anfusahum ai yakfuroo bimaaa anzalal laahu baghyan ai yunazzilal laahu min fadlilhee 'alaa mai yashaaa'u min ibaadihee fabaaa'oo bighadabin 'alaa ghadab; wa lilkaafireena 'azaabum muheen", english: "Miserable is the price for which they have sold their souls, in that they deny (the revelation) which Allah has sent down, in insolent envy that Allah of His Grace should send it to any of His servants He pleases: Thus have they drawn on themselves Wrath upon Wrath. And humiliating is the punishment of those who reject Faith", romanUrdu: "Kya bura zariya hai jissey yeh apne nafs ki tasalli hasil karte hain ke jo hidayat Allah ne nazil ki hai, usko qabool karne se sirf is zidd ki bina par inkar kar rahey hain ke Allah ne apne fazal (wahee o risalat) se apne jis banday ko khud chaha, nawaz diya! Lihaza ab yeh gazab balaa e gazab ke mustahiq ho gaye hain aur aisey kafiron ke liye sakht zillat aamez saza muqarrar hai" },
    { number: 91, arabic: "وَإِذَا قِيلَ لَهُمْ ءَامِنُوا۟ بِمَآ أَنزَلَ ٱللَّهُ قَالُوا۟ نُؤْمِنُ بِمَآ أُنزِلَ عَلَيْنَا وَيَكْفُرُونَ بِمَا وَرَآءَهُۥ وَهُوَ ٱلْحَقُّ مُصَدِّقًۭا لِّمَا مَعَهُمْ ۗ قُلْ فَلِمَ تَقْتُلُونَ أَنۢبِيَآءَ ٱللَّهِ مِن قَبْلُ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Waitha qeela lahum aminoo bima anzala Allahu qaloo numinu bima onzila AAalayna wayakfuroona bima waraahu wahuwa alhaqqu musaddiqan lima maAAahum qul falima taqtuloona anbiyaa Allahi min qablu in kuntum mumineena", transliterationB: "Wa izaa qeela lahum aaminoo bimaaa anzalal laahu qaaloo nu'minu bimaaa unzila 'alainaa wa yakfuroona bimaa waraaa'ahoo wa huwal haqqu musaddiqal limaa ma'ahum; qul falima taqtuloona Ambiyaaa'al laahi min qablu in kuntum mu'mineen", english: "When it is said to them, \"Believe in what Allah Hath sent down, \"they say, \"We believe in what was sent down to us:\" yet they reject all besides, even if it be Truth confirming what is with them. Say: \"Why then have ye slain the prophets of Allah in times gone by, if ye did indeed believe", romanUrdu: "Jab unse kaha jata hai ke jo kuch Allah ne nazil kiya hai uspar iman lao to woh kehte hain “hum to sirf us cheez par iman latey hain jo hamare haan (yani nasal e Israel) mein utri hai” is daiyre ke bahar jo kuch aaya hai usey maanne se woh inkar karte hain, halaanke woh haqq hai aur us taleem ki tasdeeq o taeed kar raha hai jo unke haan pehle se maujood thi. Accha, unse kaho : agar tum us taleem hi par iman rakhne waley ho jo tumhare haan aayi thi, to issey pehle Allah ke un paighambaron ko (jo khud bani Israel mein paida huey thay) kyun qatal karte rahey" },
    { number: 92, arabic: "۞ وَلَقَدْ جَآءَكُم مُّوسَىٰ بِٱلْبَيِّنَٰتِ ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَٰلِمُونَ", transliteration: "Walaqad jaakum moosa bialbayyinati thumma ittakhathtumu alAAijla min baAAdihi waantum thalimoona", transliterationB: "Wa laqad jaaa'akum Moosa bilbaiyinaati summat takhaztunmul 'ijla mim ba'dihee wa antum zaalimoon", english: "There came to you Moses with clear (Signs); yet ye worshipped the calf (Even) after that, and ye did behave wrongfully", romanUrdu: "Tumhare paas Moosa kaisi kaisi roshan nishaniyon ke saath aaya phir bhi tum aisey zalim thay ke iske peeth moadte hi bachde ko mabood bana baithey" },
    { number: 93, arabic: "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱسْمَعُوا۟ ۖ قَالُوا۟ سَمِعْنَا وَعَصَيْنَا وَأُشْرِبُوا۟ فِى قُلُوبِهِمُ ٱلْعِجْلَ بِكُفْرِهِمْ ۚ قُلْ بِئْسَمَا يَأْمُرُكُم بِهِۦٓ إِيمَٰنُكُمْ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Waith akhathna meethaqakum warafaAAna fawqakumu alttoora khuthoo ma ataynakum biquwwatin waismaAAoo qaloo samiAAna waAAasayna waoshriboo fee quloobihimu alAAijla bikufrihim qul bisama yamurukum bihi eemanukum in kuntum mumineena", transliterationB: "Wa iz akhaznaa meesaaqakum wa rafa'naa fawqa kumut Toora khuzoo maaa aatainaakum biquwwatinw wasma'oo qaaloo sami'naa wa 'asainaa wa ushriboo fee quloobihimul 'ijla bikufrihim; qul bi'samaa yaamurukum biheee eemaanukum in kuntum m'mineen", english: "And remember We took your covenant and We raised above you (the towering height) of Mount (Sinai): (Saying): \"Hold firmly to what We have given you, and hearken (to the Law)\": They said:\" We hear, and we disobey:\" And they had to drink into their hearts (of the taint) of the calf because of their Faithlessness. Say: \"Vile indeed are the behests of your Faith if ye have any faith", romanUrdu: "Phir zara us misaq (covenant) ko yaad karo jo Tur (mount Tur) ko tumhare upar utha kar humne tumse liya tha, humne taaqeed ki thi ke jo hidayaat hum de rahey hain, unki sakhti ke saath pabandi karo aur kaan laga kar suno. Tumhare aslaaf ne kaha ke humne sun liya, magar maanenge nahin aur inki baatil parasti ka yeh haal tha ke dilon mein unke bachda (calf) hi basa hua tha. Kaho: agar tum momin ho to yeh ajeeb iman hai jo aisi buri harakat ka tumhein hukum deta hai" },
    { number: 94, arabic: "قُلْ إِن كَانَتْ لَكُمُ ٱلدَّارُ ٱلْءَاخِرَةُ عِندَ ٱللَّهِ خَالِصَةًۭ مِّن دُونِ ٱلنَّاسِ فَتَمَنَّوُا۟ ٱلْمَوْتَ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Qul in kanat lakumu alddaru alakhiratu AAinda Allahi khalisatan min dooni alnnasi fatamannawoo almawta in kuntum sadiqeena", transliterationB: "Qul in kaanat lakumud Daarul Aakhiratu 'indal laahi khaalisatam min doonin naasi fatamannawul mawta in kuntum saadiqeen", english: "Say: \"If the last Home, with Allah, be for you specially, and not for anyone else, then seek ye for death, if ye are sincere", romanUrdu: "Inse kaho ke agar waqayi Allah ke nazdeek aakhirat ka ghar tamaan insaano ko chodh kar sirf tumhare hi liye makhsoos hai, tab to tumhein chahiye ke maut ki tamanna karo agar tum apne is khayal mein sacchey ho" },
    { number: 95, arabic: "وَلَن يَتَمَنَّوْهُ أَبَدًۢا بِمَا قَدَّمَتْ أَيْدِيهِمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّٰلِمِينَ", transliteration: "Walan yatamannawhu abadan bima qaddamat aydeehim waAllahu AAaleemun bialththalimeena", transliterationB: "Wa lai yatamannawhu abadam bimaa qaddamat aydeehim; wallaahu 'aleemum bizzaalimeen", english: "But they will never seek for death, on account of the (sins) which their hands have sent on before them. and Allah is well-acquainted with the wrong-doers", romanUrdu: "Yaqeen jaano ke yeh kabhi iski tamanna na karenge, isliye ke apne haathon jo kuch kamaa kar unhon ne wahaan bheja hai, uska iqtaza yahi hai (ke yeh wahan janey ki tamanna na karein) Allah in zalimon ke haal se khoob waqif hai" },
    { number: 96, arabic: "وَلَتَجِدَنَّهُمْ أَحْرَصَ ٱلنَّاسِ عَلَىٰ حَيَوٰةٍۢ وَمِنَ ٱلَّذِينَ أَشْرَكُوا۟ ۚ يَوَدُّ أَحَدُهُمْ لَوْ يُعَمَّرُ أَلْفَ سَنَةٍۢ وَمَا هُوَ بِمُزَحْزِحِهِۦ مِنَ ٱلْعَذَابِ أَن يُعَمَّرَ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ", transliteration: "Walatajidannahum ahrasa alnnasi AAala hayatin wamina allatheena ashrakoo yawaddu ahaduhum law yuAAammaru alfa sanatin wama huwa bimuzahzihihi mina alAAathabi an yuAAammara waAllahu baseerun bima yaAAmaloona", transliterationB: "Wa latajidannahum ahrasannaasi 'alaa hayaatinw wa minal lazeena ashrakoo; yawaddu ahaduhum law yu'ammaru alfa sanatinw wa maa huwa bi muzahzihihee minal 'azaabi ai yu'ammar; wallaahu baseerum bimaa ya'maloon", english: "Thou wilt indeed find them, of all people, most greedy of life,-even more than the idolaters: Each one of them wishes He could be given a life of a thousand years: But the grant of such life will not save him from (due) punishment. For Allah sees well all that they do", romanUrdu: "Tum inhein sabse badh kar jeene ka harees paogey hatta ke yeh is maamle mein mushrikon se bhi badey huey hain . Inmein se ek ek shaks yeh chahta hai ke kisi tarah hazaar baras jiye, halaanke lambi umar bahar haal usey azaab to dur nahin phenk sakti. Jaise kuch aamaal yeh kar rahey hain, Allah to inhein dekh hi raha hai" },
    { number: 97, arabic: "قُلْ مَن كَانَ عَدُوًّۭا لِّجِبْرِيلَ فَإِنَّهُۥ نَزَّلَهُۥ عَلَىٰ قَلْبِكَ بِإِذْنِ ٱللَّهِ مُصَدِّقًۭا لِّمَا بَيْنَ يَدَيْهِ وَهُدًۭى وَبُشْرَىٰ لِلْمُؤْمِنِينَ", transliteration: "Qul man kana AAaduwwan lijibreela fainnahu nazzalahu AAala qalbika biithni Allahi musaddiqan lima bayna yadayhi wahudan wabushra lilmumineena", transliterationB: "Qul man kaana 'aduwwal li Jibreela fainnahoo nazzalahoo 'alaa qalbika bi iznil laahi musaddiqal limaa baina yadihi wa hudanw wa bushraa lilmu'mineen", english: "Say: Whoever is an enemy to Gabriel-for he brings down the (revelation) to thy heart by Allah's will, a confirmation of what went before, and guidance and glad tidings for those who believe", romanUrdu: "Inse kaho ke jo koi Jibrael se adawat (dushmani) rakhta ho, usey maloom hona chahiye ke Jibrael ne Allah hi ke izan se yeh Quran tumhare qalb par nazil kiya hai, jo pehle aayi hui kitabon ki tasdeeq o taeed karta hai aur iman laney walon ke liye hidayat aur kamiyabi ki basharat bankar aaya hai" },
    { number: 98, arabic: "مَن كَانَ عَدُوًّۭا لِّلَّهِ وَمَلَٰٓئِكَتِهِۦ وَرُسُلِهِۦ وَجِبْرِيلَ وَمِيكَىٰلَ فَإِنَّ ٱللَّهَ عَدُوٌّۭ لِّلْكَٰفِرِينَ", transliteration: "Man kana AAaduwwan lillahi wamalaikatihi warusulihi wajibreela wameekala fainna Allaha AAaduwwun lilkafireena", transliterationB: "Man kaana 'aduwwal lillaahi wa malaaa'ikatihee wa Rusulihee wa Jibreela wa Meekaala fa innal laaha 'aduwwul lilkaafireen", english: "Whoever is an enemy to Allah and His angels and messengers, to Gabriel and Michael,- Lo! Allah is an enemy to those who reject Faith", romanUrdu: "(Agar Jibrael se inki adawat ka sabab yahi hai, to kehdo ke) jo Allah aur uske Farsihton aur uske Rasoolon aur Jibrael aur Michael ke dushman hain, Allah un kafiron ka dushman hai" },
    { number: 99, arabic: "وَلَقَدْ أَنزَلْنَآ إِلَيْكَ ءَايَٰتٍۭ بَيِّنَٰتٍۢ ۖ وَمَا يَكْفُرُ بِهَآ إِلَّا ٱلْفَٰسِقُونَ", transliteration: "Walaqad anzalna ilayka ayatin bayyinatin wama yakfuru biha illa alfasiqoona", transliterationB: "Wa laqad anzalnaaa ilaika Aayaatim baiyinaatinw wa maa yakfuru bihaaa illal faasiqoon", english: "We have sent down to thee Manifest Signs (ayat); and none reject them but those who are perverse", romanUrdu: "Humne tumhari taraf aisi ayaat nazil ki hain jo saaf saaf haqq ka izhar karne wali hain aur inki pairwi se sirf wahi log inkar karte hain jo fasiq hain" },
    { number: 100, arabic: "أَوَكُلَّمَا عَٰهَدُوا۟ عَهْدًۭا نَّبَذَهُۥ فَرِيقٌۭ مِّنْهُم ۚ بَلْ أَكْثَرُهُمْ لَا يُؤْمِنُونَ", transliteration: "Awakullama AAahadoo AAahdan nabathahu fareequn minhum bal aktharuhum la yuminoona", transliterationB: "Awa kullamaa 'aahadoo ahdan nabazahoo fareequm minhum; bal aksaruhum laa u'minoon", english: "Is it not (the case) that every time they make a covenant, some party among them throw it aside?- Nay, Most of them are faithless", romanUrdu: "Kya hamesha aisa hi nahin hota raha hai ke jab unhon ne koi ahad kiya, to unmein se ek na ek giroh ne usey zaroor hi balaa e talq rakh diya (set them aside)? Balke inmein se aksar aisey hi hain jo sacchey dil se iman nahin latey" },
    { number: 101, arabic: "وَلَمَّا جَآءَهُمْ رَسُولٌۭ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌۭ لِّمَا مَعَهُمْ نَبَذَ فَرِيقٌۭ مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ كِتَٰبَ ٱللَّهِ وَرَآءَ ظُهُورِهِمْ كَأَنَّهُمْ لَا يَعْلَمُونَ", transliteration: "Walamma jaahum rasoolun min AAindi Allahi musaddiqun lima maAAahum nabatha fareequn mina allatheena ootoo alkitaba kitaba Allahi waraa thuhoorihim kaannahum la yaAAlamoona", transliterationB: "Wa lammaa jaaa'ahum Rasoolum min 'indil laahi musaddiqul limaa ma'ahum nabaza fareequm minal lazeena ootul Kitaaba Kitaabal laahi waraaa'a zuhoorihim ka annahum laa ya'lamoon", english: "And when there came to them a messenger from Allah, confirming what was with them, a party of the people of the Book threw away the Book of Allah behind their backs, as if (it had been something) they did not know", romanUrdu: "Aur jab inke paas Allah ki taraf se koi Rasool us kitab ki tasdeeq o taeed karta hua aaya jo inke haan pehle se maujood thi to in ehle kitab mein se ek giroh ne kitab Allah ko is tarah pas-e-pusht (behind their backs) dala goya ke woh kuch jaante hi nahin" },
    { number: 102, arabic: "وَٱتَّبَعُوا۟ مَا تَتْلُوا۟ ٱلشَّيَٰطِينُ عَلَىٰ مُلْكِ سُلَيْمَٰنَ ۖ وَمَا كَفَرَ سُلَيْمَٰنُ وَلَٰكِنَّ ٱلشَّيَٰطِينَ كَفَرُوا۟ يُعَلِّمُونَ ٱلنَّاسَ ٱلسِّحْرَ وَمَآ أُنزِلَ عَلَى ٱلْمَلَكَيْنِ بِبَابِلَ هَٰرُوتَ وَمَٰرُوتَ ۚ وَمَا يُعَلِّمَانِ مِنْ أَحَدٍ حَتَّىٰ يَقُولَآ إِنَّمَا نَحْنُ فِتْنَةٌۭ فَلَا تَكْفُرْ ۖ فَيَتَعَلَّمُونَ مِنْهُمَا مَا يُفَرِّقُونَ بِهِۦ بَيْنَ ٱلْمَرْءِ وَزَوْجِهِۦ ۚ وَمَا هُم بِضَآرِّينَ بِهِۦ مِنْ أَحَدٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَيَتَعَلَّمُونَ مَا يَضُرُّهُمْ وَلَا يَنفَعُهُمْ ۚ وَلَقَدْ عَلِمُوا۟ لَمَنِ ٱشْتَرَىٰهُ مَا لَهُۥ فِى ٱلْءَاخِرَةِ مِنْ خَلَٰقٍۢ ۚ وَلَبِئْسَ مَا شَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "WaittabaAAoo ma tatloo alshshayateenu AAala mulki sulaymana wama kafara sulaymanu walakinna alshshayateena kafaroo yuAAallimoona alnnasa alssihra wama onzila AAala almalakayni bibabila haroota wamaroota wama yuAAallimani min ahadin hatta yaqoola innama nahnu fitnatun fala takfur fayataAAallamoona minhuma ma yufarriqoona bihi bayna almari wazawjihi wama hum bidarreena bihi min ahadin illa biithni Allahi wayataAAallamoona ma yadurruhum wala yanfaAAuhum walaqad AAalimoo lamani ishtarahu ma lahu fee alakhirati min khalaqin walabisa ma sharaw bihi anfusahum law kanoo yaAAlamoona", transliterationB: "Wattaba'oo maa tatlush Shayaateenu 'alaa mulki Sulaimaana wa maa kafara Sulaimaanu wa laakinnash Shayattena kafaroo yu'al limoonan naasas sihra wa maaa unzila 'alal malakaini bi Baabila Haaroota wa Maaroot; wa maa yu'allimaani min ahadin hattaa yaqoolaaa innamaa nahnu fitnatun falaa takfur fayata'al lamoona minhumaa maa yufarriqoona bihee bainal mar'i wa zawjih; wa maa hum bidaaarreena bihee min ahadin illaa bi-iznillah; wa yata'allamoona maa yadurruhum wa laa yanfa'uhum; wa laqad 'alimoo lamanish taraahu maa lahoo fil Aakhirati min khalaaq; wa labi'sa maa sharaw biheee anfusahum; law kaanoo ya'lamoon", english: "They followed what the evil ones gave out (falsely) against the power of Solomon: the blasphemers Were, not Solomon, but the evil ones, teaching men Magic, and such things as came down at babylon to the angels Harut and Marut. But neither of these taught anyone (Such things) without saying: \"We are only for trial; so do not blaspheme.\" They learned from them the means to sow discord between man and wife. But they could not thus harm anyone except by Allah's permission. And they learned what harmed them, not what profited them. And they knew that the buyers of (magic) would have no share in the happiness of the Hereafter. And vile was the price for which they did sell their souls, if they but knew", romanUrdu: "Aur lagey un cheezon ki pairwi karne jo shayateen Sulaiman ki sultanat ka naam lekar pesh kiya karte thay, halaanke Sulaiman ne kabhi kufr nahin kiya, kufr ke murtaqib to woh shayateen thay jo logon ko jaadugari ki taleem dete thay.Woh pichey padey us cheez ke jo babil (babylon) mein do Farishton, Harut o Marut par nazil ki gayi thi, halaanke woh (Farishtey) jab bhi kisi ko uski taleem dete thay to pehle saaf taur par mutanabbey (warn) kardiya karte thay ke “dekh, hum mehaz ek aazmaish hain, tu kufr mein mubtila na ho”.Phir bhi yeh log unse woh cheez seekhte thay jissey shohar aur biwi mein judai daal dein, zaahir tha ke izan e ilahi ke bagair woh is zariye se kisi ko bhi zarar (harm) na pahuncha sakte thay, magar iske bawajood woh aisi cheez seekhte thay jo khud inke liye nafa baksh nahin, balke nuqsan-de thi aur unhein khoob maloom tha ke jo is cheez ka khareedar bana uske liye aakhirat mein koi hissa nahin. Kitni buri mataa thi jiske badle unhon ne apni jaano ko bech dala, kaash unhein maloom hota" },
    { number: 103, arabic: "وَلَوْ أَنَّهُمْ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَمَثُوبَةٌۭ مِّنْ عِندِ ٱللَّهِ خَيْرٌۭ ۖ لَّوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "Walaw annahum amanoo waittaqaw lamathoobatun min AAindi Allahi khayrun law kanoo yaAAlamoona", transliterationB: "Wa law annahum aamanoo wattaqaw lamasoobatum min 'indillaahi khairun law kaanoo ya'lamoon", english: "If they had kept their Faith and guarded themselves from evil, far better had been the reward from their Lord, if they but knew", romanUrdu: "Agar woh iman aur taqwa ikhtiyar karte, to Allah ke haan iska jo badla milta to unke liye zyada behtar tha, kaash unhein khabar hoti" },
    { number: 104, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقُولُوا۟ رَٰعِنَا وَقُولُوا۟ ٱنظُرْنَا وَٱسْمَعُوا۟ ۗ وَلِلْكَٰفِرِينَ عَذَابٌ أَلِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo la taqooloo raAAina waqooloo onthurna waismaAAoo walilkafireena AAathabun aleemun", transliterationB: "Yaaa ayyuhal lazeena aamanoo laa taqooloo raa'inaa wa qoolun zurnaa wasma'oo; wa lilkaafireena 'azaabun aleem", english: "O ye of Faith! Say not (to the Messenger) words of ambiguous import, but words of respect; and hearken (to him): To those without Faith is a grievous punishment", romanUrdu: "Aey logon jo iman laye ho! Raina (Listen to us) na kaha karo, balke unzurna (make us understand) kaho aur tawajju se baat ko suno, yeh kafir to azaab e aleem ke mustahiq hain" },
    { number: 105, arabic: "مَّا يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَٰبِ وَلَا ٱلْمُشْرِكِينَ أَن يُنَزَّلَ عَلَيْكُم مِّنْ خَيْرٍۢ مِّن رَّبِّكُمْ ۗ وَٱللَّهُ يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", transliteration: "Ma yawaddu allatheena kafaroo min ahli alkitabi wala almushrikeena an yunazzala AAalaykum min khayrin min rabbikum waAllahu yakhtassu birahmatihi man yashao waAllahu thoo alfadli alAAatheemi", transliterationB: "Maa yawaddul lazeena kafaroo min ahlil kitaabi wa lal mushrikeena ai-yunazzala 'alaikum min khairim mir Rabbikum; wallaahu yakhtassu birahmatihee mai-yashaaa; wallaahu zul fadlil'azeem", english: "It is never the wish of those without Faith among the People of the Book, nor of the Pagans, that anything good should come down to you from your Lord. But Allah will choose for His special Mercy whom He will - for Allah is Lord of grace abounding", romanUrdu: "Yeh log jinhon ne dawat e haqq ko qabool karne se inkar kardiya hai, khwah ehle kitab mein se hon ya mushrik hon, hargiz yeh pasand nahin karte ke tumhare Rubb ki taraf se tumpar koi bhalayi nazil ho, magar Allah jisko chahta hai apni rehmat ke liye chun leta hai aur woh bada fazal farmane wala hai" },
    { number: 106, arabic: "۞ مَا نَنسَخْ مِنْ ءَايَةٍ أَوْ نُنسِهَا نَأْتِ بِخَيْرٍۢ مِّنْهَآ أَوْ مِثْلِهَآ ۗ أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Ma nansakh min ayatin aw nunsiha nati bikhayrin minha aw mithliha alam taAAlam anna Allaha AAala kulli shayin qadeerun", transliterationB: "Maa nansakh min aayatin aw nunsihaa na-ti bikhairim minhaaa aw mislihaaa; alam ta'lam annal laaha 'alaa kulli shai'in qadeer", english: "None of Our revelations do We abrogate or cause to be forgotten, but We substitute something better or similar: Knowest thou not that Allah Hath power over all things", romanUrdu: "Hum apni jis ayat ko mansookh (abrogate) kardete hain ya bhula dete hain, uski jagah ussey behtar le aate hain ya kam az kam waisi hi. Kya tum jaante nahin ho ke Allah har cheez par qudart rakhta hai" },
    { number: 107, arabic: "أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍ", transliteration: "Alam taAAlam anna Allaha lahu mulku alssamawati waalardi wama lakum min dooni Allahi min waliyyin wala naseerin", transliterationB: "Alam ta'lam annallaaha lahoo mulkus samaawaati wal ard; wa maa lakum min doonil laahi minw waliyyinw wa laa naseer", english: "Knowest thou not that to Allah belongeth the dominion of the heavens and the earth? And besides Him ye have neither patron nor helper", romanUrdu: "Kya tumhein khabar nahin hai ke zameen aur asmaano ki farma rawayi Allah hi ke liye hai aur uske siwa koi tumhari khabargiri karne aur tumhari madad karne wala nahin hai" },
    { number: 108, arabic: "أَمْ تُرِيدُونَ أَن تَسْـَٔلُوا۟ رَسُولَكُمْ كَمَا سُئِلَ مُوسَىٰ مِن قَبْلُ ۗ وَمَن يَتَبَدَّلِ ٱلْكُفْرَ بِٱلْإِيمَٰنِ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ", transliteration: "Am tureedoona an tasaloo rasoolakum kama suila moosa min qablu waman yatabaddali alkufra bialeemani faqad dalla sawaa alssabeeli", transliterationB: "Am tureedoona an tas'aloo Rasoolakum kamaa su'ila Moosa min qabl; wa mai yatabaddalil kufra bil eemaani faqad dalla sawaaa'as sabeel", english: "Would ye question your Messenger as Moses was questioned of old? but whoever changeth from Faith to Unbelief, Hath strayed without doubt from the even way", romanUrdu: "Phir kya tum apne Rasool se us qism ke sawalaat aur mutalabe karna chahte ho jaise issey pehle Moosa se kiye ja chuke hain? Halaanke jis shaks ne iman ki rawish ko kufr ki rawish se badal liya woh raah e raast se bhatak gaya" },
    { number: 109, arabic: "وَدَّ كَثِيرٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ لَوْ يَرُدُّونَكُم مِّنۢ بَعْدِ إِيمَٰنِكُمْ كُفَّارًا حَسَدًۭا مِّنْ عِندِ أَنفُسِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ٱلْحَقُّ ۖ فَٱعْفُوا۟ وَٱصْفَحُوا۟ حَتَّىٰ يَأْتِىَ ٱللَّهُ بِأَمْرِهِۦٓ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Wadda katheerun min ahli alkitabi law yaruddoonakum min baAAdi eemanikum kuffaran hasadan min AAindi anfusihim min baAAdi ma tabayyana lahumu alhaqqu faoAAfoo waisfahoo hatta yatiya Allahu biamrihi inna Allaha AAala kulli shayin qadeerun", transliterationB: "Wadda kaseerum min ahlil kitaabi law yaruddoo nakum mim ba'di eemaanikum kuffaaran hasadam min 'indi anfusihim mim ba'di maa tabaiyana lahumul haqqu fa'foo washfahoo hattaa yaa tiyallaahu bi amrih; innal laaha 'alaa kulli shai'in qadeer", english: "Quite a number of the People of the Book wish they could Turn you (people) back to infidelity after ye have believed, from selfish envy, after the Truth hath become Manifest unto them: But forgive and overlook, Till Allah accomplish His purpose; for Allah Hath power over all things", romanUrdu: "Ehle kitab mein se aksar log yeh chahte hain ke kisi tarah tumhein iman se pher kar phir kufr ki taraf palta le jayein agarche haqq unpar zaahir ho chuka hai, magar apne nafs ke hasad ki bina par tumhare liye unki yeh khwahish hai iske jawab mein tum afu o darguzar (forgive and overlook) se kaam lo, yahan tak ke Allah khud hi apna faisla nafiz karde. Mutmaeen raho ke Allah taala har cheez par qudrat rakhta hai" },
    { number: 110, arabic: "وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ۚ وَمَا تُقَدِّمُوا۟ لِأَنفُسِكُم مِّنْ خَيْرٍۢ تَجِدُوهُ عِندَ ٱللَّهِ ۗ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Waaqeemoo alssalata waatoo alzzakata wama tuqaddimoo lianfusikum min khayrin tajidoohu AAinda Allahi inna Allaha bima taAAmaloona baseerun", transliterationB: "Wa aqeemus salaata wa aatuz zakaah; wa maa tuqaddimoo li anfusikum min khairin tajidoohu 'indal laah; innal laaha bimaa ta'maloona baseer", english: "And be steadfast in prayer and regular in charity: And whatever good ye send forth for your souls before you, ye shall find it with Allah: for Allah sees Well all that ye do", romanUrdu: "Namaz qayam karo aur zakat do. Tum apni aaqibat ke liye jo bhalayi kamaa kar aagey bhejoge, Allah ke haan usey maujood paogey. Jo kuch tum karte ho woh sab Allah ki nazar mein hai" },
    { number: 111, arabic: "وَقَالُوا۟ لَن يَدْخُلَ ٱلْجَنَّةَ إِلَّا مَن كَانَ هُودًا أَوْ نَصَٰرَىٰ ۗ تِلْكَ أَمَانِيُّهُمْ ۗ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Waqaloo lan yadkhula aljannata illa man kana hoodan aw nasara tilka amaniyyuhum qul hatoo burhanakum in kuntum sadiqeena", transliterationB: "Wa qaaloo lai yadkhulal jannata illaa man kaana Hoodan aw Nasaaraa; tilka ammniyyuhum; qul haatoo burhaa nakum in kuntum saadiqeen", english: "And they say: \"None shall enter Paradise unless he be a Jew or a Christian.\" Those are their (vain) desires. Say: \"Produce your proof if ye are truthful", romanUrdu: "Unka kehna hai ke koi shaks jannat mein na jayega jab tak ke woh yahudi na ho (ya Isaiyon ke khayal ke mutabiq) Isayi na ho. Yeh unki tamannayein hain, inse kaho apni daleel pesh karo agar tum apne dawey mein sacchey ho" },
    { number: 112, arabic: "بَلَىٰ مَنْ أَسْلَمَ وَجْهَهُۥ لِلَّهِ وَهُوَ مُحْسِنٌۭ فَلَهُۥٓ أَجْرُهُۥ عِندَ رَبِّهِۦ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Bala man aslama wajhahu lillahi wahuwa muhsinun falahu ajruhu AAinda rabbihi wala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Balaa man aslama wajhahoo lillaahi wa huwa muhsinun falahooo ajruhoo 'inda rabbihee wa laa khawfun 'alaihim wa laa hum yahzanoon", english: "Nay,-whoever submits His whole self to Allah and is a doer of good,- He will get his reward with his Lord; on such shall be no fear, nor shall they grieve", romanUrdu: "Darasal na tumhari kuch khususiyat hai na kisi aur ki, haqq yeh hai ke jo bhi apni hasti ko Allah ki itaat mein somp de aur amalan neik rawish par chale, uske liye uske Rubb ke paas uska ajar hai aur aisey logon ke liye kisi khauf ya ranjh ka koi mauqa nahin" },
    { number: 113, arabic: "وَقَالَتِ ٱلْيَهُودُ لَيْسَتِ ٱلنَّصَٰرَىٰ عَلَىٰ شَىْءٍۢ وَقَالَتِ ٱلنَّصَٰرَىٰ لَيْسَتِ ٱلْيَهُودُ عَلَىٰ شَىْءٍۢ وَهُمْ يَتْلُونَ ٱلْكِتَٰبَ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ لَا يَعْلَمُونَ مِثْلَ قَوْلِهِمْ ۚ فَٱللَّهُ يَحْكُمُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ", transliteration: "Waqalati alyahoodu laysati alnnasara AAala shayin waqalati alnnasara laysati alyahoodu AAala shayin wahum yatloona alkitaba kathalika qala allatheena la yaAAlamoona mithla qawlihim faAllahu yahkumu baynahum yawma alqiyamati feema kanoo feehi yakhtalifoona", transliterationB: "Wa qaalatil Yahoodu laisatin Nasaaraa 'alaa shai'inw-wa qaalatin Nasaaraaa laisatil Yahoodu 'alaa shai'inw'wa hum yatloonal Kitaab; kazaalika qaalal lazeena la ya'lamoona misla qawlihim Yawmal Qiyaamati feemaa kaanoo feehi yakhtalifoon", english: "The Jews say: \"The Christians have naught (to stand) upon; and the Christians say: \"The Jews have naught (To stand) upon.\" Yet they (Profess to) study the (same) Book. Like unto their word is what those say who know not; but Allah will judge between them in their quarrel on the Day of Judgment", romanUrdu: "Yahudi kehte hain: Isaiyon ke paas kuch nahin, Isayi kehte hain: Yahudiyon ke paas kuch nahin, halaanke ke dono hi kitab padhte hain aur isi qism ke dawey un logon ke bhi hain jinke paas kitab ka ilm nahin hai, yeh ikhtilafaat jin mein yeh log mubtila hain inka faisla Allah qayamat ke roz kardega" },
    { number: 114, arabic: "وَمَنْ أَظْلَمُ مِمَّن مَّنَعَ مَسَٰجِدَ ٱللَّهِ أَن يُذْكَرَ فِيهَا ٱسْمُهُۥ وَسَعَىٰ فِى خَرَابِهَآ ۚ أُو۟لَٰٓئِكَ مَا كَانَ لَهُمْ أَن يَدْخُلُوهَآ إِلَّا خَآئِفِينَ ۚ لَهُمْ فِى ٱلدُّنْيَا خِزْىٌۭ وَلَهُمْ فِى ٱلْءَاخِرَةِ عَذَابٌ عَظِيمٌۭ", transliteration: "Waman athlamu mimman manaAAa masajida Allahi an yuthkara feeha ismuhu wasaAAa fee kharabiha olaika ma kana lahum an yadkhulooha illa khaifeena lahum fee alddunya khizyun walahum fee alakhirati AAathabun AAatheemun", transliterationB: "Wa man azlamu mimmam-mana'a masaajidal laahi ai-yuzkara feehas muhoo wa sa'aa fee kharaabihaaa; ulaaa'ika maa kaana lahum ai yadkhuloohaaa illaa khaaa''feen; lahum fiddunyaa khizyunw wa lahum fil aakhirati 'azaabun 'azeem", english: "And who is more unjust than he who forbids that in places for the worship of Allah, Allah's name should be celebrated?-whose zeal is (in fact) to ruin them? It was not fitting that such should themselves enter them except in fear. For them there is nothing but disgrace in this world, and in the world to come, an exceeding torment", romanUrdu: "Aur us shaks se badhkar zalim kaun hoga jo Allah ke maabadon (places of worship) mein uske naam ki yaad se rokay aur unki veerani ke darpe ho? Aisey log is qabil hain ke unki ibadat-gaahon mein qadam na rakkhein aur agar wahan jayein bhi to darte huey jayein, unke liye to duniya mein ruswayi hai aur aakhirat mein azaab e azeem" },
    { number: 115, arabic: "وَلِلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ فَأَيْنَمَا تُوَلُّوا۟ فَثَمَّ وَجْهُ ٱللَّهِ ۚ إِنَّ ٱللَّهَ وَٰسِعٌ عَلِيمٌۭ", transliteration: "Walillahi almashriqu waalmaghribu faaynama tuwalloo fathamma wajhu Allahi inna Allaha wasiAAun AAaleemun", transliterationB: "Wa lillaahil mashriqu walmaghrib; fa aynamaa tuwalloo fasamma wajhullaah; innal laaha waasi'un Aleem", english: "To Allah belong the east and the West: Whithersoever ye turn, there is the presence of Allah. For Allah is all-Pervading, all-Knowing", romanUrdu: "Mashrik aur magrib sab Allah ke hain, jis taraf bhi tum rukh karoge usi taraf Allah ka rukh hai,Allah badi wusat wala aur sabkuch jaanne wala hai" },
    { number: 116, arabic: "وَقَالُوا۟ ٱتَّخَذَ ٱللَّهُ وَلَدًۭا ۗ سُبْحَٰنَهُۥ ۖ بَل لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّۭ لَّهُۥ قَٰنِتُونَ", transliteration: "Waqaloo itakhatha Allahu waladan subhanahu bal lahu ma fee alssamawati waalardi kullun lahu qanitoona", transliterationB: "Wa qaalut takhazal laahu waladan subhaanahoo bal lahoo maa fis samaawaati wal ardi kullul lahoo qaanitoon", english: "They say: \"Allah hath begotten a son\": Glory be to Him.-Nay, to Him belongs all that is in the heavens and on earth: everything renders worship to Him", romanUrdu: "Unka qaul hai ke Allah ne kisi ko beta banaya hai, Allah paak hai in baaton se. Asal haqeeqat yeh hai ke zameen aur asmaano ki tamaam maujudaat uski milk (milkiyat) hain, sabke sab uske mutii o farmaan hain" },
    { number: 117, arabic: "بَدِيعُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ", transliteration: "BadeeAAu alssamawati waalardi waitha qada amran fainnama yaqoolu lahu kun fayakoonu", transliterationB: "Badree'us samaawaati wal ardi wa izaa qadaaa amran fa innamaa yaqoolu lahoo kun fayakoon", english: "To Him is due the primal origin of the heavens and the earth: When He decreeth a matter, He saith to it: \"Be,\" and it is", romanUrdu: "Woh asmaano aur zameen ka mujid (originator) hai aur jis baat ka woh faisla karta hai uske liye bas yeh hukum deta hai ke “hoja” aur woh ho jati hai" },
    { number: 118, arabic: "وَقَالَ ٱلَّذِينَ لَا يَعْلَمُونَ لَوْلَا يُكَلِّمُنَا ٱللَّهُ أَوْ تَأْتِينَآ ءَايَةٌۭ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ مِن قَبْلِهِم مِّثْلَ قَوْلِهِمْ ۘ تَشَٰبَهَتْ قُلُوبُهُمْ ۗ قَدْ بَيَّنَّا ٱلْءَايَٰتِ لِقَوْمٍۢ يُوقِنُونَ", transliteration: "Waqala allatheena la yaAAlamoona lawla yukallimuna Allahu aw tateena ayatun kathalika qala allatheena min qablihim mithla qawlihim tashabahat quloobuhum qad bayyanna alayati liqawmin yooqinoona", transliterationB: "Wa qaalal lazeena laa ya'lamoona law laa yukallimunal laahu aw taateenaaa aayah; kazaalika qaalal lazeena min qablihim misla qawlihim; tashaabahat quloobuhum; qad baiyannal aayaati liqawminy yooqinoon", english: "Say those without knowledge: \"Why speaketh not Allah unto us? or why cometh not unto us a Sign?\" So said the people before them words of similar import. Their hearts are alike. We have indeed made clear the Signs unto any people who hold firmly to Faith (in their hearts)", romanUrdu: "Naadaan kehte hain ke Allah khud humse baat kyun nahin karta ya koi nishani hamare paas kyun nahin aati? Aisi hi baatein inse pehle log bhi kiya karte thay , in sab (agle pichle gumraahon) ki zehniyatein (mentality) ek jaisi hain. Yakeen laney walon ke liye to hum nishaniyan saaf saaf numayan kar chuke hain" },
    { number: 119, arabic: "إِنَّآ أَرْسَلْنَٰكَ بِٱلْحَقِّ بَشِيرًۭا وَنَذِيرًۭا ۖ وَلَا تُسْـَٔلُ عَنْ أَصْحَٰبِ ٱلْجَحِيمِ", transliteration: "Inna arsalnaka bialhaqqi basheeran wanatheeran wala tusalu Aaan ashabi aljaheemi", transliterationB: "Innaaa arsalnaaka bilhaqqi basheeranw wa nazeeranw wa laa tus'alu 'am Ashaabil Jaheem", english: "Verily We have sent thee in truth as a bearer of glad tidings and a warner: But of thee no question shall be asked of the Companions of the Blazing Fire", romanUrdu: "(Issey badh kar nishani kya hogi ke) humne tumko ilm e haqq ke saath khush khabri dene wala aur darane wala bana kar bheja, ab jo log jahannum se rishta jodh chuke hain unki taraf se tum zimmedaar o jawabdey nahin ho" },
    { number: 120, arabic: "وَلَن تَرْضَىٰ عَنكَ ٱلْيَهُودُ وَلَا ٱلنَّصَٰرَىٰ حَتَّىٰ تَتَّبِعَ مِلَّتَهُمْ ۗ قُلْ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلْهُدَىٰ ۗ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم بَعْدَ ٱلَّذِى جَآءَكَ مِنَ ٱلْعِلْمِ ۙ مَا لَكَ مِنَ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍ", transliteration: "Walan tarda AAanka alyahoodu wala alnnasara hatta tattabiAAa millatahum qul inna huda Allahi huwa alhuda walaini ittabaAAta ahwaahum baAAda allathee jaaka mina alAAilmi ma laka mina Allahi min waliyyin wala naseerin", transliterationB: "Wa lan tardaa 'ankal Yahoodu wa lan Nasaaraa hattaa tattabi'a millatahum; qul inna hudal laahi huwalhudaa; wa la'init taba'ta ahwaaa'ahum ba'dal lazee jaaa'aka minal 'ilmimaa laka minal laahi minw waliyyinw wa laa naseer", english: "Never will the Jews or the Christians be satisfied with thee unless thou follow their form of religion. Say: \"The Guidance of Allah,-that is the (only) Guidance.\" Wert thou to follow their desires after the knowledge which hath reached thee, then wouldst thou find neither Protector nor helper against Allah", romanUrdu: "Yahudi aur Isayi tumse hargiz raazi na honge, jab tak tum unke tareeqe par na chalne lago. Saaf kehdo ke raasta bas wahi hai jo Allah ne bataya hai, warna agar us ilm ke baad jo tumhare paas aa chuka hai tumne unki khwahishaat ki pairwi ki to Allah ki pakad se bachane wala koi dost aur madadgaar tumhare liye nahin hai" },
    { number: 121, arabic: "ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يَتْلُونَهُۥ حَقَّ تِلَاوَتِهِۦٓ أُو۟لَٰٓئِكَ يُؤْمِنُونَ بِهِۦ ۗ وَمَن يَكْفُرْ بِهِۦ فَأُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", transliteration: "Allatheena ataynahumu alkitaba yatloonahu haqqa tilawatihi olaika yuminoona bihi waman yakfur bihi faolaika humu alkhasiroona", transliterationB: "Allazeena aatainaahumul Kitaaba yatloonahoo haqqa tilaawatiheee ulaaa'ika yu'minoona bi; wa mai yakfur bihee fa ulaaa'ika humul khaasiroon", english: "Those to whom We have sent the Book study it as it should be studied: They are the ones that believe therein: Those who reject faith therein,- the loss is their own", romanUrdu: "Jin logon ko humne kitab di hai, woh usey is tarah padhte hain jaisa ke padhne ka haqq hai, woh ispar sacchey dil se iman latey hain aur jo iske saath kufr ka rawayya ikhtiyar karein wahi asal mein nuqsaan uthane waley hain" },
    { number: 122, arabic: "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Ya banee israeela othkuroo niAAmatiya allatee anAAamtu AAalaykum waannee faddaltukum AAala alAAalameena", transliterationB: "Yaa Baneee Israaa'eelaz-kuroo ni'matiyal lateee an'amtu 'alaikum wa annee faddaltukum 'alal 'aalameen", english: "O Children of Israel! call to mind the special favour which I bestowed upon you, and that I preferred you to all others (for My Message)", romanUrdu: "Aey bani Israel! Yaad karo meri woh niyamat jissey maine tumhein nawaza tha, aur yeh ke maine tumhein duniya ki tamaam qaumon par fazilat di thi" },
    { number: 123, arabic: "وَٱتَّقُوا۟ يَوْمًۭا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍۢ شَيْـًۭٔا وَلَا يُقْبَلُ مِنْهَا عَدْلٌۭ وَلَا تَنفَعُهَا شَفَٰعَةٌۭ وَلَا هُمْ يُنصَرُونَ", transliteration: "Waittaqoo yawman la tajzee nafsun AAan nafsin shayan wala yuqbalu minha AAadlun wala tanfaAAuha shafaAAatun wala hum yunsaroona", transliterationB: "Wattaqoo yawmal laa tajzee nafsun 'an nafsin shai 'anw wa laa yuqbalu minhaa 'adlunw wa laa tanfa'uhaa shafaa 'atunw wa laa hum yunsaroon", english: "Then guard yourselves against a Day when one soul shall not avail another, nor shall compensation be accepted from her nor shall intercession profit her nor shall anyone be helped (from outside)", romanUrdu: "Aur daro us din se, jab koi kisi ke zara kaam na aayega, na kisi se fidiya (ransom) qabool kiya jayega, na koi sifarish hi aadmi ko faiyda degi, aur na mujreemo ko kahin se koi madad pahunch sakegi" },
    { number: 124, arabic: "۞ وَإِذِ ٱبْتَلَىٰٓ إِبْرَٰهِۦمَ رَبُّهُۥ بِكَلِمَٰتٍۢ فَأَتَمَّهُنَّ ۖ قَالَ إِنِّى جَاعِلُكَ لِلنَّاسِ إِمَامًۭا ۖ قَالَ وَمِن ذُرِّيَّتِى ۖ قَالَ لَا يَنَالُ عَهْدِى ٱلظَّٰلِمِينَ", transliteration: "Waithi ibtala ibraheema rabbuhu bikalimatin faatammahunna qala innee jaAAiluka lilnnasi imaman qala wamin thurriyyatee qala la yanalu AAahdee alththalimeena", transliterationB: "Wa izib talaaa Ibraaheema Rabbuho bi Kalimaatin fa atammahunna qaala Innee jaa'iluka linnaasi Imaaman qaala wa min zurriyyatee qaala laa yanaalu 'ahdiz zaalimeen", english: "And remember that Abraham was tried by his Lord with certain commands, which he fulfilled: He said: \"I will make thee an Imam to the Nations.\" He pleaded: \"And also (Imams) from my offspring!\" He answered: \"But My Promise is not within the reach of evil-doers", romanUrdu: "Yaad karo ke jab Ibrahim ko uske Rubb ne chandh baaton mein aazmaya aur woh un sab mein poora utar gaya, to usne kaha : “main tujhey sab logon ka peshwa banane wala hoon” Ibrahim ne arz kiya: “ aur kya meri aulad se bhi yahi waada hai?” Usne jawab diya: “mera waada zalimon se mutaaliq nahin hai.”" },
    { number: 125, arabic: "وَإِذْ جَعَلْنَا ٱلْبَيْتَ مَثَابَةًۭ لِّلنَّاسِ وَأَمْنًۭا وَٱتَّخِذُوا۟ مِن مَّقَامِ إِبْرَٰهِۦمَ مُصَلًّۭى ۖ وَعَهِدْنَآ إِلَىٰٓ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ أَن طَهِّرَا بَيْتِىَ لِلطَّآئِفِينَ وَٱلْعَٰكِفِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ", transliteration: "Waith jaAAalna albayta mathabatan lilnnasi waamnan waittakhithoo min maqami ibraheema musallan waAAahidna ila ibraheema waismaAAeela an tahhira baytiya lilttaifeena waalAAakifeena waalrrukkaAAi alssujoodi", transliterationB: "Wa iz ja'alnal Baita masaabatal linnassi wa amnanw wattakhizoo mim Maqaami Ibraaheema musallaaa; wa 'ahidnaaa ilaaa Ibraaheema wa Ismaa'eela an tahhiraa Baitiya littaaa'ifeena wal'aakifeena warrukka'is sujood", english: "Remember We made the House a place of assembly for men and a place of safety; and take ye the station of Abraham as a place of prayer; and We covenanted with Abraham and Isma'il, that they should sanctify My House for those who compass it round, or use it as a retreat, or bow, or prostrate themselves (therein in prayer)", romanUrdu: "Aur yeh ke humne is ghar (kaaba) ko logon ke liye markaz aur aman ki jagah qaraar diya tha aur logon ko hukum diya tha ke Ibrahim jahan ibadat ke liye khada hota hai us muqaam ko mustaqil jaaye namaz bana lo aur Ibrahim aur Ismael ko taqeed ki thi ke mere is ghar ko tawaf aur aiteqaf aur ruku aur sajda karne walon ke liye paak rakkho" },
    { number: 126, arabic: "وَإِذْ قَالَ إِبْرَٰهِۦمُ رَبِّ ٱجْعَلْ هَٰذَا بَلَدًا ءَامِنًۭا وَٱرْزُقْ أَهْلَهُۥ مِنَ ٱلثَّمَرَٰتِ مَنْ ءَامَنَ مِنْهُم بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ قَالَ وَمَن كَفَرَ فَأُمَتِّعُهُۥ قَلِيلًۭا ثُمَّ أَضْطَرُّهُۥٓ إِلَىٰ عَذَابِ ٱلنَّارِ ۖ وَبِئْسَ ٱلْمَصِيرُ", transliteration: "Waith qala ibraheemu rabbi ijAAal hatha baladan aminan waorzuq ahlahu mina alththamarati man amana minhum biAllahi waalyawmi alakhiri qala waman kafara faomattiAAuhu qaleelan thumma adtarruhu ila AAathabi alnnari wabisa almaseeru", transliterationB: "Wa iz qaala Ibraaheemu Rabbij 'al haazaa baladan aaminanw warzuq ahlahoo minas samaraati man aamana minhum billaahi wal yawmil aakhiri qaala wa man kafara faumatti'uhoo qaleelan summa adtarruhooo ilaa 'azaabin Naari wa bi'salmaseer", english: "And remember Abraham said: \"My Lord, make this a City of Peace, and feed its people with fruits,-such of them as believe in Allah and the Last Day.\" He said: \"(Yea), and such as reject Faith,-for a while will I grant them their pleasure, but will soon drive them to the torment of Fire,- an evil destination (indeed)", romanUrdu: "Aur yeh ke Ibrahim ne dua ki: “Aey mere Rubb, is shehar ko aman ka shehar bana dey, aur iske bashindon (people) mein jo Allah aur aakhirat ko maanein, unhein har qism ke phalon ka rizq de”. Jawab mein uske Rubb ne farmaya: “aur jo na maanega ,duniya ki chandh roza zindagi ka samaan to main usey bhi dunga magar aakhir e kaar usey azaab e jahannum ki taraf ghaseetunga, aur woh badhtareen thikana hai”" },
    { number: 127, arabic: "وَإِذْ يَرْفَعُ إِبْرَٰهِۦمُ ٱلْقَوَاعِدَ مِنَ ٱلْبَيْتِ وَإِسْمَٰعِيلُ رَبَّنَا تَقَبَّلْ مِنَّآ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Waith yarfaAAu ibraheemu alqawaAAida mina albayti waismaAAeelu rabbana taqabbal minna innaka anta alssameeAAu alAAaleemu", transliterationB: "Wa iz yarfa'u Ibraaheemul qawaa'ida minal Baitiwa Ismaa'eelu Rabbanaa taqabbal minnaa innaka Antas Samee'ul Aleem", english: "And remember Abraham and Isma'il raised the foundations of the House (With this prayer): \"Our Lord! Accept (this service) from us: For Thou art the All-Hearing, the All-knowing", romanUrdu: "Aur yaad karo Ibrahim aur Ismail jab is ghar ki deewarein utha rahey thay , to dua karte jatay thay : “Aey hamare Rubb, humse yeh khidmat qabool farma le, tu sabki sunne aur sab kuch jaanne wala hai" },
    { number: 128, arabic: "رَبَّنَا وَٱجْعَلْنَا مُسْلِمَيْنِ لَكَ وَمِن ذُرِّيَّتِنَآ أُمَّةًۭ مُّسْلِمَةًۭ لَّكَ وَأَرِنَا مَنَاسِكَنَا وَتُبْ عَلَيْنَآ ۖ إِنَّكَ أَنتَ ٱلتَّوَّابُ ٱلرَّحِيمُ", transliteration: "Rabbana waijAAalna muslimayni laka wamin thurriyyatina ommatan muslimatan laka waarina manasikana watub AAalayna innaka anta alttawwabu alrraheemu", transliterationB: "Rabbanaa waj'alnaa muslimaini laka wa min zurriyyatinaaa ummatam muslimatal laka wa arinaa manaasikanaa wa tub 'alainaa innaka antat Tawwaabur Raheem", english: "Our Lord! make of us Muslims, bowing to Thy (Will), and of our progeny a people Muslim, bowing to Thy (will); and show us our place for the celebration of (due) rites; and turn unto us (in Mercy); for Thou art the Oft-Returning, Most Merciful", romanUrdu: "Aey Rubb, hum dono ko apna muslim (mutii e farmaan) bana, hamari nasal se ek aisi qaum utha jo teri muslim ho, humein apni ibadat ke tareeqe bata, aur hamari kotahiyon se darguzar farma, tu bada maaf karne wala aur reham farmane wala hai" },
    { number: 129, arabic: "رَبَّنَا وَٱبْعَثْ فِيهِمْ رَسُولًۭا مِّنْهُمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِكَ وَيُعَلِّمُهُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَيُزَكِّيهِمْ ۚ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Rabbana waibAAath feehim rasoolan minhum yatloo AAalayhim ayatika wayuAAallimuhumu alkitaba waalhikmata wayuzakkeehim innaka anta alAAazeezu alhakeemu", transliterationB: "Rabbanaa wab'as feehim Rasoolam minhum yatloo 'alaihim aayaatika wa yu'allimuhumul Kitaaba wal Hikmata wa yuzakkeehim; innaka Antal 'Azeezul Hakeem", english: "Our Lord! send amongst them a Messenger of their own, who shall rehearse Thy Signs to them and instruct them in scripture and wisdom, and sanctify them: For Thou art the Exalted in Might, the Wise", romanUrdu: "Aur aey Rubb, un logon mein khud unhi ki qaum se ek aisa Rasool uthaiyo jo unhein teri ayaat sunaye, unko kitab aur hikmat ki taleem de aur unki zindagiyan sanwarey, tu bada muqtadar (All-Powerful) aur hakeem hai.”" },
    { number: 130, arabic: "وَمَن يَرْغَبُ عَن مِّلَّةِ إِبْرَٰهِۦمَ إِلَّا مَن سَفِهَ نَفْسَهُۥ ۚ وَلَقَدِ ٱصْطَفَيْنَٰهُ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ", transliteration: "Waman yarghabu AAan millati ibraheema illa man safiha nafsahu walaqadi istafaynahu fee alddunya wainnahu fee alakhirati lamina alssaliheena", transliterationB: "Wa manny yarghabu 'am-Millarti Ibraaheema illaa man safiha nafsah; wa laqadis tafainaahu fid-dunyaa wa innaho fil aakhirati laminas saaliheen", english: "And who turns away from the religion of Abraham but such as debase their souls with folly? Him We chose and rendered pure in this world: And he will be in the Hereafter in the ranks of the Righteous", romanUrdu: "Ab kaun hai, jo Ibrahim ke tareeqe se nafrat karey? Jisne khud apne aap ko himaqat o jihalat mein mubtila karliya ho, uske siwa kaun yeh harakat kar sakta hai? Ibrahim to woh shaks hai jisko humne duniya mein apne kaam ke liye chun liya tha aur aakhiarat mein uska shumaar saliheen mein hoga" },
    { number: 131, arabic: "إِذْ قَالَ لَهُۥ رَبُّهُۥٓ أَسْلِمْ ۖ قَالَ أَسْلَمْتُ لِرَبِّ ٱلْعَٰلَمِينَ", transliteration: "Ith qala lahu rabbuhu aslim qala aslamtu lirabbi alAAalameena", transliterationB: "Iz qaala lahoo Rabbuhooo aslim qaala aslamtu li Rabbil 'aalameen", english: "Behold! his Lord said to him: \"Bow (thy will to Me):\" He said: \"I bow (my will) to the Lord and Cherisher of the Universe", romanUrdu: "Uska haal yeh tha ke jab uske Rubb ne ussey kaha : “Muslim ho ja” to usne fawran kaha : “main maalik e qaiynaat ka ‘muslim’ ho gaya.”" },
    { number: 132, arabic: "وَوَصَّىٰ بِهَآ إِبْرَٰهِۦمُ بَنِيهِ وَيَعْقُوبُ يَٰبَنِىَّ إِنَّ ٱللَّهَ ٱصْطَفَىٰ لَكُمُ ٱلدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ", transliteration: "Wawassa biha ibraheemu baneehi wayaAAqoobu ya baniyya inna Allaha istafa lakumu alddeena fala tamootunna illa waantum muslimoona", transliterationB: "Wa wassaa bihaaa Ibraaheemu baneehi wa Ya'qoob, yaa baniyya innal laahas tafaa lakumud deena falaa tamootunna illaa wa antum muslimoon", english: "And this was the legacy that Abraham left to his sons, and so did Jacob; \"Oh my sons! Allah hath chosen the Faith for you; then die not except in the Faith of Islam", romanUrdu: "Isi tareeqe par chalne ki hidayat usne apni aulad ko ki thi aur isi ki wasiyat Yakub apni aulad ko kar gaya, usne kaha tha ke : “mere bacchon! Allah ne tumhare liye yahi deen pasand kiya hai lihaza marte dum tak Muslim hi rehna”" },
    { number: 133, arabic: "أَمْ كُنتُمْ شُهَدَآءَ إِذْ حَضَرَ يَعْقُوبَ ٱلْمَوْتُ إِذْ قَالَ لِبَنِيهِ مَا تَعْبُدُونَ مِنۢ بَعْدِى قَالُوا۟ نَعْبُدُ إِلَٰهَكَ وَإِلَٰهَ ءَابَآئِكَ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ إِلَٰهًۭا وَٰحِدًۭا وَنَحْنُ لَهُۥ مُسْلِمُونَ", transliteration: "Am kuntum shuhadaa ith hadara yaAAqooba almawtu ith qala libaneehi ma taAAbudoona min baAAdee qaloo naAAbudu ilahaka wailaha abaika ibraheema waismaAAeela waishaqa ilahan wahidan wanahnu lahu muslimoona", transliterationB: "Am kuntum shuhadaaa'a iz hadara Ya'qoobal mawtu iz qaala libaneehi maa ta'budoona mim ba'dee qaaloo na'budu ilaahaka wa ilaaha aabaaa'ika Ibraaheema wa Ismaa'eela wa Ishaaqa Ilaahanw waahidanw wa nahnu lahoo muslimoon", english: "Were ye witnesses when death appeared before Jacob? Behold, he said to his sons: \"What will ye worship after me?\" They said: \"We shall worship Thy god and the god of thy fathers, of Abraham, Isma'il and Isaac,- the one (True) Allah: To Him we bow (in Islam)", romanUrdu: "Phir kya tum us waqt maujood thay jab Yakub is duniya se ruksat ho raha tha? Usne marte waqt apne bacchon se pucha: “ bacchon! Mere baad tum kiski bandagi karoge?” un sab ne jawab diya : “ hum usi ek khuda ki bandagi karenge jisey aap ne aur aapke buzurgon Ibrahim, Ismail, aur Ishaq ne khuda maana hai aur hum usi ke muslim hain”" },
    { number: 134, arabic: "تِلْكَ أُمَّةٌۭ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ", transliteration: "Tilka ommatun qad khalat laha ma kasabat walakum ma kasabtum wala tusaloona AAamma kano yaAAmaloona", transliterationB: "Tilka ummatun qad khalat lahaa maa kasabat wa lakum maa kasabtum wa laa tus'aloona 'ammaa kaano ya'maloon", english: "That was a people that hath passed away. They shall reap the fruit of what they did, and ye of what ye do! Of their merits there is no question in your case", romanUrdu: "Woh kuch log thay jo guzar gaye, jo kuch unhon ne kamaya woh unke liye hai aur jo kuch tum kamaoge, woh tumhare liye hai. Tumse yeh na pucha jayega ke woh kya karte thay" },
    { number: 135, arabic: "وَقَالُوا۟ كُونُوا۟ هُودًا أَوْ نَصَٰرَىٰ تَهْتَدُوا۟ ۗ قُلْ بَلْ مِلَّةَ إِبْرَٰهِۦمَ حَنِيفًۭا ۖ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Waqaloo koonoo hoodan aw nasara tahtadoo qul bal millata ibraheema haneefan wama kana mina almushrikeena", transliterationB: "Wa qaaloo koonoo Hoodan aw Nasaaraa tahtadoo; qul bal Millata Ibraaheema Haneefanw wa maa kaana minal mushrikeen", english: "They say: \"Become Jews or Christians if ye would be guided (To salvation).\" Say thou: \"Nay! (I would rather) the Religion of Abraham the True, and he joined not gods with Allah", romanUrdu: "Yahudi kehte hain: Yahudi ho to raah e raast paogey, Isayi kehte hain: Isayi ho to hidayat milegi , inse kaho: “nahin, balke sabko chodh kar Ibrahim ka tareeqa, aur Ibrahim mushrikon mein se na tha.”" },
    { number: 136, arabic: "قُولُوٓا۟ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْنَا وَمَآ أُنزِلَ إِلَىٰٓ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَمَآ أُوتِىَ ٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ", transliteration: "Qooloo amanna biAllahi wama onzila ilayna wama onzila ila ibraheema waismaAAeela waishaqa wayaAAqooba waalasbati wama ootiya moosa waAAeesa wama ootiya alnnabiyyoona min rabbihim la nufarriqu bayna ahadin minhum wanahnu lahu muslimoona", transliterationB: "Qoolooo aamannaa billaahi wa maaa unzila ilainaa wa maaa unzila ilaaa Ibraaheema wa Ismaa'eela wa Ishaaqa wa Ya'qooba wal Asbaati wa maaootiya Moosa wa 'Eesaa wa maaa ootiyan Nabiyyoona mir Rabbihim laa nufaariq baina ahadim minhum wa nahnu lahoo muslimoon", english: "Say ye: \"We believe in Allah, and the revelation given to us, and to Abraham, Isma'il, Isaac, Jacob, and the Tribes, and that given to Moses and Jesus, and that given to (all) prophets from their Lord: We make no difference between one and another of them: And we bow to Allah (in Islam)", romanUrdu: "(Musalmaano)! Kaho ke: “hum iman laye Allah par aur us hidayat par jo hamari taraf nazil hui hai aur jo Ibrahim, Ismail, Ishaq, Yakub aur aulad e Yakub ki taraf nazil hui thi aur jo Moosa aur Isa aur dusre tamaam paighambaron ko unke Rubb ki taraf se di gayi thi. Hum unke darmiyan koi tafreeq nahin karte aur hum Allah ke Muslim hain”" },
    { number: 137, arabic: "فَإِنْ ءَامَنُوا۟ بِمِثْلِ مَآ ءَامَنتُم بِهِۦ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا هُمْ فِى شِقَاقٍۢ ۖ فَسَيَكْفِيكَهُمُ ٱللَّهُ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Fain amanoo bimithli ma amantum bihi faqadi ihtadaw wain tawallaw fainnama hum fee shiqaqin fasayakfeekahumu Allahu wahuwa alssameeAAu alAAaleemu", transliterationB: "Fa in aamanoo bimisli maaa aamantum bihee faqadih tadaw wa in tawallaw fa innamaa hum fee shiqaaq; fasayakfeekahumul laah; wa Huwas Samee'ul Aleem", english: "So if they believe as ye believe, they are indeed on the right path; but if they turn back, it is they who are in schism; but Allah will suffice thee as against them, and He is the All-Hearing, the All-Knowing", romanUrdu: "Phir agar woh isi tarah iman layein, jis tarah tum laye ho, to hidayat par hain, aur agar issey mooh pherein to khuli baat hai ke woh hathdharmi (schism) mein padh gaye hain, lihaza itminaan rakkho ke unke muqable mein Allah tumhari himayat ke liye kafi hai. Woh sabkuch sunta aur jaanta hai" },
    { number: 138, arabic: "صِبْغَةَ ٱللَّهِ ۖ وَمَنْ أَحْسَنُ مِنَ ٱللَّهِ صِبْغَةًۭ ۖ وَنَحْنُ لَهُۥ عَٰبِدُونَ", transliteration: "Sibghata Allahi waman ahsanu mina Allahi sibghatan wanahnu lahu AAabidoona", transliterationB: "Sibghatal laahi wa man ahsanu minal laahi sibghatanw wa nahnu lahoo 'aabidoon", english: "(Our religion is) the Baptism of Allah: And who can baptize better than Allah? And it is He Whom we worship", romanUrdu: "Kaho: “ Allah ka rang ikhtiyar karo uske rang se accha aur kiska rang hoga? Aur hum usi ki bandagi karne waley log hain.”" },
    { number: 139, arabic: "قُلْ أَتُحَآجُّونَنَا فِى ٱللَّهِ وَهُوَ رَبُّنَا وَرَبُّكُمْ وَلَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ وَنَحْنُ لَهُۥ مُخْلِصُونَ", transliteration: "Qul atuhajjoonana fee Allahi wahuwa rabbuna warabbukum walana aAAmaluna walakum aAAmalukum wanahnu lahu mukhlisoona", transliterationB: "Qul atuhaaajjoonanaa fil laahi wa Huwa Rabbunaa wa Rabbukum wa lanaa a'maalunaa wa lakum a'maalukum wa nahnu lahoo mukhlisson", english: "Say: Will ye dispute with us about Allah, seeing that He is our Lord and your Lord; that we are responsible for our doings and ye for yours; and that We are sincere (in our faith) in Him", romanUrdu: "Aey Nabi! Inse kaho : “Kya tum Allah ke barey mein humse jhagadte ho? Halaanke wahi hamara Rubb hai aur tumhara Rubb bhi. Hamare aamaal hamare liye hain, tumhare aamaal tumhare liye , aur hum Allah hi ke liye apni bandagi ko khalis kar chuke hain" },
    { number: 140, arabic: "أَمْ تَقُولُونَ إِنَّ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطَ كَانُوا۟ هُودًا أَوْ نَصَٰرَىٰ ۗ قُلْ ءَأَنتُمْ أَعْلَمُ أَمِ ٱللَّهُ ۗ وَمَنْ أَظْلَمُ مِمَّن كَتَمَ شَهَٰدَةً عِندَهُۥ مِنَ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Am taqooloona inna ibraheema waismaAAeela waishaqa wayaAAqooba waalasbata kanoo hoodan aw nasara qul aantum aAAlamu ami Allahu waman athlamu mimman katama shahadatan AAindahu mina Allahi wama Allahu bighafilin AAamma taAAmaloona", transliterationB: "Am taqooloona inna Ibraaheema wa Ismaa'eela wa Ishaaq wa Ya'qooba wal asbaata kaanoo Hoodan aw Nasaaraa; qul 'a-antum a'lamu amil laah; wa man azlamu mimman katama shahaadatan 'indahoo minallaah; wa mallaahu bighaafilin 'ammaa ta'maloon", english: "Or do ye say that Abraham, Isma'il Isaac, Jacob and the Tribes were Jews or Christians? Say: Do ye know better than Allah? Ah! who is more unjust than those who conceal the testimony they have from Allah? but Allah is not unmindful of what ye do", romanUrdu: "Ya phir kya tumhara kehna yeh hai ke Ibrahim , Ismail, Ishaq, Yakub aur aulad e Yakub sab ke sab yahudi thay ya nasrani thay? Kaho: “tum zyada jaante ho ya Allah? Us shaks se bada zalim aur kaun hoga jiske zimme Allah ki taraf se ek gawahi ho aur woh usey chupaye? Tumhari harakat se Allah gaafil to nahin hai" },
    { number: 141, arabic: "تِلْكَ أُمَّةٌۭ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ", transliteration: "Tilka ommatun qad khalat laha ma kasabat walakum ma kasabtum wala tusaloona AAamma kanoo yaAAmaloona", transliterationB: "Tilka ummatun qad khalat lahaa maa kasabat wa lakum maa kasabtum wa laa tus'aloona 'ammaa kaano ya'maloo", english: "That was a people that hath passed away. They shall reap the fruit of what they did, and ye of what ye do! Of their merits there is no question in your case", romanUrdu: "Woh kuch log thay jo guzar chuke, unki kamayi unke liye thi aur tumhari kamayi tumhare liye. Tumse unke aamaal ke mutaaliq sawal nahin hoga.”" },
    { number: 142, arabic: "۞ سَيَقُولُ ٱلسُّفَهَآءُ مِنَ ٱلنَّاسِ مَا وَلَّىٰهُمْ عَن قِبْلَتِهِمُ ٱلَّتِى كَانُوا۟ عَلَيْهَا ۚ قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Sayaqoolu alssufahao mina alnnasi ma wallahum AAan qiblatihimu allatee kanoo AAalayha qul lillahi almashriqu waalmaghribu yahdee man yashao ila siratin mustaqeemin", transliterationB: "Sayaqoolus sufahaaa'u minan naasi maa wallaahum 'an Qiblatihimul latee kaanoo 'alaihaa; qulo lillaahil mashriqu walmaghrib; yahdee mai yashaaa'u ilaa Siraatim Mustaqeem", english: "The fools among the people will say: \"What hath turned them from the Qibla to which they were used?\" Say: To Allah belong both east and West: He guideth whom He will to a Way that is straight", romanUrdu: "Nadaan log zaroor kahenge : inhein kya hua ke pehle yeh jis qible ki taraf rukh karke namaz padhte thay ussey yakayak phir gaye? (Aey Nabi) Inse kaho : “mashriq aur magrib sab Allah ke hain, Allah jisey chahta hai seedhi raah dikha deta hai" },
    { number: 143, arabic: "وَكَذَٰلِكَ جَعَلْنَٰكُمْ أُمَّةًۭ وَسَطًۭا لِّتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ وَيَكُونَ ٱلرَّسُولُ عَلَيْكُمْ شَهِيدًۭا ۗ وَمَا جَعَلْنَا ٱلْقِبْلَةَ ٱلَّتِى كُنتَ عَلَيْهَآ إِلَّا لِنَعْلَمَ مَن يَتَّبِعُ ٱلرَّسُولَ مِمَّن يَنقَلِبُ عَلَىٰ عَقِبَيْهِ ۚ وَإِن كَانَتْ لَكَبِيرَةً إِلَّا عَلَى ٱلَّذِينَ هَدَى ٱللَّهُ ۗ وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَٰنَكُمْ ۚ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌۭ رَّحِيمٌۭ", transliteration: "Wakathalika jaAAalnakum ommatan wasatan litakoonoo shuhadaa AAala alnnasi wayakoona alrrasoolu AAalaykum shaheedan wama jaAAalna alqiblata allatee kunta AAalayha illa linaAAlama man yattabiAAu alrrasoola mimman yanqalibu AAala AAaqibayhi wain kanat lakabeeratan illa AAala allatheena hada Allahu wama kana Allahu liyudeeAAa eemanakum inna Allaha bialnnasi laraoofun raheemun", transliterationB: "Wa kazaalika ja'alnaakum ummatanw wasatal litakoonoo shuhadaaa'a 'alan naasi wa yakoonar Rasoolu 'alaikum shaheedaa; wa maa ja'alnal qiblatal latee kunta 'alaihaaa illaa lina'lama mai yattabi'ur Rasoola mimmai yanqalibu 'alaa 'aqibayh; wa in kaanat lakabeeratan illaa 'alal lazeena hadal laah; wa maa kaanal laahu liyudee'a eemaanakum; innal laaha binnaasi la Ra'oofur Raheem", english: "Thus, have We made of you an Ummat justly balanced, that ye might be witnesses over the nations, and the Messenger a witness over yourselves; and We appointed the Qibla to which thou wast used, only to test those who followed the Messenger from those who would turn on their heels (From the Faith). Indeed it was (A change) momentous, except to those guided by Allah. And never would Allah Make your faith of no effect. For Allah is to all people Most surely full of kindness, Most Merciful", romanUrdu: "Aur isi tarah to humne tumhein ek “ummat e wasat (middle nation)” banaya hai taa-ke tum duniya ke logon par gawah ho aur Rasool tumpar gawah ho. Pehle jis taraf tum rukh karte thay, usko to humne sirf yeh dekhne ke liye qibla muqarrar kiya tha ke kaun Rasool ki pairwi karta hai aur kaun ulta phir jata hai. Yeh maamla tha to bada sakht, magar un logon ke liye kuch bhi sakht na saabit hua jo Allah ki hidayat se faiziyaab thay, Allah tumhare is iman ko hargiz zaya na karega. Yaqeen jaano ke woh logon ke haqq mein nihayat shafeeq o raheem hai" },
    { number: 144, arabic: "قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ فَلَنُوَلِّيَنَّكَ قِبْلَةًۭ تَرْضَىٰهَا ۚ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ ۗ وَإِنَّ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ لَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا يَعْمَلُونَ", transliteration: "Qad nara taqalluba wajhika fee alssamai falanuwalliyannaka qiblatan tardaha fawalli wajhaka shatra almasjidi alharami wahaythu ma kuntum fawalloo wujoohakum shatrahu wainna allatheena ootoo alkitaba layaAAlamoona annahu alhaqqu min rabbihim wama Allahu bighafilin AAamma yaAAmaloona", transliterationB: "Qad naraa taqalluba wajhika fis samaaa'i fala nuwalliyannaka qiblatan tardaahaa; fawalli wajhaka shatral Masjidil haaraam; wa haisu maa kuntum fawalloo wujoohakum shatrah; wa innal lazeena ootul Kitaaba laya'lamoona annahul haqqu mir Rabbihim; wa mal laahu bighaafilin 'ammaa ya'maloon", english: "We see the turning of thy face (for guidance to the heavens: now Shall We turn thee to a Qibla that shall please thee. Turn then Thy face in the direction of the sacred Mosque: Wherever ye are, turn your faces in that direction. The people of the Book know well that that is the truth from their Lord. Nor is Allah unmindful of what they do)", romanUrdu: "Yeh tumhare mooh ka baar baar asmaan ki taraf uthna hum dekh rahey hain, lo hum isi qible ki taraf tumhein phere dete hain jisey tum pasand karte ho, Masjid e haraam ki taraf rukh pher do ab jahan kahin tum ho usi ki taraf mooh karke namaz padha karo. Yeh log jinhein kitab di gayi thi khoob jaante hain ke (tahweel e qibla ka/change of qibla) yeh hukum unke Rubb hi ki taraf se hai aur bar-haqq hai magar iske bawajood jo kuch yeh kar rahey hain Allah ussey gaafil nahin hai" },
    { number: 145, arabic: "وَلَئِنْ أَتَيْتَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ بِكُلِّ ءَايَةٍۢ مَّا تَبِعُوا۟ قِبْلَتَكَ ۚ وَمَآ أَنتَ بِتَابِعٍۢ قِبْلَتَهُمْ ۚ وَمَا بَعْضُهُم بِتَابِعٍۢ قِبْلَةَ بَعْضٍۢ ۚ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم مِّنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ ۙ إِنَّكَ إِذًۭا لَّمِنَ ٱلظَّٰلِمِينَ", transliteration: "Walain atayta allatheena ootoo alkitaba bikulli ayatin ma tabiAAoo qiblataka wama anta bitabiAAin qiblatahum wama baAAduhum bitabiAAin qiblata baAAdin walaini ittabaAAta ahwaahum min baAAdi ma jaaka mina alAAilmi innaka ithan lamina alththalimeena", transliterationB: "Wa la'in ataital lazeena ootul kitaaba bikulli aayatim maa tabi'oo Qiblatak; wa maaa anta bitaabi'in Qiblatahum; wa maa ba'duhum bitaabi''in Qiblata ba'd; wa la'init taba'ta ahwaaa;ahum mim ba'di maa jaaa'aka minal 'ilmi innaka izal laminaz zaalimeen", english: "Even if thou wert to bring to the people of the Book all the Signs (together), they would not follow Thy Qibla; nor art thou going to follow their Qibla; nor indeed will they follow each other's Qibla. If thou after the knowledge hath reached thee, Wert to follow their (vain) desires,-then wert thou Indeed (clearly) in the wrong", romanUrdu: "Tum in ehle kitab ke paas khwa koi nishani le aao, mumkin nahin ke yeh tumhare qible ki pairwi karne lagein, aur na tumhare liye yeh mumkin hai ke inke qible ki pairwi karo, aur inmein se koi giroh bhi dusre ke qible ki pairwi ke liye tayyar nahin hai, aur agar tumne is ilm ke baad jo tumhare paas aa chuka hai inki khwahishaat ki pairwi ki to yaqeenan tumhara shumaar zalimon mein hoga" },
    { number: 146, arabic: "ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يَعْرِفُونَهُۥ كَمَا يَعْرِفُونَ أَبْنَآءَهُمْ ۖ وَإِنَّ فَرِيقًۭا مِّنْهُمْ لَيَكْتُمُونَ ٱلْحَقَّ وَهُمْ يَعْلَمُونَ", transliteration: "Allatheena ataynahumu alkitaba yaAArifoonahu kama yaAArifoona abnaahum wainna fareeqan minhum layaktumoona alhaqqa wahum yaAAlamoona", transliterationB: "Allazeena aatainaahumul kitaaba ya'rifoonahoo kamaa ya'rifoona abnaaa'ahum wa inna fareeqam minhum layaktumoonal haqqa wa hum ya'lamoon", english: "The people of the Book know this as they know their own sons; but some of them conceal the truth which they themselves know", romanUrdu: "Jin logon ko humne kitab di hai woh is muqaam ko (jisey qible banaya gaya hai) aisa pehchante hain jaisa apni aulad ko pehchante hain, magar unmein se ek giroh jaante boojhte haqq ko chupa raha hai" },
    { number: 147, arabic: "ٱلْحَقُّ مِن رَّبِّكَ ۖ فَلَا تَكُونَنَّ مِنَ ٱلْمُمْتَرِينَ", transliteration: "Alhaqqu min rabbika fala takoonanna mina almumtareena", transliterationB: "Alhaqqu mir Rabbika falaa takoonana minal mumtareen", english: "The Truth is from thy Lord; so be not at all in doubt", romanUrdu: "Yeh qataii ek amr e haqq hai tumhare Rubb ki taraf se, lihaza iske mutaaliq tum hargiz kisi shakk mein na padho" },
    { number: 148, arabic: "وَلِكُلٍّۢ وِجْهَةٌ هُوَ مُوَلِّيهَا ۖ فَٱسْتَبِقُوا۟ ٱلْخَيْرَٰتِ ۚ أَيْنَ مَا تَكُونُوا۟ يَأْتِ بِكُمُ ٱللَّهُ جَمِيعًا ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Walikullin wijhatun huwa muwalleeha faistabiqoo alkhayrati ayna ma takoonoo yati bikumu Allahu jameeAAan inna Allaha AAala kulli shayin qadeerun", transliterationB: "Wa likullinw wijhatun huwa muwalleehaa fastabiqul khairaat; ayna maa takoonoo yaati bikumullaahu jamee'aa; innal laaha 'alaa kulli shai'in qadeer", english: "To each is a goal to which Allah turns him; then strive together (as in a race) Towards all that is good. Wheresoever ye are, Allah will bring you Together. For Allah Hath power over all things", romanUrdu: "Har ek ke liye ek rukh hai jiski taraf woh mudta hai, pas bhalaiyon ki taraf sabaqat karo. Jahan bhi tum hogey Allah tumhein paa lega, uski qudrat se koi cheez bahar nahin" },
    { number: 149, arabic: "وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۖ وَإِنَّهُۥ لَلْحَقُّ مِن رَّبِّكَ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Wamin haythu kharajta fawalli wajhaka shatra almasjidi alharami wainnahu lalhaqqu min rabbika wama Allahu bighafilin AAamma taAAmaloona", transliterationB: "Wa min haisu kharajta fawalli wajhaka shatral Masjidil Haraami wa innahoo lalhaqqu mir Rabbik; wa mallaahu bighaafilin 'ammaa ta'maloon", english: "From whencesoever Thou startest forth, turn Thy face in the direction of the sacred Mosque; that is indeed the truth from the Lord. And Allah is not unmindful of what ye do", romanUrdu: "Tumhara guzar jis muqaam se bhi ho wahin apna rukh (namaz ke waqt) masjid e haraam ki taraf pher do, kyunke yeh tumhare Rubb ka bilkul bar-haqq faisla hai aur Allah tum logon ke aamaal se be-khabar nahin hai" },
    { number: 150, arabic: "وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَيْكُمْ حُجَّةٌ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ فَلَا تَخْشَوْهُمْ وَٱخْشَوْنِى وَلِأُتِمَّ نِعْمَتِى عَلَيْكُمْ وَلَعَلَّكُمْ تَهْتَدُونَ", transliteration: "Wamin haythu kharajta fawalli wajhaka shatra almasjidi alharami wahaythu ma kuntum fawalloo wujoohakum shatrahu lialla yakoona lilnnasi AAalaykum hujjatun illa allatheena thalamoo minhum fala takhshawhum waikhshawnee waliotimma niAAmatee AAalaykum walaAAallakum tahtadoona", transliterationB: "Wa min haisu kharajta fawalli wajhaka shatral Masjidil Haraam; wa haisu maa kuntum fawalloo wujoohakum shatrahoo li'allaa yakoona linnaasi 'alaikum hujjatun illal lazeena zalamoo minhum falaa takhshawhum wakhshawnee wa liutimma ni'matee 'alaikum wa la'allakum tahtadoon", english: "So from whencesoever Thou startest forth, turn Thy face in the direction of the sacred Mosque; and wheresoever ye are, Turn your face thither: that there be no ground of dispute against you among the people, except those of them that are bent on wickedness; so fear them not, but fear Me; and that I may complete My favours on you, and ye May (consent to) be guided", romanUrdu: "Aur jahan se bhi tumhara guzar ho apna rukh masjid e haraam ki taraf phera karo, aur jahan bhi tum ho usi ki taraf mooh karke namaz padho taa-ke logon ko tumhare khilaf koi hujjat na miley. Haan jo zalim hain unki zubaan kisi haal mein bandh na hogi to unsey tum na daro balke mujhse daro aur isliye ke main tumpar apni niyamat poori kardoon aur is tawaqqu par ke mere is hukum ki pairwi se tum isi tarah falaah ka raasta paogey" },
    { number: 151, arabic: "كَمَآ أَرْسَلْنَا فِيكُمْ رَسُولًۭا مِّنكُمْ يَتْلُوا۟ عَلَيْكُمْ ءَايَٰتِنَا وَيُزَكِّيكُمْ وَيُعَلِّمُكُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَيُعَلِّمُكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ", transliteration: "Kama arsalna feekum rasoolan minkum yatloo AAalaykum ayatina wayuzakkeekum wayuAAallimukumu alkitaba waalhikmata wayuAAallimukum ma lam takoonoo taAAlamoona", transliterationB: "kamaaa arsalnaa feekum Rasoolam minkum yatloo 'alaikum aayaatina wa yuzakkeekum wa yu'alli mukumul kitaaba wal hikmata wa yu'allimukum maa lam takoonoo ta'lamoon", english: "A similar (favour have ye already received) in that We have sent among you a Messenger of your own, rehearsing to you Our Signs, and sanctifying you, and instructing you in Scripture and Wisdom, and in new knowledge", romanUrdu: "Jis tarah (tumhein is cheez se falaah naseeb hui ke) maine tumhare darmiyaan khud tum mein se ek Rasool bheja jo tumhein meri ayaat sunata hai, tumhari zindagiyon ko sanwaarta hai, tumhein kitab aur hikmat ki taleem deta hai aur tumhein woh baatein sikhata hai jo tum na jaante thay" },
    { number: 152, arabic: "فَٱذْكُرُونِىٓ أَذْكُرْكُمْ وَٱشْكُرُوا۟ لِى وَلَا تَكْفُرُونِ", transliteration: "Faothkuroonee athkurkum waoshkuroo lee wala takfurooni", transliterationB: "Fazkurooneee azkurkum washkuroo lee wa laa takfuroon", english: "Then do ye remember Me; I will remember you. Be grateful to Me, and reject not Faith", romanUrdu: "Lihaza tum mujhey yaad rakkho main tumhein yaad rakhunga aur mera shukar ada karo, kufran e niyamat na karo" },
    { number: 153, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّٰبِرِينَ", transliteration: "Ya ayyuha allatheena amanoo istaAAeenoo bialssabri waalssalati inna Allaha maAAa alssabireena", transliterationB: "Yaaa ayyuhal laazeena aamanus ta'eenoo bissabri was Salaah; innal laaha ma'as-saabireen", english: "O ye who believe! seek help with patient perseverance and prayer; for Allah is with those who patiently persevere", romanUrdu: "Aey logon jo iman laye ho sabr aur namaz se madad lo, Allah sabr karne walon ke saath hai" },
    { number: 154, arabic: "وَلَا تَقُولُوا۟ لِمَن يُقْتَلُ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتٌۢ ۚ بَلْ أَحْيَآءٌۭ وَلَٰكِن لَّا تَشْعُرُونَ", transliteration: "Wala taqooloo liman yuqtalu fee sabeeli Allahi amwatun bal ahyaon walakin la tashAAuroona", transliterationB: "Wa laa taqooloo limai yuqtalu fee sabeelil laahi amwaat; bal ahyaaa'unw wa laakil laa tash'uroon", english: "And say not of those who are slain in the way of Allah: \"They are dead.\" Nay, they are living, though ye perceive (it) not", romanUrdu: "Aur jo log Allah ki raah mein maarey jayein unhein murda na kaho, aisey log to haqeeqat mein zinda hain, magar tumhein unki zindagi ka shaoor nahin hota" },
    { number: 155, arabic: "وَلَنَبْلُوَنَّكُم بِشَىْءٍۢ مِّنَ ٱلْخَوْفِ وَٱلْجُوعِ وَنَقْصٍۢ مِّنَ ٱلْأَمْوَٰلِ وَٱلْأَنفُسِ وَٱلثَّمَرَٰتِ ۗ وَبَشِّرِ ٱلصَّٰبِرِينَ", transliteration: "Walanabluwannakum bishayin mina alkhawfi waaljooAAi wanaqsin mina alamwali waalanfusi waalththamarati wabashshiri alssabireena", transliterationB: "Wa lanablu wannakum bishai'im minal khawfi waljoo'i wa naqsim minal amwaali wal anfusi was samaraat; wa bashshiris saabireen", english: "Be sure we shall test you with something of fear and hunger, some loss in goods or lives or the fruits (of your toil), but give glad tidings to those who patiently persevere", romanUrdu: "Aur hum zaroor tumhein khauf o khatar , faaqa kashi (bhook), jaan o maal ke nuqsanaat aur aamadaniyon ke ghatey(nuqsaan) mein mubtila karke tumhari aazmaish karenge" },
    { number: 156, arabic: "ٱلَّذِينَ إِذَآ أَصَٰبَتْهُم مُّصِيبَةٌۭ قَالُوٓا۟ إِنَّا لِلَّهِ وَإِنَّآ إِلَيْهِ رَٰجِعُونَ", transliteration: "Allatheena itha asabathum museebatun qaloo inna lillahi wainna ilayhi rajiAAoona", transliterationB: "Allazeena izaaa asaabathum museebatun qaalooo innaa lillaahi wa innaaa ilaihi raaji'oon", english: "Who say, when afflicted with calamity: \"To Allah We belong, and to Him is our return", romanUrdu: "In halaat mein jo log sabr karein aur jab koi museebat padey to kahein ke : “ hum Allah hi ke hain aur Allah hi ki taraf humein palat kar jana hai”" },
    { number: 157, arabic: "أُو۟لَٰٓئِكَ عَلَيْهِمْ صَلَوَٰتٌۭ مِّن رَّبِّهِمْ وَرَحْمَةٌۭ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُهْتَدُونَ", transliteration: "Olaika AAalayhim salawatun min rabbihim warahmatun waolaika humu almuhtadoona", transliterationB: "Ulaaa'ika 'alaihim salawaatun mir Rabbihim wa rahma; wa ulaaa'ika humul muhtadoon", english: "They are those on whom (Descend) blessings from Allah, and Mercy, and they are the ones that receive guidance", romanUrdu: "Unhein khush-khabri dedo unpar unke Rubb ki taraf se badi inayat hogi, uski rehmat unpar saya karegi aur aisey hi log raast-ro hain" },
    { number: 158, arabic: "۞ إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ فَمَنْ حَجَّ ٱلْبَيْتَ أَوِ ٱعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَن يَطَّوَّفَ بِهِمَا ۚ وَمَن تَطَوَّعَ خَيْرًۭا فَإِنَّ ٱللَّهَ شَاكِرٌ عَلِيمٌ", transliteration: "Inna alssafa waalmarwata min shaAAairi Allahi faman hajja albayta awi iAAtamara fala junaha AAalayhi an yattawwafa bihima waman tatawwaAAa khayran fainna Allaha shakirun AAaleemun", transliterationB: "Innas Safaa wal-Marwata min sha'aaa'iril laahi faman hajjal Baita awi'tamara falaa junaaha 'alaihi ai yattawwafa bihimaa; wa man tatawwa'a khairan fa innal laaha Shaakirun'Aleem", english: "Behold! Safa and Marwa are among the Symbols of Allah. So if those who visit the House in the Season or at other times, should compass them round, it is no sin in them. And if any one obeyeth his own impulse to good,- be sure that Allah is He Who recogniseth and knoweth", romanUrdu: "Yaqeenan safa aur marwa Allah ki nishaniyon mein se hain, lihaza jo shaks baitullah ka hajj ya umra karey, uske liye koi gunaah ki baat nahin ke woh in dono pahadiyon ke darmiyan sayi karle aur jo bariza o ragbat(with a willing heart) koi bhalayi ka kaam karega Allah ko iska ilm hai aur woh iski qadr karne wala hai" },
    { number: 159, arabic: "إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلْنَا مِنَ ٱلْبَيِّنَٰتِ وَٱلْهُدَىٰ مِنۢ بَعْدِ مَا بَيَّنَّٰهُ لِلنَّاسِ فِى ٱلْكِتَٰبِ ۙ أُو۟لَٰٓئِكَ يَلْعَنُهُمُ ٱللَّهُ وَيَلْعَنُهُمُ ٱللَّٰعِنُونَ", transliteration: "Inna allatheena yaktumoona ma anzalna mina albayyinati waalhuda min baAAdi ma bayyannahu lilnnasi fee alkitabi olaika yalAAanuhumu Allahu wayalAAanuhumu allaAAinoona", transliterationB: "Innal lazeena yaktumoona maaa anzalnaa minal baiyinaati walhudaa mim ba'di maa baiyannaahu linnaasi fil kitaabi ulaaa'ika yal'anuhumul laahu wa yal'anuhumul laa 'inoon", english: "Those who conceal the clear (Signs) We have sent down, and the Guidance, after We have made it clear for the people in the Book,-on them shall be Allah's curse, and the curse of those entitled to curse", romanUrdu: "Jo log hamari nazil ki hui roshan taleemat aur hidayaat ko chupate hain, daraan haal yeh ke hum inhein sab Insano ki rehnumayi ke liye apni kitab mein bayan kar chuke hain, yaqeen jaano ke Allah bhi unpar lanat karta hai aur tamaam lanat karne waley bhi unpar lanat bhejte hain" },
    { number: 160, arabic: "إِلَّا ٱلَّذِينَ تَابُوا۟ وَأَصْلَحُوا۟ وَبَيَّنُوا۟ فَأُو۟لَٰٓئِكَ أَتُوبُ عَلَيْهِمْ ۚ وَأَنَا ٱلتَّوَّابُ ٱلرَّحِيمُ", transliteration: "Illa allatheena taboo waaslahoo wabayyanoo faolaika atoobu AAalayhim waana alttawwabu alrraheemu", transliterationB: "Illal lazeena taaboo wa aslahoo wa baiyanoo fa ulaaa'ika atoobu 'alaihim; wa Anat Tawwaabur Raheem", english: "Except those who repent and make amends and openly declare (the Truth): To them I turn; for I am Oft-returning, Most Merciful", romanUrdu: "Albatta jo is rawish se baaz aa jayein aur apne tarz e amal ki islah karlein aur jo kuch chupate thay usey bayan karne lagein, unko main maaf kardunga aur main bada darguzar karne wala aur reham karne wala hoon" },
    { number: 161, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌ أُو۟لَٰٓئِكَ عَلَيْهِمْ لَعْنَةُ ٱللَّهِ وَٱلْمَلَٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ", transliteration: "Inna allatheena kafaroo wamatoo wahum kuffarun olaika AAalayhim laAAnatu Allahi waalmalaikati waalnnasi ajmaAAeena", transliterationB: "Innal lazeena kafaroo wamaa too wa hum kuffaarun ulaaa'ika 'alaihim la 'natul laahi walmalaa'ikati wannaasi ajma'een", english: "Those who reject Faith, and die rejecting,- on them is Allah's curse, and the curse of angels, and of all mankind", romanUrdu: "Jin logon ne kufr ka rawayya ikhtiyar kiya aur kufr ki haalat mein hi jaan di, unpar Allah aur farishton aur tamaam Insano ki lanat hai" },
    { number: 162, arabic: "خَٰلِدِينَ فِيهَا ۖ لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ", transliteration: "Khalideena feeha la yukhaffafu AAanhumu alAAathabu wala hum yuntharoona", transliterationB: "khaalideena feeha laa yukhaffafu 'anhumul 'azaabu wa laa hum yunzaroon", english: "They will abide therein: Their penalty will not be lightened, nor will respite be their (lot)", romanUrdu: "Isi lanat zadahgi ki haalat mein woh hamesha rahenge, na unki saza mein takhfif hogi aur na unhein phir koi dusri mohlat di jayegi" },
    { number: 163, arabic: "وَإِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۖ لَّآ إِلَٰهَ إِلَّا هُوَ ٱلرَّحْمَٰنُ ٱلرَّحِيمُ", transliteration: "Wailahukum ilahun wahidun la ilaha illa huwa alrrahmanu alrraheemu", transliterationB: "Wa ilaahukum illaahunw waahid, laaa ilaaha illaa Huwar Rahmaanur Raheem", english: "And your Allah is One Allah: There is no god but He, Most Gracious, Most Merciful", romanUrdu: "Tumhara khuda ek hi khuda hai, us rehman aur raheem ke siwa koi aur khuda nahin hai" },
    { number: 164, arabic: "إِنَّ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَٱلْفُلْكِ ٱلَّتِى تَجْرِى فِى ٱلْبَحْرِ بِمَا يَنفَعُ ٱلنَّاسَ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن مَّآءٍۢ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍۢ وَتَصْرِيفِ ٱلرِّيَٰحِ وَٱلسَّحَابِ ٱلْمُسَخَّرِ بَيْنَ ٱلسَّمَآءِ وَٱلْأَرْضِ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Inna fee khalqi alssamawati waalardi waikhtilafi allayli waalnnahari waalfulki allatee tajree fee albahri bima yanfaAAu alnnasa wama anzala Allahu mina alssamai min main faahya bihi alarda baAAda mawtiha wabaththa feeha min kulli dabbatin watasreefi alrriyahi waalssahabi almusakhkhari bayna alssamai waalardi laayatin liqawmin yaAAqiloona", transliterationB: "Inna fee khalqis samaawaati wal ardi wakhtilaafil laili wannahaari walfulkil latee tajree fil hahri bimaa yanfa'unnaasa wa maaa anzalal laahu minas samaaa'i mim maaa'in fa ahyaa bihil arda ba'da mawtihaa wa bas sa feehaa min kulli daaabbatinw wa tasreefir riyaahi wassahaabil musakhkhari bainas samaaa'i wal ardi la aayaatil liqawminy ya'qiloon", english: "Behold! in the creation of the heavens and the earth; in the alternation of the night and the day; in the sailing of the ships through the ocean for the profit of mankind; in the rain which Allah Sends down from the skies, and the life which He gives therewith to an earth that is dead; in the beasts of all kinds that He scatters through the earth; in the change of the winds, and the clouds which they Trail like their slaves between the sky and the earth;- (Here) indeed are Signs for a people that are wise", romanUrdu: "(Is haqeeqat ko pehchanne ke liye agar koi nishani aur alamat darkaar hai to) jo log aqal se kaam lete hain unke liye asmaano aur zameen ki saakht (creation) mein, raat aur din ke paiham ek dusre ke baad aane mein, un kashtiyon mein jo Insaan ke nafaa ki cheezein liye huey daryaon aur samandaron mein chalti phirti hain, baarish ke us pani mein jisey Allah upar se barsata hai, phir uske zariye se zameen ko zindagi bakshta hai aur apne isi intezam ki badaulat zameen mein har qism ki jaandaar makhlooq ko phaylata hai, hawaon ki gardish mein, aur un baadalon mein jo asmaan aur zameen ke darmiyan tabey farmaan bana kar rakkhey gaye hain, beshumaar nishaniyan hain" },
    { number: 165, arabic: "وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادًۭا يُحِبُّونَهُمْ كَحُبِّ ٱللَّهِ ۖ وَٱلَّذِينَ ءَامَنُوٓا۟ أَشَدُّ حُبًّۭا لِّلَّهِ ۗ وَلَوْ يَرَى ٱلَّذِينَ ظَلَمُوٓا۟ إِذْ يَرَوْنَ ٱلْعَذَابَ أَنَّ ٱلْقُوَّةَ لِلَّهِ جَمِيعًۭا وَأَنَّ ٱللَّهَ شَدِيدُ ٱلْعَذَابِ", transliteration: "Wamina alnnasi man yattakhithu min dooni Allahi andadan yuhibboonahum kahubbi Allahi waallatheena amanoo ashaddu hubban lillahi walaw yara allatheena thalamoo ith yarawna alAAathaba anna alquwwata lillahi jameeAAan waanna Allaha shadeedu alAAathabi", transliterationB: "Wa minan naasi mai yattakhizu min doonil laahi andaadai yuhibboonahum kahubbil laahi wallazeena aamanooo ashaddu hubbal lillah; wa law yaral lazeena zalamoo iz yarawnal 'azaaba annal quwwata lillaahi jamee'anw wa annallaaha shadeedul 'azaab", english: "Yet there are men who take (for worship) others besides Allah, as equal (with Allah): They love them as they should love Allah. But those of Faith are overflowing in their love for Allah. If only the unrighteous could see, behold, they would see the penalty: that to Allah belongs all power, and Allah will strongly enforce the penalty", romanUrdu: "(Magar wehdat e khudawandi par dalalat karne waley in khule khule aasaar ke hotey huey bhi) kuch log aisey hain jo Allah ke siwa dusron ko uska humsar aur madd e muqabil (equals and rivals) banate hain aur unke aisey girwida(adore) hain jaise Allah ke saath girwidgi honi chahiye, halaanke iman rakhne waley log sabse badhkar Allah ko mehboob rakhte hain, kaash jo kuch azaab ko saamne dekhkar unhein soojhne wala hai woh aaj hi in zalimeen ko soojh jaye ke saari taaqatein aur saare ikhtiyaraat Allah hi ke qabze mein hain aur yeh ke Allah saza dene mein bhi bahut sakht hai" },
    { number: 166, arabic: "إِذْ تَبَرَّأَ ٱلَّذِينَ ٱتُّبِعُوا۟ مِنَ ٱلَّذِينَ ٱتَّبَعُوا۟ وَرَأَوُا۟ ٱلْعَذَابَ وَتَقَطَّعَتْ بِهِمُ ٱلْأَسْبَابُ", transliteration: "Ith tabarraa allatheena ittubiAAoo mina allatheena ittabaAAoo waraawoo alAAathaba wataqattaAAat bihimu alasbabu", transliterationB: "Iz tabarra al lazeenat tubi'oo minal lazeenattaba'oo wa ra awul 'azaaba wa taqatta'at bihimul asbaab", english: "Then would those who are followed clear themselves of those who follow (them): They would see the penalty, and all relations between them would be cut off", romanUrdu: "Jab woh saza dega us waqt kaifiyat yeh hogi ke wahi peshwa aur rehnuma jinki duniya mein pairwi ki gayi thi apne pairawon se be-taaluqi zahir karenge, magar saza paa kar rahenge aur unke saare asbaab o wasail ka silsila katt jayega" },
    { number: 167, arabic: "وَقَالَ ٱلَّذِينَ ٱتَّبَعُوا۟ لَوْ أَنَّ لَنَا كَرَّةًۭ فَنَتَبَرَّأَ مِنْهُمْ كَمَا تَبَرَّءُوا۟ مِنَّا ۗ كَذَٰلِكَ يُرِيهِمُ ٱللَّهُ أَعْمَٰلَهُمْ حَسَرَٰتٍ عَلَيْهِمْ ۖ وَمَا هُم بِخَٰرِجِينَ مِنَ ٱلنَّارِ", transliteration: "Waqala allatheena ittabaAAoo law anna lana karratan fanatabarraa minhum kama tabarraoo minna kathalika yureehimu Allahu aAAmalahum hasaratin AAalayhim wama hum bikharijeena mina alnnari", transliterationB: "Wa qaalal lazeenat taba'oo law anna lanaa karratan fanatabarra a minhum kamaa tabarra'oo minnaa; kazaalika yureehimullaahu a'maalahum hasaraatin 'alaihim wa maa hum bikhaarijeena minan Naar", english: "And those who followed would say: \"If only We had one more chance, We would clear ourselves of them, as they have cleared themselves of us.\" Thus will Allah show them (The fruits of) their deeds as (nothing but) regrets. Nor will there be a way for them out of the Fire", romanUrdu: "Aur woh log jo duniya mein unki pairwi karte thay, kahenge ke kaash humko phir ek mauqa diya jata to jis tarah aaj yeh humse bezari zaahir kar rahey hain hum inse bezaar hokar dikha detey, yun Allah in logon ke woh aamaal jo yeh duniya mein kar rahey hain inke saamne is tarah layega ke yeh hasraton aur pashemaniyon ke saath haath malte rahenge, magar aag se nikalne ki koi raah na payenge" },
    { number: 168, arabic: "يَٰٓأَيُّهَا ٱلنَّاسُ كُلُوا۟ مِمَّا فِى ٱلْأَرْضِ حَلَٰلًۭا طَيِّبًۭا وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌ", transliteration: "Ya ayyuha alnnasu kuloo mimma fee alardi halalan tayyiban wala tattabiAAoo khutuwati alshshaytani innahu lakum AAaduwwun mubeenun", transliterationB: "Yaaa ayyuhan naasu kuloo mimmaa fil ardi halaalan taiyibanw wa laa tattabi'oo khutu waatish Shaitaan; innahoo lakum 'aduwwum mubeen", english: "O ye people! Eat of what is on earth, Lawful and good; and do not follow the footsteps of the evil one, for he is to you an avowed enemy", romanUrdu: "Logon! Zameen mein jo halal aur paak cheezein hain unhein khao aur shaytan ke bataye huey raaston par na chalo, woh tumhara khula dushman hai" },
    { number: 169, arabic: "إِنَّمَا يَأْمُرُكُم بِٱلسُّوٓءِ وَٱلْفَحْشَآءِ وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Innama yamurukum bialssooi waalfahshai waan taqooloo AAala Allahi ma la taAAlamoona", transliterationB: "Innamaa yaamurukum bissooo'i walfahshaaa'i wa an taqooloo alal laahi maa laa ta'lamoon", english: "For he commands you what is evil and shameful, and that ye should say of Allah that of which ye have no knowledge", romanUrdu: "Tumhein badhi(vice) aur fahash (indecency) ka hukum deta hai aur yeh sikhata hai ke tum Allah ke naam par woh baatein kaho jinke mutaaliq tumhein ilm nahin hai ke woh Allah ne farmayi hain" },
    { number: 170, arabic: "وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَآ أَلْفَيْنَا عَلَيْهِ ءَابَآءَنَآ ۗ أَوَلَوْ كَانَ ءَابَآؤُهُمْ لَا يَعْقِلُونَ شَيْـًۭٔا وَلَا يَهْتَدُونَ", transliteration: "Waitha qeela lahumu ittabiAAoo ma anzala Allahu qaloo bal nattabiAAu ma alfayna AAalayhi abaana awalaw kana abaohum la yaAAqiloona shayan wala yahtadoona", transliterationB: "Wa izaa qeela lahumuttabi'oo maaa anzalal laahu qaaloo bal nattabi'u maaa alfainaa 'alaihi aabaaa'anaaa; awalaw kaana aabaaa'hum laa ya'qiloona shai'anw wa laa yahtadoon", english: "When it is said to them: \"Follow what Allah hath revealed:\" They say: \"Nay! we shall follow the ways of our fathers.\" What! even though their fathers Were void of wisdom and guidance", romanUrdu: "Inse jab kaha jata hai ke Allah ne jo ehkaam nazil kiye hain unki pairwi karo to jawab dete hain ke hum to usi tareeqe ki pairwi karenge jispar humne apne baap dada ko paya hai, accha agar inke baap dada ne aqal se kuch bhi kaam na liya ho aur raah e raast na payi ho to kya phir bhi yeh unhin ki pairwi kiye chale jayenge" },
    { number: 171, arabic: "وَمَثَلُ ٱلَّذِينَ كَفَرُوا۟ كَمَثَلِ ٱلَّذِى يَنْعِقُ بِمَا لَا يَسْمَعُ إِلَّا دُعَآءًۭ وَنِدَآءًۭ ۚ صُمٌّۢ بُكْمٌ عُمْىٌۭ فَهُمْ لَا يَعْقِلُونَ", transliteration: "Wamathalu allatheena kafaroo kamathali allathee yanAAiqu bima la yasmaAAu illa duAAaan wanidaan summun bukmun AAumyun fahum la yaAAqiloona", transliterationB: "Wa masalul lazeena kafaroo kamasalil lazee yan'iqu bimaa laa yasma'u illaa du'aaa'anw wa nidaaa'aa; summum bukmun 'umyun fahum laa ya'qiloon", english: "The parable of those who reject Faith is as if one were to shout Like a goat-herd, to things that listen to nothing but calls and cries: Deaf, dumb, and blind, they are void of wisdom", romanUrdu: "Yeh log jinhon ne khuda ke bataye huey tareeqe par chalne se inkar kardiya hai inki haalat bilkul aisi hai jaise charwaha jaanwaron ko pukarta hai aur woh haank pukaar ki sada ke siwa kuch nahin suntey. Yeh behre hain , gungay hain andhey hain, isliye koi baat inki samajh mein nahin aati" },
    { number: 172, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ وَٱشْكُرُوا۟ لِلَّهِ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ", transliteration: "Ya ayyuha allatheena amanoo kuloo min tayyibati ma razaqnakum waoshkuroo lillahi in kuntum iyyahu taAAbudoona", transliterationB: "Yaaa ayyuhal lazeena aamanoo kuloo min taiyibaati maa razaqnaakum washkuroo lillaahi in kuntum iyyaahu ta'budoon", english: "O ye who believe! Eat of the good things that We have provided for you, and be grateful to Allah, if it is Him ye worship", romanUrdu: "Aey logon jo iman laye ho, agar tum haqeeqat mein Allah hi ki bandagi karne waley ho to jo paak cheezein humne tumhein bakshi hain unhein be-takalluf khao aur Allah ka shukar ada karo" },
    { number: 173, arabic: "إِنَّمَا حَرَّمَ عَلَيْكُمُ ٱلْمَيْتَةَ وَٱلدَّمَ وَلَحْمَ ٱلْخِنزِيرِ وَمَآ أُهِلَّ بِهِۦ لِغَيْرِ ٱللَّهِ ۖ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍۢ وَلَا عَادٍۢ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ", transliteration: "Innama harrama AAalaykumu almaytata waalddama walahma alkhinzeeri wama ohilla bihi lighayri Allahi famani idturra ghayra baghin wala AAadin fala ithma AAalayhi inna Allaha ghafoorun raheemun", transliterationB: "Innamaa harrama 'alaikumul maitata waddama wa lahmal khinzeeri wa maaa uhilla bihee lighairil laahi famanid turra ghaira baaghinw wa laa 'aadin falaaa isma 'alaih; innal laaha Ghafoorur Raheem", english: "He hath only forbidden you dead meat, and blood, and the flesh of swine, and that on which any other name hath been invoked besides that of Allah. But if one is forced by necessity, without wilful disobedience, nor transgressing due limits,- then is he guiltless. For Allah is Oft-forgiving Most Merciful", romanUrdu: "Allah ki taraf se agar koi pabandi tumpar hai to woh yeh hai ke murdaar na khao, khoon se aur suwar (swine) ke gosht se parheiz karo aur koi aisi cheez na khao jispar Allah ke siwa kisi aur ka naam liya gaya ho, haan jo shaks majboori ki haalat mein ho aur woh inmein se koi cheez kha le bagair iske ke woh kanoon shikani ka irada rakhta ho ya zaroorat ki hadd se tajawuz karey, to uspar kuch gunaah nahin. Allah bakshne wala aur reham karne wala hai" },
    { number: 174, arabic: "إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلَ ٱللَّهُ مِنَ ٱلْكِتَٰبِ وَيَشْتَرُونَ بِهِۦ ثَمَنًۭا قَلِيلًا ۙ أُو۟لَٰٓئِكَ مَا يَأْكُلُونَ فِى بُطُونِهِمْ إِلَّا ٱلنَّارَ وَلَا يُكَلِّمُهُمُ ٱللَّهُ يَوْمَ ٱلْقِيَٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ", transliteration: "Inna allatheena yaktumoona ma anzala Allahu mina alkitabi wayashtaroona bihi thamanan qaleelan olaika ma yakuloona fee butoonihim illa alnnara wala yukallimuhumu Allahu yawma alqiyamati wala yuzakkeehim walahum AAathabun aleemun", transliterationB: "Innal lazeena yaktumoona maaa anzalal laahu minal kitaabi wa yashtaroona bihee samanan qaleelan ulaaa'ika maa yaakuloona fee butoonihim illan Naara wa laa yukallimu humul laahu Yawmal Qiyaamati wa laa yuzakkeehim wa lahum 'azaabun aleem", english: "Those who conceal Allah's revelations in the Book, and purchase for them a miserable profit,- they swallow into themselves naught but Fire; Allah will not address them on the Day of Resurrection. Nor purify them: Grievous will be their penalty", romanUrdu: "Haqq yeh hai ke jo log un ehkam ko chupate hain jo Allah ne apni kitab mein nazil kiye hain aur thode se duniyavi faiydon par unhein bhent chadhate hain woh darasal apne pait aag se bhar rahey hain , qayamat ke roz Allah hargiz unse baat na karega, na unhein pakeeza therayega, aur unke liye dardnaak saza hai" },
    { number: 175, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلضَّلَٰلَةَ بِٱلْهُدَىٰ وَٱلْعَذَابَ بِٱلْمَغْفِرَةِ ۚ فَمَآ أَصْبَرَهُمْ عَلَى ٱلنَّارِ", transliteration: "Olaika allatheena ishtarawoo alddalalata bialhuda waalAAathaba bialmaghfirati fama asbarahum AAala alnnari", transliterationB: "Ulaaa'ikal lazeenash tarawud dalaalata bilhudaa wal'azaaba bilmaghfirah; famaaa asbarahum 'alan Naar", english: "They are the ones who buy Error in place of Guidance and Torment in place of Forgiveness. Ah! what boldness (They show) for the Fire", romanUrdu: "Yeh woh log hain jinhon ne hidayat ke badle zalalat kharidi aur magfirat ke badle azaab moal le liya, kaisa ajeeb hai inka hausla ke jahannum ka azaab bardasht karne ke liye tayyar hain" },
    { number: 176, arabic: "ذَٰلِكَ بِأَنَّ ٱللَّهَ نَزَّلَ ٱلْكِتَٰبَ بِٱلْحَقِّ ۗ وَإِنَّ ٱلَّذِينَ ٱخْتَلَفُوا۟ فِى ٱلْكِتَٰبِ لَفِى شِقَاقٍۭ بَعِيدٍۢ", transliteration: "Thalika bianna Allaha nazzala alkitaba bialhaqqi wainna allatheena ikhtalafoo fee alkitabi lafee shiqaqin baAAeedin", transliterationB: "Zaalika bi annal laaha nazzalal kitaaba bilhaqq; wa innal lazeenakh talafoo fil kitaabi lafee shiqaaqim ba'eed", english: "(Their doom is) because Allah sent down the Book in truth but those who seek causes of dispute in the Book are in a schism Far (from the purpose)", romanUrdu: "Yeh sab kuch is wajah se hua ke Allah ne to theek theek haqq ke mutabiq kitab nazil ki thi magar jin logon ne kitab mein ikhtilafat nikale woh apne jhagdon mein haqq se bahut door nikal gaye" },
    { number: 177, arabic: "۞ لَّيْسَ ٱلْبِرَّ أَن تُوَلُّوا۟ وُجُوهَكُمْ قِبَلَ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَلَٰكِنَّ ٱلْبِرَّ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَٱلْمَلَٰٓئِكَةِ وَٱلْكِتَٰبِ وَٱلنَّبِيِّۦنَ وَءَاتَى ٱلْمَالَ عَلَىٰ حُبِّهِۦ ذَوِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينَ وَٱبْنَ ٱلسَّبِيلِ وَٱلسَّآئِلِينَ وَفِى ٱلرِّقَابِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَٱلْمُوفُونَ بِعَهْدِهِمْ إِذَا عَٰهَدُوا۟ ۖ وَٱلصَّٰبِرِينَ فِى ٱلْبَأْسَآءِ وَٱلضَّرَّآءِ وَحِينَ ٱلْبَأْسِ ۗ أُو۟لَٰٓئِكَ ٱلَّذِينَ صَدَقُوا۟ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُتَّقُونَ", transliteration: "Laysa albirra an tuwalloo wujoohakum qibala almashriqi waalmaghribi walakinna albirra man amana biAllahi waalyawmi alakhiri waalmalaikati waalkitabi waalnnabiyyeena waata almala AAala hubbihi thawee alqurba waalyatama waalmasakeena waibna alssabeeli waalssaileena wafee alrriqabi waaqama alssalata waata alzzakata waalmoofoona biAAahdihim itha AAahadoo waalssabireena fee albasai waalddarrai waheena albasi olaika allatheena sadaqoo waolaika humu almuttaqoona", transliterationB: "Laisal birra an tuwalloo wujoohakum qibalal mashriqi walmaghribi wa laakinnal birra man aamana billaahi wal yawmil aakhiri wal malaaa 'ikati wal kitaabi wan nabiyyeena wa aatalmaala 'alaa hubbihee zawilqurbaa walyataa maa walmasaakeena wabnas sabeeli wassaaa'ileena wa firriqaabi wa aqaamas salaata wa aataz zakaata walmoofoona bi ahdihim izaa 'aahadoo wasaabireena fil baasaaa'i waddarraaa'i wa heenal baas; ulaaa'ikal lazeena sadaqoo wa ulaaa 'ika humul muttaqoon", english: "It is not righteousness that ye turn your faces Towards east or West; but it is righteousness- to believe in Allah and the Last Day, and the Angels, and the Book, and the Messengers; to spend of your substance, out of love for Him, for your kin, for orphans, for the needy, for the wayfarer, for those who ask, and for the ransom of slaves; to be steadfast in prayer, and practice regular charity; to fulfil the contracts which ye have made; and to be firm and patient, in pain (or suffering) and adversity, and throughout all periods of panic. Such are the people of truth, the Allah-fearing", romanUrdu: "Neki yeh nahin hai ke tumne apne chehre mashriq (east) ki taraf karliye ya magrib(west) ki taraf, balke neki yeh hai ke aadmi Allah ko aur yaum e aakhir aur malaika ko aur Allah ki nazil ki hui kitab aur uske paighambaron ko dil se maane aur Allah ki muhabbat mein apna dil pasand maal rishtedaaron aur yateemon par, miskeeno aur musafiron par, madad ke liye haath phaylane walon par aur ghulamo ki rihayi par kharch karey, namaz qayam karey aur zakaat de aur neik woh log hain ke jab ahad karein to usey wafa karein, aur tanggi o museebat ke waqt mein aur haqq o baatil ki jung mein sabr karein, yeh hain raast baaz log aur yahi log muttaqi (pious) hain" },
    { number: 178, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلْقِصَاصُ فِى ٱلْقَتْلَى ۖ ٱلْحُرُّ بِٱلْحُرِّ وَٱلْعَبْدُ بِٱلْعَبْدِ وَٱلْأُنثَىٰ بِٱلْأُنثَىٰ ۚ فَمَنْ عُفِىَ لَهُۥ مِنْ أَخِيهِ شَىْءٌۭ فَٱتِّبَاعٌۢ بِٱلْمَعْرُوفِ وَأَدَآءٌ إِلَيْهِ بِإِحْسَٰنٍۢ ۗ ذَٰلِكَ تَخْفِيفٌۭ مِّن رَّبِّكُمْ وَرَحْمَةٌۭ ۗ فَمَنِ ٱعْتَدَىٰ بَعْدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo kutiba AAalaykumu alqisasu fee alqatla alhurru bialhurri waalAAabdu bialAAabdi waalontha bialontha faman AAufiya lahu min akheehi shayon faittibaAAun bialmaAAroofi waadaon ilayhi biihsanin thalika takhfeefun min rabbikum warahmatun famani iAAtada baAAda thalika falahu AAathabun aleemun", transliterationB: "Yaaa ayyuhal lazeena aamanoo kutiba alaikumul qisaasu fil qatlaa alhurru bilhurri wal'abdu bil'abdi wal unsaa bil unsaa; faman 'ufiya lahoo min akheehi shai'un fattibaa'um bilma'roofi wa adaaa'un ilaihi bi ihsaan; zaalika takhfeefum mir rahbikum wa rahmah; famani' tadaa ba'da zaalika falahoo 'azaabun aleem", english: "O ye who believe! the law of equality is prescribed to you in cases of murder: the free for the free, the slave for the slave, the woman for the woman. But if any remission is made by the brother of the slain, then grant any reasonable demand, and compensate him with handsome gratitude, this is a concession and a Mercy from your Lord. After this whoever exceeds the limits shall be in grave penalty", romanUrdu: "Aey logon jo iman laye ho, tumhare liye qatal ke muqaddamo mein qisas (retribution) ka hukum likh diya gaya hai. Azad aadmi ne qatal kiya ho to us azad hi se badla liya jaye, ghulam qatil ho to woh ghulam hi qatal kiya jaye, aur aurat is jurm ki murtakib ho to us aurat hi se qisas liya jaye, haan agar kisi qatil ke saath iska bhai kuch narmi karne ke liye tayyar ho to maroof tareeqe ke mutabiq khoon baha (blood money) ka tasfiya hona chahiye aur qatil ko lazim hai ke raasti ke saath khoon baha ada karey, yeh tumhare Rubb ki taraf se takhfif aur rehmat hai, ispar bhi jo zyadati karey uske liye dardnaak saza hai" },
    { number: 179, arabic: "وَلَكُمْ فِى ٱلْقِصَاصِ حَيَوٰةٌۭ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ لَعَلَّكُمْ تَتَّقُونَ", transliteration: "Walakum fee alqisasi hayatun ya olee alalbabi laAAallakum tattaqoona", transliterationB: "Wa lakum fil qisaasi hayaatuny yaaa ulil albaabi la 'allakum tattaqoon", english: "In the Law of Equality there is (saving of) Life to you, o ye men of understanding; that ye may restrain yourselves", romanUrdu: "(Aqal o khird rakhne walon)! Tumhare liye qisas mein zindagi hai, umeed hai ke tum is kanoon ki khilaf warzi se parheiz karoge" },
    { number: 180, arabic: "كُتِبَ عَلَيْكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ إِن تَرَكَ خَيْرًا ٱلْوَصِيَّةُ لِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ", transliteration: "Kutiba AAalaykum itha hadara ahadakumu almawtu in taraka khayran alwasiyyatu lilwalidayni waalaqrabeena bialmaAAroofi haqqan AAala almuttaqeena", transliterationB: "Kutiba 'alaikum izaa hadara ahadakumul mawtu in taraka khairanil wasiyyatu lilwaalidaini wal aqrabeena bilma'roofi haqqan 'alalmut taqeen", english: "It is prescribed, when death approaches any of you, if he leave any goods that he make a bequest to parents and next of kin, according to reasonable usage; this is due from the Allah-fearing", romanUrdu: "Tum par farz kiya gaya hai ke jab tum mein se kisi ki maut ka waqt aaye aur woh apne pichey maal chodh raha ho, to walidain aur rishtedaaron ke liye maroof tareeqe se wasiyat karey, yeh haqq hai muttaqi logon par" },
    { number: 181, arabic: "فَمَنۢ بَدَّلَهُۥ بَعْدَمَا سَمِعَهُۥ فَإِنَّمَآ إِثْمُهُۥ عَلَى ٱلَّذِينَ يُبَدِّلُونَهُۥٓ ۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", transliteration: "Faman baddalahu baAAdama samiAAahu fainnama ithmuhu AAala allatheena yubaddiloonahu inna Allaha sameeAAun AAaleemun", transliterationB: "Famam baddalahoo ba'da maa sami'ahoo fa innamaaa ismuhoo 'alallazeena yubaddi loonah; innallaha Samee'un 'Aleem", english: "If anyone changes the bequest after hearing it, the guilt shall be on those who make the change. For Allah hears and knows (All things)", romanUrdu: "Phir jinhon ne wasiyat suni aur baad mein usey badal dala to iska gunaah un badalne walon par hoga, Allah sabkuch sunta aur jaanta hai" },
    { number: 182, arabic: "فَمَنْ خَافَ مِن مُّوصٍۢ جَنَفًا أَوْ إِثْمًۭا فَأَصْلَحَ بَيْنَهُمْ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Faman khafa min moosin janafan aw ithman faaslaha baynahum fala ithma AAalayhi inna Allaha ghafoorun raheemun", transliterationB: "Faman khaafa mim moosin janafan aw isman fa aslaha bainahum falaaa ismaa 'alayh; innal laaha Ghafooru Raheem", english: "But if anyone fears partiality or wrong-doing on the part of the testator, and makes peace between (The parties concerned), there is no wrong in him: For Allah is Oft-forgiving, Most Merciful", romanUrdu: "Albatta jisko yeh andesha ho ke wasiyat karne waley ne nadanishta ya qasdan haqq talafi ki hai aur phir maamle se taaluq rakhne walon ke darmiyan woh islah karey, to uspar kuch gunaah nahin hai, Allah bakshne wala aur reham farmane wala hai" },
    { number: 183, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلصِّيَامُ كَمَا كُتِبَ عَلَى ٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ", transliteration: "Ya ayyuha allatheena amanoo kutiba AAalaykumu alssiyamu kama kutiba AAala allatheena min qablikum laAAallakum tattaqoona", transliterationB: "Yaa ayyuhal lazeena aamanoo kutiba 'alaikumus Siyaamu kamaa kutiba 'alal lazeena min qablikum la'allakum tattaqoon", english: "O ye who believe! Fasting is prescribed to you as it was prescribed to those before you, that ye may (learn) self-restraint", romanUrdu: "Aey logon jo iman laye ho, tumpar roze farz kardiye gaye jis tarah tumse pehle ambiya ke pairawon par farz kiye gaye thay, issey tawaqqu hai ke tum mein taqwa ki siffat paida hogi" },
    { number: 184, arabic: "أَيَّامًۭا مَّعْدُودَٰتٍۢ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ عَلَىٰ سَفَرٍۢ فَعِدَّةٌۭ مِّنْ أَيَّامٍ أُخَرَ ۚ وَعَلَى ٱلَّذِينَ يُطِيقُونَهُۥ فِدْيَةٌۭ طَعَامُ مِسْكِينٍۢ ۖ فَمَن تَطَوَّعَ خَيْرًۭا فَهُوَ خَيْرٌۭ لَّهُۥ ۚ وَأَن تَصُومُوا۟ خَيْرٌۭ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Ayyaman maAAdoodatin faman kana minkum mareedan aw AAala safarin faAAiddatun min ayyamin okhara waAAala allatheena yuteeqoonahu fidyatun taAAamu miskeenin faman tatawwaAAa khayran fahuwa khayrun lahu waan tasoomoo khayrun lakum in kuntum taAAlamoona", transliterationB: "Ayyaamam ma'doodaat; faman kaana minkum mareedan aw'alaa safarin fa'iddatum min ayyaamin ukhar; wa 'alal lazeena yuteeqoonahoo fidyatun ta'aamu miskeenin faman tatawwa'a khairan fahuwa khairulo lahoo wa an tasoomoo khairul lakum in kuntum ta'lamoon", english: "(Fasting) for a fixed number of days; but if any of you is ill, or on a journey, the prescribed number (Should be made up) from days later. For those who can do it (With hardship), is a ransom, the feeding of one that is indigent. But he that will give more, of his own free will,- it is better for him. And it is better for you that ye fast, if ye only knew", romanUrdu: "Chandh muqarrar dino ke roze hain, agar tum mein se koi bimaar ho, ya safar par ho to dusre dino mein utni hi tadaad poori karle aur jo log roza rakhne ki qudrat rakhte hon (phi na rakhein) to woh fidya dein, ek roze ka fidiya ek miskeen ko khana khilana hai aur jo apni khushi se kuch zyada bhalayi karey to yeh usi ke liye behtar hai, lekin agar tum samjho to tumhare haqq mein accha yahi hai ke roza rakkho" },
    { number: 185, arabic: "شَهْرُ رَمَضَانَ ٱلَّذِىٓ أُنزِلَ فِيهِ ٱلْقُرْءَانُ هُدًۭى لِّلنَّاسِ وَبَيِّنَٰتٍۢ مِّنَ ٱلْهُدَىٰ وَٱلْفُرْقَانِ ۚ فَمَن شَهِدَ مِنكُمُ ٱلشَّهْرَ فَلْيَصُمْهُ ۖ وَمَن كَانَ مَرِيضًا أَوْ عَلَىٰ سَفَرٍۢ فَعِدَّةٌۭ مِّنْ أَيَّامٍ أُخَرَ ۗ يُرِيدُ ٱللَّهُ بِكُمُ ٱلْيُسْرَ وَلَا يُرِيدُ بِكُمُ ٱلْعُسْرَ وَلِتُكْمِلُوا۟ ٱلْعِدَّةَ وَلِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ وَلَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Shahru ramadana allathee onzila feehi alquranu hudan lilnnasi wabayyinatin mina alhuda waalfurqani faman shahida minkumu alshshahra falyasumhu waman kana mareedan aw AAala safarin faAAiddatun min ayyamin okhara yureedu Allahu bikumu alyusra wala yureedu bikumu alAAusra walitukmiloo alAAiddata walitukabbiroo Allaha AAala ma hadakum walaAAallakum tashkuroona", transliterationB: "Shahru Ramadaanallazeee unzila feehil Qur'aanu hudal linnaasi wa baiyinaatim minal hudaa wal furqaan; faman shahida minkumush shahra falyasumhu wa man kaana mareedan aw 'alaa safarin fa'iddatum min ayyaamin ukhar; yureedul laahu bikumul yusra wa laa yureedu bikumul 'usra wa litukmilul 'iddata wa litukabbirul laaha 'alaa maa hadaakum wa la'allakum tashkuroon", english: "Ramadhan is the (month) in which was sent down the Qur'an, as a guide to mankind, also clear (Signs) for guidance and judgment (Between right and wrong). So every one of you who is present (at his home) during that month should spend it in fasting, but if any one is ill, or on a journey, the prescribed period (Should be made up) by days later. Allah intends every facility for you; He does not want to put to difficulties. (He wants you) to complete the prescribed period, and to glorify Him in that He has guided you; and perchance ye shall be grateful", romanUrdu: "Ramazan woh mahina hai jismein Quran nazil kiya gaya jo Insaano ke liye sarasar hidayat hai aur aisi wazey taleemaat par mushtamil hai jo raah e raast dikhane wali aur haqq o baatil ka farq khol kar rakh dene wali hai, lihaza ab se jo shaks is mahine ko paye usko lazim hai ke is poorey mahine ke roze rakkhey aur jo koi mareez ho ya safar par ho to woh dusre dino mein rozon ki tadaad poori karey. Allah tumhare saath narmi karna chahta hai, sakhti karna nahin chahta, isliye yeh tareeqa tumhein bataya jaa raha hai taa-ke tum rozon ki tadaad poori kar sako aur jis hidayat se Allah ne tumhein sarfaraz kiya hai uspar Allah ki kibriyayi ka izhar o aitraf karo aur shukarguzar bano" },
    { number: 186, arabic: "وَإِذَا سَأَلَكَ عِبَادِى عَنِّى فَإِنِّى قَرِيبٌ ۖ أُجِيبُ دَعْوَةَ ٱلدَّاعِ إِذَا دَعَانِ ۖ فَلْيَسْتَجِيبُوا۟ لِى وَلْيُؤْمِنُوا۟ بِى لَعَلَّهُمْ يَرْشُدُونَ", transliteration: "Waitha saalaka AAibadee AAannee fainnee qareebun ojeebu daAAwata alddaAAi itha daAAani falyastajeeboo lee walyuminoo bee laAAallahum yarshudoona", transliterationB: "Wa izaa sa alaka 'ibaadee 'annnee fa innee qareebun ujeebu da'wataddaa'i izaa da'aani falyastajeeboo lee walyu minoo beela 'allahum yarshudoon", english: "When My servants ask thee concerning Me, I am indeed close (to them): I listen to the prayer of every suppliant when he calleth on Me: Let them also, with a will, Listen to My call, and believe in Me: That they may walk in the right way", romanUrdu: "(Aur aey Nabi)! Mere bandey agar tumse mere mutaaliq puchein, to unhein bata do ke main unse kareeb hi hoon, pukaarne wala jab mujhey pukarta hai, mai uski pukaar sunta aur jawab deta hoon, lihaza unhein chahiye ke meri dawat par labbaik kahein aur mujhpar iman layein, yeh baat tum unhein suna do, shayad ke woh raah e raast paa lein" },
    { number: 187, arabic: "أُحِلَّ لَكُمْ لَيْلَةَ ٱلصِّيَامِ ٱلرَّفَثُ إِلَىٰ نِسَآئِكُمْ ۚ هُنَّ لِبَاسٌۭ لَّكُمْ وَأَنتُمْ لِبَاسٌۭ لَّهُنَّ ۗ عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنكُمْ ۖ فَٱلْـَٰٔنَ بَٰشِرُوهُنَّ وَٱبْتَغُوا۟ مَا كَتَبَ ٱللَّهُ لَكُمْ ۚ وَكُلُوا۟ وَٱشْرَبُوا۟ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلْخَيْطُ ٱلْأَبْيَضُ مِنَ ٱلْخَيْطِ ٱلْأَسْوَدِ مِنَ ٱلْفَجْرِ ۖ ثُمَّ أَتِمُّوا۟ ٱلصِّيَامَ إِلَى ٱلَّيْلِ ۚ وَلَا تُبَٰشِرُوهُنَّ وَأَنتُمْ عَٰكِفُونَ فِى ٱلْمَسَٰجِدِ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَقْرَبُوهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَّقُونَ", transliteration: "Ohilla lakum laylata alssiyami alrrafathu ila nisaikum hunna libasun lakum waantum libasun lahunna AAalima Allahu annakum kuntum takhtanoona anfusakum fataba AAalaykum waAAafa AAankum faalana bashiroohunna waibtaghoo ma kataba Allahu lakum wakuloo waishraboo hatta yatabayyana lakumu alkhaytu alabyadu mina alkhayti alaswadi mina alfajri thumma atimmoo alssiyama ila allayli wala tubashiroohunna waantum AAakifoona fee almasajidi tilka hudoodu Allahi fala taqrabooha kathalika yubayyinu Allahu ayatihi lilnnasi laAAallahum yattaqoona", transliterationB: "Uhilla lakum laylatas Siyaamir rafasu ilaa nisaaa'ikum; hunna libaasullakum wa antum libaasullahunn; 'alimal laahu annakum kuntum takhtaanoona anfusakum fataaba 'alaikum wa 'afaa 'ankum fal'aana baashiroo hunna wabtaghoo maa katabal laahoo lakum; wa kuloo washraboo hattaa yatabaiyana lakumul khaitul abyadu minal khaitil aswadi minal fajri summa atimmus Siyaama ilal layl; wa laa tubaashiroo hunna wa antum 'aakifoona fil masaajid; tilka hudoodul laahi falaa taqraboohaa; kazaalika yubaiyinul laahu aayaatihee linnaasi la'allahum yattaqoon", english: "Permitted to you, on the night of the fasts, is the approach to your wives. They are your garments and ye are their garments. Allah knoweth what ye used to do secretly among yourselves; but He turned to you and forgave you; so now associate with them, and seek what Allah Hath ordained for you, and eat and drink, until the white thread of dawn appear to you distinct from its black thread; then complete your fast Till the night appears; but do not associate with your wives while ye are in retreat in the mosques. Those are Limits (set by) Allah: Approach not nigh thereto. Thus doth Allah make clear His Signs to men: that they may learn self-restraint", romanUrdu: "Tumhare liye rozon ke zamane mein raaton ko apni biwiyon ke paas jana halal kardiya gaya hai, woh tumhare liye libas hain aur tum unke liye. Allah ko maloom ho gaya ke tumlog chupke chupke apne aap se khayanat kar rahey thay, magar usne tumhara kasoor maaf kardiya aur tumse darguzar farmaya , ab tum apni biwiyon ke saath shab-baashi (intercourse) karo aur jo lutf Allah ne tumhare liye jayiz kardiya hai, usey hasil karo, neiz raaton ko khao pio yahan tak ke tumko syahi e shab ki dhari se sapedha subh ki dhari numaya nazar aa jaye tab yeh sab kaam chodh kar raat tak apna roza poora karo aur jab tum masjid mein mautakif (itteqaf mein) hon to biwiyon se mubashrat na karo, yeh Allah ki bandhi hui haddein hain, inke kareeb ba phatakna, is tarah Allah apne ehkam logon ke liye ba-sarahat (clearly) bayan karta hai, tawaqqu hai ke woh galat rawiyye se bachenge" },
    { number: 188, arabic: "وَلَا تَأْكُلُوٓا۟ أَمْوَٰلَكُم بَيْنَكُم بِٱلْبَٰطِلِ وَتُدْلُوا۟ بِهَآ إِلَى ٱلْحُكَّامِ لِتَأْكُلُوا۟ فَرِيقًۭا مِّنْ أَمْوَٰلِ ٱلنَّاسِ بِٱلْإِثْمِ وَأَنتُمْ تَعْلَمُونَ", transliteration: "Wala takuloo amwalakum baynakum bialbatili watudloo biha ila alhukkami litakuloo fareeqan min amwali alnnasi bialithmi waantum taAAlamoona", transliterationB: "Wa laa taakuloo amwaalakum bainakum bilbaatili wa tudloo bihaaa ilal hukkaami litaakuloo fareeqam min amwaalin naasi bil ismi wa antum ta'lamoon", english: "And do not eat up your property among yourselves for vanities, nor use it as bait for the judges, with intent that ye may eat up wrongfully and knowingly a little of (other) people's property", romanUrdu: "Aur tum log na to aapas mein ek dusre ke maal narawa tareeqe se khao aur na hakeemo ke aagey inko is garz ke liye pesh karo ke tumhein dusron ke maal ka koi hissa qasdan zalimana tareeqe se khane ka mauqa mil jaye" },
    { number: 189, arabic: "۞ يَسْـَٔلُونَكَ عَنِ ٱلْأَهِلَّةِ ۖ قُلْ هِىَ مَوَٰقِيتُ لِلنَّاسِ وَٱلْحَجِّ ۗ وَلَيْسَ ٱلْبِرُّ بِأَن تَأْتُوا۟ ٱلْبُيُوتَ مِن ظُهُورِهَا وَلَٰكِنَّ ٱلْبِرَّ مَنِ ٱتَّقَىٰ ۗ وَأْتُوا۟ ٱلْبُيُوتَ مِنْ أَبْوَٰبِهَا ۚ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", transliteration: "Yasaloonaka AAani alahillati qul hiya mawaqeetu lilnnasi waalhajji walaysa albirru bian tatoo albuyoota min thuhooriha walakinna albirra mani ittaqa watoo albuyoota min abwabiha waittaqoo Allaha laAAallakum tuflihoona", transliterationB: "Yas'aloonaka 'anil ahillati qul hiya mawaaqeetu linnaasi wal Hajj; wa laisal birru bi an taatul buyoota min zuhoorihaa wa laakinnal birra manit taqaa; waatul buyoota min abwaa bihaa; wattaqullaaha la'allakum tuflihoon", english: "They ask thee concerning the New Moons. Say: They are but signs to mark fixed periods of time in (the affairs of) men, and for Pilgrimage. It is no virtue if ye enter your houses from the back: It is virtue if ye fear Allah. Enter houses through the proper doors: And fear Allah: That ye may prosper", romanUrdu: "Log tumse chand ki ghathti badhti suraton ke mutaaliq puchte hain, kaho : yeh logon ke liye taarekon ki taayin ki aur hajj ki alamatein hain. Neiz unsey kaho : yeh koi neki ka kaam nahin hai ke apne gharon mein pichey ki taraf daakhil hote ho, neki to asal mein yeh hai ke aadmi Allah ki naraazi se bachey, lihaza tum apne gharon mein darwaze hi se aaya karo, albatta Allah se darte raho shayad ke tumhein falaah naseeb ho jaye" },
    { number: 190, arabic: "وَقَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ ٱلَّذِينَ يُقَٰتِلُونَكُمْ وَلَا تَعْتَدُوٓا۟ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُعْتَدِينَ", transliteration: "Waqatiloo fee sabeeli Allahi allatheena yuqatiloonakum wala taAAtadoo inna Allaha la yuhibbu almuAAtadeena", transliterationB: "Wa qaatiloo fee sabeelillaahil lazeena yuqaatiloonakum wa laa ta'tadooo; innal laaha laa yuhibbul mu'tadeen", english: "Fight in the cause of Allah those who fight you, but do not transgress limits; for Allah loveth not transgressors", romanUrdu: "Aur tum Allah ki raah mein un logon se lado, jo tumse ladte hain, magar zyadati na karo ka Allah zyadati karne walon ko pasand nahin karta" },
    { number: 191, arabic: "وَٱقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ وَأَخْرِجُوهُم مِّنْ حَيْثُ أَخْرَجُوكُمْ ۚ وَٱلْفِتْنَةُ أَشَدُّ مِنَ ٱلْقَتْلِ ۚ وَلَا تُقَٰتِلُوهُمْ عِندَ ٱلْمَسْجِدِ ٱلْحَرَامِ حَتَّىٰ يُقَٰتِلُوكُمْ فِيهِ ۖ فَإِن قَٰتَلُوكُمْ فَٱقْتُلُوهُمْ ۗ كَذَٰلِكَ جَزَآءُ ٱلْكَٰفِرِينَ", transliteration: "Waoqtuloohum haythu thaqiftumoohum waakhrijoohum min haythu akhrajookum waalfitnatu ashaddu mina alqatli wala tuqatiloohum AAinda almasjidi alharami hatta yuqatilookum feehi fain qatalookum faoqtuloohum kathalika jazao alkafireena", transliterationB: "Waqtuloohum haisu saqif tumoohum wa akhrijoohum min haisu akhrajookum; walfitnatu ashaddu minal qatl; wa laa tuqaatiloohum 'indal Majidil Haraami hattaa yaqaatilookum feehi fa in qaatalookum faqtuloohum; kazaalika jazaaa'ul kaafireen", english: "And slay them wherever ye catch them, and turn them out from where they have Turned you out; for tumult and oppression are worse than slaughter; but fight them not at the Sacred Mosque, unless they (first) fight you there; but if they fight you, slay them. Such is the reward of those who suppress faith", romanUrdu: "Unse lado jahan bhi tumhara unse muqabla pesh aaye aur unhein nikalo jahan se unhon ne tumko nikala hai, isliye ke qatal agarche bura hai, magar fitna issey bhi zyada bura hai aur masjid e haraam ke kareeb jab tak woh tumse na ladein tum bhi na lado, magar jab woh wahan ladne se na chukein, to tum bhi be-takalluf unhein maro ke aise kafrion ki yahi saza hai" },
    { number: 192, arabic: "فَإِنِ ٱنتَهَوْا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Faini intahaw fainna Allaha ghafoorun raheemun", transliterationB: "Fa ini-ntahaw fa innal laaha Ghafoorur Raheem", english: "But if they cease, Allah is Oft-forgiving, Most Merciful", romanUrdu: "Phir agar woh baaz aa jayein, to jaan lo ke Allah maaf karne wala aur reham farmane wala hai" },
    { number: 193, arabic: "وَقَٰتِلُوهُمْ حَتَّىٰ لَا تَكُونَ فِتْنَةٌۭ وَيَكُونَ ٱلدِّينُ لِلَّهِ ۖ فَإِنِ ٱنتَهَوْا۟ فَلَا عُدْوَٰنَ إِلَّا عَلَى ٱلظَّٰلِمِينَ", transliteration: "Waqatiloohum hatta la takoona fitnatun wayakoona alddeenu lillahi faini intahaw fala AAudwana illa AAala alththalimeena", transliterationB: "Wa qaatiloohum hatta laa takoona fitnatunw wa yakoonad deenu lillaahi fa-inin tahaw falaa 'udwaana illaa 'alaz zaalimeen", english: "And fight them on until there is no more Tumult or oppression, and there prevail justice and faith in Allah; but if they cease, Let there be no hostility except to those who practise oppression", romanUrdu: "Tum unse ladte raho yahan tak ke fitna baki na rahey aur deen Allah ke liye hojaye, phir agar woh baaz aa jayein, to samajh lo ke zalimon ke siwa aur kisi par dast-darazi rawa nahin" },
    { number: 194, arabic: "ٱلشَّهْرُ ٱلْحَرَامُ بِٱلشَّهْرِ ٱلْحَرَامِ وَٱلْحُرُمَٰتُ قِصَاصٌۭ ۚ فَمَنِ ٱعْتَدَىٰ عَلَيْكُمْ فَٱعْتَدُوا۟ عَلَيْهِ بِمِثْلِ مَا ٱعْتَدَىٰ عَلَيْكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَعَ ٱلْمُتَّقِينَ", transliteration: "Alshshahru alharamu bialshshahri alharami waalhurumatu qisasun famani iAAtada AAalaykum faiAAtadoo AAalayhi bimithli ma iAAtada AAalaykum waittaqoo Allaha waiAAlamoo anna Allaha maAAa almuttaqeena", transliterationB: "Ash Shahrul Haraamu bish Shahril Haraami wal hurumaatu qisaas; famani'tadaa 'alaikum fa'tadoo 'alaihi bimsisli ma'tadaa 'alaikum; wattaqul laaha wa'lamooo annal laaha ma'al muttaqeen", english: "The prohibited month for the prohibited month,- and so for all things prohibited,- there is the law of equality. If then any one transgresses the prohibition against you, Transgress ye likewise against him. But fear Allah, and know that Allah is with those who restrain themselves", romanUrdu: "Maah e haraam ka badla haraam hi hai aur tamaam hurmaton ka lihaz barabari ke saath hoga, lihaza jo tumpar dast darazi karey, tum bhi usi tarah uspar dast darazi karo, albatta Allah se darte raho aur yeh jaan rakkho ke Allah unhi logon ke saath hai jo uski hudood todne se paheiz karte hain" },
    { number: 195, arabic: "وَأَنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلَا تُلْقُوا۟ بِأَيْدِيكُمْ إِلَى ٱلتَّهْلُكَةِ ۛ وَأَحْسِنُوٓا۟ ۛ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُحْسِنِينَ", transliteration: "Waanfiqoo fee sabeeli Allahi wala tulqoo biaydeekum ila alttahlukati waahsinoo inna Allaha yuhibbu almuhsineena", transliterationB: "Wa anfiqoo fee sabeelil laahi wa laa tulqoo bi aydeekum ilat tahlukati wa ahsinoo; innal laaha yuhibbul muhsineen", english: "And spend of your substance in the cause of Allah, and make not your own hands contribute to (your) destruction; but do good; for Allah loveth those who do good", romanUrdu: "Allah ki raah mein kharch karo aur apne haathon apne aap ko halakat mein na daalo, ehsan ka tareeqa ikhtiyar karo ke Allah mohsino ko pasand karta hai" },
    { number: 196, arabic: "وَأَتِمُّوا۟ ٱلْحَجَّ وَٱلْعُمْرَةَ لِلَّهِ ۚ فَإِنْ أُحْصِرْتُمْ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۖ وَلَا تَحْلِقُوا۟ رُءُوسَكُمْ حَتَّىٰ يَبْلُغَ ٱلْهَدْىُ مَحِلَّهُۥ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ بِهِۦٓ أَذًۭى مِّن رَّأْسِهِۦ فَفِدْيَةٌۭ مِّن صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍۢ ۚ فَإِذَآ أَمِنتُمْ فَمَن تَمَتَّعَ بِٱلْعُمْرَةِ إِلَى ٱلْحَجِّ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۚ فَمَن لَّمْ يَجِدْ فَصِيَامُ ثَلَٰثَةِ أَيَّامٍۢ فِى ٱلْحَجِّ وَسَبْعَةٍ إِذَا رَجَعْتُمْ ۗ تِلْكَ عَشَرَةٌۭ كَامِلَةٌۭ ۗ ذَٰلِكَ لِمَن لَّمْ يَكُنْ أَهْلُهُۥ حَاضِرِى ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ", transliteration: "Waatimmoo alhajja waalAAumrata lillahi fain ohsirtum fama istaysara mina alhadyi wala tahliqoo ruoosakum hatta yablugha alhadyu mahillahu faman kana minkum mareedan aw bihi athan min rasihi fafidyatun min siyamin aw sadaqatin aw nusukin faitha amintum faman tamattaAAa bialAAumrati ila alhajji fama istaysara mina alhadyi faman lam yajid fasiyamu thalathati ayyamin fee alhajji wasabAAatin itha rajaAAtum tilka AAasharatun kamilatun thalika liman lam yakun ahluhu hadiree almasjidi alharami waittaqoo Allaha waiAAlamoo anna Allaha shadeedu alAAiqabi", transliterationB: "Wa atimmul Hajja wal Umarata lillaah; fain uhsirtum famas taisara minal hadyi walaa tahliqoo ru'oosakum hatta yablughal hadyu mahillah; faman kaana minkum mareedan aw biheee azam mir raasihee fafidyatum min Siyaamin aw sadaqatin aw nusuk; fa izaaa amintum faman tamatta'a bil 'Umrati ilal Hajji famastaisara minal hady; famal lam yajid fa Siyaamu salaasti ayyaamin fil Hajji wa sab'atin izaa raja'tum; tilka 'asharatun kaamilah; zaalika limal lam yakun ahluhoo haadiril Masjidil Haraam; wattaqul laaha wa'lamoo annal laaha shadeedul'iqaab", english: "And complete the Hajj or 'umra in the service of Allah. But if ye are prevented (From completing it), send an offering for sacrifice, such as ye may find, and do not shave your heads until the offering reaches the place of sacrifice. And if any of you is ill, or has an ailment in his scalp, (Necessitating shaving), (He should) in compensation either fast, or feed the poor, or offer sacrifice; and when ye are in peaceful conditions (again), if any one wishes to continue the 'umra on to the hajj, He must make an offering, such as he can afford, but if he cannot afford it, He should fast three days during the hajj and seven days on his return, Making ten days in all. This is for those whose household is not in (the precincts of) the Sacred Mosque. And fear Allah, and know that Allah Is strict in punishment", romanUrdu: "Allah ki khushnudi ke liye jab hajj aur umra ki niyat karo to usey poora karo aur agar kahin ghir jao (detained/prevented) to jo qurbani muyassar aaye Allah ki janaab mein pesh karo aur apne sarr na mundo(shave) jabtak ke qurbani apni jagah na pahunch jaye, magar jo shaks mareez ho ya jiske sarr mein koi takleef ho aur is bina par apna sar mundwa le to usey chahiye ke fidiye ke taur par roze rakkhey ya sadaqa de ya qurbani karey, phir agar tumhein aman naseeb ho jaye (aur tum hajj se pehle Makkah pahunch jao), to jo shaks tum mein se hajj ka zamana aane tak umra ka faiyda uthaye woh hasb-e-maqdoor (can afford) qurbani dey,aur agar qurbani muyassar na ho to teen roze hajj ke zamane mein aur saat ghar pahunch kar, is tarah poorey dus roze rakhle, yeh riayat un logon ke liye hai jinke ghar baar masjid e haraam ke kareeb na hon. Allah ke in ehkam ki khilaf-warzi se bacho aur khoob jaan lo ke Allah sakht saza dene wala hai" },
    { number: 197, arabic: "ٱلْحَجُّ أَشْهُرٌۭ مَّعْلُومَٰتٌۭ ۚ فَمَن فَرَضَ فِيهِنَّ ٱلْحَجَّ فَلَا رَفَثَ وَلَا فُسُوقَ وَلَا جِدَالَ فِى ٱلْحَجِّ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍۢ يَعْلَمْهُ ٱللَّهُ ۗ وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ وَٱتَّقُونِ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ", transliteration: "Alhajju ashhurun maAAloomatun faman farada feehinna alhajja fala rafatha wala fusooqa wala jidala fee alhajji wama tafAAaloo min khayrin yaAAlamhu Allahu watazawwadoo fainna khayra alzzadi alttaqwa waittaqooni ya olee alalbabi", transliterationB: "Al-Hajju ashhurum ma'-loomaat; faman farada feeinnal hajja falaa rafasa wa laa fusooqa wa laa jidaala fil Hajj; wa maa taf'aloo min khairiny ya'lamhul laah; wa tazawwadoo fa inna khairaz zaadit taqwaa; wattaqooni yaaa ulil albaab", english: "For Hajj are the months well known. If any one undertakes that duty therein, Let there be no obscenity, nor wickedness, nor wrangling in the Hajj. And whatever good ye do, (be sure) Allah knoweth it. And take a provision (With you) for the journey, but the best of provisions is right conduct. So fear Me, o ye that are wise", romanUrdu: "Hajj ke mahine sabko maloom hain , jo shaks in muqakkar mahino mein hajj ki niyat karey, usey khabardaar rehna chahiye ke hajj ke dauran mein ussey koi shehwani fail (sexual indulgence) , koi badh amali, koi ladayi jhagde ki baat sarzad na ho aur jo neik kaam tum karoge woh Allah ke ilm mein hoga. Safar e hajj ke liye zaad e raah (provisions) saath le jao, aur sabse behtar zaad e raah(provisions) parheizgaari hai, pas aey hosh-mandon! Meri nafarmani se parheiz karo" },
    { number: 198, arabic: "لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَبْتَغُوا۟ فَضْلًۭا مِّن رَّبِّكُمْ ۚ فَإِذَآ أَفَضْتُم مِّنْ عَرَفَٰتٍۢ فَٱذْكُرُوا۟ ٱللَّهَ عِندَ ٱلْمَشْعَرِ ٱلْحَرَامِ ۖ وَٱذْكُرُوهُ كَمَا هَدَىٰكُمْ وَإِن كُنتُم مِّن قَبْلِهِۦ لَمِنَ ٱلضَّآلِّينَ", transliteration: "Laysa AAalaykum junahun an tabtaghoo fadlan min rabbikum faitha afadtum min AAarafatin faothkuroo Allaha AAinda almashAAari alharami waothkuroohu kama hadakum wain kuntum min qablihi lamina alddalleena", transliterationB: "Laisa 'alaikum junaahun an tabtaghoo fad lam mir rabbikum; fa izaaa afadtum min 'Arafaatin fazkurul laaha 'indal-Mash'aril Haraami waz kuroohu kamaa hadaakum wa in kuntum min qablihee laminad daaaleen", english: "It is no crime in you if ye seek of the bounty of your Lord (during pilgrimage). Then when ye pour down from (Mount) Arafat, celebrate the praises of Allah at the Sacred Monument, and celebrate His praises as He has directed you, even though, before this, ye went astray", romanUrdu: "Aur agar hajj ke saath saath tum apne Rubb ka fazal (bounty) bhi talash karte jao to ismein koi muzahiqa nahin, phir jab arafat se chalo to mashhare haraam (muzdalifa) ke paas thehar kar Allah ko yaad karo aur us tarah yaad karo, jiski hidayat usne tumhein di hai, warna issey pehle tumlog bhatke huey thay" },
    { number: 199, arabic: "ثُمَّ أَفِيضُوا۟ مِنْ حَيْثُ أَفَاضَ ٱلنَّاسُ وَٱسْتَغْفِرُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Thumma afeedoo min haythu afada alnnasu waistaghfiroo Allaha inna Allaha ghafoorun raheemun", transliterationB: "Summa afeedoo min haisu afaadan naasu wastagh firullaah; innnal laaha Ghafoo rur-Raheem", english: "Then pass on at a quick pace from the place whence it is usual for the multitude so to do, and ask for Allah's forgiveness. For Allah is Oft-forgiving, Most Merciful", romanUrdu: "Phir jahan se aur sab log palat-te hain wahin se tum bhi palato aur Allah se maafi chaho, yaqeenan woh maaf karne wala aur reham farmane wala hai" },
    { number: 200, arabic: "فَإِذَا قَضَيْتُم مَّنَٰسِكَكُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًۭا ۗ فَمِنَ ٱلنَّاسِ مَن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا وَمَا لَهُۥ فِى ٱلْءَاخِرَةِ مِنْ خَلَٰقٍۢ", transliteration: "Faitha qadaytum manasikakum faothkuroo Allaha kathikrikum abaakum aw ashadda thikran famina alnnasi man yaqoolu rabbana atina fee alddunya wama lahu fee alakhirati min khalaqin", transliterationB: "Fa-izan qadaitum manaa sikakum fazkurul laaha kazikrikum aabaaa'akum aw ashadda zikraa; faminannaasi mai yaqoolu Rabbanaaa aatinaa fiddunyaa wa maa lahoo fil Aakhirati min khalaaq", english: "So when ye have accomplished your holy rites, celebrate the praises of Allah, as ye used to celebrate the praises of your fathers,- yea, with far more Heart and soul. There are men who say: \"Our Lord! Give us (Thy bounties) in this world!\" but they will have no portion in the Hereafter", romanUrdu: "Phir jab apne hajj ke arkan ada kar chuko, to jis tarah pehle apne abaa o ajdad ka zikr karte thay, usi tarah ab Allah ka zikr karo, balke ussey bhi badkar (magar Allah ko yaad karne waley logon mein bhi bahut farq hai) un mein se koi to aisa hai, jo kehta hai ke aey hamare Rubb humein duniya hi mein sabkuch de de, aisey shaks ke liye aakhirat mein koi hissa nahin" },
    { number: 201, arabic: "وَمِنْهُم مَّن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا حَسَنَةًۭ وَفِى ٱلْءَاخِرَةِ حَسَنَةًۭ وَقِنَا عَذَابَ ٱلنَّارِ", transliteration: "Waminhum man yaqoolu rabbana atina fee alddunya hasanatan wafee alakhirati hasanatan waqina AAathaba alnnari", transliterationB: "Wa minhum mai yaqoolu rabbanaaa aatina fid dunyaa hasanatawn wa fil aakhirati hasanatanw wa qinaa azaaban Naar", english: "And there are men who say: \"Our Lord! Give us good in this world and good in the Hereafter, and defend us from the torment of the Fire", romanUrdu: "Aur koi kehta hai ke aey hamare Rubb! Humein duniya mein bhalayi de aur aakhirat mein bhi bhalayi , aur aag ke azaab se humein bacha" },
    { number: 202, arabic: "أُو۟لَٰٓئِكَ لَهُمْ نَصِيبٌۭ مِّمَّا كَسَبُوا۟ ۚ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ", transliteration: "Olaika lahum naseebun mimma kasaboo waAllahu sareeAAu alhisabi", transliterationB: "Ulaaa'ika lahum naseebum mimmaa kasaboo; wal laahu saree'ul hisaab", english: "To these will be allotted what they have earned; and Allah is quick in account", romanUrdu: "Aisey log apni kamayi ke mutabiq (dono jagah) hissa payenge aur Allah ko hisaab chukate kuch dair nahin lagti" },
    { number: 203, arabic: "۞ وَٱذْكُرُوا۟ ٱللَّهَ فِىٓ أَيَّامٍۢ مَّعْدُودَٰتٍۢ ۚ فَمَن تَعَجَّلَ فِى يَوْمَيْنِ فَلَآ إِثْمَ عَلَيْهِ وَمَن تَأَخَّرَ فَلَآ إِثْمَ عَلَيْهِ ۚ لِمَنِ ٱتَّقَىٰ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُمْ إِلَيْهِ تُحْشَرُونَ", transliteration: "Waothkuroo Allaha fee ayyamin maAAdoodatin faman taAAajjala fee yawmayni fala ithma AAalayhi waman taakhkhara fala ithma AAalayhi limani ittaqa waittaqoo Allaha waiAAlamoo annakum ilayhi tuhsharoona", transliterationB: "Wazkurul laaha feee ayyaamim ma'doodaat; faman ta'ajjala fee yawmaini falaaa ismaa 'alaihi wa man taakhkhara falaaa isma 'alayh; limanit-taqaa; wattaqul laaha wa'lamooo annakum ilaihi tuhsharoon", english: "Celebrate the praises of Allah during the Appointed Days. But if any one hastens to leave in two days, there is no blame on him, and if any one stays on, there is no blame on him, if his aim is to do right. Then fear Allah, and know that ye will surely be gathered unto Him", romanUrdu: "Yeh ginti ke chandh roz hain, jo tumhein Allah ki yaad mein basar karne chahiye, phir jo koi jaldi karke do hi din mein wapas hogaya to koi harj nahin, aur jo kuch dair zyada thehar kar palta to bhi koi harj nahin bashart yeh din usne taqwa ke saath basar kiye ho. Allah ki nafarmani se bacho aur khoob jaan rakkho ke ek roz uske huzoor mein tumhari peshi honay wali hai" },
    { number: 204, arabic: "وَمِنَ ٱلنَّاسِ مَن يُعْجِبُكَ قَوْلُهُۥ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيُشْهِدُ ٱللَّهَ عَلَىٰ مَا فِى قَلْبِهِۦ وَهُوَ أَلَدُّ ٱلْخِصَامِ", transliteration: "Wamina alnnasi man yuAAjibuka qawluhu fee alhayati alddunya wayushhidu Allaha AAala ma fee qalbihi wahuwa aladdu alkhisami", transliterationB: "Wa minan naasi mai yu'jibuka qawluhoo fil hayaatid dunyaa wa yushhidul laaha 'alaa maa fee qalbihee wa huwa aladdulkhisaam", english: "There is the type of man whose speech about this world's life May dazzle thee, and he calls Allah to witness about what is in his heart; yet is he the most contentious of enemies", romanUrdu: "Insaano mein koi to aisa hai jiski baatein duniya ki zindagi mein tumhein bahut bhali maloom hoti hai, aur apni neik niyati par woh baar baar khuda ko gawah thehrata hai, magar haqeeqat mein woh badhtareen dushman e haqq hota hai" },
    { number: 205, arabic: "وَإِذَا تَوَلَّىٰ سَعَىٰ فِى ٱلْأَرْضِ لِيُفْسِدَ فِيهَا وَيُهْلِكَ ٱلْحَرْثَ وَٱلنَّسْلَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلْفَسَادَ", transliteration: "Waitha tawalla saAAa fee alardi liyufsida feeha wayuhlika alhartha waalnnasla waAllahu la yuhibbu alfasada", transliterationB: "Wa izaa tawallaa sa'aa fil ardi liyufsida feeha wa yuhlikal harsa wannasl; wallaahu laa yuhibbul fasaad", english: "When he turns his back, His aim everywhere is to spread mischief through the earth and destroy crops and cattle. But Allah loveth not mischief", romanUrdu: "Jab usey iqtedar hasil ho jata hai, to zameen mein uski saari daud dhoop isliye hoti hai ke fasaad phailaye, kheton ko gaarat karey aur nasal e Insaani ko tabaah karey , halaanke Allah (jisey woh gawah bana raha tha) fasaad ko hargiz pasand nahin karta" },
    { number: 206, arabic: "وَإِذَا قِيلَ لَهُ ٱتَّقِ ٱللَّهَ أَخَذَتْهُ ٱلْعِزَّةُ بِٱلْإِثْمِ ۚ فَحَسْبُهُۥ جَهَنَّمُ ۚ وَلَبِئْسَ ٱلْمِهَادُ", transliteration: "Waitha qeela lahu ittaqi Allaha akhathathu alAAizzatu bialithmi fahasbuhu jahannamu walabisa almihadu", transliterationB: "Wa izaa qeela lahuttaqil laaha akhazathul izzatu bil-ism; fahasbuhoo jahannam; wa labi'sal mihaad", english: "When it is said to him, \"Fear Allah\", He is led by arrogance to (more) crime. Enough for him is Hell;-An evil bed indeed (To lie on)", romanUrdu: "Aur jab ussey kaha jata hai ke Allah se darr, to apne waqar ka khayal usko gunaah par jamaa deta hai, aisey shaks ke liye to bas jahannum hi kafi hai aur woh bahut bura thikana hai" },
    { number: 207, arabic: "وَمِنَ ٱلنَّاسِ مَن يَشْرِى نَفْسَهُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ", transliteration: "Wamina alnnasi man yashree nafsahu ibtighaa mardati Allahi waAllahu raoofun bialAAibadi", transliterationB: "Wa minan naasi mai yashree nafsahub tighaaa'a mardaatil laah; wallaahu ra'oofum bil'ibaad", english: "And there is the type of man who gives his life to earn the pleasure of Allah: And Allah is full of kindness to (His) devotees", romanUrdu: "Dusri taraf Insaano hi mein koi aisa bhi hai jo raza e ilahi ki talab mein apni jaan khapa deta hai aur aisey bandon par Allah bahut meharbaan hai" },
    { number: 208, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱدْخُلُوا۟ فِى ٱلسِّلْمِ كَآفَّةًۭ وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ", transliteration: "Ya ayyuha allatheena amanoo odkhuloo fee alssilmi kaffatan wala tattabiAAoo khutuwati alshshaytani innahu lakum AAaduwwun mubeenun", transliterationB: "Yaaa ayyuhal lazeena aamanud khuloo fis silmi kaaaffatanw wa laa tattabi'oo khutuwaatish Shaitaan; innahoo lakum 'aduwwum mubeen", english: "O ye who believe! Enter into Islam whole-heartedly; and follow not the footsteps of the evil one; for he is to you an avowed enemy", romanUrdu: "Aey iman laney walon! Tum poorey ke poorey Islam mein aa jao aur shaytan ki pairwi na karo ke woh tumhara khula dushman hai" },
    { number: 209, arabic: "فَإِن زَلَلْتُم مِّنۢ بَعْدِ مَا جَآءَتْكُمُ ٱلْبَيِّنَٰتُ فَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ", transliteration: "Fain zalaltum min baAAdi ma jaatkumu albayyinatu faiAAlamoo anna Allaha AAazeezun hakeemun", transliterationB: "Fa in zalaltum mimba'di maa jaaa'atkumul baiyinaatu fa'lamoo annallaaha 'Azeezun hakeem", english: "If ye backslide after the clear (Signs) have come to you, then know that Allah is Exalted in Power, Wise", romanUrdu: "Jo saaf saaf hidayaat tumhare paas aa chuki hai agar unko paa lene ke baad phir tumne lagzish khayi, to khoob jaan rakkho ke Allah sab par gaalib aur hakeem o dana hai" },
    { number: 210, arabic: "هَلْ يَنظُرُونَ إِلَّآ أَن يَأْتِيَهُمُ ٱللَّهُ فِى ظُلَلٍۢ مِّنَ ٱلْغَمَامِ وَٱلْمَلَٰٓئِكَةُ وَقُضِىَ ٱلْأَمْرُ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", transliteration: "Hal yanthuroona illa an yatiyahumu Allahu fee thulalin mina alghamami waalmalaikatu waqudiya alamru waila Allahi turjaAAu alomooru", transliterationB: "Hal yanzuroona illaaa ai yaatiyahumul laahu fee zulalim minal ghamaami walmalaaa'ikatu wa qudiyal amr; wa ilal laahi turja'ulumoor", english: "Will they wait until Allah comes to them in canopies of clouds, with angels (in His train) and the question is (thus) settled? but to Allah do all questions go back (for decision)", romanUrdu: "(In saari naseehaton aur hidayaton ke baad bhi log seedhe na hon to) kya ab woh iske muntazir hain ke Allah baadalon ka chatar lagay farishton ke parey saath(canopies of clouds with a retinue of angels) liye khud saamne aa maujood ho aur faisla hi kar dala jaye? Aakhir e kaar saare maamlaat pesh to Allah hi ke huzoor honay waley hain" },
    { number: 211, arabic: "سَلْ بَنِىٓ إِسْرَٰٓءِيلَ كَمْ ءَاتَيْنَٰهُم مِّنْ ءَايَةٍۭ بَيِّنَةٍۢ ۗ وَمَن يُبَدِّلْ نِعْمَةَ ٱللَّهِ مِنۢ بَعْدِ مَا جَآءَتْهُ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ", transliteration: "Sal banee israeela kam ataynahum min ayatin bayyinatin waman yubaddil niAAmata Allahi min baAAdi ma jaathu fainna Allaha shadeedu alAAiqabi", transliterationB: "Sal Banee Israaa'eela kam aatainaahum min aayatim baiyinah; wa mai yubaddil ni'matal laahi mim ba'di maa jaaa'athu fa innallaaha shadeedul'iqaab", english: "Ask the Children of Israel how many clear (Signs) We have sent them. But if any one, after Allah's favour has come to him, substitutes (something else), Allah is strict in punishment", romanUrdu: "Bani Israel se pucho: kaisi khuli khuli nishaniyan humne unhein dikhayi hain (aur phir yeh bhi unhin se puch lo ke) Allah ki niyamat paney ke baad jo qaum isko shiqawat (wretchdness) se badalti hai usey Allah kaisi sakht saza deta hai" },
    { number: 212, arabic: "زُيِّنَ لِلَّذِينَ كَفَرُوا۟ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَيَسْخَرُونَ مِنَ ٱلَّذِينَ ءَامَنُوا۟ ۘ وَٱلَّذِينَ ٱتَّقَوْا۟ فَوْقَهُمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍۢ", transliteration: "Zuyyina lillatheena kafaroo alhayatu alddunya wayaskharoona mina allatheena amanoo waallatheena ittaqaw fawqahum yawma alqiyamati waAllahu yarzuqu man yashao bighayri hisabin", transliterationB: "Zuyyina lillazeena kafarul hayaatud dunyaa wa yaskharoona minal lazeena aamanoo; wallazeenat taqaw fawqahum yawmal Qiyaamah; wallaahu yarzuqu mai yashaaa'u bighairi hisaab", english: "The life of this world is alluring to those who reject faith, and they scoff at those who believe. But the righteous will be above them on the Day of Resurrection; for Allah bestows His abundance without measure on whom He will", romanUrdu: "Jin logon ne kufr ki raah ikhtiyar ki hai unke liye duniya ki zindagi badi mehboob o dil pasand bana di gayi hai, aisey log iman ki raah ikhtiyar karne walon ka mazaq udhate hain, magar qayamat ke roz parheizgaar log hi unke muqable mein aali muqaam honge, raha duniya ka rizq, to Allah ko ikhtiyar hai jisey chahe be-hisaab de" },
    { number: 213, arabic: "كَانَ ٱلنَّاسُ أُمَّةًۭ وَٰحِدَةًۭ فَبَعَثَ ٱللَّهُ ٱلنَّبِيِّۦنَ مُبَشِّرِينَ وَمُنذِرِينَ وَأَنزَلَ مَعَهُمُ ٱلْكِتَٰبَ بِٱلْحَقِّ لِيَحْكُمَ بَيْنَ ٱلنَّاسِ فِيمَا ٱخْتَلَفُوا۟ فِيهِ ۚ وَمَا ٱخْتَلَفَ فِيهِ إِلَّا ٱلَّذِينَ أُوتُوهُ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَٰتُ بَغْيًۢا بَيْنَهُمْ ۖ فَهَدَى ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ لِمَا ٱخْتَلَفُوا۟ فِيهِ مِنَ ٱلْحَقِّ بِإِذْنِهِۦ ۗ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍ", transliteration: "Kana alnnasu ommatan wahidatan fabaAAatha Allahu alnnabiyyeena mubashshireena wamunthireena waanzala maAAahumu alkitaba bialhaqqi liyahkuma bayna alnnasi feema ikhtalafoo feehi wama ikhtalafa feehi illa allatheena ootoohu min baAAdi ma jaathumu albayyinatu baghyan baynahum fahada Allahu allatheena amanoo lima ikhtalafoo feehi mina alhaqqi biithnihi waAllahu yahdee man yashao ila siratin mustaqeemin", transliterationB: "Kaanan naasu ummatanw waahidatan fab'asal laahun Nabiyyeena mubashshireena wa munzireena wa anzala ma'ahumul kitaaba bilhaqqi liyahkuma bainan naasi feemakh talafoo feeh; wa makh talafa feehi 'illallazeena ootoohu mim ba'di maa jaaa'athumul baiyinaatu baghyam bainahm fahadal laahul lazeena aamanoo limakh talafoo feehi minal haqqi bi iznih; wallaahu yahdee mai yashaaa'u ilaa Siraatim Mustaqeem", english: "Mankind was one single nation, and Allah sent Messengers with glad tidings and warnings; and with them He sent the Book in truth, to judge between people in matters wherein they differed; but the People of the Book, after the clear Signs came to them, did not differ among themselves, except through selfish contumacy. Allah by His Grace Guided the believers to the Truth, concerning that wherein they differed. For Allah guided whom He will to a path that is straight", romanUrdu: "Ibtida mein sab log ek hi tareeqe par thay (phir yeh haalat baqi na rahi aur ikhtilafaat runuma huey) tab Allah ne Nabi bheje jo raast rawi par basharat dene waley aur kajhrawi ke nataij se darane waley thay, aur unke saath kitab e bar haqq nazil ki taa-ke haqq ke barey mein logon ke darmiyan jo ikhtilafaat runuma ho gaye thay unka faisla karey. (Aur in ikhtilafaat ke runuma honay ki wajah yeh na thi ke ibtidaa mein logon ko haqq bataya nahin gaya tha, nahin) ikhtilaf un logon ne kiya jinhein haqq ka ilm diya (ja) chuka tha, unhon ne roshan hidayaat paa lene ke baad mehaz isliye haqq ko chodh kar mukhtalif tareeqe nikale ke woh aapas mein zyadati karna chahte thay, pas jo log ambiya par iman le aaye unhein Allah ne apne izan se us haqq ka raasta dikha diya jismein logon ne ikhtilaf kiya tha, Allah jisey chahta hai raah e raast dikha deta hai" },
    { number: 214, arabic: "أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَأْتِكُم مَّثَلُ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُم ۖ مَّسَّتْهُمُ ٱلْبَأْسَآءُ وَٱلضَّرَّآءُ وَزُلْزِلُوا۟ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ مَتَىٰ نَصْرُ ٱللَّهِ ۗ أَلَآ إِنَّ نَصْرَ ٱللَّهِ قَرِيبٌۭ", transliteration: "Am hasibtum an tadkhuloo aljannata walamma yatikum mathalu allatheena khalaw min qablikum massathumu albasao waalddarrao wazulziloo hatta yaqoola alrrasoolu waallatheena amanoo maAAahu mata nasru Allahi ala inna nasra Allahi qareebun", transliterationB: "Am hasibtum an tadkhulul jannata wa lammaa yaa-tikum masalul lazeena khalaw min qablikum massathumul baasaaa'u waddarraaaa'u wa zulziloo hattaa yaqoolar Rasoolu wallazeena aamanoo ma'ahoo mataa nasrul laah; alaaa inna nasral laahiqareeb", english: "Or do ye think that ye shall enter the Garden (of bliss) without such (trials) as came to those who passed away before you? they encountered suffering and adversity, and were so shaken in spirit that even the Messenger and those of faith who were with him cried: \"When (will come) the help of Allah?\" Ah! Verily, the help of Allah is (always) near", romanUrdu: "Phir kya tum logon ne yeh samajh rakkha hai ke yunhi jannat ka daakhila tumhein mil jayega, halaanke abhi tumpar woh sab kuch nahin guzra hai jo tumse pehle iman laney walon par guzar chuka hai? Unpar sakhtiyan guzri, museebatein aayi, hila maarey gaye, hatta ke waqt ka Rasool aur uske saathi ehle iman cheekh utthey ke Allah ki madad kab aayegi, us waqt unhein tasalli di gayi ke haan Allah ki madad qareeb hai" },
    { number: 215, arabic: "يَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ ۖ قُلْ مَآ أَنفَقْتُم مِّنْ خَيْرٍۢ فَلِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَٱبْنِ ٱلسَّبِيلِ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌۭ", transliteration: "Yasaloonaka matha yunfiqoona qul ma anfaqtum min khayrin falilwalidayni waalaqrabeena waalyatama waalmasakeeni waibni alssabeeli wama tafAAaloo min khayrin fainna Allaha bihi AAaleemun", transliterationB: "Yas'aloonaka maazaa yunfiqoona qul maaa anfaqtum min khairin falil waalidaini wal aqrabeena walyataamaa wal masaakeeni wabnis sabeel; wa maa taf'aloo min khairin fa innal laaha bihee 'Aleem", english: "They ask thee what they should spend (In charity). Say: Whatever ye spend that is good, is for parents and kindred and orphans and those in want and for wayfarers. And whatever ye do that is good, -Allah knoweth it well", romanUrdu: "Log puchte hain ke hum kya kharch karein? Jawab do ke jo maal bhi tum kharch karo apne walidain par, rishtedaaron par, yateemo aur miskeeno aur musafiron par kharch karo aur jo bhalayi bhi tum karoge, Allah ussey ba-khabar hoga" },
    { number: 216, arabic: "كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ وَهُوَ كُرْهٌۭ لَّكُمْ ۖ وَعَسَىٰٓ أَن تَكْرَهُوا۟ شَيْـًۭٔا وَهُوَ خَيْرٌۭ لَّكُمْ ۖ وَعَسَىٰٓ أَن تُحِبُّوا۟ شَيْـًۭٔا وَهُوَ شَرٌّۭ لَّكُمْ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", transliteration: "Kutiba AAalaykumu alqitalu wahuwa kurhun lakum waAAasa an takrahoo shayan wahuwa khayrun lakum waAAasa an tuhibboo shayan wahuwa sharrun lakum waAllahu yaAAlamu waantum la taAAlamoona", transliterationB: "Kutiba alaikumulqitaalu wa huwa kurhullakum wa 'asaaa an takrahoo shai'anw wa huwa khairullakum wa 'asaaa an tuhibbo shai'anw wa huwa sharrullakum; wallaahu ya'lamu wa antum laa ta'lamoon", english: "Fighting is prescribed for you, and ye dislike it. But it is possible that ye dislike a thing which is good for you, and that ye love a thing which is bad for you. But Allah knoweth, and ye know not", romanUrdu: "Tumhein jung ka hukm diya gaya hai aur woh tumhein na-gawar hai, ho sakta hai ke ek cheez tumhein na-gawar ho aur wahi tumhare liye behtar ho aur ho sakta hai ke ek cheez tumhein pasand ho aur wahi tumhare liye buri ho.Allah jaanta hai, tum nahin jaante" },
    { number: 217, arabic: "يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ قِتَالٍۢ فِيهِ ۖ قُلْ قِتَالٌۭ فِيهِ كَبِيرٌۭ ۖ وَصَدٌّ عَن سَبِيلِ ٱللَّهِ وَكُفْرٌۢ بِهِۦ وَٱلْمَسْجِدِ ٱلْحَرَامِ وَإِخْرَاجُ أَهْلِهِۦ مِنْهُ أَكْبَرُ عِندَ ٱللَّهِ ۚ وَٱلْفِتْنَةُ أَكْبَرُ مِنَ ٱلْقَتْلِ ۗ وَلَا يَزَالُونَ يُقَٰتِلُونَكُمْ حَتَّىٰ يَرُدُّوكُمْ عَن دِينِكُمْ إِنِ ٱسْتَطَٰعُوا۟ ۚ وَمَن يَرْتَدِدْ مِنكُمْ عَن دِينِهِۦ فَيَمُتْ وَهُوَ كَافِرٌۭ فَأُو۟لَٰٓئِكَ حَبِطَتْ أَعْمَٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۖ وَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Yasaloonaka AAani alshshahri alharami qitalin feehi qul qitalun feehi kabeerun wasaddun AAan sabeeli Allahi wakufrun bihi waalmasjidi alharami waikhraju ahlihi minhu akbaru AAinda Allahi waalfitnatu akbaru mina alqatli wala yazaloona yuqatiloonakum hatta yaruddookum AAan deenikum ini istataAAoo waman yartadid minkum AAan deenihi fayamut wahuwa kafirun faolaika habitat aAAmaluhum fee alddunya waalakhirati waolaika ashabu alnnari hum feeha khalidoona", transliterationB: "Yas'aloonaka 'anish Shahril Haraami qitaalin feehi qul qitaahun feehi kabeerunw wa saddun 'an sabeelil laahi wa kufrum bihee wal Masjidil Haraami wa ikhraaju ahlihee minhu akbaru 'indal laah; walfitnatu akbaru minal qatl; wa laa yazaaloona yuqaatiloonakum hatta yaruddookum 'an deenikum inis tataa'oo; wa mai yartadid minkum 'an deenihee fayamut wahuwa kaafirun fa ulaaa'ika habitat a'maaluhum fid dunyaa wal aakhirati wa ulaaa'ika ashaabun Naari hum feehaa khaalidoon", english: "They ask thee concerning fighting in the Prohibited Month. Say: \"Fighting therein is a grave (offence); but graver is it in the sight of Allah to prevent access to the path of Allah, to deny Him, to prevent access to the Sacred Mosque, and drive out its members.\" Tumult and oppression are worse than slaughter. Nor will they cease fighting you until they turn you back from your faith if they can. And if any of you Turn back from their faith and die in unbelief, their works will bear no fruit in this life and in the Hereafter; they will be companions of the Fire and will abide therein", romanUrdu: "Log puchte hain maah e haraam mein ladna kaisa hai? Kaho: ismein ladna bahut bura hai, magar raah e khuda se logon ko roakna aur Allah se kufr karna aur masjid e haram ka raasta khuda paraston par bandh karna aur haram ke rehne walon ko wahan se nikalna Allah ke nazdeek issey bhi zyada bura hai aur fitna khoon-rezi se shadeed-tar hai. Woh to tumse ladey hi jayenge hatta ke agar unka bas chale to tumhein is deen se pher le jayein (aur yeh khoob samajhlo ke) tum mein se jo koi is deen se phirega aur kufr ki haalat mein jaan dega, uske aamaal duniya aur aakhirat dono mein zaya ho jayenge, aisey sab log jahannumi hain aur hamesha jahannum hi mein rahenge" },
    { number: 218, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَاجَرُوا۟ وَجَٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ أُو۟لَٰٓئِكَ يَرْجُونَ رَحْمَتَ ٱللَّهِ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Inna allatheena amanoo waallatheena hajaroo wajahadoo fee sabeeli Allahi olaika yarjoona rahmata Allahi waAllahu ghafoorun raheemun", transliterationB: "Innal lazeena aamanoo wallazeena haajaroo wa jaahadoo fee sabeelil laahi ulaaaika yarjoona rahmatal laah; wallaahu Ghafoorur Raheem", english: "Those who believed and those who suffered exile and fought (and strove and struggled) in the path of Allah,- they have the hope of the Mercy of Allah: And Allah is Oft-forgiving, Most Merciful", romanUrdu: "Ba-khilaf iske jo log iman laye hain aur jinhon ne khuda ki raah mein apna ghar baar choda aur jihad kiya hai, woh rehmat e ilahi ke jayiz umeedwaar hain aur Allah unki lagzishon ko maaf karne wala aur apni rehmat se unhein nawazne wala hai" },
    { number: 219, arabic: "۞ يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ قُلْ فِيهِمَآ إِثْمٌۭ كَبِيرٌۭ وَمَنَٰفِعُ لِلنَّاسِ وَإِثْمُهُمَآ أَكْبَرُ مِن نَّفْعِهِمَا ۗ وَيَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ قُلِ ٱلْعَفْوَ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ", transliteration: "Yasaloonaka AAani alkhamri waalmaysiri qul feehima ithmun kabeerun wamanafiAAu lilnnasi waithmuhuma akbaru min nafAAihima wayasaloonaka matha yunfiqoona quli alAAafwa kathalika yubayyinu Allahu lakumu alayati laAAallakum tatafakkaroona", transliterationB: "Yas'aloonaka 'anilkhamri walmaisiri qul feehimaaa ismun kabeerunw wa manaafi'u linnaasi wa ismuhumaa akbaru min naf'ihimaa; wa yas'aloonaka maaza yunfiqoona qulil-'afw; kazaalika yubaiyinul laahu lakumul-aayaati la'allakum tatafakkaroon", english: "They ask thee concerning wine and gambling. Say: \"In them is great sin, and some profit, for men; but the sin is greater than the profit.\" They ask thee how much they are to spend; Say: \"What is beyond your needs.\" Thus doth Allah Make clear to you His Signs: In order that ye may consider", romanUrdu: "Puchte hain : sharab aur juwey (gambling) ka kya hukum hai? Kaho: in dono cheezon mein badi kharabi hai agarchey inmein logon ke liye kuch munafey bhi hai, magar unka gunaah unke faiyde se bahut zyada hai. Puchte hain: hum raah e khuda mein kya kharch karein? Kaho: jo kuch tumhari zaroorat se zyada ho, is tarah Allah tumhare liye saaf saaf ehkaam bayaan karta hai, shayad ke tum duniya aur aakhirat dono ki fikr karo" },
    { number: 220, arabic: "فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۗ وَيَسْـَٔلُونَكَ عَنِ ٱلْيَتَٰمَىٰ ۖ قُلْ إِصْلَاحٌۭ لَّهُمْ خَيْرٌۭ ۖ وَإِن تُخَالِطُوهُمْ فَإِخْوَٰنُكُمْ ۚ وَٱللَّهُ يَعْلَمُ ٱلْمُفْسِدَ مِنَ ٱلْمُصْلِحِ ۚ وَلَوْ شَآءَ ٱللَّهُ لَأَعْنَتَكُمْ ۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ", transliteration: "Fee alddunya waalakhirati wayasaloonaka AAani alyatama qul islahun lahum khayrun wain tukhalitoohum faikhwanukum waAllahu yaAAlamu almufsida mina almuslihi walaw shaa Allahu laaAAnatakum inna Allaha AAazeezun hakeemun", transliterationB: "Fid dunyaa wal aakhirah; wa yas'aloonaka 'anil yataamaa qul islaahullahum khayr, wa in tukhaalitoohum fa ikhwaanukum; wallaahu ya'lamul mufsida minalmuslih; wa law shaaa'al laahu la-a'natakum; innal laaha 'Azeezun Hakeem", english: "(Their bearings) on this life and the Hereafter. They ask thee concerning orphans. Say: \"The best thing to do is what is for their good; if ye mix their affairs with yours, they are your brethren; but Allah knows the man who means mischief from the man who means good. And if Allah had wished, He could have put you into difficulties: He is indeed Exalted in Power, Wise", romanUrdu: "Puchte hain : yateemon ke saath kya maamla kiya jaye? Kaho: jis tarz e amal mein unke liye bhalayi ho wahi ikhtiyar karna behtar hai. Agar tum apna aur unka kharch aur rehna sehna mushtarik (mix) rakkho to ismein koi muzahiqa nahin, aakhir woh tumhare bhai bandh hi to hain. Burayi karne waley aur bhalayi karne waley dono ka haal Allah par roshan hai, Allah chahta to is maamle mein tumpar sakhti karta, magar woh sahib e ikhtiyar honay ke saath sahib e hikmat bhi hai" },
    { number: 221, arabic: "وَلَا تَنكِحُوا۟ ٱلْمُشْرِكَٰتِ حَتَّىٰ يُؤْمِنَّ ۚ وَلَأَمَةٌۭ مُّؤْمِنَةٌ خَيْرٌۭ مِّن مُّشْرِكَةٍۢ وَلَوْ أَعْجَبَتْكُمْ ۗ وَلَا تُنكِحُوا۟ ٱلْمُشْرِكِينَ حَتَّىٰ يُؤْمِنُوا۟ ۚ وَلَعَبْدٌۭ مُّؤْمِنٌ خَيْرٌۭ مِّن مُّشْرِكٍۢ وَلَوْ أَعْجَبَكُمْ ۗ أُو۟لَٰٓئِكَ يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَٱللَّهُ يَدْعُوٓا۟ إِلَى ٱلْجَنَّةِ وَٱلْمَغْفِرَةِ بِإِذْنِهِۦ ۖ وَيُبَيِّنُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَ", transliteration: "Wala tankihoo almushrikati hatta yuminna walaamatun muminatun khayrun min mushrikatin walaw aAAjabatkum wala tunkihoo almushrikeena hatta yuminoo walaAAabdun muminun khayrun min mushrikin walaw aAAjabakum olaika yadAAoona ila alnnari waAllahu yadAAoo ila aljannati waalmaghfirati biithnihi wayubayyinu ayatihi lilnnasi laAAallahum yatathakkaroona", transliterationB: "Wa laatankihul mushrikaati hattaa yu'minn; wa la amatum mu'minatun khairum mim mushrikatinw wa law a'jabatkum; wa laa tunkihul mushrikeena hattaa yu'minoo; wa la'abdummu'minun khairum mimmushrikinw wa law 'ajabakum; ulaaa'ika yad'oona ilan Naari wallaahu yad'ooo ilal Jannati walmaghfirati biiznihee wa yubaiyinu Aayaatihee linnaasi la'allahum yatazakkaroon", english: "Do not marry unbelieving women (idolaters), until they believe: A slave woman who believes is better than an unbelieving woman, even though she allures you. Nor marry (your girls) to unbelievers until they believe: A man slave who believes is better than an unbeliever, even though he allures you. Unbelievers do (but) beckon you to the Fire. But Allah beckons by His Grace to the Garden (of bliss) and forgiveness, and makes His Signs clear to mankind: That they may celebrate His praise", romanUrdu: "Tum mushrik auraton se hargiz nikah na karna jab tak ke woh iman na le aayein, ek momin laundi (slave) mushrik sharif-zaadi se behtar hai agarche woh tumhein bahut pasand ho, aur apni auraton ke nikah mushrik mardon se kabhi na karna jab tak ke woh iman na le aayein. Ek momin ghulam mushrik sharif se behtar hai agarche woh tumhein bahut pasand ho. Yeh log tumhein aag ki taraf bulate hain aur Allah apne izan se tumko jannat aur magfirat ki taraf bulata hai, aur woh apne ehkaam wazey taur par logon ke saamne bayan karta hai, tawaqqu hai ke woh sabaq lenge aur naseehat qabool karenge" },
    { number: 222, arabic: "وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًۭى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ وَلَا تَقْرَبُوهُنَّ حَتَّىٰ يَطْهُرْنَ ۖ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمُ ٱللَّهُ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلتَّوَّٰبِينَ وَيُحِبُّ ٱلْمُتَطَهِّرِينَ", transliteration: "Wayasaloonaka AAani almaheedi qul huwa athan faiAAtaziloo alnnisaa fee almaheedi wala taqraboohunna hatta yathurna faitha tatahharna fatoohunna min haythu amarakumu Allahu inna Allaha yuhibbu alttawwabeena wayuhibbu almutatahhireena", transliterationB: "Wa yas'aloonaka 'anil maheedi qul huwa azan fa'tazilun nisaaa'a fil maheedi wa laa taqraboo hunna hattaa yathurna fa-izaa tathharna faatoohunna min haisu amarakumul laah; innallaaha yuhibbut Tawwaabeena wa yuhibbul mutatahhireen", english: "They ask thee concerning women's courses. Say: They are a hurt and a pollution: So keep away from women in their courses, and do not approach them until they are clean. But when they have purified themselves, ye may approach them in any manner, time, or place ordained for you by Allah. For Allah loves those who turn to Him constantly and He loves those who keep themselves pure and clean", romanUrdu: "Puchte hain: haiz ka kya hukm hai? Kaho: woh ek gandagi ki haalat hai, ismein auraton se alag raho aur unke kareeb na jao, jab tak ke woh paak saaf na ho jayein, phir jab woh paak ho jayein to unke paas jao us tarah jaisa ke Allah ne tumko hukum diya hai, Allah un logon ko pasand karta hai jo badhi (gunaah) se baaz rahein aur pakeezgi ikhtiyar karein" },
    { number: 223, arabic: "نِسَآؤُكُمْ حَرْثٌۭ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ وَقَدِّمُوا۟ لِأَنفُسِكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُم مُّلَٰقُوهُ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ", transliteration: "Nisaokum harthun lakum fatoo harthakum anna shitum waqaddimoo lianfusikum waittaqoo Allaha waiAAlamoo annakum mulaqoohu wabashshiri almumineena", transliterationB: "Nisaaa'ukum harsullakum faatoo harsakum annaa shi'tum wa qaddimoo li anfusikum; wattaqul laaha wa'lamooo annakum mulaaqooh; wa bash shirilmu 'mineen", english: "Your wives are as a tilth unto you; so approach your tilth when or how ye will; but do some good act for your souls beforehand; and fear Allah. And know that ye are to meet Him (in the Hereafter), and give (these) good tidings to those who believe", romanUrdu: "Tumhari auratein tumhari khetiyan hain, tumhein ikhtiyar hai jis tarah chaho apni kheti mein jao, magar apne mustaqbil ki fikr karo aur Allah ki narazi se bacho. Khoob jaan lo ke tumhein ek din ussey milna hai. Aur (aey Nabi)! Jo tumhari hidayaat ko maan lein unhein falaah o saadat ka musda (khushkhabri) suna do" },
    { number: 224, arabic: "وَلَا تَجْعَلُوا۟ ٱللَّهَ عُرْضَةًۭ لِّأَيْمَٰنِكُمْ أَن تَبَرُّوا۟ وَتَتَّقُوا۟ وَتُصْلِحُوا۟ بَيْنَ ٱلنَّاسِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ", transliteration: "Wala tajAAaloo Allaha AAurdatan liaymanikum an tabarroo watattaqoo watuslihoo bayna alnnasi waAllahu sameeAAun AAaleemun", transliterationB: "Wa laa taj'alul laaha 'urdatal li aymaanikum an tabarroo wa tattaqoo wa tuslihoo bainan naas; wallaahu Samee'un 'Aleem", english: "And make not Allah's (name) an excuse in your oaths against doing good, or acting rightly, or making peace between persons; for Allah is One Who heareth and knoweth all things", romanUrdu: "Allah ke naam ko aisi kasamein khane ke liye istemal na karo jinse maqsood neki aur taqwa aur bandagaan e khuda ki bhalayi ke kaamon se baaz rehna ho. Allah tumhari sari baatein sun raha hai aur sabkuch jaanta hai" },
    { number: 225, arabic: "لَّا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغْوِ فِىٓ أَيْمَٰنِكُمْ وَلَٰكِن يُؤَاخِذُكُم بِمَا كَسَبَتْ قُلُوبُكُمْ ۗ وَٱللَّهُ غَفُورٌ حَلِيمٌۭ", transliteration: "La yuakhithukumu Allahu biallaghwi fee aymanikum walakin yuakhithukum bima kasabat quloobukum waAllahu ghafoorun haleemun", transliterationB: "Laa yu'aakhi zukumul laahu billaghwi feee aymaa nikum wa laakiny yu'aakhi zukum bimaa kasabat quloo bukum; wallaahu Ghafoorun Haleem", english: "Allah will not call you to account for thoughtlessness in your oaths, but for the intention in your hearts; and He is Oft-forgiving, Most Forbearing", romanUrdu: "Jo be-maani kasamein tum bila irada kha liya karte ho unpar Allah giraft nahin karta, magar jo kasamein tum sachhey dil se khate ho unki baazpurs woh zaroor karega. Allah bahut darguzar karne wala aur burdbaar (Forbearing) hai" },
    { number: 226, arabic: "لِّلَّذِينَ يُؤْلُونَ مِن نِّسَآئِهِمْ تَرَبُّصُ أَرْبَعَةِ أَشْهُرٍۢ ۖ فَإِن فَآءُو فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Lillatheena yuloona min nisaihim tarabbusu arbaAAati ashhurin fain faoo fainna Allaha ghafoorun raheemun", transliterationB: "Lillazeena yu'loona min nisaaa'ihim tarabbusu arba'ati ashhurin fain faaa'oo fa innal laaha Ghafoorur Raheem", english: "For those who take an oath for abstention from their wives, a waiting for four months is ordained; if then they return, Allah is Oft-forgiving, Most Merciful", romanUrdu: "Jo log apni auraton se taaluq na rakhne ki kasam kha baithey hain unke liye char mahine ki mohlat hai, agar unhon ne rujoo karliya to Allah maaf karne wala aur Raheem hai" },
    { number: 227, arabic: "وَإِنْ عَزَمُوا۟ ٱلطَّلَٰقَ فَإِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", transliteration: "Wain AAazamoo alttalaqa fainna Allaha sameeAAun AAaleemun", transliterationB: "Wa in 'azamut talaaqa fa innal laaha Samee'un 'Aleem", english: "But if their intention is firm for divorce, Allah heareth and knoweth all things", romanUrdu: "Aur agar unhon ne talaq hi ki thaan li ho to jaane rahein ke Allah sabkuch sunta aur jaanta hai" },
    { number: 228, arabic: "وَٱلْمُطَلَّقَٰتُ يَتَرَبَّصْنَ بِأَنفُسِهِنَّ ثَلَٰثَةَ قُرُوٓءٍۢ ۚ وَلَا يَحِلُّ لَهُنَّ أَن يَكْتُمْنَ مَا خَلَقَ ٱللَّهُ فِىٓ أَرْحَامِهِنَّ إِن كُنَّ يُؤْمِنَّ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۚ وَبُعُولَتُهُنَّ أَحَقُّ بِرَدِّهِنَّ فِى ذَٰلِكَ إِنْ أَرَادُوٓا۟ إِصْلَٰحًۭا ۚ وَلَهُنَّ مِثْلُ ٱلَّذِى عَلَيْهِنَّ بِٱلْمَعْرُوفِ ۚ وَلِلرِّجَالِ عَلَيْهِنَّ دَرَجَةٌۭ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ", transliteration: "Waalmutallaqatu yatarabbasna bianfusihinna thalathata qurooin wala yahillu lahunna an yaktumna ma khalaqa Allahu fee arhamihinna in kunna yuminna biAllahi waalyawmi alakhiri wabuAAoolatuhunna ahaqqu biraddihinna fee thalika in aradoo islahan walahunna mithlu allathee AAalayhinna bialmaAAroofi walilrrijali AAalayhinna darajatun waAllahu AAazeezun hakeemun", transliterationB: "Walmutallaqaatu yatarab basna bi anfusihinna salaasata qurooo'; wa laa yahillu lahunna ai yaktumna maa khalaqal laahu feee arhaaminhinna in kunna yu'minna billaahi wal yawmil aakhir; wa bu'oola tuhunna ahaqqu biraddihinna fee zaalika in araadooo islaahaa; wa lahunna mislul lazee 'araihinna bilma'roof; wa lirrijjaali 'alaihinna daraja; wallaahu 'Azeezun Hakeem", english: "Divorced women shall wait concerning themselves for three monthly periods. Nor is it lawful for them to hide what Allah Hath created in their wombs, if they have faith in Allah and the Last Day. And their husbands have the better right to take them back in that period, if they wish for reconciliation. And women shall have rights similar to the rights against them, according to what is equitable; but men have a degree (of advantage) over them. And Allah is Exalted in Power, Wise", romanUrdu: "Jin auraton ko talaq di gayi ho woh teen martaba ayaam e mahwari aane tak apne aap ko rokey rakkhein aur unke liye yeh jayiz nahin hai ke Allah ne unke reham (womb) mein jo kuch khalq (paida) farmaya ho usey chupayein. Unhein hargiz aisa na karna chahiye agar woh Allah aur roz e aakhir par iman rakhti hain. Unke shohar taaluqaat durust karlene par aamada hon to woh is iddat ke dauraan mein unhein phir apni zawjiyat mein wapas le lene ke haqdaar hain. Auraton ke liye bhi maroof tareeqe par waise hi huqooq hain jaise Mardon ke huqooq unpar hain. Albatta Mardon ko unpar ek darja hasil hai aur sab par Allah gaalib iqtedar rakhne wala aur hakeem o dana maujood hai" },
    { number: 229, arabic: "ٱلطَّلَٰقُ مَرَّتَانِ ۖ فَإِمْسَاكٌۢ بِمَعْرُوفٍ أَوْ تَسْرِيحٌۢ بِإِحْسَٰنٍۢ ۗ وَلَا يَحِلُّ لَكُمْ أَن تَأْخُذُوا۟ مِمَّآ ءَاتَيْتُمُوهُنَّ شَيْـًٔا إِلَّآ أَن يَخَافَآ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ ۖ فَإِنْ خِفْتُمْ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ فَلَا جُنَاحَ عَلَيْهِمَا فِيمَا ٱفْتَدَتْ بِهِۦ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَعْتَدُوهَا ۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ", transliteration: "Alttalaqu marratani faimsakun bimaAAroofin aw tasreehun biihsanin wala yahillu lakum an takhuthoo mimma ataytumoohunna shayan illa an yakhafa alla yuqeema hudooda Allahi fain khiftum alla yuqeema hudooda Allahi fala junaha AAalayhima feema iftadat bihi tilka hudoodu Allahi fala taAAtadooha waman yataAAadda hudooda Allahi faolaika humu alththalimoona", transliterationB: "Attalaaqu marrataani fa imsaakum bima'roofin aw tasreehum bi ihsaan; wa laa yahillu lakum an taakhuzoo mimmaaa aataitumoohunna shai'an illaaa ai yakhaafaaa alla yuqeemaa hudoodallahi fa in khiftum allaa yuqeemaa budoodal laahi falaa junaaha 'Alaihimaa feemaf tadat bihee tilka hudoodul laahi falaa ta'tadoohaa; wa mai yata'adda hudoodal laahi fa ulaaa'ika humuzzaa limoon", english: "A divorce is only permissible twice: after that, the parties should either hold Together on equitable terms, or separate with kindness. It is not lawful for you, (Men), to take back any of your gifts (from your wives), except when both parties fear that they would be unable to keep the limits ordained by Allah. If ye (judges) do indeed fear that they would be unable to keep the limits ordained by Allah, there is no blame on either of them if she give something for her freedom. These are the limits ordained by Allah; so do not transgress them if any do transgress the limits ordained by Allah, such persons wrong (Themselves as well as others)", romanUrdu: "Talaq do baar hai, phir ya to seedhi tarah aurat ko rok liya jaye ya bhale tareeqe se usko rukhsat kardiya jaye, aur rukhsat karte huey aisa karna tumhare liye jayiz nahin hai ke jo kuch tum unhein de chuke ho, usmein se kuch wapas lelo, albatta yeh surat mustasna hai ke zawjain ko Allah ke hudood par qayam na reh sakne ka andesha ho, aisi surat mein agar tumhein yeh khauf ho ke woh dono hudood e ilahi par qayam na rahenge, to un dono ke darmiyan yeh maamla ho janey mein muzahiqa nahin ke aurat apne shohar ko kuch muawaza dekar alaidagi (seperation) hasil karle, yeh Allah ke muqarrar karda huddod hain, inse tajawuz na karo, aur jo log hudood e ilahi se tajawuz karein wahi zalim hain" },
    { number: 230, arabic: "فَإِن طَلَّقَهَا فَلَا تَحِلُّ لَهُۥ مِنۢ بَعْدُ حَتَّىٰ تَنكِحَ زَوْجًا غَيْرَهُۥ ۗ فَإِن طَلَّقَهَا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يَتَرَاجَعَآ إِن ظَنَّآ أَن يُقِيمَا حُدُودَ ٱللَّهِ ۗ وَتِلْكَ حُدُودُ ٱللَّهِ يُبَيِّنُهَا لِقَوْمٍۢ يَعْلَمُونَ", transliteration: "Fain tallaqaha fala tahillu lahu min baAAdu hatta tankiha zawjan ghayrahu fain tallaqaha fala junaha AAalayhima an yatarajaAAa in thanna an yuqeema hudooda Allahi watilka hudoodu Allahi yubayyinuha liqawmin yaAAlamoona", transliterationB: "Fa in tallaqahaa falaa tahillu lahoo mim ba'du hattaa tankiha zawjan ghairah; fa in tallaqahaa falaa junaaha 'alaihimaaa ai yataraaja'aaa in zannaaa ai yuqeemaa hudoodal laa; wa tilka hudoodul laahi yubaiyinuhaa liqawminy ya'lamoon", english: "So if a husband divorces his wife (irrevocably), He cannot, after that, re-marry her until after she has married another husband and He has divorced her. In that case there is no blame on either of them if they re-unite, provided they feel that they can keep the limits ordained by Allah. Such are the limits ordained by Allah, which He makes plain to those who understand", romanUrdu: "Phir agar (do baar talaq dene ke baad shohar ne aurat ko teesri baar) talaq de di to woh aurat phir uske liye halal na hogi, illa yeh ke uska Nikah kisi dusre shaks se ho aur woh usey talaq dede, tab agar pehla shohar aur yeh aurat dono yeh khayal karein ke hudood e ilahi par qayam rahenge, to unke liye ek dusre ki taraf rujoo karlene mein koi muzahiqa nahin. Yeh Allah ki muqarrar karda hadein hain jinhein woh un logon ki hidayat ke liye wazey kar raha hai jo (uski hudood ko todne ka anjaam) jaante hain" },
    { number: 231, arabic: "وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ سَرِّحُوهُنَّ بِمَعْرُوفٍۢ ۚ وَلَا تُمْسِكُوهُنَّ ضِرَارًۭا لِّتَعْتَدُوا۟ ۚ وَمَن يَفْعَلْ ذَٰلِكَ فَقَدْ ظَلَمَ نَفْسَهُۥ ۚ وَلَا تَتَّخِذُوٓا۟ ءَايَٰتِ ٱللَّهِ هُزُوًۭا ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ وَمَآ أَنزَلَ عَلَيْكُم مِّنَ ٱلْكِتَٰبِ وَٱلْحِكْمَةِ يَعِظُكُم بِهِۦ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Waitha tallaqtumu alnnisaa fabalaghna ajalahunna faamsikoohunna bimaAAroofin aw sarrihoohunna bimaAAroofin wala tumsikoohunna diraran litaAAtadoo waman yafAAal thalika faqad thalama nafsahu wala tattakhithoo ayati Allahi huzuwan waothkuroo niAAmata Allahi AAalaykum wama anzala AAalaykum mina alkitabi waalhikmati yaAAithukum bihi waittaqoo Allaha waiAAlamoo anna Allaha bikulli shayin AAaleemun", transliterationB: "Wa izaa tallaqtumun nisaaa'a fabalaghna ajala hunna fa amsikoohunna bima'roofin law sarrihoo hunna bima'roof; wa laa tumsikoo hunna diraa rallita'tadoo; wa mai yaf'al zaalika faqad zalama nafsah; wa laa tattakhizooo aayaatillaahi huzuwaa; wazkuroo ni'matal laahi 'alaikum wa maaa anzala 'alaikum minal kitaabi wal ikmati ya'izukum bih; wattaqul laaha wa'lamooo annal laaha bikulli shai'i 'Aleem", english: "When ye divorce women, and they fulfil the term of their ('Iddat), either take them back on equitable terms or set them free on equitable terms; but do not take them back to injure them, (or) to take undue advantage; if any one does that; He wrongs his own soul. Do not treat Allah's Signs as a jest, but solemnly rehearse Allah's favours on you, and the fact that He sent down to you the Book and Wisdom, for your instruction. And fear Allah, and know that Allah is well acquainted with all things", romanUrdu: "Aur jab tum auraton ko talaq dedo aur unki iddat poori honay ko aa jaye, to ya bhale tareeqe se unhein rok lo ya bhale tareeqe se rukhsat kardo, mehaz satane ki khatir unhein na rokey rakhna, yeh zyadati hogi, aur jo aisa karega woh dar haqeeqat aap apne hi upar zulm karega. Allah ki ayaat ka khel na banao, bhool na jao ke Allah ne kis niyamat e uzma se tumhein sarfaraz kiya hai, woh tumhein naseehat karta hai ke jo kitab aur hikmat usne tumpar nazil ki hai, uska ehtaram malhooz rakkho. Allah se daro aur khoob jaan lo ke Allah ko har baat ki khabar hai" },
    { number: 232, arabic: "وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ أَن يَنكِحْنَ أَزْوَٰجَهُنَّ إِذَا تَرَٰضَوْا۟ بَيْنَهُم بِٱلْمَعْرُوفِ ۗ ذَٰلِكَ يُوعَظُ بِهِۦ مَن كَانَ مِنكُمْ يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۗ ذَٰلِكُمْ أَزْكَىٰ لَكُمْ وَأَطْهَرُ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", transliteration: "Waitha tallaqtumu alnnisaa fabalaghna ajalahunna fala taAAduloohunna an yankihna azwajahunna itha taradaw baynahum bialmaAAroofi thalika yooAAathu bihi man kana minkum yuminu biAllahi waalyawmi alakhiri thalikum azka lakum waatharu waAllahu yaAAlamu waantum la taAAlamoona", transliterationB: "Wa izaa tallaqtumun nisaaa'a fabalaghna ajalahunna falaa ta'duloo hunna ai yankihna azwaaja humna izaa taraadaw bainahum bilma' roof; zaalika yoo'azu bihee man kaana minkum yu'minu billaahi wal yawmil aakhir; zaalikum azkaa lakum wa athar; wallaahu ya'lamu wa antum laa ta'lamu wa antum laa ta'lamoon", english: "When ye divorce women, and they fulfil the term of their ('Iddat), do not prevent them from marrying their (former) husbands, if they mutually agree on equitable terms. This instruction is for all amongst you, who believe in Allah and the Last Day. That is (the course Making for) most virtue and purity amongst you and Allah knows, and ye know not", romanUrdu: "Jab tum apni auraton ko talaq de chuko aur woh apni iddat poori karlein, to phir ismein maney na ho ke woh apne zerey tajweej shoharon se nikah karlein, jab ke woh maroof tareeqe se baham munakihat (marriage) par raazi hon. Tumhein naseehat ki jati hai ke aisi harakat hargiz na karna agar tum Allah aur roz e aakhir par iman laney wale ho, tumhare liye shaishta aur pakeeza tareeqa yahi hai ke issey baaz raho. Allah jaanta hai, tum nahin jaante" },
    { number: 233, arabic: "۞ وَٱلْوَٰلِدَٰتُ يُرْضِعْنَ أَوْلَٰدَهُنَّ حَوْلَيْنِ كَامِلَيْنِ ۖ لِمَنْ أَرَادَ أَن يُتِمَّ ٱلرَّضَاعَةَ ۚ وَعَلَى ٱلْمَوْلُودِ لَهُۥ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِٱلْمَعْرُوفِ ۚ لَا تُكَلَّفُ نَفْسٌ إِلَّا وُسْعَهَا ۚ لَا تُضَآرَّ وَٰلِدَةٌۢ بِوَلَدِهَا وَلَا مَوْلُودٌۭ لَّهُۥ بِوَلَدِهِۦ ۚ وَعَلَى ٱلْوَارِثِ مِثْلُ ذَٰلِكَ ۗ فَإِنْ أَرَادَا فِصَالًا عَن تَرَاضٍۢ مِّنْهُمَا وَتَشَاوُرٍۢ فَلَا جُنَاحَ عَلَيْهِمَا ۗ وَإِنْ أَرَدتُّمْ أَن تَسْتَرْضِعُوٓا۟ أَوْلَٰدَكُمْ فَلَا جُنَاحَ عَلَيْكُمْ إِذَا سَلَّمْتُم مَّآ ءَاتَيْتُم بِٱلْمَعْرُوفِ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Waalwalidatu yurdiAAna awladahunna hawlayni kamilayni liman arada an yutimma alrradaAAata waAAala almawloodi lahu rizquhunna wakiswatuhunna bialmaAAroofi la tukallafu nafsun illa wusAAaha la tudarra walidatun biwaladiha wala mawloodun lahu biwaladihi waAAala alwarithi mithlu thalika fain arada fisalan AAan taradin minhuma watashawurin fala junaha AAalayhima wain aradtum an tastardiAAoo awladakum fala junaha AAalaykum itha sallamtum ma ataytum bialmaAAroofi waittaqoo Allaha waiAAlamoo anna Allaha bima taAAmaloona baseerun", transliterationB: "Walwaa lidaatu yurdi'na awlaada hunna hawlaini kaamilaini liman araada ai yutimmar radaa'ah; wa 'alalmawloodi lahoo rizuhunna wa kiswatuhunna bilma'roof; laatukallafu nafsun illaa wus'ahaa; laa tudaaarra waalidatum biwaladihaa wa laa mawloodul lahoo biwaladih; wa 'alal waarisi mislu zaalik; fa in araadaa Fisaalan 'an taraadim minhumaa wa tashaawurin falaa junaaha 'alaimaa; wa in arattum an tastardi'ooo awlaadakum falaa junaaha 'alaikum izaa sallamtum maaa aataitum bilma'roof; wattaqul laaha wa'lamooo annal laaha bimaa ta'maloona baseer", english: "The mothers shall give such to their offspring for two whole years, if the father desires to complete the term. But he shall bear the cost of their food and clothing on equitable terms. No soul shall have a burden laid on it greater than it can bear. No mother shall be Treated unfairly on account of her child. Nor father on account of his child, an heir shall be chargeable in the same way. If they both decide on weaning, by mutual consent, and after due consultation, there is no blame on them. If ye decide on a foster-mother for your offspring, there is no blame on you, provided ye pay (the mother) what ye offered, on equitable terms. But fear Allah and know that Allah sees well what ye do", romanUrdu: "Jo baap chahte hon ke unki aulad poori muddat e razaat tak doodh piye, to Maaein (mothers) apne bacchon ko kamil do saal doodh pilayein. Is surat mein bacchey ke baap ko maroof tareeqe se unhein khana, kapda dena hoga. Magar kisi par uski wusat se badhkar baar na daalna chahiye, na to Maa ko is wajah se takleef mein dala jaye ke baccha uska hai, aur na baap hi ko is wajah se tangg kiya jaye ke baccha uska hai. Doodh pilane wali ka yeh haqq jaisa bacchey ke baap par hai waisa hi uske waris par bhi hai , lekin agar fareeqain bahami razamandi aur mashware se doodh chudana chahein to aisa karne mein koi muzahiqa nahin, aur agar tumhara khayal apni aulad ko kisi gair aurat se doodh pilwane ka ho, to ismein bhi koi harj nahin bashart yeh ke iska jo kuch muawaza (compensation) tai karo, woh maroof tareeqe par ada kardo. Allah se daro aur jaan rakkho ke jo kuch tum karte ho, sab Allah ki nazar mein hai" },
    { number: 234, arabic: "وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًۭا يَتَرَبَّصْنَ بِأَنفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍۢ وَعَشْرًۭا ۖ فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ بِٱلْمَعْرُوفِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "Waallatheena yutawaffawna minkum wayatharoona azwajan yatarabbasna bianfusihinna arbaAAata ashhurin waAAashran faitha balaghna ajalahunna fala junaha AAalaykum feema faAAalna fee anfusihinna bialmaAAroofi waAllahu bima taAAmaloona khabeerun", transliterationB: "Wallazeena yutawaffawna minkum wa yazaroona azwaajai yatarabbasna bi anfusihinna arba'ata ashhurinw wa 'ashran fa izaa balaghna ajalahunna falaa junaaha 'alaikum feemaa fa'alna feee anfusihinna bilma'roof; wallaahu bimaa ta'maloona Khabeer", english: "If any of you die and leave widows behind, they shall wait concerning themselves four months and ten days: When they have fulfilled their term, there is no blame on you if they dispose of themselves in a just and reasonable manner. And Allah is well acquainted with what ye do", romanUrdu: "Tum mein se jo log marr jayein, unke pichey agar unki biwiyan zinda hon, to woh apne aap ko char mahine dus din roke rakkhein, phir jab unki iddat poori ho jaye, to unhein ikhtiyar hai apni zaat ke maamle mein maroof tareeqe se jo chahien karein tumpar iski koi zimmedaari nahin. Allah tum sab ke aamaal se bakhabar hai" },
    { number: 235, arabic: "وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُم بِهِۦ مِنْ خِطْبَةِ ٱلنِّسَآءِ أَوْ أَكْنَنتُمْ فِىٓ أَنفُسِكُمْ ۚ عَلِمَ ٱللَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَلَٰكِن لَّا تُوَاعِدُوهُنَّ سِرًّا إِلَّآ أَن تَقُولُوا۟ قَوْلًۭا مَّعْرُوفًۭا ۚ وَلَا تَعْزِمُوا۟ عُقْدَةَ ٱلنِّكَاحِ حَتَّىٰ يَبْلُغَ ٱلْكِتَٰبُ أَجَلَهُۥ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِىٓ أَنفُسِكُمْ فَٱحْذَرُوهُ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَفُورٌ حَلِيمٌۭ", transliteration: "Wala junaha AAalaykum feema AAarradtum bihi min khitbati alnnisai aw aknantum fee anfusikum AAalima Allahu annakum satathkuroonahunna walakin la tuwaAAidoohunna sirran illa an taqooloo qawlan maAAroofan wala taAAzimoo AAuqdata alnnikahi hatta yablugha alkitabu ajalahu waiAAlamoo anna Allaha yaAAlamu ma fee anfusikum faihtharoohu waiAAlamoo anna Allaha ghafoorun haleemun", transliterationB: "Wa laa junaaha 'alaikum feema 'arradtum bihee min khitbatin nisaaa'i aw aknantum feee anfusikum; 'alimal laahu annakum satazkuroonahunna wa laakil laa tuwaa'idoohunna sirran illaaa an taqooloo qawlamma'roofaa; wa laa ta'zimoo 'uqdatan nikaahi hattaa yablughal kitaabu ajalah; wa'lamooo annal laaha ya'lamumaa feee anfusikum fahzarooh; wa'lamooo annallaaha Ghafoorun Haleem", english: "There is no blame on you if ye make an offer of betrothal or hold it in your hearts. Allah knows that ye cherish them in your hearts: But do not make a secret contract with them except in terms Honourable, nor resolve on the tie of marriage till the term prescribed is fulfilled. And know that Allah Knoweth what is in your hearts, and take heed of Him; and know that Allah is Oft-forgiving, Most Forbearing", romanUrdu: "Zamana e iddat mein khwa tum un bewa aurton ke saath mangni ki irada ishare kanayi mein zahir kardo, khwa dil mein chupaye rakkho, dono suraton mein koi muzahiqa nahin. Allah jaanta hai ke unka khayal to tumhare dil mein aayega hi magar dekho! Khufiya (hidden) ahad o paiman na karna agar koi baat karni hai to maroof tareeqe se karo aur aqd e nikah baandhne ka faisla us waqt tak na karo jab tak ke iddat poori na ho jaye, khoob samajh lo ke Allah tumhare dilon ka haal tak jaanta hai, lihaza ussey daro aur yeh bhi jaan lo ke Allah burdbaar hai, choti choti baaton se darguzar farmata hai" },
    { number: 236, arabic: "لَّا جُنَاحَ عَلَيْكُمْ إِن طَلَّقْتُمُ ٱلنِّسَآءَ مَا لَمْ تَمَسُّوهُنَّ أَوْ تَفْرِضُوا۟ لَهُنَّ فَرِيضَةًۭ ۚ وَمَتِّعُوهُنَّ عَلَى ٱلْمُوسِعِ قَدَرُهُۥ وَعَلَى ٱلْمُقْتِرِ قَدَرُهُۥ مَتَٰعًۢا بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُحْسِنِينَ", transliteration: "La junaha AAalaykum in tallaqtumu alnnisaa ma lam tamassoohunna aw tafridoo lahunna fareedatan wamattiAAoohunna AAala almoosiAAi qadaruhu waAAala almuqtiri qadaruhu mataAAan bialmaAAroofi haqqan AAala almuhsineena", transliterationB: "Laa junaaha 'alaikum in tallaqtumun nisaaa'a maa lam tamassoohunna aw tafridoo lahunna fareedah; wa matti'oona 'alal moosi'i qadaruhoo wa 'alal muqtiri qadaruhoo matta'am bilma'roofi haqqan 'alalmuhsineen", english: "There is no blame on you if ye divorce women before consummation or the fixation of their dower; but bestow on them (A suitable gift), the wealthy according to his means, and the poor according to his means;- A gift of a reasonable amount is due from those who wish to do the right thing", romanUrdu: "Tumpar kuch gunaah nahin, agar tum apni auraton ko talaq dedo qabl iske ke haath lagane ki naubat aaye ya mehar muqarrar ho, is surat mein unhein kuch na kuch dena zaroor chahiye. Khush haal aadmi apni maqdarat ke mutabiq aur gareeb apni madarat ke mutabiq maroof tareeqe se dey, yeh haqq hai neik aadmiyon par" },
    { number: 237, arabic: "وَإِن طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ وَقَدْ فَرَضْتُمْ لَهُنَّ فَرِيضَةًۭ فَنِصْفُ مَا فَرَضْتُمْ إِلَّآ أَن يَعْفُونَ أَوْ يَعْفُوَا۟ ٱلَّذِى بِيَدِهِۦ عُقْدَةُ ٱلنِّكَاحِ ۚ وَأَن تَعْفُوٓا۟ أَقْرَبُ لِلتَّقْوَىٰ ۚ وَلَا تَنسَوُا۟ ٱلْفَضْلَ بَيْنَكُمْ ۚ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌ", transliteration: "Wain tallaqtumoohunna min qabli an tamassoohunna waqad faradtum lahunna fareedatan fanisfu ma faradtum illa an yaAAfoona aw yaAAfuwa allathee biyadihi AAuqdatu alnnikahi waan taAAfoo aqrabu lilttaqwa wala tansawoo alfadla baynakum inna Allaha bima taAAmaloona baseerun", transliterationB: "Wa in tallaqtumoohunna min qabli an tamassoohunna wa qad farad tum lahunna fareedatan fanisfu maa faradtum illaaa ai ya'foona aw ya'fuwallazee biyadihee 'uqdatunnikaah; wa an ta'foona aw ya'fuwallazee biyadihee 'uqdatunnikaah; wa an ta'fooo aqrabu littaqwaa; wa laa tansawulfadla bainakum; innal laaha bimaa ta'maloona Baseer", english: "And if ye divorce them before consummation, but after the fixation of a dower for them, then the half of the dower (Is due to them), unless they remit it or (the man's half) is remitted by him in whose hands is the marriage tie; and the remission (of the man's half) is the nearest to righteousness. And do not forget Liberality between yourselves. For Allah sees well all that ye do", romanUrdu: "Aur agar tumne haath lagane se pehle talaq di ho, lekin mehar muqarrar kiya ja chuka ho, to us surat mein nisf (half) mehar dena hoga, yeh aur baat hai ke aurat narmi barte (aur mehar na le) ya woh Mard jiske ikhtiyar mein aqd e nikah hai, narmi se kaam le (aur poora mehar de de), aur tum (yani Mard) narmi se kaam lo to yeh taqwa se zyada munasibat rakhta hai, aapas ke maamlaat mein fayyazi ko na bhoolo, Tumhare aamal ko Allah dekh raha hai" },
    { number: 238, arabic: "حَٰفِظُوا۟ عَلَى ٱلصَّلَوَٰتِ وَٱلصَّلَوٰةِ ٱلْوُسْطَىٰ وَقُومُوا۟ لِلَّهِ قَٰنِتِينَ", transliteration: "Hafithoo AAala alssalawati waalssalati alwusta waqoomoo lillahi qaniteena", transliterationB: "Haafizoo 'alas salawaati was Salaatil Wustaa wa qoomoo lillaahi qaaniteen", english: "Guard strictly your (habit of) prayers, especially the Middle Prayer; and stand before Allah in a devout (frame of mind)", romanUrdu: "Apni namazon ki nigehdaasht rakkho, khususan aisi namaaz ki jo mohasan salawat ki jamey (middle prayer) ho. Allah ke aage is tarah khade ho jaise farmabardaar ghulam khade hotay hain" },
    { number: 239, arabic: "فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًۭا ۖ فَإِذَآ أَمِنتُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَمَا عَلَّمَكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ", transliteration: "Fain khiftum farijalan aw rukbanan faitha amintum faothkuroo Allaha kama AAallamakum ma lam takoonoo taAAlamoona", transliterationB: "Fa in khiftum farijaalan aw rukbaanan fa izaaa amintum fazkurul laaha kamaa 'allamakum maa lam takoonoo ta'lamoon", english: "If ye fear (an enemy), pray on foot, or riding, (as may be most convenient), but when ye are in security, celebrate Allah's praises in the manner He has taught you, which ye knew not (before)", romanUrdu: "Badh-amani ki haalat ho, to khwa paidal ho, khwa sawaar , jis tarah mumkin ho namaz padho aur jab aman mayassar aa jaye to Allah ko us tareeqe se yaad karo jo usne tumhein sikha diya hai, jissey tum pehle na-waqif thay" },
    { number: 240, arabic: "وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًۭا وَصِيَّةًۭ لِّأَزْوَٰجِهِم مَّتَٰعًا إِلَى ٱلْحَوْلِ غَيْرَ إِخْرَاجٍۢ ۚ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِى مَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ مِن مَّعْرُوفٍۢ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌۭ", transliteration: "Waallatheena yutawaffawna minkum wayatharoona azwajan wasiyyatan liazwajihim mataAAan ila alhawli ghayra ikhrajin fain kharajna fala junaha AAalaykum fee ma faAAalna fee anfusihinna min maAAroofin waAllahu AAazeezun hakeemun", transliterationB: "Wallazeena yutawaf fawna minkum wa yazaroona azwaajanw wasiyyatal li azwaajihim mataa'an ilal hawlighaira ikhraaj; fa in kharajna falaa junaaha 'alaikum fee maa fa'alna junaaha 'alaikum fee maa fa'alna feee anfusihinna mim ma'roof; wallaahu Azeezun Hakeem", english: "Those of you who die and leave widows should bequeath for their widows a year's maintenance and residence; but if they leave (The residence), there is no blame on you for what they do with themselves, provided it is reasonable. And Allah is Exalted in Power, Wise", romanUrdu: "Tum mein se jo log wafaat payein aur pichey biwiyan chodh rahey hon, unko chahiye ke apni biwiyon ke haqq mein yeh wasiyat kar jayein ke ek saal tak unko naan-o-nafaqa (maintenance) diya jaye aur woh ghar se na nikali jayein. Phir agar woh khud nikal jayein to apni zaat ke maamle mein maroof tareeqe se woh jo kuch bhi karein uski koi zimmedari tumpar nahin hai. Allah sab par gaalib iqtedar rakhne wala aur hakeem o daana hai" },
    { number: 241, arabic: "وَلِلْمُطَلَّقَٰتِ مَتَٰعٌۢ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ", transliteration: "Walilmutallaqati mataAAun bialmaAAroofi haqqan AAala almuttaqeena", transliterationB: "Wa lilmutallaqaati mataa'um bilma'roofi haqqan 'alal muttaqeen", english: "For divorced women Maintenance (should be provided) on a reasonable (scale). This is a duty on the righteous", romanUrdu: "Isi tarah jin auraton ko talaq di gayi ho, unhein bhi munasib taur par kuch na kuch de kar rukhsat kiya jaye, yeh haqq hai muttaqi logon par" },
    { number: 242, arabic: "كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ", transliteration: "Kathalika yubayyinu Allahu lakum ayatihi laAAallakum taAAqiloona", transliterationB: "Kazaalika yubaiyinul laahu lakum aayaatihee la'allakum ta'qiloon", english: "Thus doth Allah Make clear His Signs to you: In order that ye may understand", romanUrdu: "Is tarah Allah apne ehkam tumhein saaf saaf batata hai, umeed hai ke tum samajh boojh kar kaam karo" },
    { number: 243, arabic: "۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ خَرَجُوا۟ مِن دِيَٰرِهِمْ وَهُمْ أُلُوفٌ حَذَرَ ٱلْمَوْتِ فَقَالَ لَهُمُ ٱللَّهُ مُوتُوا۟ ثُمَّ أَحْيَٰهُمْ ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ", transliteration: "Alam tara ila allatheena kharajoo min diyarihim wahum oloofun hathara almawti faqala lahumu Allahu mootoo thumma ahyahum inna Allaha lathoo fadlin AAala alnnasi walakinna akthara alnnasi la yashkuroona", transliterationB: "Alam tara ilal lazeena kharajoo min diyaarihim wa hum uloofun hazaral mawti faqaaala lahumul laahu mootoo summa ahyaahum; innal laaha lazoo fadlin 'alannaasi wa laakinna aksarannaasi laa yashkuroon", english: "Didst thou not Turn by vision to those who abandoned their homes, though they were thousands (In number), for fear of death? Allah said to them: \"Die\": Then He restored them to life. For Allah is full of bounty to mankind, but Most of them are ungrateful", romanUrdu: "Tumne un logon ke haal par bhi kuch gaur kiya, jo maut ke darr se apne ghar baar chodh kar nikle thay aur hazaaron ki tadaad mein thay? Allah ne unse farmaya: marr jao , phir usne unko dobara zindagi bakshi, haqeeqat yeh hai ke Allah Insaan par bada fazal farmane wala hai magar aksar log shukar ada nahin karte" },
    { number: 244, arabic: "وَقَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", transliteration: "Waqatiloo fee sabeeli Allahi waiAAlamoo anna Allaha sameeAAun AAaleemun", transliterationB: "Wa qaatiloo fee sabeelil laahi wa'lamooo annal laaha Samee'un 'Aleem", english: "Then fight in the cause of Allah, and know that Allah Heareth and knoweth all things", romanUrdu: "(Musalmano)! Allah ki raah mein jung karo, aur khoob jaan rakkho ke Allah sunne wala aur jaanne wala hai" },
    { number: 245, arabic: "مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًۭا فَيُضَٰعِفَهُۥ لَهُۥٓ أَضْعَافًۭا كَثِيرَةًۭ ۚ وَٱللَّهُ يَقْبِضُ وَيَبْصُۜطُ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Man tha allathee yuqridu Allaha qardan hasanan fayudaAAifahu lahu adAAafan katheeratan waAllahu yaqbidu wayabsutu wailayhi turjaAAoona", transliterationB: "Man zal lazee yuqridul laaha qardan hasanan fayudaa 'ifahoo lahoo ad'aafan kaseerah; wallaahu yaqbidu wa yabsut-u wa ilaihi turja'oon", english: "Who is he that will loan to Allah a beautiful loan, which Allah will double unto his credit and multiply many times? It is Allah that giveth (you) Want or plenty, and to Him shall be your return", romanUrdu: "Tum mein kaun hai jo Allah ko qarz e hasan (good loan) de taa-ke Allah usey kai gunaa badha chadha kar wapas karey? Ghatana bhi Allah ke ikhtiyar mein hai aur badana bhi, aur usi ki taraf tumhein palat kar jana hai" },
    { number: 246, arabic: "أَلَمْ تَرَ إِلَى ٱلْمَلَإِ مِنۢ بَنِىٓ إِسْرَٰٓءِيلَ مِنۢ بَعْدِ مُوسَىٰٓ إِذْ قَالُوا۟ لِنَبِىٍّۢ لَّهُمُ ٱبْعَثْ لَنَا مَلِكًۭا نُّقَٰتِلْ فِى سَبِيلِ ٱللَّهِ ۖ قَالَ هَلْ عَسَيْتُمْ إِن كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ أَلَّا تُقَٰتِلُوا۟ ۖ قَالُوا۟ وَمَا لَنَآ أَلَّا نُقَٰتِلَ فِى سَبِيلِ ٱللَّهِ وَقَدْ أُخْرِجْنَا مِن دِيَٰرِنَا وَأَبْنَآئِنَا ۖ فَلَمَّا كُتِبَ عَلَيْهِمُ ٱلْقِتَالُ تَوَلَّوْا۟ إِلَّا قَلِيلًۭا مِّنْهُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّٰلِمِينَ", transliteration: "Alam tara ila almalai min banee israeela min baAAdi moosa ith qaloo linabiyyin lahumu ibAAath lana malikan nuqatil fee sabeeli Allahi qala hal AAasaytum in kutiba AAalaykumu alqitalu alla tuqatiloo qaloo wama lana alla nuqatila fee sabeeli Allahi waqad okhrijna min diyarina waabnaina falamma kutiba AAalayhimu alqitalu tawallaw illa qaleelan minhum waAllahu AAaleemun bialththalimeena", transliterationB: "Alam tara ilal malai mim Baneee Israaa'eela mim ba'di Moosaaa iz qaaloo li Nabiyyil lahumub 'as lanaa malikan nuqaatil fee sabeelillaahi qaala hal 'asaitum in kutiba 'alaikumul qitaalu allaa tuqaatiloo qaaloo wa maa lanaaa allaa nuqaatila fee sabeelil laahi wa qad ukhrijnaa min diyaarinaa wa abnaaa'inaa falammaa kutiba 'alaihimul qitaalu tawallaw illaa qaleelam minhum; wallaahu 'aleemum bizzaalimeen", english: "Hast thou not Turned thy vision to the Chiefs of the Children of Israel after (the time of) Moses? they said to a prophet (That was) among them: \"Appoint for us a king, that we May fight in the cause of Allah.\" He said: \"Is it not possible, if ye were commanded to fight, that that ye will not fight?\" They said: \"How could we refuse to fight in the cause of Allah, seeing that we were turned out of our homes and our families?\" but when they were commanded to fight, they turned back, except a small band among them. But Allah Has full knowledge of those who do wrong", romanUrdu: "Phir tumne us maamle par bhi gaur kiya, jo Moosa ke baad sardaraan e bani Israel ko pesh aaya tha? Unhon ne apne Nabi se kaha: hamare liye ek baadshah muqarrar kardo taa-ke hum Allah ki raah mein jung karein, Nabi ne pucha : kahin aisa to na hoga ke tumko ladayi ka hukum diya jaye aur phir tum na lado? Woh kehne lagey : bhala yeh kaise ho sakta hai ke hum raah e khuda mein na ladein, jabke humein apne gharon se nikaal diya gaya hai aur hamare baal bacchey humse juda kardiye gaye hain? Magar jab unko jung ka hukum diya gaya to ek qaleel tadaad ke siwa woh sab peeth moad gaye, aur Allah unmein se ek ek zalim ko jaanta hai" },
    { number: 247, arabic: "وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ٱللَّهَ قَدْ بَعَثَ لَكُمْ طَالُوتَ مَلِكًۭا ۚ قَالُوٓا۟ أَنَّىٰ يَكُونُ لَهُ ٱلْمُلْكُ عَلَيْنَا وَنَحْنُ أَحَقُّ بِٱلْمُلْكِ مِنْهُ وَلَمْ يُؤْتَ سَعَةًۭ مِّنَ ٱلْمَالِ ۚ قَالَ إِنَّ ٱللَّهَ ٱصْطَفَىٰهُ عَلَيْكُمْ وَزَادَهُۥ بَسْطَةًۭ فِى ٱلْعِلْمِ وَٱلْجِسْمِ ۖ وَٱللَّهُ يُؤْتِى مُلْكَهُۥ مَن يَشَآءُ ۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", transliteration: "Waqala lahum nabiyyuhum inna Allaha qad baAAatha lakum taloota malikan qaloo anna yakoonu lahu almulku AAalayna wanahnu ahaqqu bialmulki minhu walam yuta saAAatan mina almali qala inna Allaha istafahu AAalaykum wazadahu bastatan fee alAAilmi waaljismi waAllahu yutee mulkahu man yashao waAllahu wasiAAun AAaleemun", transliterationB: "Wa qaala lahum Nabiy yuhum innal laaha qad ba'asa lakum Taaloota malikaa; qaalooo annaa yakoonu lahul mulku 'alainaa wa nahnu ahaqqu bilmulki minhu wa lam yu'ta sa'atamminal maal; qaala innallaahas tafaahu 'alaikum wa zaadahoo bastatan fil'ilmi waljismi wallaahu yu'tee mulkahoo mai yashaaa'; wallaahu Waasi'un 'Aleem", english: "Their Prophet said to them: \"Allah hath appointed Talut as king over you.\" They said: \"How can he exercise authority over us when we are better fitted than he to exercise authority, and he is not even gifted, with wealth in abundance?\" He said: \"Allah hath Chosen him above you, and hath gifted him abundantly with knowledge and bodily prowess: Allah Granteth His authority to whom He pleaseth. Allah careth for all, and He knoweth all things", romanUrdu: "Unke Nabi ne unse kaha ke Allah ne Talut ko tumhare liye baadshah muqarrar kiya hai, yeh sunkar woh bole : “humpar baadshah banney ka woh kaise haqqdaar hogaya? Uske muqable mein baadshahi ke hum zyada mustahiq hain, woh to koi bada maaldaar aadmi nahin hai”. Nabi ne jawab diya: “Allah ne tumhare muqable mein usi ko muntakhab kiya hai aur usko dimaagi o jismani dono kism ki ehliyatein farawani ke saath ata farmayi hain aur Allah ko ikhtiyar hai ke apna mulk jisey chahe dey, Allah badi wusat rakhta hai aur sabkuch uske ilm mein hai”" },
    { number: 248, arabic: "وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ءَايَةَ مُلْكِهِۦٓ أَن يَأْتِيَكُمُ ٱلتَّابُوتُ فِيهِ سَكِينَةٌۭ مِّن رَّبِّكُمْ وَبَقِيَّةٌۭ مِّمَّا تَرَكَ ءَالُ مُوسَىٰ وَءَالُ هَٰرُونَ تَحْمِلُهُ ٱلْمَلَٰٓئِكَةُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Waqala lahum nabiyyuhum inna ayata mulkihi an yatiyakumu alttabootu feehi sakeenatun min rabbikum wabaqiyyatun mimma taraka alu moosa waalu haroona tahmiluhu almalaikatu inna fee thalika laayatan lakum in kuntum mumineena", transliterationB: "Wa qaala lahum Nabiyyuhum inna Aayata mulkiheee ai yaatiyakumut Taabootu feei sakeenatummir Rabbikum wa baqiyyatummimmaa taraka Aalu Moosa wa Aalu Haaroona tahmiluhul malaaa'ikah; inna fee zaalika la Aayatal lakum in kuntum mu'mineen", english: "And (further) their Prophet said to them: \"A Sign of his authority is that there shall come to you the Ark of the covenant, with (an assurance) therein of security from your Lord, and the relics left by the family of Moses and the family of Aaron, carried by angels. In this is a symbol for you if ye indeed have faith", romanUrdu: "Iske saath unke Nabi ne unko yeh bhi bataya ke “khuda ki taraf se uske baadshah muqarrar honay ki alamat yeh hai ke uske ahad mein woh sandook tumhein wapas mil jayega, jismein tumhare Rubb ki taraf se tumhare liye sukoon e qalb ka samaan hai, jismein aale Moosa aur aale Haroon ke chodey huey tabarrukaat hain, aur jisko is waqt Farishte sambhale huey hain agar tum momin ho, to yeh tumhare liye bahut badi nishani hai" },
    { number: 249, arabic: "فَلَمَّا فَصَلَ طَالُوتُ بِٱلْجُنُودِ قَالَ إِنَّ ٱللَّهَ مُبْتَلِيكُم بِنَهَرٍۢ فَمَن شَرِبَ مِنْهُ فَلَيْسَ مِنِّى وَمَن لَّمْ يَطْعَمْهُ فَإِنَّهُۥ مِنِّىٓ إِلَّا مَنِ ٱغْتَرَفَ غُرْفَةًۢ بِيَدِهِۦ ۚ فَشَرِبُوا۟ مِنْهُ إِلَّا قَلِيلًۭا مِّنْهُمْ ۚ فَلَمَّا جَاوَزَهُۥ هُوَ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ قَالُوا۟ لَا طَاقَةَ لَنَا ٱلْيَوْمَ بِجَالُوتَ وَجُنُودِهِۦ ۚ قَالَ ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُوا۟ ٱللَّهِ كَم مِّن فِئَةٍۢ قَلِيلَةٍ غَلَبَتْ فِئَةًۭ كَثِيرَةًۢ بِإِذْنِ ٱللَّهِ ۗ وَٱللَّهُ مَعَ ٱلصَّٰبِرِينَ", transliteration: "Falamma fasala talootu bialjunoodi qala inna Allaha mubtaleekum binaharin faman shariba minhu falaysa minnee waman lam yatAAamhu fainnahu minnee illa mani ightarafa ghurfatan biyadihi fashariboo minhu illa qaleelan minhum falamma jawazahu huwa waallatheena amanoo maAAahu qaloo la taqata lana alyawma bijaloota wajunoodihi qala allatheena yathunnoona annahum mulaqoo Allahi kam min fiatin qaleelatin ghalabat fiatan katheeratan biithni Allahi waAllahu maAAa alssabireena", transliterationB: "Falammaa fasala Taalootu biljunoodi qaala innal laaha mubtaleekum binaharin faman shariba minhu falaisa minnee wa mallam yat'amhu fa innahoo minneee illaa manigh tarafa ghurfatam biyadih; fashariboo minhu illaa qaleelamminhum; falammaa jaawazahoo huwa wallazeena aamanoo ma'ahoo qaaloo laa taaqata lanal yawma bi Jaaloota wa junoodih; qaalallazeena yazunnoona annahum mulaaqul laahi kam min fi'atin qaleelatin ghalabat fi'atan kaseeratam bi iznil laah; wallaahuma'as saabireen", english: "When Talut set forth with the armies, he said: \"Allah will test you at the stream: if any drinks of its water, He goes not with my army: Only those who taste not of it go with me: A mere sip out of the hand is excused.\" but they all drank of it, except a few. When they crossed the river,- He and the faithful ones with him,- they said: \"This day We cannot cope with Goliath and his forces.\" but those who were convinced that they must meet Allah, said: \"How oft, by Allah's will, Hath a small force vanquished a big one? Allah is with those who steadfastly persevere", romanUrdu: "Phir jab Talut laskar lekar chala, to usne kaha: “ek dariya par Allah ki taraf se tumhari aazmaish honay wali hai, jo uska pani piyega, woh mera saathi nahin. Mera saathi sirf woh hai jo ussey pyas na bujhaye, haan ek aadh chillu koi pee ley to pee ley”. Magar ek giroh e qaleel ke siwa woh sab us dariya se sairaab huey, phir jab Talut aur uske saathi musalman dariya paar karke aagey badey to unhon ne Talut se kehdiya ke aaj hum mein Jaaluth (goliath) aur uske lashkaron ka muqabla karne ki taaqat nahin hai, lekin jo log yeh samajhte thay ke unhein ek din Allah se milna hai, unhone ne kaha: “ baaraha aisa hua hai ke ek qaleel giroh Allah ke izan se ek badey giroh par gaalib aa gaya hai, Allah sabr karne walon ka saathi hai.”" },
    { number: 250, arabic: "وَلَمَّا بَرَزُوا۟ لِجَالُوتَ وَجُنُودِهِۦ قَالُوا۟ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًۭا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", transliteration: "Walamma barazoo lijaloota wajunoodihi qaloo rabbana afrigh AAalayna sabran wathabbit aqdamana waonsurna AAala alqawmi alkafireena", transliterationB: "Wa lammaa barazoo liJaaloota wa junoodihee qaaloo Rabbanaaa afrigh 'alainaa sabranw wa sabbit aqdaamanaa wansurnaa 'alal qawmil kaafireen", english: "When they advanced to meet Goliath and his forces, they prayed: \"Our Lord! Pour out constancy on us and make our steps firm: Help us against those that reject faith", romanUrdu: "Aur jab woh Jaaluth aur uske lashkaron ke muqable par nikle to unhon ne dua ki: “aye hamare Rubb humpar sabr ka faizan kar, hamare qadam jamaa de aur is kafir giroh par humein fatah naseeb kar.”" },
    { number: 251, arabic: "فَهَزَمُوهُم بِإِذْنِ ٱللَّهِ وَقَتَلَ دَاوُۥدُ جَالُوتَ وَءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ وَٱلْحِكْمَةَ وَعَلَّمَهُۥ مِمَّا يَشَآءُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍۢ لَّفَسَدَتِ ٱلْأَرْضُ وَلَٰكِنَّ ٱللَّهَ ذُو فَضْلٍ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Fahazamoohum biithni Allahi waqatala dawoodu jaloota waatahu Allahu almulka waalhikmata waAAallamahu mimma yashao walawla dafAAu Allahi alnnasa baAAdahum bibaAAdin lafasadati alardu walakinna Allaha thoo fadlin AAala alAAalameena", transliterationB: "Fahazamoohum bi iznillaahi wa qatala Daawoodu jaaloota wa aataahul laahulmulka Wal Hikmata wa 'allamahoo mimmaa yashaaa'; wa law laa daf'ullaahin naasa ba'dahum biba'dil lafasadatil ardu wa laakinnal laaha zoo fadlin 'alal'aalameen", english: "By Allah's will they routed them; and David slew Goliath; and Allah gave him power and wisdom and taught him whatever (else) He willed. And did not Allah Check one set of people by means of another, the earth would indeed be full of mischief: But Allah is full of bounty to all the worlds", romanUrdu: "Aakhir e kaar Allah ke izan se unhon ne kafiron ko maar bhagaya aur Dawood ne Jaaluth ko qatal kardiya aur Allah ne usey sultanat aur hikmat se nawaza aur jin jin cheezon ka chaha usko ilm diya, agar is tarah Allah insaano ke ek giroh ko dusre giroh ke zariye se hatata na rehta, to zameen ka nizam bigad jata, lekin duniya ke logon par Allah ka bada fazl hai (ke woh is tarah dafey fasaad ka intezam karta rehta hai)" },
    { number: 252, arabic: "تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۚ وَإِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ", transliteration: "Tilka ayatu Allahi natlooha AAalayka bialhaqqi wainnaka lamina almursaleena", transliterationB: "Tilka Aayaatul laahi natloohaa 'alaika bilhaqq; wa innaka laminal mursaleen", english: "These are the Signs of Allah: we rehearse them to thee in truth: verily Thou art one of the messengers", romanUrdu: "Yeh Allah ki aayaat hain jo hum theek theek tumko suna rahey hain aur tum yaqeenan un logon mein se ho jo Rasool bana kar bheje gaye hain" },
    { number: 253, arabic: "۞ تِلْكَ ٱلرُّسُلُ فَضَّلْنَا بَعْضَهُمْ عَلَىٰ بَعْضٍۢ ۘ مِّنْهُم مَّن كَلَّمَ ٱللَّهُ ۖ وَرَفَعَ بَعْضَهُمْ دَرَجَٰتٍۢ ۚ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَٰتِ وَأَيَّدْنَٰهُ بِرُوحِ ٱلْقُدُسِ ۗ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلَ ٱلَّذِينَ مِنۢ بَعْدِهِم مِّنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَٰتُ وَلَٰكِنِ ٱخْتَلَفُوا۟ فَمِنْهُم مَّنْ ءَامَنَ وَمِنْهُم مَّن كَفَرَ ۚ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلُوا۟ وَلَٰكِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ", transliteration: "Tilka alrrusulu faddalna baAAdahum AAala baAAdin minhum man kallama Allahu warafaAAa baAAdahum darajatin waatayna AAeesa ibna maryama albayyinati waayyadnahu biroohi alqudusi walaw shaa Allahu ma iqtatala allatheena min baAAdihim min baAAdi ma jaathumu albayyinatu walakini ikhtalafoo faminhum man amana waminhum man kafara walaw shaa Allahu ma iqtataloo walakinna Allaha yafAAalu ma yureedu", transliterationB: "Tilkar Rusulu faddalnaa ba'dahum 'alaa ba'd; minhum man kallamal laahu wa rafa'a ba'dahum darajaat; wa aatainaa 'Eesab na Maryamal baiyinaati wa ayyadnaahu bi Roohil Qudus; wa law shaaa'al laahu maqtatalal lazeena mimba'dihim mim ba'di maa jaaa'athumul baiyinaatu wa laakinikh talafoo faminhum man aamana wa minhum man kafar; wa law shaaa'al laahu maq tataloo wa laakinnallaaha yaf'alu maa yureed", english: "Those messengers We endowed with gifts, some above others: To one of them Allah spoke; others He raised to degrees (of honour); to Jesus the son of Mary We gave clear (Signs), and strengthened him with the holy spirit. If Allah had so willed, succeeding generations would not have fought among each other, after clear (Signs) had come to them, but they (chose) to wrangle, some believing and others rejecting. If Allah had so willed, they would not have fought each other; but Allah Fulfilleth His plan", romanUrdu: "Yeh Rasool (jo hamari taraf se Insaano ki hidayat par mamoor huey) humne unko ek dusre se badh chadh kar martabe ata kiye, unmein koi aisa tha jissey khuda khud hum-kalaam hua, kisi ko usne dusri haisyaton se buland darje diye, aur aakhir mein Isa Ibn-Mariyam ko roshan nishaniyan ata ki aur rooh e paak se uski madad ki , agar Allah chahta to mumkin na tha ke in Rasoolon ke baad jo log roshan nishaniyan dekh chuke thay wo aapas mein ladte , magar (Allah ki mashiyat yeh na thi ke woh logon ko jabran ikhtilaaf se roke, is wajah se) unhon ne baham ikhtilaaf kiya, phir koi iman laya aur kisi ne kufr ki raah ikhtiyar ki, haan , Allah chahta to woh hargiz na ladte, magar Allah jo chahta hai karta hai" },
    { number: 254, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِمَّا رَزَقْنَٰكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا بَيْعٌۭ فِيهِ وَلَا خُلَّةٌۭ وَلَا شَفَٰعَةٌۭ ۗ وَٱلْكَٰفِرُونَ هُمُ ٱلظَّٰلِمُونَ", transliteration: "Ya ayyuha allatheena amanoo anfiqoo mimma razaqnakum min qabli an yatiya yawmun la bayAAun feehi wala khullatun wala shafaAAatun waalkafiroona humu alththalimoona", transliterationB: "Yaa ayyuhal lazeena aamanoo anfiqoo mimmaa razaqnaakum min qabli ai yaatiya yawmul laa bai'un fee wa la khullatunw wa laa shafaa'ah; walkaa firoona humuz zaalimoon", english: "O ye who believe! Spend out of (the bounties) We have provided for you, before the Day comes when no bargaining (Will avail), nor friendship nor intercession. Those who reject Faith they are the wrong-doers", romanUrdu: "Aey logon jo iman laye ho, jo kuch maal mataa humne tumko baksha hai, usmein se kharch karo, qabl iske ke woh din aaye jismein na khareed o farokht hogi, na dosti kaam aayegi aur na sifarish chalegi aur zalim asal mein wahi hain jo kufr ki rawish ikhtiyar karte hain" },
    { number: 255, arabic: "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ ۚ لَا تَأْخُذُهُۥ سِنَةٌۭ وَلَا نَوْمٌۭ ۚ لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ مَن ذَا ٱلَّذِى يَشْفَعُ عِندَهُۥٓ إِلَّا بِإِذْنِهِۦ ۚ يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۖ وَلَا يُحِيطُونَ بِشَىْءٍۢ مِّنْ عِلْمِهِۦٓ إِلَّا بِمَا شَآءَ ۚ وَسِعَ كُرْسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ ۖ وَلَا يَـُٔودُهُۥ حِفْظُهُمَا ۚ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ", transliteration: "Allahu la ilaha illa huwa alhayyu alqayyoomu la takhuthuhu sinatun wala nawmun lahu ma fee alssamawati wama fee alardi man tha allathee yashfaAAu AAindahu illa biithnihi yaAAlamu ma bayna aydeehim wama khalfahum wala yuheetoona bishayin min AAilmihi illa bima shaa wasiAAa kursiyyuhu alssamawati waalarda wala yaooduhu hifthuhuma wahuwa alAAaliyyu alAAatheemu", transliterationB: "Allahu laaa ilaaha illaa Huwal Haiyul Qaiyoom; laa taakhuzuhoo sinatunw wa laa nawm; lahoo maa fissamaawaati wa maa fil ard; man zal lazee yashfa'u indahooo illaa bi-iznih; ya'lamu maa baina aydeehim wa mww khalfahum wa laa yuheetoona bishai'im min 'ilmihee illaa bimaa shaaa'; wasi'a Kursiyyuhus samaawaati wal arda wa laa ya'ooduho hifzuhumaa; wa Huwal Aliyyul 'Azeem", english: "Allah! There is no god but He,-the Living, the Self-subsisting, Eternal. No slumber can seize Him nor sleep. His are all things in the heavens and on earth. Who is there can intercede in His presence except as He permitteth? He knoweth what (appeareth to His creatures as) before or after or behind them. Nor shall they compass aught of His knowledge except as He willeth. His Throne doth extend over the heavens and the earth, and He feeleth no fatigue in guarding and preserving them for He is the Most High, the Supreme (in glory)", romanUrdu: "Allah woh zinda e javed (hamesha rehne wali) hasti hai, jo tamaam qayinaat ko sambhale huey hai, uske siwa koi khuda nahin hai, woh na sota hai aur na usey oung lagti hai, zameen aur asmaano mein jo kuch hai usi ka hai, kaun hai jo uski janaab mein uski ijazat ke bagair sifarish kar sakey? Jo kuch bandon ke saamne hai usey bhi woh jaanta hai aur jo kuch unsey ojhal hai ussey bhi woh waqif hai, aur uski maloomaat mein se koi cheez unki giraft e idraak mein nahin aa sakti illa yeh ke kisi cheez ka ilm woh khud hi unko dena chahey, uski hukumat asmaano aur zameen par chayi hui hai aur unki nigehbaani uske liye koi thaka dene wala kaam nahin hai, bas wahi ek buzurg o bartar zaat hai" },
    { number: 256, arabic: "لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ فَمَن يَكْفُرْ بِٱلطَّٰغُوتِ وَيُؤْمِنۢ بِٱللَّهِ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ لَا ٱنفِصَامَ لَهَا ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", transliteration: "La ikraha fee alddeeni qad tabayyana alrrushdu mina alghayyi faman yakfur bialttaghooti wayumin biAllahi faqadi istamsaka bialAAurwati alwuthqa la infisama laha waAllahu sameeAAun AAaleemun", transliterationB: "Laaa ikraaha fid deeni qat tabiyanar rushdu minal ghayy; famai yakfur bit Taaghooti wa yu'mim billaahi faqadis tamsaka bil'urwatil wusqaa lan fisaama lahaa; wallaahu Samee'un 'Aleem", english: "Let there be no compulsion in religion: Truth stands out clear from Error: whoever rejects evil and believes in Allah hath grasped the most trustworthy hand-hold, that never breaks. And Allah heareth and knoweth all things", romanUrdu: "Deen ke maamle mein koi zoar zabardasti nahin hai, saheeh baat galat khayalat se alag chaant kar rakh di gayi hai, ab jo koi taagut ka inkar karke Allah par iman le aaya, usne ek aisa mazboot sahara thaam liya jo kabhi tootne wala nahin, aur Allah ( jiska sahara usne liya hai) sabkuch sunne aur jaanne wala hai" },
    { number: 257, arabic: "ٱللَّهُ وَلِىُّ ٱلَّذِينَ ءَامَنُوا۟ يُخْرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۖ وَٱلَّذِينَ كَفَرُوٓا۟ أَوْلِيَآؤُهُمُ ٱلطَّٰغُوتُ يُخْرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِ ۗ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Allahu waliyyu allatheena amanoo yukhrijuhum mina alththulumati ila alnnoori waallatheena kafaroo awliyaohumu alttaghootu yukhrijoonahum mina alnnoori ila alththulumati olaika ashabu alnnari hum feeha khalidoona", transliterationB: "Allaahu waliyyul lazeena aamanoo yukhrijuhum minaz zulumaati ilan noori wallazeena kafarooo awliyaaa'uhumut Taaghootu yukhrijoonahum minan noori ilaz zulumaat; ulaaa'ika Ashaabun Naari hum feehaa khaalidoon", english: "Allah is the Protector of those who have faith: from the depths of darkness He will lead them forth into light. Of those who reject faith the patrons are the evil ones: from light they will lead them forth into the depths of darkness. They will be companions of the fire, to dwell therein (For ever)", romanUrdu: "Jo log iman latey hain, unka haami o madadgaar Allah hai aur woh unko tareekiyon (andhere) se roshni mein nikaal laata hai aur jo log kufr ki raah ikhtiyar karte hain unke haami o madadgaar taagut hain aur woh unhein roshni se tareekiyon ki tafaf khench le jatay hain, yeh aag mein janey waley log hain jahan yeh hamesha rahenge" },
    { number: 258, arabic: "أَلَمْ تَرَ إِلَى ٱلَّذِى حَآجَّ إِبْرَٰهِۦمَ فِى رَبِّهِۦٓ أَنْ ءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ إِذْ قَالَ إِبْرَٰهِۦمُ رَبِّىَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ قَالَ أَنَا۠ أُحْىِۦ وَأُمِيتُ ۖ قَالَ إِبْرَٰهِۦمُ فَإِنَّ ٱللَّهَ يَأْتِى بِٱلشَّمْسِ مِنَ ٱلْمَشْرِقِ فَأْتِ بِهَا مِنَ ٱلْمَغْرِبِ فَبُهِتَ ٱلَّذِى كَفَرَ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", transliteration: "Alam tara ila allathee hajja ibraheema fee rabbihi an atahu Allahu almulka ith qala ibraheemu rabbiya allathee yuhyee wayumeetu qala ana ohyee waomeetu qala ibraheemu fainna Allaha yatee bialshshamsi mina almashriqi fati biha mina almaghribi fabuhita allathee kafara waAllahu la yahdee alqawma alththalimeena", transliterationB: "Alam tara ilal lazee Haaajja Ibraaheema fee Rabbiheee an aataahullaahul mulka iz qaala Ibraaheemu Rabbiyal lazee yuhyee wa yumeetu qaala ana uhyee wa yumeetu qaala ana uhyee wa umeetu qaala Ibraaheemu fa innal laaha yaatee bishshamsi minal mashriqi faati bihaa minal maghribi fabuhital lazee kafar; wallaahu laa yahdil qawmaz zaalimeen", english: "Hast thou not Turned thy vision to one who disputed with Abraham About his Lord, because Allah had granted him power? Abraham said: \"My Lord is He Who Giveth life and death.\" He said: \"I give life and death\". Said Abraham: \"But it is Allah that causeth the sun to rise from the east: Do thou then cause him to rise from the West.\" Thus was he confounded who (in arrogance) rejected faith. Nor doth Allah Give guidance to a people unjust", romanUrdu: "Kya tumne us shaks ke haal par gaur nahin kiya jisne Ibrahim se jhagda kiya tha? Jhagda is baat par ke Ibrahim ka Rubb kaun hai, aur is bina par ke us shaks ko Allah ne hukumat de rakkhi thi. Jab Ibrahim ne kaha ke “mera Rubb woh hai, jiske ikhtiyar mein zindagi aur maut hai, to usne jawab diya : “zindagi aur maut mere ikhtiyar mein hai” Ibrahim ne kaha: “ accha, Allah Suraj ko mashirq se nikalta hai, tu zara usey magrib se nikaal la”. Yeh sunkar woh munkir e haqq shashtar (astonish) reh gaya, magar Allah zalimon ko raah e raast nahin dikhaya karta" },
    { number: 259, arabic: "أَوْ كَٱلَّذِى مَرَّ عَلَىٰ قَرْيَةٍۢ وَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا قَالَ أَنَّىٰ يُحْىِۦ هَٰذِهِ ٱللَّهُ بَعْدَ مَوْتِهَا ۖ فَأَمَاتَهُ ٱللَّهُ مِا۟ئَةَ عَامٍۢ ثُمَّ بَعَثَهُۥ ۖ قَالَ كَمْ لَبِثْتَ ۖ قَالَ لَبِثْتُ يَوْمًا أَوْ بَعْضَ يَوْمٍۢ ۖ قَالَ بَل لَّبِثْتَ مِا۟ئَةَ عَامٍۢ فَٱنظُرْ إِلَىٰ طَعَامِكَ وَشَرَابِكَ لَمْ يَتَسَنَّهْ ۖ وَٱنظُرْ إِلَىٰ حِمَارِكَ وَلِنَجْعَلَكَ ءَايَةًۭ لِّلنَّاسِ ۖ وَٱنظُرْ إِلَى ٱلْعِظَامِ كَيْفَ نُنشِزُهَا ثُمَّ نَكْسُوهَا لَحْمًۭا ۚ فَلَمَّا تَبَيَّنَ لَهُۥ قَالَ أَعْلَمُ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Aw kaallathee marra AAala qaryatin wahiya khawiyatun AAala AAurooshiha qala anna yuhyee hathihi Allahu baAAda mawtiha faamatahu Allahu miata AAamin thumma baAAathahu qala kam labithta qala labithtu yawman aw baAAda yawmin qala bal labithta miata AAamin faonthur ila taAAamika washarabika lam yatasannah waonthur ila himarika walinajAAalaka ayatan lilnnasi waonthur ila alAAithami kayfa nunshizuha thumma naksooha lahman falamma tabayyana lahu qala aAAlamu anna Allaha AAala kulli shayin qadeerun", transliterationB: "Aw kallazee marra 'alaa qaryatinw wa hiya khaawiyatun 'alaa 'urooshihaa qaala annaa yuhyee haazihil laahu ba'da mawtihaa fa amaatahul laahu mi'ata 'aamin suumma ba'asahoo qaala kam labista qaala labistu yawman aw ba'da yawmin qaala bal labista mi'ata 'aamin fanzur ilaa ta'aamika wa sharaabika lam yatasannah wanzur ilaa himaarika wa linaj'alaka Aayatal linnaasi wanzur ilal'izaami kaifa nunshizuhaa summa naksoohaa lahmaa; falammaa tabiyana lahoo qaala a'lamu annal laaha 'alaakulli shai'in Qadeer", english: "Or (take) the similitude of one who passed by a hamlet, all in ruins to its roofs. He said: \"Oh! how shall Allah bring it (ever) to life, after (this) its death?\" but Allah caused him to die for a hundred years, then raised him up (again). He said: \"How long didst thou tarry (thus)?\" He said: (Perhaps) a day or part of a day.\" He said: \"Nay, thou hast tarried thus a hundred years; but look at thy food and thy drink; they show no signs of age; and look at thy donkey: And that We may make of thee a sign unto the people, Look further at the bones, how We bring them together and clothe them with flesh.\" When this was shown clearly to him, he said: \"I know that Allah hath power over all things", romanUrdu: "Ya phir misaal ke taur par us shaks ko dekho jiska guzar ek aisi basti par hua jo apni chathon (canopies) par aundhi giri padi thi. Usne kaha : “yeh abaadi , jo halaak ho chuki hai, isey Allah kis tarah dobara zindagi bakshega ?” Ispar Allah ne uski rooh qabz karli aur woh sau (hundred) baras tak murda pada raha, phir Allah ne usey dobara zindagi bakshi aur ussey pucha: “batao, kitni muddat padey rahey ho?” Usne kaha: “ ek din ya chandh ghante raha honga”. Farmaya: “ tumpar sau baras isi halat mein guzar chuke hain, ab zara apne khane aur pani ko dekho ke ismein zara tagayyur (changes) nahin aaya hai, dusri taraf zara apne gadhey (donkey) ko bhi dekho [ke iska panjar (skeleton) tak boseeda(rot) ho raha hai] aur yeh humne isliye kiya hai ke hum tumhein logon ke liye ek nishani bana dena chahte hain, phir dekho ke haddiyon ke is panjar (skeleton) ko hum kis tarah utha kar gosht posht ispar chadhate hain”. Is tarah jab haqeeqat uske saamne bilkul numayan ho gayi, to usne kaha: “main jaanta hoon ke Allah har cheez par qudrat rakhta hai”" },
    { number: 260, arabic: "وَإِذْ قَالَ إِبْرَٰهِۦمُ رَبِّ أَرِنِى كَيْفَ تُحْىِ ٱلْمَوْتَىٰ ۖ قَالَ أَوَلَمْ تُؤْمِن ۖ قَالَ بَلَىٰ وَلَٰكِن لِّيَطْمَئِنَّ قَلْبِى ۖ قَالَ فَخُذْ أَرْبَعَةًۭ مِّنَ ٱلطَّيْرِ فَصُرْهُنَّ إِلَيْكَ ثُمَّ ٱجْعَلْ عَلَىٰ كُلِّ جَبَلٍۢ مِّنْهُنَّ جُزْءًۭا ثُمَّ ٱدْعُهُنَّ يَأْتِينَكَ سَعْيًۭا ۚ وَٱعْلَمْ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ", transliteration: "Waith qala ibraheemu rabbi arinee kayfa tuhyee almawta qala awalam tumin qala bala walakin liyatmainna qalbee qala fakhuth arbaAAatan mina alttayri fasurhunna ilayka thumma ijAAal AAala kulli jabalin minhunna juzan thumma odAAuhunna yateenaka saAAyan waiAAlam anna Allaha AAazeezun hakeemun", transliterationB: "Wa iz qaala Ibraaheemu Rabbi arinee kaifa tuhyil mawtaa qaala awa lam tu'min qaala balaa wa laakil liyatma'inna qalbee qaala fakhuz arab'atam minal tairi fasurhunna ilaika summaj 'al a'alaa kulli jabalim minhunna juz'an sumaad 'uhunna yaateenaka sa'yaa; wa'lam annal laaha 'Azeezun Hakeem", english: "When Abraham said: \"Show me, Lord, how You will raise the dead, \" He replied: \"Have you no faith?\" He said \"Yes, but just to reassure my heart.\" Allah said, \"Take four birds, draw them to you, and cut their bodies to pieces. Scatter them over the mountain-tops, then call them back. They will come swiftly to you. Know that Allah is Mighty, Wise", romanUrdu: "Aur woh waqiya bhi pesh e nazar rahey, jab Ibrahim ne kaha tha ke: “ mere maalik, mujhey dikha de tu murdon ko kaise zinda karta hai” Farmaya: “kya tu iman nahin rakhta?” usne arz kiya “iman to rakhta hoon, magar dil ka itminaan darkaar hai”, Farmaya: “ accha to chaar parindey le aur unko apne se manoos (incline/tame) karle phir unka ek ek juz (part) ek ek pahaad par rakhde phir unko pukaar, woh tere paas daude chale aayenge, khoob jaan le ke Allah nihayat ba iqtedar aur hakeem hai”" },
    { number: 261, arabic: "مَّثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ كَمَثَلِ حَبَّةٍ أَنۢبَتَتْ سَبْعَ سَنَابِلَ فِى كُلِّ سُنۢبُلَةٍۢ مِّا۟ئَةُ حَبَّةٍۢ ۗ وَٱللَّهُ يُضَٰعِفُ لِمَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ", transliteration: "Mathalu allatheena yunfiqoona amwalahum fee sabeeli Allahi kamathali habbatin anbatat sabAAa sanabila fee kulli sunbulatin miatu habbatin waAllahu yudaAAifu liman yashao waAllahu wasiAAun AAaleemun", transliterationB: "Masalul lazeena yunfiqoona amwaalahum fee sabeelil laahi kamasali habbatin ambatat sab'a sanaabila fee kulli sumbulatim mi'atu habbah; wallaahu yudaa'ifu limai yashaaa; wallaahu Waasi'un 'Aleem", english: "The parable of those who spend their substance in the way of Allah is that of a grain of corn: it groweth seven ears, and each ear Hath a hundred grains. Allah giveth manifold increase to whom He pleaseth: And Allah careth for all and He knoweth all things", romanUrdu: "Jo log apne maal Allah ki raah mein sarf (kharch) karte hain, unke kharch ki misaal aisi hai, jaise ek dana boya (sow) jaye aur uske saat (seven) baalein niklein aur har baal mein sau (hundred) daaney hon, isi tarah Allah jiske amal ko chahta hai afzoni (manifold/zyada) ata farmata hai , woh faraag dast (All-Embracing) bhi hai aur aleem bhi" },
    { number: 262, arabic: "ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ ثُمَّ لَا يُتْبِعُونَ مَآ أَنفَقُوا۟ مَنًّۭا وَلَآ أَذًۭى ۙ لَّهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Allatheena yunfiqoona amwalahum fee sabeeli Allahi thumma la yutbiAAoona ma anfaqoo mannan wala athan lahum ajruhum AAinda rabbihim wala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Allazeena yunfiqoona amwaalahum fee sabeelillaahi summa laa yutbi'oona maaa anfaqoo mannanw wa laaa azal lahum ajruhum 'inda Rabbihim; wa laa khawfun 'alaihim wa laa hum yahzanoon", english: "Those who spend their substance in the cause of Allah, and follow not up their gifts with reminders of their generosity or with injury,-for them their reward is with their Lord: on them shall be no fear, nor shall they grieve", romanUrdu: "Jo log apne maal Allah ki raah mein kharch karte hain aur kharch karke phir ehsan nahin jatate na dukh dete hain, unka ajar unke Rubb ke paas hai aur unke liye kisi ranjh aur khauf ka mauqa nahin" },
    { number: 263, arabic: "۞ قَوْلٌۭ مَّعْرُوفٌۭ وَمَغْفِرَةٌ خَيْرٌۭ مِّن صَدَقَةٍۢ يَتْبَعُهَآ أَذًۭى ۗ وَٱللَّهُ غَنِىٌّ حَلِيمٌۭ", transliteration: "Qawlun maAAroofun wamaghfiratun khayrun min sadaqatin yatbaAAuha athan waAllahu ghaniyyun haleemun", transliterationB: "Qawlum ma'roofunw wa maghfiratun khairum min sadaqatiny yatba'uhaaa azaa; wallaahu Ghaniyyun Haleem", english: "Kind words and the covering of faults are better than charity followed by injury. Allah is free of all wants, and He is Most-Forbearing", romanUrdu: "Ek meetha bol aur kisi nagawaar baat par zara si chasm poshi (forbearance) us khairaat se behtar hai, jiske pichey dukh ho. Allah be-niyaz hai aur burdbaari (forbearing) uski siffat hai" },
    { number: 264, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُبْطِلُوا۟ صَدَقَٰتِكُم بِٱلْمَنِّ وَٱلْأَذَىٰ كَٱلَّذِى يُنفِقُ مَالَهُۥ رِئَآءَ ٱلنَّاسِ وَلَا يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ فَمَثَلُهُۥ كَمَثَلِ صَفْوَانٍ عَلَيْهِ تُرَابٌۭ فَأَصَابَهُۥ وَابِلٌۭ فَتَرَكَهُۥ صَلْدًۭا ۖ لَّا يَقْدِرُونَ عَلَىٰ شَىْءٍۢ مِّمَّا كَسَبُوا۟ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَٰفِرِينَ", transliteration: "Ya ayyuha allatheena amanoo la tubtiloo sadaqatikum bialmanni waalatha kaallathee yunfiqu malahu riaa alnnasi wala yuminu biAllahi waalyawmi alakhiri famathaluhu kamathali safwanin AAalayhi turabun faasabahu wabilun fatarakahu saldan la yaqdiroona AAala shayin mimma kasaboo waAllahu la yahdee alqawma alkafireena", transliterationB: "Yaaa ayyuhal lazeena aamanoo laa tubtiloo sadaqaatikum bilmanni wal azaa kallazee yunfiqu maalahoo ri'aaa'an naasi wa laa yu'minu billaahi wal yawmil aakhiri famasaluhoo kamasali safwaanin 'alaihi turaabun fa asaabahoo waabilun fatara kahoo saldaa; laa yaqdiroona 'alaa shai'im mimmaa kasaboo; wallaahu laa yahdil qawmal kaafireen", english: "O ye who believe! cancel not your charity by reminders of your generosity or by injury,- like those who spend their substance to be seen of men, but believe neither in Allah nor in the Last Day. They are in parable like a hard, barren rock, on which is a little soil: on it falls heavy rain, which leaves it (Just) a bare stone. They will be able to do nothing with aught they have earned. And Allah guideth not those who reject faith", romanUrdu: "Aey iman laney walon! Apne sadaqat ko ehsan jata kar aur dukh dekar us shaks ki tarah khaakh mein na mila do, jo apna maal mehaz logon ke dikhane ko kharch karta hai aur na Allah par iman rakhta hai na aakhirat par, uske kharch ki misaal aisi hai jaise ek chattan (rock) thi, jispar mitti ki teh jami hui thi, ispar jab zoar ka meh (barish) barsa, to saari mitti bhi gayi aur saaf chattan ki chattan reh gayi, aisey log apne nazdeek khayraat karke jo neki kamate hain, ussey kuch bhi unke haath nahin aata, aur kaafiron ko seedhi raah dikhana Allah ka dastoor nahin hai" },
    { number: 265, arabic: "وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ وَتَثْبِيتًۭا مِّنْ أَنفُسِهِمْ كَمَثَلِ جَنَّةٍۭ بِرَبْوَةٍ أَصَابَهَا وَابِلٌۭ فَـَٔاتَتْ أُكُلَهَا ضِعْفَيْنِ فَإِن لَّمْ يُصِبْهَا وَابِلٌۭ فَطَلٌّۭ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ", transliteration: "Wamathalu allatheena yunfiqoona amwalahumu ibtighaa mardati Allahi watathbeetan min anfusihim kamathali jannatin birabwatin asabaha wabilun faatat okulaha diAAfayni fain lam yusibha wabilun fatallun waAllahu bima taAAmaloona baseerun", transliterationB: "Wa masalul lazeena yunfiqoona amwaalahumub ti ghaaaa'a mardaatil laahi wa tasbeetam min anfusihim kamasali jannatim birabwatin asaabahaa waabilun fa aatat ukulahaa di'faini fa il lam yusibhaa waabilun fatall; wallaahu bimaa ta'maloona Baseer", english: "And the likeness of those who spend their substance, seeking to please Allah and to strengthen their souls, is as a garden, high and fertile: heavy rain falls on it but makes it yield a double increase of harvest, and if it receives not Heavy rain, light moisture sufficeth it. Allah seeth well whatever ye do", romanUrdu: "Bakhilaf iske jo log apne maal mehaz Allah ki raza-joyi ke liye dil ke poorey sabaat o qarar (single-minded) ke saath kharch karte hain, unke kharch ki misaal aisi hai, jaise kisi satah martafa (plateau) par ek baagh ho , agar zoar ki baarish ho jaye to duguna(twofold) phal laye, aur agar zoar ki baarish na bhi ho to ek halki phawar (light shower) hi uske liye kafi ho jaye, tum jo kuch karte ho, sab Allah ki nazar mein hai" },
    { number: 266, arabic: "أَيَوَدُّ أَحَدُكُمْ أَن تَكُونَ لَهُۥ جَنَّةٌۭ مِّن نَّخِيلٍۢ وَأَعْنَابٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ لَهُۥ فِيهَا مِن كُلِّ ٱلثَّمَرَٰتِ وَأَصَابَهُ ٱلْكِبَرُ وَلَهُۥ ذُرِّيَّةٌۭ ضُعَفَآءُ فَأَصَابَهَآ إِعْصَارٌۭ فِيهِ نَارٌۭ فَٱحْتَرَقَتْ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ", transliteration: "Ayawaddu ahadukum an takoona lahu jannatun min nakheelin waaAAnabin tajree min tahtiha alanharu lahu feeha min kulli alththamarati waasabahu alkibaru walahu thurriyyatun duAAafao faasabaha iAAsarun feehi narun faihtaraqat kathalika yubayyinu Allahu lakumu alayati laAAallakum tatafakkaroona", transliterationB: "Ayawaddu ahadukum an takoona lahoo jannatum min nakheelinw wa a'naabin tajree min tahtihal anhaaru lahoo feehaa min kullis samaraati wa asaabahul kibaru wa lahoo zurriyyatun du'afaaa'u fa asaabahaaa i'saarun feehi naarun fahtaraqat; kazaalika yubaiyinul laahu lakumul aayaati la'allakum tatafakkaroon", english: "Does any of you wish that he should have a garden with date-palms and vines and streams flowing underneath, and all kinds of fruit, while he is stricken with old age, and his children are not strong (enough to look after themselves)- that it should be caught in a whirlwind, with fire therein, and be burnt up? Thus doth Allah make clear to you (His) Signs; that ye may consider", romanUrdu: "Kya tum mein se koi yeh pasand karta hai ke uske paas ek hara bhara baagh ho, nehron se sairaab, khajooron aur angooron aur har qism ke phalon se ladha hua, aur woh ain us waqt ek teiz baghule (fiery whirlwind) ki zard mein aakar jhulas jaye, jabke woh khud boodha ho aur uske kamsin (small) bacchey abhi kisi layaq na hon? Is tarah Allah apni baatein tumhare saamne bayan karta hai, shayad ke tum gaur o fikr karo" },
    { number: 267, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ وَلَسْتُم بِـَٔاخِذِيهِ إِلَّآ أَن تُغْمِضُوا۟ فِيهِ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌ", transliteration: "Ya ayyuha allatheena amanoo anfiqoo min tayyibati ma kasabtum wamimma akhrajna lakum mina alardi wala tayammamoo alkhabeetha minhu tunfiqoona walastum biakhitheehi illa an tughmidoo feehi waiAAlamoo anna Allaha ghaniyyun hameedun", transliterationB: "Yaaa 'ayyuhal lazeena aamanooo anfiqoo min taiyibaati maa kasabtum wa mimmaaa akhrajuaa lakum minal ardi wa laa tayammamul khabeesa minhu tunfiqoona wa lastum bi aakhizeehi illaaa an tughmidoo feeh; wa'lamooo annal laaha Ghaniyyun Hameed", english: "O ye who believe! Give of the good things which ye have (honourably) earned, and of the fruits of the earth which We have produced for you, and do not even aim at getting anything which is bad, in order that out of it ye may give away something, when ye yourselves would not receive it except with closed eyes. And know that Allah is Free of all wants, and worthy of all praise", romanUrdu: "Aey logon jo iman laye ho, jo maal tumne kamaye hain aur jo kuch humne zameen se tumhare liye nikala hai, usmein se behtar hissa raah e khuda mein kharch karo, aisa na ho ke uski raah mein dene ke liye buri se buri cheez chaantne (pick out) ki koshish karne lago, halaanke wahi cheez agar koi tumhein dey to tum hargiz usey lena gawara na karoge illa yeh ke isko qabool karne mein tum igmaaz (disdain) barat jao, tumhein jaan lena chahiye ke Allah bay-niyaz hai aur behtareen sifaat se muttasif hai" },
    { number: 268, arabic: "ٱلشَّيْطَٰنُ يَعِدُكُمُ ٱلْفَقْرَ وَيَأْمُرُكُم بِٱلْفَحْشَآءِ ۖ وَٱللَّهُ يَعِدُكُم مَّغْفِرَةًۭ مِّنْهُ وَفَضْلًۭا ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", transliteration: "Alshshaytanu yaAAidukumu alfaqra wayamurukum bialfahshai waAllahu yaAAidukum maghfiratan minhu wafadlan waAllahu wasiAAun AAaleemun", transliterationB: "Ash Shaitaanu ya'idukumul faqra wa yaamurukum bilfahshaaa'i wallaahu ya'idukum maghfiratam minhu wa fadlaa; wallaahu Waasi'un 'Aleem", english: "The Evil one threatens you with poverty and bids you to conduct unseemly. Allah promiseth you His forgiveness and bounties. And Allah careth for all and He knoweth all things", romanUrdu: "Shaytan tumhein muflisi (poverty) se darata hai aur sharmnaak tarz-e-amal ikhtiyar karne ki targeeb deta hai, magar Allah tumhein apni bakshish aur fazal ki umeed dilata hai, Allah bada farag-dast aur daana hai" },
    { number: 269, arabic: "يُؤْتِى ٱلْحِكْمَةَ مَن يَشَآءُ ۚ وَمَن يُؤْتَ ٱلْحِكْمَةَ فَقَدْ أُوتِىَ خَيْرًۭا كَثِيرًۭا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", transliteration: "Yutee alhikmata man yashao waman yuta alhikmata faqad ootiya khayran katheeran wama yaththakkaru illa oloo alalbabi", transliterationB: "Yu'til Hikmata mai yashaaa'; wa mai yutal Hikmata faqad ootiya khairan kaseeraa; wa maa yazzakkaru illaaa ulul albaab", english: "He granteth wisdom to whom He pleaseth; and he to whom wisdom is granted receiveth indeed a benefit overflowing; but none will grasp the Message but men of understanding", romanUrdu: "Jisko chahta hai hikmat ata karta hai, aur jisko hikmat (wisdom) mili usey haqeeqat mein badi daulat mil gayi, in baaton se sirf wahi log sabaq lete hain jo danishmand hain" },
    { number: 270, arabic: "وَمَآ أَنفَقْتُم مِّن نَّفَقَةٍ أَوْ نَذَرْتُم مِّن نَّذْرٍۢ فَإِنَّ ٱللَّهَ يَعْلَمُهُۥ ۗ وَمَا لِلظَّٰلِمِينَ مِنْ أَنصَارٍ", transliteration: "Wama anfaqtum min nafaqatin aw nathartum min nathrin fainna Allaha yaAAlamuhu wama lilththalimeena min ansarin", transliterationB: "Wa maaa anfaqtum min nafaqatin aw nazartum min nazrin fa innal laaha ya'lamuh; wa maa lizzaalimeena min ansaar", english: "And whatever ye spend in charity or devotion, be sure Allah knows it all. But the wrong-doers have no helpers", romanUrdu: "Tumne jo kuch bhi kharch kiya ho aur jo nazar bhi maani ho, Allah ko uska ilm hai, aur zalimon ka koi madadgaar nahin" },
    { number: 271, arabic: "إِن تُبْدُوا۟ ٱلصَّدَقَٰتِ فَنِعِمَّا هِىَ ۖ وَإِن تُخْفُوهَا وَتُؤْتُوهَا ٱلْفُقَرَآءَ فَهُوَ خَيْرٌۭ لَّكُمْ ۚ وَيُكَفِّرُ عَنكُم مِّن سَيِّـَٔاتِكُمْ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "In tubdoo alssadaqati faniAAimma hiya wain tukhfooha watutooha alfuqaraa fahuwa khayrun lakum wayukaffiru AAankum min sayyiatikum waAllahu bima taAAmaloona khabeerun", transliterationB: "In tubdus sadaqaati fani'immaa hiya wa in tukhfoohaa wa tu'toohal fuqaraaa'a fahuwa khayrul lakum; wa yukaffiru 'ankum min saiyi aatikum; wallaahu bimaa ta'maloona Khabeer", english: "If ye disclose (acts of) charity, even so it is well, but if ye conceal them, and make them reach those (really) in need, that is best for you: It will remove from you some of your (stains of) evil. And Allah is well acquainted with what ye do", romanUrdu: "Agar apne sadaqaat elaniya (openly) do to yeh bhi accha hai, lekin agar chupa kar haajat-mandon ko do to yeh tumhare haqq mein zyada behtar hai, tumhari bahut si buraiyan is tarz e amal se mehw (expiate) ho jati hain .Aur jo kuch tum karte ho Allah ko bahar haal uski khabar hai" },
    { number: 272, arabic: "۞ لَّيْسَ عَلَيْكَ هُدَىٰهُمْ وَلَٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ فَلِأَنفُسِكُمْ ۚ وَمَا تُنفِقُونَ إِلَّا ٱبْتِغَآءَ وَجْهِ ٱللَّهِ ۚ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لَا تُظْلَمُونَ", transliteration: "Laysa AAalayka hudahum walakinna Allaha yahdee man yashao wama tunfiqoo min khayrin falianfusikum wama tunfiqoona illa ibtighaa wajhi Allahi wama tunfiqoo min khayrin yuwaffa ilaykum waantum la tuthlamoona", transliterationB: "Laisa 'alaika hudaahum wa laakinnal laaha yahdee mai yashaaa'; wa maa tunfiqoo min khairin fali anfusikum; wa maa tunfiqoona illab tighaaa'a wajhil laah; wa maa tunfiqoo min khairiny yuwaffa ilaikum wa antum laa tuzlamoon", english: "It is not required of thee (O Messenger), to set them on the right path, but Allah sets on the right path whom He pleaseth. Whatever of good ye give benefits your own souls, and ye shall only do so seeking the \"Face\" of Allah. Whatever good ye give, shall be rendered back to you, and ye shall not Be dealt with unjustly", romanUrdu: "Logon ko hidayat baksh dene ki zimmedari tumpar nahin hai, hidayat to Allah hi jisey chahta hai bakshta hai aur khairaat mein jo maal tum kharch karte ho woh tumhare apne liye bhala hai, aakhir tum isi liye to kharch karte ho ke Allah ki raza hasil ho, to jo kuch maal tum khairaat mein kharch karoge uska poora poora ajar tumhein diya jayega aur tumhari haqq talafi hargiz na hogi" },
    { number: 273, arabic: "لِلْفُقَرَآءِ ٱلَّذِينَ أُحْصِرُوا۟ فِى سَبِيلِ ٱللَّهِ لَا يَسْتَطِيعُونَ ضَرْبًۭا فِى ٱلْأَرْضِ يَحْسَبُهُمُ ٱلْجَاهِلُ أَغْنِيَآءَ مِنَ ٱلتَّعَفُّفِ تَعْرِفُهُم بِسِيمَٰهُمْ لَا يَسْـَٔلُونَ ٱلنَّاسَ إِلْحَافًۭا ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ", transliteration: "Lilfuqarai allatheena ohsiroo fee sabeeli Allahi la yastateeAAoona darban fee alardi yahsabuhumu aljahilu aghniyaa mina alttaAAaffufi taAArifuhum biseemahum la yasaloona alnnasa ilhafan wama tunfiqoo min khayrin fainna Allaha bihi AAaleemun", transliterationB: "Lilfuqaraaa'il lazeena uhsiroo fee sabeelil laahi laa yastatee'oona darban fil ardi yah sabuhumul jaahilu aghniyaaa'a minat ta'affufi ta'rifuhum biseemaahum laa yas'aloonan naasa ilhaafaa; wa maa tunfiqoo min khairin fa innal laaha bihee 'Aleem", english: "(Charity is) for those in need, who, in Allah's cause are restricted (from travel), and cannot move about in the land, seeking (For trade or work): the ignorant man thinks, because of their modesty, that they are free from want. Thou shalt know them by their (Unfailing) mark: They beg not importunately from all the sundry. And whatever of good ye give, be assured Allah knoweth it well", romanUrdu: "Khaas taur par madad ke mustahiq to tangdast log hain jo Allah ke kaam mein aisey ghir gaye hain ke apni zaati kasb-e-maash (livelihood) ke liye zameen mein koi daud-dhoop nahin kar sakte. Unki khuddaari dekh kar nawaqif aadmi gumaan karta hai ke yeh khush-haal hain, tum unke chehron se unki andaruni haalat pehchan sakte ho magar woh aisey log nahin hain ke logon ke pichey padh kar kuch maangein. Unki iyanat mein jo kuch maal tum kharch karoge woh Allah se posheeda na rahega" },
    { number: 274, arabic: "ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُم بِٱلَّيْلِ وَٱلنَّهَارِ سِرًّۭا وَعَلَانِيَةًۭ فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Allatheena yunfiqoona amwalahum biallayli waalnnahari sirran waAAalaniyatan falahum ajruhum AAinda rabbihim wala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Allazeena yunfiqoona amwaalahum billaili wan nahaari sirranw wa 'alaaniyatan falahum ajruhum 'inda Rabbihim wa laa khawfun 'alaihim wa laa hum yahzanoon", english: "Those who (in charity) spend of their goods by night and by day, in secret and in public, have their reward with their Lord: on them shall be no fear, nor shall they grieve", romanUrdu: "Jo log apne maal shab-o-roz khule aur chupe kharch karte hain unka ajar unke Rubb ke paas hai aur unke liye kisi khauf aur ranjh ka muqaam nahin" },
    { number: 275, arabic: "ٱلَّذِينَ يَأْكُلُونَ ٱلرِّبَوٰا۟ لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ ٱلَّذِى يَتَخَبَّطُهُ ٱلشَّيْطَٰنُ مِنَ ٱلْمَسِّ ۚ ذَٰلِكَ بِأَنَّهُمْ قَالُوٓا۟ إِنَّمَا ٱلْبَيْعُ مِثْلُ ٱلرِّبَوٰا۟ ۗ وَأَحَلَّ ٱللَّهُ ٱلْبَيْعَ وَحَرَّمَ ٱلرِّبَوٰا۟ ۚ فَمَن جَآءَهُۥ مَوْعِظَةٌۭ مِّن رَّبِّهِۦ فَٱنتَهَىٰ فَلَهُۥ مَا سَلَفَ وَأَمْرُهُۥٓ إِلَى ٱللَّهِ ۖ وَمَنْ عَادَ فَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Allatheena yakuloona alrriba la yaqoomoona illa kama yaqoomu allathee yatakhabbatuhu alshshaytanu mina almassi thalika biannahum qaloo innama albayAAu mithlu alrriba waahalla Allahu albayAAa waharrama alrriba faman jaahu mawAAithatun min rabbihi faintaha falahu ma salafa waamruhu ila Allahi waman AAada faolaika ashabu alnnari hum feeha khalidoona", transliterationB: "Allazeena yaakuloonar ribaa laa yaqoomoona illaa kamaa yaqoomul lazee yatakhabbatuhush shaitaanu minal mass; zaalika bi annahum qaalooo innamal bai'u mishur ribaa; wa ahallal laahul bai'a wa harramar ribba; faman jaaa'ahoo maw'izatum mir rabbihee fantahaa falahoo maa salafa wa amruhooo ilal laahi wa man 'aada fa ulaaa 'ika Ashaabun naari hum feehaa khaalidoon", english: "Those who devour usury will not stand except as stand one whom the Evil one by his touch Hath driven to madness. That is because they say: \"Trade is like usury,\" but Allah hath permitted trade and forbidden usury. Those who after receiving direction from their Lord, desist, shall be pardoned for the past; their case is for Allah (to judge); but those who repeat (The offence) are companions of the Fire: They will abide therein (for ever)", romanUrdu: "Magar jo log sood (usury) khate hain, unka haal us shaks ka sa hota hai, jisey Shaytan ne choo kar bawla (deewana) kardiya ho aur is haalat mein unke mubtila hone ki wajah yeh hai ke woh kehte hain : “ tijarat bhi to aakhir sood hi jaisi cheez hai”, halanke Allah ne tijarat ko halal kiya hai aur sood ko haraam. Lihaza jis shaks ko uske Rubb ki taraf se yeh naseehat pahunche aur aainda ke liye woh sood-khori se baaz aa jaye , to jo kuch woh pehle kha chuka, so kha chuka, uska maamla Allah ke hawale hai aur jo is hukm ke baad phir isi harakat ka iaada (repeat) karey, toh jahannami hai, jahan woh hamesha rahega" },
    { number: 276, arabic: "يَمْحَقُ ٱللَّهُ ٱلرِّبَوٰا۟ وَيُرْبِى ٱلصَّدَقَٰتِ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ كَفَّارٍ أَثِيمٍ", transliteration: "Yamhaqu Allahu alrriba wayurbee alssadaqati waAllahu la yuhibbu kulla kaffarin atheemin", transliterationB: "Yamhaqul laahur ribaa wa yurbis sadaqaat; wallaahu laa yuhibbu kulla kaffaarin aseem", english: "Allah will deprive usury of all blessing, but will give increase for deeds of charity: For He loveth not creatures ungrateful and wicked", romanUrdu: "Allah Sood ka matth maar deta hai (deprives interest of all blessing ) aur sadaqaat ko nasho numa deta hai, aur Allah kisi nashukre badh-amal Insaan ko pasand nahin karta" },
    { number: 277, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Inna allatheena amanoo waAAamiloo alssalihati waaqamoo alssalata waatawoo alzzakata lahum ajruhum AAinda rabbihim wala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Innal lazeena aamanoo wa amilus saalihaati wa aqaamus salaata wa aatawuz zakaata lahum ajruhum 'inda rabbihim wa laa khawfun 'alaihim wa laa hum yahzanoon", english: "Those who believe, and do deeds of righteousness, and establish regular prayers and regular charity, will have their reward with their Lord: on them shall be no fear, nor shall they grieve", romanUrdu: "Haan, jo log iman le ayein aur neik amal karein aur namaz qayam karein aur zakaat dein, unka ajar beshak unke Rubb ke paas hai aur unke liye kisi khauf aur ranjh ka mauqa nahin" },
    { number: 278, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَذَرُوا۟ مَا بَقِىَ مِنَ ٱلرِّبَوٰٓا۟ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Ya ayyuha allatheena amanoo ittaqoo Allaha watharoo ma baqiya mina alrriba in kuntum mumineena", transliterationB: "Yaaa ayyuhal lazeena aamanut taqul laaha wa zaroo maa baqiya minar ribaaa in kuntum mu'mineen", english: "O ye who believe! Fear Allah, and give up what remains of your demand for usury, if ye are indeed believers", romanUrdu: "Aey logon jo iman laye ho, khuda se daro aur jo kuch tumhara sood logon par baki reh gaya hai usye chodh do, agar waqayi tum iman laye ho" },
    { number: 279, arabic: "فَإِن لَّمْ تَفْعَلُوا۟ فَأْذَنُوا۟ بِحَرْبٍۢ مِّنَ ٱللَّهِ وَرَسُولِهِۦ ۖ وَإِن تُبْتُمْ فَلَكُمْ رُءُوسُ أَمْوَٰلِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ", transliteration: "Fain lam tafAAaloo fathanoo biharbin mina Allahi warasoolihi wain tubtum falakum ruoosu amwalikum la tathlimoona wala tuthlamoona", transliterationB: "Fail lam taf'aloo faazanoo biharbim minal laahi wa Rasoolihee wa in tubtum falakum ru'oosu amwaalikum laa tazlimoona wa laa tuzlamoon", english: "If ye do it not, Take notice of war from Allah and His Messenger: But if ye turn back, ye shall have your capital sums: Deal not unjustly, and ye shall not be dealt with unjustly", romanUrdu: "Lekin agar tumne aisa na kiya, to aagaah ho jao ke Allah aur uske Rasool ki taraf se tumhare khilaf elan-e-jung hai. Ab bhi tawba karlo (aur sood chod do) to apna asal sarmaya lene ke tum haqqdaar ho, na tum zulm karo , na tumpar zulm kiya jaye" },
    { number: 280, arabic: "وَإِن كَانَ ذُو عُسْرَةٍۢ فَنَظِرَةٌ إِلَىٰ مَيْسَرَةٍۢ ۚ وَأَن تَصَدَّقُوا۟ خَيْرٌۭ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Wain kana thoo AAusratin fanathiratun ila maysaratin waan tasaddaqoo khayrun lakum in kuntum taAAlamoona", transliterationB: "Wa in kaana zoo 'usratin fanaziratun ilaa maisarah; wa an tasaddaqoo khairul lakum in kuntum ta'lamoon", english: "If the debtor is in a difficulty, grant him time Till it is easy for him to repay. But if ye remit it by way of charity, that is best for you if ye only knew", romanUrdu: "Tumhara qarzdaar tangdast ho, to haath khulne tak usey mohlat do, aur jo sadaqa kardo to yeh tumhare liye zyada behtar hai, agar tum samjho" },
    { number: 281, arabic: "وَٱتَّقُوا۟ يَوْمًۭا تُرْجَعُونَ فِيهِ إِلَى ٱللَّهِ ۖ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Waittaqoo yawman turjaAAoona feehi ila Allahi thumma tuwaffa kullu nafsin ma kasabat wahum la yuthlamoona", transliterationB: "Wattaqoo yawman turja'oona feehi ilal laahi summa tuwaffaa kullu nafsim maa kasabat wa hum laa yuzlamoon", english: "And fear the Day when ye shall be brought back to Allah. Then shall every soul be paid what it earned, and none shall be dealt with unjustly", romanUrdu: "Us din ki ruswayi o museebat se bacho, jabke tum Allah ki taraf wapas hongey, wahan har shaks ko uski kamayi hui neki ya badhi ka poora poora badla mil jayega aur kisi par zulm hargiz na hoga" },
    { number: 282, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا تَدَايَنتُم بِدَيْنٍ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى فَٱكْتُبُوهُ ۚ وَلْيَكْتُب بَّيْنَكُمْ كَاتِبٌۢ بِٱلْعَدْلِ ۚ وَلَا يَأْبَ كَاتِبٌ أَن يَكْتُبَ كَمَا عَلَّمَهُ ٱللَّهُ ۚ فَلْيَكْتُبْ وَلْيُمْلِلِ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ وَلَا يَبْخَسْ مِنْهُ شَيْـًۭٔا ۚ فَإِن كَانَ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ سَفِيهًا أَوْ ضَعِيفًا أَوْ لَا يَسْتَطِيعُ أَن يُمِلَّ هُوَ فَلْيُمْلِلْ وَلِيُّهُۥ بِٱلْعَدْلِ ۚ وَٱسْتَشْهِدُوا۟ شَهِيدَيْنِ مِن رِّجَالِكُمْ ۖ فَإِن لَّمْ يَكُونَا رَجُلَيْنِ فَرَجُلٌۭ وَٱمْرَأَتَانِ مِمَّن تَرْضَوْنَ مِنَ ٱلشُّهَدَآءِ أَن تَضِلَّ إِحْدَىٰهُمَا فَتُذَكِّرَ إِحْدَىٰهُمَا ٱلْأُخْرَىٰ ۚ وَلَا يَأْبَ ٱلشُّهَدَآءُ إِذَا مَا دُعُوا۟ ۚ وَلَا تَسْـَٔمُوٓا۟ أَن تَكْتُبُوهُ صَغِيرًا أَوْ كَبِيرًا إِلَىٰٓ أَجَلِهِۦ ۚ ذَٰلِكُمْ أَقْسَطُ عِندَ ٱللَّهِ وَأَقْوَمُ لِلشَّهَٰدَةِ وَأَدْنَىٰٓ أَلَّا تَرْتَابُوٓا۟ ۖ إِلَّآ أَن تَكُونَ تِجَٰرَةً حَاضِرَةًۭ تُدِيرُونَهَا بَيْنَكُمْ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَلَّا تَكْتُبُوهَا ۗ وَأَشْهِدُوٓا۟ إِذَا تَبَايَعْتُمْ ۚ وَلَا يُضَآرَّ كَاتِبٌۭ وَلَا شَهِيدٌۭ ۚ وَإِن تَفْعَلُوا۟ فَإِنَّهُۥ فُسُوقٌۢ بِكُمْ ۗ وَٱتَّقُوا۟ ٱللَّهَ ۖ وَيُعَلِّمُكُمُ ٱللَّهُ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo itha tadayantum bidaynin ila ajalin musamman faoktuboohu walyaktub baynakum katibun bialAAadli wala yaba katibun an yaktuba kama AAallamahu Allahu falyaktub walyumlili allathee AAalayhi alhaqqu walyattaqi Allaha rabbahu wala yabkhas minhu shayan fain kana allathee AAalayhi alhaqqu safeehan aw daAAeefan aw la yastateeAAu an yumilla huwa falyumlil waliyyuhu bialAAadli waistashhidoo shaheedayni min rijalikum fain lam yakoona rajulayni farajulun waimraatani mimman tardawna mina alshshuhadai an tadilla ihdahuma fatuthakkira ihdahuma alokhra wala yaba alshshuhadao itha ma duAAoo wala tasamoo an taktuboohu sagheeran aw kabeeran ila ajalihi thalikum aqsatu AAinda Allahi waaqwamu lilshshahadati waadna alla tartaboo illa an takoona tijaratan hadiratan tudeeroonaha baynakum falaysa AAalaykum junahun alla taktubooha waashhidoo itha tabayaAAtum wala yudarra katibun wala shaheedun wain tafAAaloo fainnahu fusooqun bikum waittaqoo Allaha wayuAAallimukumu Allahu waAllahu bikulli shayin AAaleemun", transliterationB: "Yaa ayyuhal lazeena aamanoo izaa tadaayantum bidinin ilaa ajalimmusamman faktubooh; walyaktub bainakum kaatibum bil'adl; wa laa yaaba kaatibun ai yaktuba kamaa 'allamahul laah; falyaktub walyumlilil lazee 'alaihil haqqu walyattaqil laaha rabbahoo wa laa yabkhas minhu shai'aa; fa in kaanal lazee 'alaihil lhaqqu safeehan aw da'eefan aw laa yastatee'u ai yumilla huwa falyumlil waliyyuhoo bil'adl; wastash hidoo shaheedaini mir rijaalikum fa il lam yakoonaa rajulaini farajulunw wamra ataani mimman tardawna minash shuhadaaa'i an tadilla ihdaahumaa fatuzakkira ihdaahumal ukhraa; wa laa yaabash shuhadaaa'u izaa maadu'oo; wa laa tas'amooo an taktuboohu sagheeran awkabeeran ilaaa ajalih; zaalikum aqsatu 'indal laahi wa aqwamu lishshahaadati wa adnaaa allaa tartaabooo illaaa an takoona tijaaratan haadiratan tudeeroonahaa bainakum falaisa 'alaikum junaahun allaa taktuboohan; wa ashidooo izaa tabaaya'tum; wa laa yudaaarra kaatibunw wa laa shaheed; wa in taf'aloo fa innahoo fusooqum bikum; wattaqul laaha wa yu'allimu kumul laah; wallaahu bikulli shai'in 'Aleem", english: "O ye who believe! When ye deal with each other, in transactions involving future obligations in a fixed period of time, reduce them to writing Let a scribe write down faithfully as between the parties: let not the scribe refuse to write: as Allah Has taught him, so let him write. Let him who incurs the liability dictate, but let him fear His Lord Allah, and not diminish aught of what he owes. If they party liable is mentally deficient, or weak, or unable Himself to dictate, Let his guardian dictate faithfully, and get two witnesses, out of your own men, and if there are not two men, then a man and two women, such as ye choose, for witnesses, so that if one of them errs, the other can remind her. The witnesses should not refuse when they are called on (For evidence). Disdain not to reduce to writing (your contract) for a future period, whether it be small or big: it is juster in the sight of Allah, More suitable as evidence, and more convenient to prevent doubts among yourselves but if it be a transaction which ye carry out on the spot among yourselves, there is no blame on you if ye reduce it not to writing. But take witness whenever ye make a commercial contract; and let neither scribe nor witness suffer harm. If ye do (such harm), it would be wickedness in you. So fear Allah; For it is Good that teaches you. And Allah is well acquainted with all things. If ye are on a journey, and cannot find a scribe, a pledge with possession (may serve the purpose). And if one of you deposits a thing on trust with another, let the trustee (faithfully) discharge his trust, and let him Fear his Lord conceal not evidence; for whoever conceals it, - his heart is tainted with sin. And Allah knoweth all that ye do", romanUrdu: "Aey logon jo iman laye ho, jab kisi muqarrar muddat ke liye tum aapas mein qarz ka lein dein karo to usey likh liya karo. Fareeqain ke darmiyan insaaf ke saath ek shaks dastawez (document) tehrir karey. Jisey Allah ne likhe padhne ki kaabiliyat bakshi ho, usey likhne se inkar na karna chahiye. Woh likhey aur imla (dictate) woh shaks karaye jispar haqq aata hai (yaani qarz lene wala), aur usey Allah, apne Rubb se darna chahiye ke jo maamla tai ho usmein koi kami beshi na karey. Lekin agar qarz lene wala khud nadaan ya zaeef ho, ya imla na kara sakta ho, to uska wali insaaf ke saath imla karaye, phir apne mardon mein se do aadmiyon ki ispar gawahi karalo aur agar do Mard na hon to ek Mard aur do auratein hon, taa-ke ek bhool jaye to dusri usey yaad dila de. Yeh gawaah aisey logon mein se honi chahiye jinki gawahi tumhare darmiyan maqbool ho. Gawahon ko jab gawaah banney ke liye kaha jaye, to unhein inkar na karna chahiye. Maamla khwa chota ho ya bada, miyaad ki taeen (specified term) ke saath uski dastawez (documents) likhwa lene mein tasahul (neglect) na karo. Allah ke nazdeek yeh tareeqa tumhare liye zyada mabni bar Insaaf hai, issey shahadat qayam honay mein zyada sahulat hoti hai, aur tumhare shukook o shubhaaat mein mubtila honay ka imkan kam reh jata hai. Haan jo tijarati lein dein dast ba dast tumlog aapas mein karte ho, usko na likha jaye to koi harj nahin, magar tijarati maamle tai karte waqt gawah karliya karo. Kaatib (scribe) aur gawah ko sataya na jaye , aisa karoge to gunaah ka irteqaab karoge. Allah ke gazab se bacho, woh tumko saheeh tareeq e amal ki taleem deta hai aur usey har cheez ka ilm hai" },
    { number: 283, arabic: "۞ وَإِن كُنتُمْ عَلَىٰ سَفَرٍۢ وَلَمْ تَجِدُوا۟ كَاتِبًۭا فَرِهَٰنٌۭ مَّقْبُوضَةٌۭ ۖ فَإِنْ أَمِنَ بَعْضُكُم بَعْضًۭا فَلْيُؤَدِّ ٱلَّذِى ٱؤْتُمِنَ أَمَٰنَتَهُۥ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ ۗ وَلَا تَكْتُمُوا۟ ٱلشَّهَٰدَةَ ۚ وَمَن يَكْتُمْهَا فَإِنَّهُۥٓ ءَاثِمٌۭ قَلْبُهُۥ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌۭ", transliteration: "Wain kuntum AAala safarin walam tajidoo katiban farihanun maqboodatun fain amina baAAdukum baAAdan falyuaddi allathee itumina amanatahu walyattaqi Allaha rabbahu wala taktumoo alshshahadata waman yaktumha fainnahu athimun qalbuhu waAllahu bima taAAmaloona AAaleemun", transliterationB: "Wa in kuntum 'alaa safarinw wa lam tajidoo kaatiban farihaanum maqboodatun fa in amina ba'dukum ba'dan falyu'addil lazi tumina amaa natahoo walyattaqil laaha Rabbah; wa laa taktumush shahaadah; wa mai yaktumhaa fa innahooo aasimun qalbuh; wallaahu bimaa ta'maloona 'Aleem", english: "If ye are on a journey, and cannot find a scribe, a pledge with possession (may serve the purpose). And if one of you deposits a thing on trust with another, Let the trustee (Faithfully) discharge His trust, and let him fear his Lord. Conceal not evidence; for whoever conceals it,- His heart is tainted with sin. And Allah Knoweth all that ye do", romanUrdu: "Agar tum safar ki haalat mein ho aur dastawez likhne ke liye koi kaatib (scribe) na miley to rehan bil qabz (security of a pledge in hand ) par maamla karo, agar tum mein se koi shaks dusre par bharosa karke iske saath koi maamla karey to jispar bharosa kiya gaya hai usey chahiye ke amanat ada karey aur Allah apne Rubb se darey aur shahadat hargiz na chupao. Jo shahadat chupata hai uska dil gunaah mein aaluda hai aur Allah tumhare aamaal se bekhabar nahin hai" },
    { number: 284, arabic: "لِّلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Lillahi ma fee alssamawati wama fee alardi wain tubdoo ma fee anfusikum aw tukhfoohu yuhasibkum bihi Allahu fayaghfiru liman yashao wayuAAaththibu man yashao waAllahu AAala kulli shayin qadeerun", transliterationB: "Lillaahi maa fissamaawaati wa maa fil ard; wa in tubdoo maa feee anfusikum aw tukhfoohu yuhaasibkum bihil laa; fayaghfiru li mai yashaaa'u wa yu'azzibu mai yashaaa u;wallaahu 'alaa kulli shai in qadeer", english: "To Allah belongeth all that is in the heavens and on earth. Whether ye show what is in your minds or conceal it, Allah Calleth you to account for it. He forgiveth whom He pleaseth, and punisheth whom He pleaseth, for Allah hath power over all things", romanUrdu: "Asmaano aur zameen mein jo kuch hai sab Allah ka hai, tum apne dil ki baatein khwa zaahir karo ya chupao, Allah bahar haal unka hisaab tumse le lega, phir usey ikhtiyar hai jisey chahe maaf karde aur jisey chahe saza de, woh har cheez par qudrat rakhta hai" },
    { number: 285, arabic: "ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ", transliteration: "Amana alrrasoolu bima onzila ilayhi min rabbihi waalmuminoona kullun amana biAllahi wamalaikatihi wakutubihi warusulihi la nufarriqu bayna ahadin min rusulihi waqaloo samiAAna waataAAna ghufranaka rabbana wailayka almaseeru", transliterationB: "Aamanar-Rasoolu bimaaa unzila ilaihi mir-Rabbihee walmu'minoon; kullun aamana billaahi wa Malaaa'ikathihee wa Kutubhihee wa Rusulih laa nufarriqu baina ahadim-mir-Rusulihee wa qaaloo sami'naa wa ata'naa ghufraanaka Rabbanaa wa ilaikal-maseer", english: "The Messenger believeth in what hath been revealed to him from his Lord, as do the men of faith. Each one (of them) believeth in Allah, His angels, His books, and His messengers. \"We make no distinction (they say) between one and another of His messengers.\" And they say: \"We hear, and we obey: (We seek) Thy forgiveness, our Lord, and to Thee is the end of all journeys", romanUrdu: "Rasool us hidayat par iman laya hai jo uske Rubb ki taraf se uspar nazil hui hai aur jo log is Rasool ke maanne waley hain unhon ne bhi is hidayat ko dilse tasleem karliya hai, yeh sab Allah aur uske Farishton aur uski kitabon aur uske Rasoolon ko maante hain aur unka qaul yeh hai ke : “hum Allah ke Rasoolon ko ek dusre se alag nahin karte, humne hukum suna aur itaat qabool ki. Malik! Hum tujhse khata-bakhsi (bakshish) ke taalib hain aur humein teri hi taraf palatna hai.”" },
    { number: 286, arabic: "لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًۭا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ وَٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", transliteration: "La yukallifu Allahu nafsan illa wusAAaha laha ma kasabat waAAalayha ma iktasabat rabbana la tuakhithna in naseena aw akhtana rabbana wala tahmil AAalayna isran kama hamaltahu AAala allatheena min qablina rabbana wala tuhammilna ma la taqata lana bihi waoAAfu AAanna waighfir lana wairhamna anta mawlana faonsurna AAala alqawmi alkafireena", transliterationB: "Laa yukalliful-laahu nafsan illaa wus'ahaa; lahaa maa kasabat wa 'alaihaa maktasabat; Rabbanaa la tu'aakhiznaa in naseenaaa aw akhtaanaa; Rabbanaa wa laa tahmil-'alainaaa isran kamaa hamaltahoo 'alal-lazeena min qablinaa; Rabbanaa wa laa tuhammilnaa maa laa taaqata lanaa bih wa'fu 'annaa waghfir lanaa warhamnaa; Anta mawlaanaa fansurnaa 'alal qawmil kaafireen", english: "On no soul doth Allah Place a burden greater than it can bear. It gets every good that it earns, and it suffers every ill that it earns. (Pray:) \"Our Lord! Condemn us not if we forget or fall into error; our Lord! Lay not on us a burden Like that which Thou didst lay on those before us; Our Lord! Lay not on us a burden greater than we have strength to bear. Blot out our sins, and grant us forgiveness. Have mercy on us. Thou art our Protector; Help us against those who stand against faith", romanUrdu: "Allah kisi mutanaffis par uski maqdarat (taqat) se badkar zimmedari ka bojh nahin daalta, har shaks ne jo neki kamayi hai uska phal usi ke liye hai aur jo badhi sameti hai uska wabaal usi par hai, (Iman laney walon! Tum yun dua kiya karo) aey hamare Rubb! Humse bhool chuk mein jo kasoor ho jayein unpar giraft na kar, Malik! Humpar woh bojh na daal jo tu-nay humse pehle logon par daley thay. Parwardigaar ! jis baar ko uthane ki taaqat hum mein nahin hai woh humpar na rakh, hamare saath narmi kar, humse darguzar farma, humpar reham kar, tu hamara maula hai, kafiron ke muqable mein hamari madad kar" }
  ]
};
